def _bk_tables_ready() -> bool:
    """Return True if backup policy tables exist."""
    try:
        insp = db.inspect(db.engine)
        return (
            insp.has_table('bk_library')
            and insp.has_table('bk_location')
            and insp.has_table('bk_tape')
        )
    except Exception:
        logger.exception('Failed to inspect backup policy tables')
        return False


def _bk_policy_tables_ready() -> bool:
    """Return True if backup target policy tables exist."""
    try:
        insp = db.inspect(db.engine)
        return insp.has_table('bk_storage_pool') and insp.has_table('bk_backup_target_policy')
    except Exception:
        logger.exception('Failed to inspect backup target policy tables')
        return False


