@api_bp.route('/api/governance/dr-trainings/<int:training_id>', methods=['PUT'])
@_require_login_decorator
@_require_tables_decorator('dr_training')
@_db_transaction_decorator('모의훈련 수정 중 오류가 발생했습니다.')
def update_dr_training(training_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return api_unauthorized('사용자 세션이 만료되었습니다.')

    payload = request.get_json(silent=True) or {}
    now = datetime.utcnow().isoformat(timespec='seconds')

    row = DrTraining.query.filter(DrTraining.training_id == training_id).first()
    if not row or int(row.is_deleted or 0) != 0:
        return api_not_found()

    client_version = payload.get('version')
    if client_version is not None and int(client_version) != (row.version or 1):
        return api_error('다른 사용자가 이미 수정한 데이터입니다. 새로고침 후 다시 시도해 주세요.', status=409)

    _dr_training_apply_payload(row, payload, strict_required=False)
    row.updated_at = now
    row.updated_by_user_id = actor_user_id
    row.version = (row.version or 1) + 1
    db.session.commit()
    return api_response(item=_dr_training_to_item(row))


@api_bp.route('/api/governance/dr-trainings/bulk-delete', methods=['POST'])
@_require_login_decorator
@_require_tables_decorator('dr_training')
@_db_transaction_decorator('모의훈련 삭제 중 오류가 발생했습니다.')
def delete_dr_trainings():
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return api_unauthorized('사용자 세션이 만료되었습니다.')

    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids')
    if not isinstance(ids, (list, tuple)) or not ids:
        return api_bad_request('삭제할 항목을 선택하세요.')

    now = datetime.utcnow().isoformat(timespec='seconds')
    ids_int = []
    for raw in ids:
        try:
            ids_int.append(int(raw))
        except Exception:
            continue
    if not ids_int:
        return api_bad_request('삭제할 항목을 선택하세요.')

    rows = DrTraining.query.filter(DrTraining.training_id.in_(ids_int)).all()
    deleted = 0
    for row in rows:
        if int(row.is_deleted or 0) != 0:
            continue
        row.is_deleted = 1
        row.updated_at = now
        row.updated_by_user_id = actor_user_id
        deleted += 1
    db.session.commit()
    return api_response(deleted=deleted)


