_BK_ALLOWED_BACKUP_SCOPES = {'내부망', '외부망'}
_BK_ALLOWED_DATA_TYPES = {'ARC', 'DB', 'FILE', 'LOG', 'OS', 'SRC', 'VM'}
_BK_ALLOWED_GRADES = {'1등급', '2등급', '3등급'}
_BK_ALLOWED_OFFSITE = {'O', 'X'}
_BK_ALLOWED_MEDIA = {'Client(Network)', 'Client(SAN)', 'Media Server'}
_BK_ALLOWED_RETENTION_UNITS = {'주', '월', '년', 'Infinity'}

_BK_ALLOWED_SCHEDULE_PERIODS = {'매일', '매주', '매달', '매년'}
_BK_ALLOWED_WEEKDAYS = {'월', '화', '수', '목', '금', '토', '일'}


def _coerce_int_or_none(value: Any) -> Optional[int]:
    if value is None:
        return None
    if isinstance(value, bool):
        return None
    s = str(value).strip()
    if not s:
        return None
    try:
        return int(s)
    except (TypeError, ValueError):
        return None


def _validate_bk_schedule(period: str, weekday: str, day: Optional[int]) -> Optional[str]:
    p = (period or '').strip()
    w = (weekday or '').strip()

    # Treat all-empty as "no schedule" (allowed)
    if not p and not w and day is None:
        return None

    if not p:
        return '주기를 선택하세요.'
    if p not in _BK_ALLOWED_SCHEDULE_PERIODS:
        return '주기 값이 올바르지 않습니다. (매일/매주/매달/매년)'

    if p == '매주':
        if w not in _BK_ALLOWED_WEEKDAYS:
            return '요일을 선택하세요. (매주 선택 시)'
        if day is not None:
            return '일자는 매달 선택 시에만 입력합니다.'
        return None

    if p == '매달':
        if w:
            return '요일은 매주 선택 시에만 입력합니다.'
        if day is None:
            return '일자를 입력하세요. (1~31, 매달 선택 시)'
        if day < 1 or day > 31:
            return '일자는 1~31 범위여야 합니다.'
        return None

    # 매일/매년
    if w:
        return '요일은 매주 선택 시에만 입력합니다.'
    if day is not None:
        return '일자는 매달 선택 시에만 입력합니다.'
    return None


