def _hw_server_vl_to_dict(row: HwServerVulnerability) -> dict:
    def _norm_action_status(value: str) -> str:
        v = (value or '').strip()
        if not v:
            return ''
        if v in ('완료', '미완료'):
            return v
        if v.upper() in ('O', 'Y', 'YES'):
            return '완료'
        if v.upper() in ('X', 'N', 'NO'):
            return '미완료'
        return v

    legacy_action = (row.action_yn or '').strip()
    action_status = _norm_action_status((row.action_status or '').strip() or legacy_action)
    action_yn = legacy_action
    if not action_yn and action_status:
        action_yn = 'O' if action_status == '완료' else ('X' if action_status == '미완료' else '')

    return {
        'id': row.id,
        'asset_category': row.asset_category,
        'asset_id': int(row.asset_id),
        'category': row.category,
        'item': row.item,
        'severity': (row.severity or '').strip(),
        'code': row.code or '',
        'content': row.content or '',
        'result': (row.result or '').strip(),
        'action_yn': action_yn,
        'remark': row.remark or '',

        # Extended schema fields (preferred by new UI)
        'check_category': (row.check_category or row.category or '').strip(),
        'check_code': (row.check_code or row.code or '').strip(),
        'check_topic': (row.check_topic or row.item or '').strip(),
        'check_subtopic': (row.check_subtopic or '').strip(),
        'check_overview': row.check_overview or row.content or '',
        'check_standard': row.check_standard or '',
        'check_result': row.check_result or '',
        'action_method': row.action_method or '',
        'action_status': action_status,
        'action_due_date': (row.action_due_date or '').strip(),
        'worker_name': (row.worker_name or '').strip(),

        'created_at': row.created_at,
        'updated_at': row.updated_at,
        'is_deleted': int(row.is_deleted or 0),
    }


