def _validate_hhmm(value: Optional[str]) -> bool:
    raw = (value or '').strip()
    if not raw:
        return True
    return bool(re.match(r'^([01]\d|2[0-3]):([0-5]\d)$', raw))


def _append_diag_text(filename: str, text: str) -> None:
    try:
        base_dir = os.getcwd()
        path = os.path.join(base_dir, filename)
        with open(path, 'a', encoding='utf-8') as f:
            f.write(text)
            if not text.endswith('\n'):
                f.write('\n')
    except Exception:
        # Never fail the request due to diagnostics.
        return


