@api_bp.route('/api/governance/packages', methods=['GET'])
def list_governance_packages():
    q = (request.args.get('q') or '').strip()
    raw_limit = (request.args.get('limit') or '').strip()
    limit = None
    if raw_limit:
        try:
            limit = int(raw_limit)
        except Exception:
            return jsonify({'success': False, 'message': 'limit must be an integer'}), 400
    try:
        items = svc_list_governance_packages(q=q, limit=limit)
        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to list governance packages')
        return jsonify({'success': False, 'message': '패키지 목록 조회 중 오류가 발생했습니다.'}), 500


