@api_bp.route('/api/governance/package-vulnerabilities', methods=['POST'])
def create_governance_package_vulnerability():
    auth = _require_login_for_write()
    if auth is not None:
        return auth

    payload = request.get_json(silent=True) or {}
    cve_id = _s(payload, 'cve_id')
    if not cve_id:
        return jsonify({'success': False, 'message': 'cve_id is required'}), 400

    raw_cvss = payload.get('cvss')
    cvss_val = None
    if raw_cvss not in (None, ''):
        try:
            cvss_val = float(raw_cvss)
        except Exception:
            return jsonify({'success': False, 'message': 'cvss must be a number'}), 400

    remediated = 1 if _parse_bool_arg(payload.get('remediated')) else 0
    content = _s(payload, 'content')
    package_name = _s(payload, 'package_name')
    remark = _s(payload, 'remark')

    try:
        item = create_package_vuln(
            cve_id=cve_id,
            package_name=package_name,
            severity=_s(payload, 'severity'),
            cvss=cvss_val,
            status=_s(payload, 'status'),
            affected_versions=_s(payload, 'affected_versions'),
            fixed_versions=_s(payload, 'fixed_versions'),
            remark=remark,
            published_at=_s(payload, 'published_at'),
            content=content,
            remediated=remediated,
        )
        return jsonify({'success': True, 'item': item}), 201
    except ValueError as e:
        return jsonify({'success': False, 'message': str(e)}), 400
    except Exception as e:
        # Common case: duplicate CVE (unique partial index)
        msg = str(e)
        if 'UNIQUE' in msg.upper() or 'constraint' in msg.lower():
            return jsonify({'success': False, 'message': '이미 존재하는 CVE ID 입니다.'}), 409
        logger.exception('Failed to create package vulnerability')
        return jsonify({'success': False, 'message': '취약점 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/governance/package-vulnerabilities/<int:vuln_id>', methods=['PUT'])
def update_governance_package_vulnerability(vuln_id: int):
    auth = _require_login_for_write()
    if auth is not None:
        return auth

    payload = request.get_json(silent=True) or {}
    cve_id = _s(payload, 'cve_id')
    if not cve_id:
        return jsonify({'success': False, 'message': 'cve_id is required'}), 400

    raw_cvss = payload.get('cvss')
    cvss_val = None
    if raw_cvss not in (None, ''):
        try:
            cvss_val = float(raw_cvss)
        except Exception:
            return jsonify({'success': False, 'message': 'cvss must be a number'}), 400

    remediated = None
    if 'remediated' in payload:
        remediated = 1 if _parse_bool_arg(payload.get('remediated')) else 0

    content = None
    if 'content' in payload:
        content = _s(payload, 'content')

    package_name = None
    if 'package_name' in payload:
        package_name = _s(payload, 'package_name')

    remark = None
    if 'remark' in payload:
        remark = _s(payload, 'remark')

    try:
        item = update_package_vuln(
            vuln_id=vuln_id,
            cve_id=cve_id,
            package_name=package_name,
            severity=_s(payload, 'severity'),
            cvss=cvss_val,
            status=_s(payload, 'status'),
            affected_versions=_s(payload, 'affected_versions'),
            fixed_versions=_s(payload, 'fixed_versions'),
            remark=remark,
            published_at=_s(payload, 'published_at'),
            content=content,
            remediated=remediated,
        )
        if not item:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404
        return jsonify({'success': True, 'item': item})
    except ValueError as e:
        return jsonify({'success': False, 'message': str(e)}), 400
    except Exception as e:
        msg = str(e)
        if 'UNIQUE' in msg.upper() or 'constraint' in msg.lower():
            return jsonify({'success': False, 'message': '이미 존재하는 CVE ID 입니다.'}), 409
        logger.exception('Failed to update package vulnerability')
        return jsonify({'success': False, 'message': '취약점 수정 중 오류가 발생했습니다.'}), 500


