@api_bp.route('/api/governance/backup/storage-pools/<int:pool_id>', methods=['PUT'])
def update_backup_storage_pool(pool_id: int):
    if not _bk_policy_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (bk_storage_pool/bk_backup_target_policy)'}), 500
    auth = _require_login_for_write()
    if auth is not None:
        return auth
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    payload = request.get_json(silent=True) or {}
    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        row = BkStoragePool.query.filter(BkStoragePool.id == pool_id).first()
        if not row or int(row.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        client_version = payload.get('version')
        if client_version is not None and int(client_version) != (row.version or 1):
            return jsonify({'success': False, 'message': '다른 사용자가 이미 수정한 데이터입니다. 새로고침 후 다시 시도해 주세요.', 'error_code': 'VERSION_MISMATCH'}), 409

        if 'pool_name' in payload:
            cand = _s(payload, 'pool_name')
            if cand:
                row.pool_name = cand
        if 'storage_asset_id' in payload:
            cand_id = _coerce_positive_int(payload.get('storage_asset_id'))
            if cand_id:
                row.storage_asset_id = cand_id
        if 'remark' in payload:
            row.remark = _s(payload, 'remark')

        row.updated_at = now
        row.updated_by = actor_user_id
        row.version = (row.version or 1) + 1
        db.session.commit()
        asset_name_map = _hw_asset_name_map([row.storage_asset_id])
        return jsonify({'success': True, 'item': _bk_storage_pool_to_dict(row, asset_name_map)})
    except IntegrityError:
        db.session.rollback()
        return jsonify({'success': False, 'message': '이미 존재하는 스토리지 풀명입니다. (pool_name)'}), 409
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update backup storage pool')
        return jsonify({'success': False, 'message': '스토리지 풀 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/governance/backup/storage-pools/bulk-delete', methods=['POST'])
def delete_backup_storage_pools():
    if not _bk_policy_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (bk_storage_pool/bk_backup_target_policy)'}), 500
    auth = _require_login_for_write()
    if auth is not None:
        return auth
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids') or []
    if not isinstance(ids, list) or not ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400
    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        deleted: List[int] = []
        for raw_id in ids:
            pid = _coerce_positive_int(raw_id)
            if not pid:
                continue
            row = BkStoragePool.query.filter(BkStoragePool.id == pid).first()
            if not row or int(row.is_deleted or 0) != 0:
                continue
            row.is_deleted = 1
            row.updated_at = now
            row.updated_by = actor_user_id
            deleted.append(row.id)
        db.session.commit()
        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete backup storage pools')
        return jsonify({'success': False, 'message': '스토리지 풀 삭제 중 오류가 발생했습니다.'}), 500


