@api_bp.route('/api/governance/backup/target-policies', methods=['POST'])
def create_backup_target_policy():
    if not _bk_policy_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (bk_storage_pool/bk_backup_target_policy)'}), 500
    auth = _require_login_for_write()
    if auth is not None:
        return auth
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    payload = request.get_json(silent=True) or {}

    backup_scope = _s(payload, 'backup_scope')
    system_name = _s(payload, 'system_name')
    backup_policy_name = _s(payload, 'backup_policy_name')
    backup_directory = _s(payload, 'backup_directory')
    data_type = _s(payload, 'data_type')
    backup_grade = _s(payload, 'backup_grade')
    storage_pool_id = _coerce_positive_int(payload.get('storage_pool_id'))
    offsite_yn = _s(payload, 'offsite_yn')
    media_type = _s(payload, 'media_type')
    retention_unit = _s(payload, 'retention_unit')
    retention_value = payload.get('retention_value')
    schedule_period = _s(payload, 'schedule_period')
    schedule_weekday = _s(payload, 'schedule_weekday')
    schedule_day = _coerce_int_or_none(payload.get('schedule_day'))
    start_time = _s(payload, 'start_time')

    if not backup_scope:
        return jsonify({'success': False, 'message': 'backup_scope is required'}), 400
    if backup_scope not in _BK_ALLOWED_BACKUP_SCOPES:
        return jsonify({'success': False, 'message': 'backup_scope must be 내부망/외부망'}), 400
    if not system_name:
        return jsonify({'success': False, 'message': 'system_name is required'}), 400
    if not backup_policy_name:
        return jsonify({'success': False, 'message': 'backup_policy_name is required'}), 400
    if not backup_directory:
        return jsonify({'success': False, 'message': 'backup_directory is required'}), 400
    if not data_type or data_type not in _BK_ALLOWED_DATA_TYPES:
        return jsonify({'success': False, 'message': 'data_type is invalid'}), 400
    if not backup_grade or backup_grade not in _BK_ALLOWED_GRADES:
        return jsonify({'success': False, 'message': 'backup_grade is invalid'}), 400
    if not storage_pool_id:
        return jsonify({'success': False, 'message': 'storage_pool_id is required'}), 400
    if not offsite_yn or offsite_yn not in _BK_ALLOWED_OFFSITE:
        return jsonify({'success': False, 'message': 'offsite_yn must be O/X'}), 400
    if not media_type or media_type not in _BK_ALLOWED_MEDIA:
        return jsonify({'success': False, 'message': 'media_type is invalid'}), 400
    if retention_unit and retention_unit not in _BK_ALLOWED_RETENTION_UNITS:
        return jsonify({'success': False, 'message': 'retention_unit is invalid'}), 400

    retention_value_int: Optional[int] = None
    if retention_unit and retention_unit != 'Infinity':
        if retention_value is None or str(retention_value).strip() == '':
            return jsonify({'success': False, 'message': 'retention_value is required'}), 400
        try:
            retention_value_int = int(retention_value)
        except (TypeError, ValueError):
            return jsonify({'success': False, 'message': 'retention_value must be integer'}), 400
        if retention_value_int <= 0:
            return jsonify({'success': False, 'message': 'retention_value must be > 0'}), 400
    elif retention_unit == 'Infinity':
        retention_value_int = None

    if not _validate_hhmm(start_time):
        return jsonify({'success': False, 'message': 'start_time must be HH:MM'}), 400

    schedule_err = _validate_bk_schedule(schedule_period, schedule_weekday, schedule_day)
    if schedule_err:
        return jsonify({'success': False, 'message': schedule_err}), 400

    # Ensure storage pool exists and is not deleted.
    pool = BkStoragePool.query.filter(BkStoragePool.id == storage_pool_id).first()
    if not pool or int(pool.is_deleted or 0) != 0:
        return jsonify({'success': False, 'message': 'storage_pool_id not found'}), 400

    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        row = BkBackupTargetPolicy(
            backup_scope=backup_scope,
            business_name=_s(payload, 'business_name'),
            system_name=system_name,
            ip_address=_s(payload, 'ip_address'),
            backup_policy_name=backup_policy_name,
            backup_directory=backup_directory,
            data_type=data_type,
            backup_grade=backup_grade,
            retention_value=retention_value_int,
            retention_unit=retention_unit,
            storage_pool_id=storage_pool_id,
            offsite_yn=offsite_yn,
            media_type=media_type,
            schedule_period=schedule_period,
            schedule_weekday=schedule_weekday,
            schedule_day=schedule_day,
            schedule_name=_s(payload, 'schedule_name'),
            start_time=start_time,
            remark=_s(payload, 'remark'),
            created_at=now,
            created_by=actor_user_id,
            updated_at=now,
            updated_by=actor_user_id,
            is_deleted=0,
        )
        db.session.add(row)
        db.session.commit()
        row = BkBackupTargetPolicy.query.options(joinedload(BkBackupTargetPolicy.storage_pool)).get(row.id)

        # ── 변경이력 ──
        _try_record_bk_governance_change(
            action_type='CREATE',
            system_name=(row.system_name or '').strip(),
            new_data=_bk_target_policy_to_dict(row),
            summary='백업 정책 등록: ' + (row.backup_policy_name or ''),
        )

        return jsonify({'success': True, 'item': _bk_target_policy_to_dict(row)}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create backup target policy')
        return jsonify({'success': False, 'message': '백업 정책 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/governance/backup/target-policies/<int:policy_id>', methods=['PUT'])
def update_backup_target_policy(policy_id: int):
    if not _bk_policy_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (bk_storage_pool/bk_backup_target_policy)'}), 500
    auth = _require_login_for_write()
    if auth is not None:
        return auth
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    payload = request.get_json(silent=True) or {}
    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        row = BkBackupTargetPolicy.query.filter(BkBackupTargetPolicy.id == policy_id).first()
        if not row or int(row.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        client_version = payload.get('version')
        if client_version is not None and int(client_version) != (row.version or 1):
            return jsonify({'success': False, 'message': '다른 사용자가 이미 수정한 데이터입니다. 새로고침 후 다시 시도해 주세요.', 'error_code': 'VERSION_MISMATCH'}), 409

        # ── 변경이력: before 캡처 ──
        _bk_gov_old_data = _bk_target_policy_to_dict(row)

        if 'backup_scope' in payload:
            cand = _s(payload, 'backup_scope')
            if cand:
                if cand not in _BK_ALLOWED_BACKUP_SCOPES:
                    return jsonify({'success': False, 'message': 'backup_scope must be 내부망/외부망'}), 400
                row.backup_scope = cand

        if 'business_name' in payload:
            row.business_name = _s(payload, 'business_name')
        if 'system_name' in payload:
            cand = _s(payload, 'system_name')
            if cand:
                row.system_name = cand
        if 'ip_address' in payload:
            row.ip_address = _s(payload, 'ip_address')

        if 'backup_policy_name' in payload:
            cand = _s(payload, 'backup_policy_name')
            if cand:
                row.backup_policy_name = cand
        if 'backup_directory' in payload:
            cand = _s(payload, 'backup_directory')
            if cand:
                row.backup_directory = cand

        if 'data_type' in payload:
            cand = _s(payload, 'data_type')
            if cand:
                if cand not in _BK_ALLOWED_DATA_TYPES:
                    return jsonify({'success': False, 'message': 'data_type is invalid'}), 400
                row.data_type = cand
        if 'backup_grade' in payload:
            cand = _s(payload, 'backup_grade')
            if cand:
                if cand not in _BK_ALLOWED_GRADES:
                    return jsonify({'success': False, 'message': 'backup_grade is invalid'}), 400
                row.backup_grade = cand

        if 'storage_pool_id' in payload:
            cand_id = _coerce_positive_int(payload.get('storage_pool_id'))
            if cand_id:
                pool = BkStoragePool.query.filter(BkStoragePool.id == cand_id).first()
                if not pool or int(pool.is_deleted or 0) != 0:
                    return jsonify({'success': False, 'message': 'storage_pool_id not found'}), 400
                row.storage_pool_id = cand_id

        if 'offsite_yn' in payload:
            cand = _s(payload, 'offsite_yn')
            if cand:
                if cand not in _BK_ALLOWED_OFFSITE:
                    return jsonify({'success': False, 'message': 'offsite_yn must be O/X'}), 400
                row.offsite_yn = cand

        if 'media_type' in payload:
            cand = _s(payload, 'media_type')
            if cand:
                if cand not in _BK_ALLOWED_MEDIA:
                    return jsonify({'success': False, 'message': 'media_type is invalid'}), 400
                row.media_type = cand

        if 'retention_unit' in payload or 'retention_value' in payload:
            unit = _s(payload, 'retention_unit') if 'retention_unit' in payload else (row.retention_unit or None)
            value = payload.get('retention_value') if 'retention_value' in payload else row.retention_value

            if unit and unit not in _BK_ALLOWED_RETENTION_UNITS:
                return jsonify({'success': False, 'message': 'retention_unit is invalid'}), 400
            if unit and unit != 'Infinity':
                if value is None or str(value).strip() == '':
                    return jsonify({'success': False, 'message': 'retention_value is required'}), 400
                try:
                    v_int = int(value)
                except (TypeError, ValueError):
                    return jsonify({'success': False, 'message': 'retention_value must be integer'}), 400
                if v_int <= 0:
                    return jsonify({'success': False, 'message': 'retention_value must be > 0'}), 400
                row.retention_value = v_int
            else:
                row.retention_value = None
            row.retention_unit = unit

        if 'schedule_name' in payload:
            row.schedule_name = _s(payload, 'schedule_name')

        # Structured schedule fields (new UI)
        if 'schedule_period' in payload or 'schedule_weekday' in payload or 'schedule_day' in payload:
            period = _s(payload, 'schedule_period') if 'schedule_period' in payload else (row.schedule_period or '')
            weekday = _s(payload, 'schedule_weekday') if 'schedule_weekday' in payload else (row.schedule_weekday or '')
            day = _coerce_int_or_none(payload.get('schedule_day')) if 'schedule_day' in payload else row.schedule_day
            schedule_err = _validate_bk_schedule(period, weekday, day)
            if schedule_err:
                return jsonify({'success': False, 'message': schedule_err}), 400
            period_s = (period or '').strip()
            weekday_s = (weekday or '').strip()
            row.schedule_period = period_s or None
            row.schedule_weekday = weekday_s or None
            row.schedule_day = day
        if 'start_time' in payload:
            cand = _s(payload, 'start_time')
            if not _validate_hhmm(cand):
                return jsonify({'success': False, 'message': 'start_time must be HH:MM'}), 400
            row.start_time = cand
        if 'remark' in payload:
            row.remark = _s(payload, 'remark')

        row.updated_at = now
        row.updated_by = actor_user_id
        row.version = (row.version or 1) + 1
        db.session.commit()
        row = BkBackupTargetPolicy.query.options(joinedload(BkBackupTargetPolicy.storage_pool)).get(row.id)

        # ── 변경이력 ──
        _try_record_bk_governance_change(
            action_type='UPDATE',
            system_name=(row.system_name or '').strip(),
            old_data=_bk_gov_old_data,
            new_data=_bk_target_policy_to_dict(row),
            summary='백업 정책 수정: ' + (row.backup_policy_name or ''),
        )

        return jsonify({'success': True, 'item': _bk_target_policy_to_dict(row)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update backup target policy')

        # Extra diagnostics: terminal output can be unreliable on some Windows
        # setups due to PSReadLine rendering exceptions.
        try:
            if current_app and (bool(getattr(current_app, 'debug', False)) or os.environ.get('BLOSSOM_DIAG') == '1'):
                payload_keys = []
                try:
                    payload_keys = sorted(list((payload or {}).keys()))
                except Exception:
                    payload_keys = []
                _append_diag_text(
                    '_tmp_bk_target_policy_put_500.txt',
                    '\n'.join(
                        [
                            '=' * 80,
                            f"ts={datetime.utcnow().isoformat(timespec='seconds')}Z",
                            f"path={request.path}",
                            f"method={request.method}",
                            f"policy_id={policy_id}",
                            f"payload_keys={payload_keys}",
                            traceback.format_exc(),
                        ]
                    ),
                )
        except Exception:
            pass
        return jsonify({'success': False, 'message': '백업 정책 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/governance/backup/target-policies/bulk-delete', methods=['POST'])
def delete_backup_target_policies():
    if not _bk_policy_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (bk_storage_pool/bk_backup_target_policy)'}), 500
    auth = _require_login_for_write()
    if auth is not None:
        return auth
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids') or []
    if not isinstance(ids, list) or not ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400
    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        deleted: List[int] = []
        # 변경이력용: 삭제 전 전체 데이터 캡처
        _deleted_snapshots: List[dict] = []
        for raw_id in ids:
            pid = _coerce_positive_int(raw_id)
            if not pid:
                continue
            row = BkBackupTargetPolicy.query.filter(BkBackupTargetPolicy.id == pid).first()
            if not row or int(row.is_deleted or 0) != 0:
                continue
            _deleted_snapshots.append(_bk_target_policy_to_dict(row))
            row.is_deleted = 1
            row.updated_at = now
            row.updated_by = actor_user_id
            deleted.append(row.id)
        db.session.commit()

        # ── 변경이력 기록 ──
        for snap in _deleted_snapshots:
            _try_record_bk_governance_change(
                action_type='DELETE',
                system_name=(snap.get('system_name') or '').strip(),
                old_data=snap,
                summary='백업 정책 삭제: ' + (snap.get('backup_policy_name') or ''),
            )

        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete backup target policies')
        return jsonify({'success': False, 'message': '백업 정책 삭제 중 오류가 발생했습니다.'}), 500


