@api_bp.route('/api/governance/backup/libraries/<int:library_id>', methods=['PUT'])
def update_backup_library(library_id: int):
    if not _bk_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (bk_library/bk_location/bk_tape)'}), 500
    auth = _require_login_for_write()
    if auth is not None:
        return auth
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    payload = request.get_json(silent=True) or {}
    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        row = BkLibrary.query.filter(BkLibrary.id == library_id).first()
        if not row or int(row.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        client_version = payload.get('version')
        if client_version is not None and int(client_version) != (row.version or 1):
            return jsonify({'success': False, 'message': '다른 사용자가 이미 수정한 데이터입니다. 새로고침 후 다시 시도해 주세요.', 'error_code': 'VERSION_MISMATCH'}), 409

        if 'library_name' in payload:
            cand = _s(payload, 'library_name')
            if cand:
                row.library_name = cand
        if 'backup_device_asset_id' in payload:
            cand_id = _coerce_positive_int(payload.get('backup_device_asset_id'))
            if cand_id:
                row.backup_device_asset_id = cand_id
        if 'remark' in payload:
            row.remark = _s(payload, 'remark')

        row.updated_at = now
        row.updated_by = actor_user_id
        row.version = (row.version or 1) + 1
        db.session.commit()
        asset_name_map = _hardware_asset_names_by_ids([row.backup_device_asset_id])
        return jsonify({'success': True, 'item': _bk_library_to_dict(row, asset_name_map)})
    except IntegrityError:
        db.session.rollback()
        return jsonify({'success': False, 'message': '이미 존재하는 백업 라이브러리명입니다. (library_name)'}), 409
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update backup library')
        return jsonify({'success': False, 'message': '백업 라이브러리 수정 중 오류가 발생했습니다.'}), 500


