@api_bp.route('/api/governance/backup/tapes', methods=['POST'])
def create_backup_tape():
    if not _bk_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (bk_library/bk_location/bk_tape)'}), 500
    auth = _require_login_for_write()
    if auth is not None:
        return auth
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    payload = request.get_json(silent=True) or {}

    backup_id = _s(payload, 'backup_id')
    backup_policy_name = _s(payload, 'backup_policy_name')
    retention_type = _s(payload, 'retention_type')
    backup_size_k = payload.get('backup_size_k')
    library_id = _coerce_positive_int(payload.get('library_id'))
    backup_created_date = _s(payload, 'backup_created_date')
    backup_expired_date = _s(payload, 'backup_expired_date')
    backup_status = _s(payload, 'backup_status')
    location_id = _coerce_positive_int(payload.get('location_id'))

    if not backup_id:
        return jsonify({'success': False, 'message': 'backup_id is required'}), 400
    if not backup_policy_name:
        return jsonify({'success': False, 'message': 'backup_policy_name is required'}), 400
    if not retention_type:
        return jsonify({'success': False, 'message': 'retention_type is required'}), 400
    if backup_size_k is None or str(backup_size_k).strip() == '':
        return jsonify({'success': False, 'message': 'backup_size_k is required'}), 400
    try:
        backup_size_k_int = int(backup_size_k)
    except (TypeError, ValueError):
        return jsonify({'success': False, 'message': 'backup_size_k must be integer'}), 400
    if backup_size_k_int < 0:
        return jsonify({'success': False, 'message': 'backup_size_k must be >= 0'}), 400
    if not library_id:
        return jsonify({'success': False, 'message': 'library_id is required'}), 400
    if not backup_created_date:
        return jsonify({'success': False, 'message': 'backup_created_date is required'}), 400
    if not backup_status:
        return jsonify({'success': False, 'message': 'backup_status is required'}), 400
    if not location_id:
        return jsonify({'success': False, 'message': 'location_id is required'}), 400

    created_year = _derive_year_from_ymd(backup_created_date)
    if not created_year:
        return jsonify({'success': False, 'message': 'backup_created_date must be YYYY-MM-DD'}), 400

    if retention_type not in ('단기 보관', '장기 보관'):
        return jsonify({'success': False, 'message': 'retention_type must be 단기 보관 or 장기 보관'}), 400
    if backup_status not in ('Active', 'Full', 'Suspended'):
        return jsonify({'success': False, 'message': 'backup_status must be Active/Full/Suspended'}), 400
    if backup_expired_date and not _derive_year_from_ymd(backup_expired_date):
        return jsonify({'success': False, 'message': 'backup_expired_date must be YYYY-MM-DD'}), 400

    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        row = BkTape(
            backup_id=backup_id,
            backup_policy_name=backup_policy_name,
            retention_type=retention_type,
            backup_size_k=backup_size_k_int,
            backup_size_t=round(backup_size_k_int / 1099511627776.0, 6),
            library_id=library_id,
            backup_created_date=backup_created_date,
            backup_created_year=created_year,
            backup_expired_date=backup_expired_date,
            backup_status=backup_status,
            location_id=location_id,
            remark=_s(payload, 'remark'),
            created_at=now,
            created_by=actor_user_id,
            updated_at=now,
            updated_by=actor_user_id,
            is_deleted=0,
        )
        db.session.add(row)
        db.session.commit()
        # ensure relationships loaded
        row = BkTape.query.options(joinedload(BkTape.library), joinedload(BkTape.location)).get(row.id)
        return jsonify({'success': True, 'item': _bk_tape_to_dict(row)}), 201
    except IntegrityError:
        db.session.rollback()
        return jsonify({'success': False, 'message': '이미 존재하는 백업 ID 입니다. (backup_id)'}), 409
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create backup tape')
        return jsonify({'success': False, 'message': '백업 테이프 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/governance/backup/tapes/<int:tape_id>', methods=['PUT'])
def update_backup_tape(tape_id: int):
    if not _bk_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (bk_library/bk_location/bk_tape)'}), 500
    auth = _require_login_for_write()
    if auth is not None:
        return auth
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    payload = request.get_json(silent=True) or {}
    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        row = BkTape.query.filter(BkTape.id == tape_id).first()
        if not row or int(row.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        if 'backup_id' in payload:
            cand = _s(payload, 'backup_id')
            if cand:
                row.backup_id = cand
        if 'backup_policy_name' in payload:
            cand = _s(payload, 'backup_policy_name')
            if cand:
                row.backup_policy_name = cand
        if 'retention_type' in payload:
            cand = _s(payload, 'retention_type')
            if cand:
                if cand not in ('단기 보관', '장기 보관'):
                    return jsonify({'success': False, 'message': 'retention_type must be 단기 보관 or 장기 보관'}), 400
                row.retention_type = cand
        if 'backup_size_k' in payload:
            raw_k = payload.get('backup_size_k')
            try:
                k_int = int(raw_k)
            except (TypeError, ValueError):
                return jsonify({'success': False, 'message': 'backup_size_k must be integer'}), 400
            if k_int < 0:
                return jsonify({'success': False, 'message': 'backup_size_k must be >= 0'}), 400
            row.backup_size_k = k_int
            row.backup_size_t = round(k_int / 1099511627776.0, 6)
        if 'library_id' in payload:
            cand = _coerce_positive_int(payload.get('library_id'))
            if cand:
                row.library_id = cand
        if 'backup_created_date' in payload:
            cand = _s(payload, 'backup_created_date')
            if cand:
                year = _derive_year_from_ymd(cand)
                if not year:
                    return jsonify({'success': False, 'message': 'backup_created_date must be YYYY-MM-DD'}), 400
                row.backup_created_date = cand
                row.backup_created_year = year
        if 'backup_expired_date' in payload:
            cand = _s(payload, 'backup_expired_date')
            if cand and not _derive_year_from_ymd(cand):
                return jsonify({'success': False, 'message': 'backup_expired_date must be YYYY-MM-DD'}), 400
            row.backup_expired_date = cand
        if 'backup_status' in payload:
            cand = _s(payload, 'backup_status')
            if cand:
                if cand not in ('Active', 'Full', 'Suspended'):
                    return jsonify({'success': False, 'message': 'backup_status must be Active/Full/Suspended'}), 400
                row.backup_status = cand
        if 'location_id' in payload:
            cand = _coerce_positive_int(payload.get('location_id'))
            if cand:
                row.location_id = cand
        if 'remark' in payload:
            row.remark = _s(payload, 'remark')

        row.updated_at = now
        row.updated_by = actor_user_id
        db.session.commit()
        row = BkTape.query.options(joinedload(BkTape.library), joinedload(BkTape.location)).get(row.id)
        return jsonify({'success': True, 'item': _bk_tape_to_dict(row)})
    except IntegrityError:
        db.session.rollback()
        return jsonify({'success': False, 'message': '이미 존재하는 백업 ID 입니다. (backup_id)'}), 409
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update backup tape')
        return jsonify({'success': False, 'message': '백업 테이프 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/governance/backup/tapes/bulk-delete', methods=['POST'])
def delete_backup_tapes():
    if not _bk_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (bk_library/bk_location/bk_tape)'}), 500
    auth = _require_login_for_write()
    if auth is not None:
        return auth
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids') or []
    if not isinstance(ids, list) or not ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400
    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        deleted: List[int] = []
        for raw_id in ids:
            tid = _coerce_positive_int(raw_id)
            if not tid:
                continue
            row = BkTape.query.filter(BkTape.id == tid).first()
            if not row or int(row.is_deleted or 0) != 0:
                continue
            row.is_deleted = 1
            row.updated_at = now
            row.updated_by = actor_user_id
            deleted.append(row.id)
        db.session.commit()
        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete backup tapes')
        return jsonify({'success': False, 'message': '백업 테이프 삭제 중 오류가 발생했습니다.'}), 500
logger = logging.getLogger(__name__)


_calendar_attachment_table_exists = False

_wrk_report_table_exists = False

_wrk_report_comment_table_exists = False


def _calendar_attachment_table_ready() -> bool:
    """Return True if attachment table exists.

    Note: This intentionally does *not* cache negative results forever.
    In dev, a migration may be applied while the server is still running.
    """
    global _calendar_attachment_table_exists
    if _calendar_attachment_table_exists:
        return True
    try:
        import sqlalchemy as sa

        insp = sa.inspect(db.engine)
        _calendar_attachment_table_exists = bool(insp.has_table('cal_schedule_attachment'))
    except Exception:
        _calendar_attachment_table_exists = False
    return bool(_calendar_attachment_table_exists)


def _wrk_report_table_ready() -> bool:
    """Return True if work report tables exist.

    This mirrors the calendar attachment guard so we can return a clean error
    in dev environments where migrations haven't been applied yet.
    """
    global _wrk_report_table_exists
    if _wrk_report_table_exists:
        return True
    try:
        import sqlalchemy as sa

        insp = sa.inspect(db.engine)
        _wrk_report_table_exists = bool(insp.has_table('wrk_report'))
    except Exception:
        _wrk_report_table_exists = False
    return bool(_wrk_report_table_exists)


def _wrk_report_comment_table_ready() -> bool:
    """Return True if work report comment table exists."""
    global _wrk_report_comment_table_exists
    if _wrk_report_comment_table_exists:
        return True
    try:
        import sqlalchemy as sa

        insp = sa.inspect(db.engine)
        _wrk_report_comment_table_exists = bool(insp.has_table('wrk_report_comment'))
    except Exception:
        _wrk_report_comment_table_exists = False
    return bool(_wrk_report_comment_table_exists)


@api_bp.route('/api/chat/whoami', methods=['GET'])
@api_bp.route('/api/chat/v2/whoami', methods=['GET'])
def chat_whoami():
    """Return current chat identity derived from session.

    The chat frontend needs a numeric UserProfile id (same id used by MsgRoomMember.user_id)
    to send messages and to apply membership-based message gating.
    """
    emp_no = session.get('emp_no')
    if not emp_no:
        return jsonify({'user_id': None}), 200

    try:
        prof = UserProfile.query.filter_by(emp_no=emp_no).first()
        if not prof:
            return jsonify({'user_id': None, 'emp_no': emp_no}), 200
        return jsonify({
            'user_id': prof.id,
            'emp_no': prof.emp_no,
            'name': prof.name,
            'department': prof.department,
            'profile_image': prof.profile_image,
        }), 200
    except Exception as e:
        return jsonify({'error': 'whoami_failed', 'detail': str(e)}), 500

