@api_bp.route('/api/chat/messages/<int:message_id>', methods=['PATCH'])
def update_chat_message(message_id: int):
    message = MsgMessage.query.get_or_404(message_id, description='Message not found')
    payload = request.get_json() or {}
    if 'content_text' in payload:
        message.content_text = payload['content_text']
        message.edited_at = datetime.utcnow()
    if 'is_deleted' in payload:
        message.is_deleted = bool(payload['is_deleted'])
        if message.is_deleted:
            message.deleted_at = datetime.utcnow()
    db.session.commit()
    if message.room:
        latest = (
            MsgMessage.query.filter_by(room_id=message.room_id, is_deleted=False)
            .order_by(MsgMessage.created_at.desc(), MsgMessage.id.desc())
            .first()
        )
        if latest:
            _update_room_last_message(message.room, latest)
            db.session.commit()
    return jsonify(message.to_dict())


@api_bp.route('/api/chat/messages/<int:message_id>', methods=['DELETE'])
def delete_chat_message(message_id: int):
    message = MsgMessage.query.get_or_404(message_id, description='Message not found')
    message.is_deleted = True
    message.deleted_at = datetime.utcnow()
