def _wrk_can_edit_comment(report_row: WrkReport, comment_row: WrkReportComment, actor_user_id: int) -> bool:
    if not report_row or not comment_row:
        return False
    if (report_row.is_deleted or 0) != 0 or (comment_row.is_deleted or 0) != 0:
        return False
    # 의견 수정/삭제는 모든 상태에서 허용
    # report owner/creator can moderate
    if actor_user_id and (report_row.owner_user_id == actor_user_id or report_row.created_by_user_id == actor_user_id):
        return True
    return bool(actor_user_id and comment_row.created_by_user_id == actor_user_id)


@api_bp.route('/api/wrk/reports/<int:report_id>/comments', methods=['GET'])
def list_wrk_report_comments(report_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _wrk_report_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (wrk_report)'}), 500
    if not _wrk_report_comment_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (wrk_report_comment)'}), 500

    try:
        report_row = WrkReport.query.filter(WrkReport.id == report_id, WrkReport.is_deleted == 0).first()
        if not report_row:
            return jsonify({'success': False, 'message': '작업보고서를 찾을 수 없습니다.'}), 404
        actor_profile = UserProfile.query.get(actor_user_id)
        if not actor_profile:
            return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
        if not _wrk_can_view_report(report_row, actor_user_id, actor_profile):
            return jsonify({'success': False, 'message': '조회 권한이 없습니다.'}), 403

        rows = (
            WrkReportComment.query
            .filter(WrkReportComment.report_id == report_id, WrkReportComment.is_deleted == 0)
            .order_by(WrkReportComment.id.asc())
            .all()
        )
        items = [
            {
                'id': c.id,
                'text': c.text,
                'created_at': (c.created_at.isoformat() + 'Z') if c.created_at else None,
                'created_by_user_id': c.created_by_user_id,
                'created_by_name': (c.created_by.name if c.created_by and c.created_by.name else None),
                'updated_at': (c.updated_at.isoformat() + 'Z') if c.updated_at else None,
                'updated_by_user_id': c.updated_by_user_id,
            }
            for c in rows
        ]
        return jsonify({'success': True, 'total': len(items), 'items': items}), 200
    except Exception:
        logger.exception('Failed to list work report comments report_id=%s', report_id)
        return jsonify({'success': False, 'message': '의견 조회 중 오류가 발생했습니다.'}), 500


