def _wrk_can_view_report(row: WrkReport, actor_user_id: int, actor_profile: Optional[UserProfile]) -> bool:
    if not row or (row.is_deleted or 0):
        return False
    if actor_user_id and (row.owner_user_id == actor_user_id or row.created_by_user_id == actor_user_id):
        return True
    # participants: user or department
    try:
        exists_user = (
            db.session.query(WrkReportParticipantUser.id)
            .filter(WrkReportParticipantUser.report_id == row.id, WrkReportParticipantUser.user_id == actor_user_id)
            .first()
        )
        if exists_user:
            return True
    except Exception:
        pass
    dept_id = getattr(actor_profile, 'department_id', None) if actor_profile else None
    if dept_id:
        try:
            exists_dept = (
                db.session.query(WrkReportParticipantDept.id)
                .filter(WrkReportParticipantDept.report_id == row.id, WrkReportParticipantDept.dept_id == dept_id)
                .first()
            )
            if exists_dept:
                return True
        except Exception:
            pass
    return False


def _wrk_can_edit_report(row: WrkReport, actor_user_id: int) -> bool:
    if not row or (row.is_deleted or 0):
        return False
    if row.status == 'ARCHIVED':
        return False
    return bool(actor_user_id and (row.owner_user_id == actor_user_id or row.created_by_user_id == actor_user_id))


@api_bp.route('/api/wrk/reports/<int:report_id>', methods=['DELETE'])
def delete_wrk_report(report_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _wrk_report_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (wrk_report)'}), 500

    try:
        row = WrkReport.query.filter(WrkReport.id == report_id, WrkReport.is_deleted == 0).first()
        if not row:
            return jsonify({'success': False, 'message': '작업보고서를 찾을 수 없습니다.'}), 404
        # ARCHIVED(완료) reports can now be deleted via 비우기
        # Permission: owner or creator can delete (skip _wrk_can_edit_report which blocks ARCHIVED)
        can_delete = bool(actor_user_id and (row.owner_user_id == actor_user_id or row.created_by_user_id == actor_user_id))
        if not can_delete:
            return jsonify({'success': False, 'message': '삭제 권한이 없습니다.'}), 403

        now_dt = datetime.utcnow()

        # Policy: when soft-deleting a report, also remove its artifacts.
        # - Comments: soft-delete (preserves history while keeping them hidden)
        # - Files: delete DB rows + best-effort disk delete (storage cleanup)
        try:
            if _wrk_report_comment_table_ready():
                (
                    WrkReportComment.query
                    .filter(WrkReportComment.report_id == report_id, WrkReportComment.is_deleted == 0)
                    .update(
                        {
                            WrkReportComment.is_deleted: 1,
                            WrkReportComment.updated_at: now_dt,
                            WrkReportComment.updated_by_user_id: actor_user_id,
                        },
                        synchronize_session=False,
                    )
                )
        except Exception:
            logger.exception('Failed to soft-delete work report comments report_id=%s', report_id)

        try:
            files = WrkReportFile.query.filter_by(report_id=report_id).all()
        except Exception:
            files = []

        if files:
            folder = os.path.join(current_app.instance_path, 'uploads', 'wrk_reports', str(report_id))
            for f in files:
                try:
                    stored_name = os.path.basename((f.stored_name or '').replace('\\', '/'))
                    abs_path = os.path.join(folder, stored_name) if stored_name else None
                    if abs_path and os.path.exists(abs_path):
                        os.remove(abs_path)
                except OSError:
                    pass
                except Exception:
                    logger.exception('Failed to delete work report file from disk report_id=%s file_id=%s', report_id, getattr(f, 'id', None))
            try:
                WrkReportFile.query.filter_by(report_id=report_id).delete(synchronize_session=False)
            except Exception:
                logger.exception('Failed to delete work report file rows report_id=%s', report_id)

        row.is_deleted = 1
        row.updated_at = now_dt
        row.updated_by_user_id = actor_user_id
        db.session.commit()
        return jsonify({'success': True, 'deleted': 1}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete work report report_id=%s', report_id)
        return jsonify({'success': False, 'message': '작업보고서 삭제 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/wrk/reports/batch-clear', methods=['POST'])
def batch_clear_wrk_reports():
    """Per-user 비우기: 해당 사용자에 대해서만 숨김 처리 (다른 사용자 목록에는 영향 없음)."""
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _wrk_report_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (wrk_report)'}), 500

    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids') or []
    if not isinstance(ids, list) or not ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400

    safe_ids = [int(x) for x in ids if str(x).isdigit()]
    if not safe_ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400

    try:
        # 이미 비우기 처리된 report_id 조회
        already_cleared = set(
            r[0] for r in db.session.query(WrkReportUserClear.report_id).filter(
                WrkReportUserClear.report_id.in_(safe_ids),
                WrkReportUserClear.user_id == actor_user_id,
            ).all()
        )

        rows = WrkReport.query.filter(
            WrkReport.id.in_(safe_ids),
            WrkReport.is_deleted == 0,
        ).all()

        cleared_count = 0
        for row in rows:
            if row.id in already_cleared:
                continue  # 이미 비우기 됨
            uc = WrkReportUserClear(report_id=row.id, user_id=actor_user_id)
            db.session.add(uc)
            cleared_count += 1

        db.session.commit()
        return jsonify({'success': True, 'cleared': cleared_count}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to batch clear work reports')
        return jsonify({'success': False, 'message': '비우기 처리 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/wrk/reports/<int:report_id>/files', methods=['GET'])
def list_wrk_report_files(report_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _wrk_report_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (wrk_report)'}), 500

    try:
        row = WrkReport.query.filter(WrkReport.id == report_id, WrkReport.is_deleted == 0).first()
        if not row:
            return jsonify({'success': False, 'message': '작업보고서를 찾을 수 없습니다.'}), 404
        actor_profile = UserProfile.query.get(actor_user_id)
        if not actor_profile:
            return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
        if not _wrk_can_view_report(row, actor_user_id, actor_profile):
            return jsonify({'success': False, 'message': '조회 권한이 없습니다.'}), 403

        files = WrkReportFile.query.filter_by(report_id=report_id).order_by(WrkReportFile.id.asc()).all()
        items = [
            {
                'id': f.id,
                'stored_name': f.stored_name,
                'original_name': f.original_name,
                'content_type': f.content_type,
                'size_bytes': f.size_bytes,
                'created_at': f.created_at.isoformat() if f.created_at else None,
                'created_by_user_id': f.created_by_user_id,
                'download_url': f"/api/wrk/reports/{report_id}/files/{f.id}/download",
            }
            for f in files
        ]
        return jsonify({'success': True, 'total': len(items), 'items': items}), 200
    except Exception:
        logger.exception('Failed to list work report files report_id=%s', report_id)
        return jsonify({'success': False, 'message': '첨부파일 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/wrk/reports/<int:report_id>/files', methods=['POST'])
def upload_wrk_report_files(report_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _wrk_report_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (wrk_report)'}), 500

    try:
        row = WrkReport.query.filter(WrkReport.id == report_id, WrkReport.is_deleted == 0).first()
        if not row:
            return jsonify({'success': False, 'message': '작업보고서를 찾을 수 없습니다.'}), 404
        if not _wrk_can_edit_report(row, actor_user_id):
            return jsonify({'success': False, 'message': '첨부파일 업로드 권한이 없습니다.'}), 403

        files = []
        try:
            files.extend(request.files.getlist('files'))
        except Exception:
            pass
        try:
            files.extend(request.files.getlist('attachments'))
        except Exception:
            pass
        files = [f for f in files if f and getattr(f, 'filename', None)]
        if not files:
            return jsonify({'success': False, 'message': '첨부 파일이 없습니다.'}), 400
        if len(files) > 10:
            return jsonify({'success': False, 'message': '첨부 파일은 최대 10개까지 업로드할 수 있습니다.'}), 400

        base_dir = os.path.join(current_app.instance_path, 'uploads', 'wrk_reports', str(report_id))
        os.makedirs(base_dir, exist_ok=True)

        max_bytes = 50 * 1024 * 1024
        created: List[WrkReportFile] = []
        for file in files:
            original = (file.filename or '').strip()
            safe = secure_filename(original)
            if not safe:
                continue
            if not _is_allowed_upload_file(safe):
                return jsonify({'success': False, 'message': f'허용되지 않는 파일 형식입니다: {safe}'}), 400
            stored = f"{uuid.uuid4().hex}_{safe}"
            abs_path = os.path.join(base_dir, stored)
            file.save(abs_path)

            try:
                size_bytes = os.path.getsize(abs_path)
            except OSError:
                size_bytes = None
            if size_bytes is not None and size_bytes > max_bytes:
                try:
                    os.remove(abs_path)
                except OSError:
                    pass
                return jsonify({'success': False, 'message': '파일 용량은 50MB 이하만 업로드할 수 있습니다.'}), 400

            rec = WrkReportFile(
                report_id=report_id,
                stored_name=stored,
                original_name=original,
                content_type=getattr(file, 'mimetype', None),
                size_bytes=size_bytes,
                created_by_user_id=actor_user_id,
            )
            db.session.add(rec)
            created.append(rec)

        db.session.commit()
        items = [
            {
                'id': f.id,
                'stored_name': f.stored_name,
                'original_name': f.original_name,
                'content_type': f.content_type,
                'size_bytes': f.size_bytes,
                'created_at': f.created_at.isoformat() if f.created_at else None,
                'created_by_user_id': f.created_by_user_id,
                'download_url': f"/api/wrk/reports/{report_id}/files/{f.id}/download",
            }
            for f in created
        ]
        return jsonify({'success': True, 'items': items}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to upload work report files report_id=%s', report_id)
        return jsonify({'success': False, 'message': '첨부 파일 업로드 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/wrk/reports/<int:report_id>/files/<int:file_id>/download', methods=['GET'])
def download_wrk_report_file(report_id: int, file_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _wrk_report_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (wrk_report)'}), 500
    try:
        row = WrkReport.query.filter(WrkReport.id == report_id, WrkReport.is_deleted == 0).first()
        if not row:
            return jsonify({'success': False, 'message': '작업보고서를 찾을 수 없습니다.'}), 404
        actor_profile = UserProfile.query.get(actor_user_id)
        if not actor_profile:
            return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
        if not _wrk_can_view_report(row, actor_user_id, actor_profile):
            return jsonify({'success': False, 'message': '조회 권한이 없습니다.'}), 403

        rec = WrkReportFile.query.filter_by(id=file_id, report_id=report_id).first()
        if not rec:
            return jsonify({'success': False, 'message': '첨부 파일을 찾을 수 없습니다.'}), 404

        folder = os.path.join(current_app.instance_path, 'uploads', 'wrk_reports', str(report_id))
        stored_name = os.path.basename((rec.stored_name or '').replace('\\', '/'))

        inline = str(request.args.get('inline', '')).strip() in ('1', 'true', 'True', 'yes', 'Y')
        content_type = (rec.content_type or '').lower().strip()
        allow_inline = inline and content_type.startswith('image/')
        return send_from_directory(
            folder,
            stored_name,
            as_attachment=not allow_inline,
            download_name=rec.original_name,
            mimetype=(rec.content_type or None),
        )
    except Exception:
        logger.exception('Failed to download work report file report_id=%s file_id=%s', report_id, file_id)
        return jsonify({'success': False, 'message': '첨부 파일 다운로드 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/wrk/reports/<int:report_id>/files/<int:file_id>', methods=['DELETE'])
def delete_wrk_report_file(report_id: int, file_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _wrk_report_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (wrk_report)'}), 500
    try:
        row = WrkReport.query.filter(WrkReport.id == report_id, WrkReport.is_deleted == 0).first()
        if not row:
            return jsonify({'success': False, 'message': '작업보고서를 찾을 수 없습니다.'}), 404
        if not _wrk_can_edit_report(row, actor_user_id):
            return jsonify({'success': False, 'message': '첨부파일 삭제 권한이 없습니다.'}), 403

        rec = WrkReportFile.query.filter_by(id=file_id, report_id=report_id).first()
        if not rec:
            return jsonify({'success': False, 'message': '첨부 파일을 찾을 수 없습니다.'}), 404

        # best-effort disk delete
        try:
            folder = os.path.join(current_app.instance_path, 'uploads', 'wrk_reports', str(report_id))
            stored_name = os.path.basename((rec.stored_name or '').replace('\\', '/'))
            abs_path = os.path.join(folder, stored_name)
            if stored_name and os.path.exists(abs_path):
                os.remove(abs_path)
        except OSError:
            pass

        db.session.delete(rec)
        db.session.commit()
        return jsonify({'success': True}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete work report file report_id=%s file_id=%s', report_id, file_id)
        return jsonify({'success': False, 'message': '첨부 파일 삭제 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/calendar/schedules', methods=['GET'])
def list_calendar_schedules():
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    include_deleted = _parse_bool_arg(request.args.get('include_deleted') or request.args.get('includeDeleted')) or False
    start = _parse_iso_datetime(request.args.get('start') or request.args.get('start_datetime'))
    end = _parse_iso_datetime(request.args.get('end') or request.args.get('end_datetime'))
    owner_user_id = _coerce_positive_int(request.args.get('owner_user_id') or request.args.get('ownerUserId'))
    owner_dept_id = _coerce_positive_int(request.args.get('owner_dept_id') or request.args.get('ownerDeptId'))
    share_scope_param = request.args.get('share_scope') or request.args.get('shareScope')
    search = (request.args.get('q') or '').strip()
    limit = request.args.get('limit', default=500, type=int) or 500
    limit = max(1, min(limit, 1000))
    try:
        actor_profile = UserProfile.query.get(actor_user_id)
        if not actor_profile:
            return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
        query = _calendar_query(include_deleted=include_deleted)
        query = query.filter(_calendar_visible_filter(actor_user_id, actor_profile))
        if start:
            query = query.filter(CalSchedule.end_datetime >= start)
        if end:
            query = query.filter(CalSchedule.start_datetime <= end)
        if owner_user_id:
            query = query.filter(CalSchedule.owner_user_id == owner_user_id)
        if owner_dept_id:
            query = query.filter(CalSchedule.owner_dept_id == owner_dept_id)
        if share_scope_param:
            scope = _normalize_share_scope(share_scope_param)
            query = query.filter(CalSchedule.share_scope == scope)
        if search:
            like = f"%{search}%"
            query = query.filter(CalSchedule.title.ilike(like))
        rows = (
            query.order_by(CalSchedule.start_datetime.asc(), CalSchedule.id.asc())
            .limit(limit)
            .all()
        )
        return jsonify(
            {
                'success': True,
                'items': [_serialize_calendar_schedule(row, actor_user_id=actor_user_id, actor_profile=actor_profile) for row in rows],
                'total': len(rows),
            }
        )
    except Exception:
        logger.exception('Failed to list calendar schedules')
        return jsonify({'success': False, 'message': '일정 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/calendar/schedules/<int:schedule_id>', methods=['GET'])
def get_calendar_schedule(schedule_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    include_deleted = _parse_bool_arg(request.args.get('include_deleted') or request.args.get('includeDeleted')) or False
    try:
        actor_profile = UserProfile.query.get(actor_user_id)
        if not actor_profile:
            return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
        schedule = _get_calendar_schedule(schedule_id, include_deleted=include_deleted)
        if not schedule or (schedule.is_deleted and not include_deleted):
            return jsonify({'success': False, 'message': '일정을 찾을 수 없습니다.'}), 404
        if not _calendar_can_view(schedule, actor_user_id, actor_profile):
            return jsonify({'success': False, 'message': '일정 조회 권한이 없습니다.'}), 403
        return jsonify({'success': True, 'item': _serialize_calendar_schedule(schedule, actor_user_id=actor_user_id, actor_profile=actor_profile)})
    except Exception:
        logger.exception('Failed to fetch calendar schedule %s', schedule_id)
        return jsonify({'success': False, 'message': '일정 조회 중 오류가 발생했습니다.'}), 500


def _resolve_calendar_actor(payload: Dict[str, object]) -> Optional[int]:
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if actor_user_id:
        return actor_user_id
    fallback = _coerce_positive_int(payload.get('actor_user_id') or payload.get('created_by_user_id') or payload.get('updated_by_user_id'))
    return fallback


@api_bp.route('/api/calendar/schedules', methods=['POST'])
def create_calendar_schedule():
    payload = request.get_json(silent=True) or {}
    actor_user_id = _resolve_calendar_actor(payload)
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    schedule = CalSchedule(created_by_user_id=actor_user_id)
    try:
        _apply_schedule_payload(schedule, payload, actor_user_id, is_create=True)
        db.session.add(schedule)
        db.session.commit()

        # 캘린더 리마인더 알림 생성
        try:
            from app.services.notification_service import generate_calendar_reminders
            generate_calendar_reminders(schedule)
            db.session.commit()
        except Exception:
            logger.exception('calendar reminder generation failed (create)')

        fresh = _get_calendar_schedule(schedule.id, include_deleted=True)
        actor_profile = UserProfile.query.get(actor_user_id)
        return jsonify({'success': True, 'item': _serialize_calendar_schedule(fresh, actor_user_id=actor_user_id, actor_profile=actor_profile)}), 201
    except ValueError as exc:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create calendar schedule')
        return jsonify({'success': False, 'message': '일정 생성 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/calendar/schedules/<int:schedule_id>', methods=['PUT'])
def update_calendar_schedule(schedule_id: int):
    payload = request.get_json(silent=True) or {}
    actor_user_id = _resolve_calendar_actor(payload)
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    try:
        schedule = _get_calendar_schedule(schedule_id, include_deleted=True)
        if not schedule or schedule.is_deleted:
            return jsonify({'success': False, 'message': '일정을 찾을 수 없습니다.'}), 404
        actor_profile = UserProfile.query.get(actor_user_id)
        if not actor_profile:
            return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
        if not _calendar_can_edit(schedule, actor_user_id, actor_profile):
            return jsonify({'success': False, 'message': '일정 수정 권한이 없습니다.'}), 403

        client_version = payload.get('version')
        if client_version is not None and int(client_version) != (schedule.version or 1):
            return jsonify({'success': False, 'message': '다른 사용자가 이미 수정한 데이터입니다. 새로고침 후 다시 시도해 주세요.', 'error_code': 'VERSION_MISMATCH'}), 409

        _apply_schedule_payload(schedule, payload, actor_user_id, is_create=False)
        schedule.version = (schedule.version or 1) + 1
        db.session.commit()

        # 캘린더 리마인더 알림 재생성
        try:
            from app.services.notification_service import generate_calendar_reminders
            generate_calendar_reminders(schedule)
            db.session.commit()
        except Exception:
            logger.exception('calendar reminder generation failed (update)')

        fresh = _get_calendar_schedule(schedule.id, include_deleted=True)
        return jsonify({'success': True, 'item': _serialize_calendar_schedule(fresh, actor_user_id=actor_user_id, actor_profile=actor_profile)})
    except ValueError as exc:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update calendar schedule %s', schedule_id)
        return jsonify({'success': False, 'message': '일정 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/calendar/schedules/<int:schedule_id>', methods=['DELETE'])
def delete_calendar_schedule(schedule_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    try:
        schedule = _get_calendar_schedule(schedule_id, include_deleted=True)
        if not schedule or schedule.is_deleted:
            return jsonify({'success': False, 'message': '일정을 찾을 수 없습니다.'}), 404
        if schedule.owner_user_id != actor_user_id:
            return jsonify({'success': False, 'message': '일정 삭제 권한이 없습니다.'}), 403
        schedule.is_deleted = True
        schedule.updated_at = datetime.utcnow()
        schedule.updated_by_user_id = actor_user_id
        db.session.commit()
        return jsonify({'success': True})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete calendar schedule %s', schedule_id)
        return jsonify({'success': False, 'message': '일정 삭제 중 오류가 발생했습니다.'}), 500


