@api_bp.route('/api/calendar/schedules/<int:schedule_id>/attachments/<int:attachment_id>/download', methods=['GET'])
def download_calendar_schedule_attachment(schedule_id: int, attachment_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    try:
        actor_profile = UserProfile.query.get(actor_user_id)
        if not actor_profile:
            return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
        schedule = _get_calendar_schedule(schedule_id, include_deleted=False)
        if not schedule or schedule.is_deleted:
            return jsonify({'success': False, 'message': '일정을 찾을 수 없습니다.'}), 404
        if not _calendar_can_view(schedule, actor_user_id, actor_profile):
            return jsonify({'success': False, 'message': '일정 조회 권한이 없습니다.'}), 403
        rec = CalScheduleAttachment.query.filter_by(id=attachment_id, schedule_id=schedule_id).first()
        if not rec:
            return jsonify({'success': False, 'message': '첨부 파일을 찾을 수 없습니다.'}), 404
        folder = os.path.join(current_app.instance_path, 'uploads', 'calendar', str(schedule_id))

        # Default behavior is download. For image thumbnails (calendar view), allow inline rendering
        # when explicitly requested via query param.
        inline = str(request.args.get('inline', '')).strip() in ('1', 'true', 'True', 'yes', 'Y')
        content_type = (rec.content_type or '').lower().strip()
        allow_inline = inline and content_type.startswith('image/')
        return send_from_directory(
            folder,
            rec.stored_name,
            as_attachment=not allow_inline,
            download_name=rec.original_name,
            mimetype=(rec.content_type or None),
        )
    except Exception:
        logger.exception('Failed to download calendar attachment schedule_id=%s attachment_id=%s', schedule_id, attachment_id)
        return jsonify({'success': False, 'message': '첨부 파일 다운로드 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/calendar/schedules/<int:schedule_id>/attachments/<int:attachment_id>', methods=['DELETE'])
def delete_calendar_schedule_attachment(schedule_id: int, attachment_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    try:
        schedule = _get_calendar_schedule(schedule_id, include_deleted=True)
        if not schedule or schedule.is_deleted:
            return jsonify({'success': False, 'message': '일정을 찾을 수 없습니다.'}), 404
        actor_profile = UserProfile.query.get(actor_user_id)
        if not actor_profile:
            return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
        if not _calendar_can_edit(schedule, actor_user_id, actor_profile):
            return jsonify({'success': False, 'message': '일정 수정 권한이 없습니다.'}), 403

        if not _calendar_attachment_table_ready():
            return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (cal_schedule_attachment)'}), 500

        rec = CalScheduleAttachment.query.filter_by(id=attachment_id, schedule_id=schedule_id).first()
        if not rec:
            return jsonify({'success': False, 'message': '첨부 파일을 찾을 수 없습니다.'}), 404

        # Remove file from disk (best-effort)
        folder = os.path.join(current_app.instance_path, 'uploads', 'calendar', str(schedule_id))
        if rec.stored_name:
            try:
                abs_path = os.path.join(folder, rec.stored_name)
                if os.path.exists(abs_path):
                    os.remove(abs_path)
            except OSError:
                pass

        db.session.delete(rec)
        db.session.commit()
        return jsonify({'success': True}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete calendar attachment schedule_id=%s attachment_id=%s', schedule_id, attachment_id)
        return jsonify({'success': False, 'message': '첨부 파일 삭제 중 오류가 발생했습니다.'}), 500


def _resolve_actor() -> str:
    # Prefer trusted server-side session identity.
    emp_no = session.get('emp_no')
    if emp_no is not None:
        resolved = str(emp_no).strip()
        if resolved:
            return resolved

    raw_user_id = session.get('user_id')
    if raw_user_id is not None:
        # If user_id exists, try to map it to a human-friendly identifier.
        # This prevents ADMIN (or other accounts) from being logged as opaque ids.
        try:
            uid_int = int(raw_user_id)
        except (TypeError, ValueError):
            uid_int = None

        if uid_int is not None:
            try:
                from app.models import AuthUser

                u = AuthUser.query.get(uid_int)
                if u:
                    # Prefer emp_no (usually the login id). Fallback to email prefix.
                    cand = (u.emp_no or '').strip()
                    if cand:
                        return cand
                    if u.email:
                        prefix = (u.email.split('@')[0] or '').strip()
                        if prefix:
                            return prefix
                    if (u.role or '').strip().upper() == 'ADMIN':
                        return 'ADMIN'
            except Exception:
                logger.exception('Failed to resolve actor from session user_id=%s', raw_user_id)

        resolved = str(raw_user_id).strip()
        if resolved:
            return resolved

    # Fallback: allow callers to pass actor explicitly (used by some JS clients).
    hdr_actor = (request.headers.get('X-Actor') or request.headers.get('X-User') or '').strip()
    return hdr_actor or 'system'


def _require_login_for_write():
    """Block write operations when there is no authenticated session.

    Rationale: some environments can issue API requests without carrying the
    session cookie; in that case actor would fall back to 'system'. For write
    endpoints we require a session identity and return 401 otherwise.
    """
    if (
        session.get('emp_no')
        or session.get('user_id')
        or session.get('user_profile_id')
        or session.get('profile_user_id')
    ):
        return None
    return jsonify({'success': False, 'message': '로그인이 필요합니다.'}), 401


def _resolve_actor_user_id(default: Optional[int] = 0) -> Optional[int]:
    profile_keys = ('user_profile_id', 'profile_user_id')
    for key in profile_keys:
        raw = session.get(key)
        if raw is None:
            continue
        try:
            return int(raw)
        except (TypeError, ValueError):
            continue
    emp_no = session.get('emp_no')
    if emp_no:
        try:
            profile = UserProfile.query.filter_by(emp_no=emp_no).first()
        except Exception:
            logger.exception('Failed to resolve UserProfile for emp_no=%s', emp_no)
        else:
            if profile:
                return profile.id
    raw_user_id = session.get('user_id')
    if raw_user_id is not None:
        try:
            as_int = int(raw_user_id)
        except (TypeError, ValueError):
            as_int = None
        if as_int is not None:
            try:
                profile = UserProfile.query.get(as_int)
            except Exception:
                profile = None
            if profile:
                return profile.id
    return default


