def _resolve_entity_display(entity_type: str, entity_id) -> tuple:
    """entity_id 로 DB를 조회하여 표시용 (title, subtitle) 을 반환한다.

    클라이언트 payload 가 아닌 DB 원본을 사용하므로 변조 불가.
    """
    if not entity_id:
        return ('', '')
    try:
        if entity_type == 'hardware_asset':
            from app.services.hardware_asset_service import get_hardware_asset
            row = get_hardware_asset(int(entity_id))
            if row:
                title = (str(row.get('work_name') or row.get('asset_name') or '')).strip()
                subtitle = (str(row.get('system_name') or '')).strip()
                return (title, subtitle)
        if entity_type == 'network_ip_policy':
            from app.services.network_ip_policy_service import get_network_ip_policy
            rec = get_network_ip_policy(int(entity_id))
            if rec:
                title = (rec.get('policy_name') or '').strip()
                subtitle = (rec.get('role') or rec.get('center_code') or '').strip()
                return (title, subtitle)
        if entity_type == 'network_dns_policy':
            rec = svc_get_network_dns_policy(int(entity_id))
            if rec:
                title = (rec.get('domain') or '').strip()
                subtitle = (rec.get('dns_type') or '').strip()
                return (title, subtitle)
        if entity_type == 'network_ad_policy':
            from app.services.network_ad_service import get_network_ad
            rec = get_network_ad(int(entity_id))
            if rec:
                title = (rec.get('domain_name') or '').strip()
                subtitle = (rec.get('role') or '').strip()
                return (title, subtitle)
        if entity_type == 'network_vpn_line':
            row = NetVpnLine.query.filter(NetVpnLine.id == int(entity_id)).first()
            if row:
                title = ''
                if row.vpn_partner_id:
                    partner = NetVpnPartner.query.filter(NetVpnPartner.id == row.vpn_partner_id).first()
                    if partner:
                        title = (partner.org_name or '').strip()
                subtitle = (row.protocol or '').strip()
                return (title, subtitle)
        if entity_type == 'network_leased_line':
            row = NetLeasedLine.query.filter(NetLeasedLine.id == int(entity_id)).first()
            if row:
                title = (row.org_name or '').strip()
                subtitle = (row.line_no or '').strip()
                return (title, subtitle)
        if entity_type == 'org_rack':
            from app.services.org_rack_service import _fetch_single as _svc_rack_single
            rec = _svc_rack_single(int(entity_id))
            if rec:
                title = (rec.get('rack_name') or rec.get('rack_position') or rec.get('rack_code') or '').strip()
                subtitle = (rec.get('center_code') or '').strip()
                return (title, subtitle)
        if entity_type == 'biz_work_group':
            wg = svc_get_work_group(int(entity_id))
            if wg:
                title = (wg.get('group_name') or wg.get('wc_name') or '').strip()
                subtitle = (wg.get('group_code') or '').strip()
                return (title, subtitle)
        if entity_type == 'vendor_manufacturer':
            row = svc_get_vendor(int(entity_id))
            if row:
                title = (row.get('manufacturer_name') or '').strip()
                subtitle = (row.get('business_no') or '').strip()
                return (title, subtitle)
        if entity_type == 'vendor_maintenance':
            row = svc_get_maintenance_vendor(int(entity_id))
            if row:
                title = (row.get('maintenance_name') or '').strip()
                subtitle = (row.get('business_no') or row.get('business_number') or '').strip()
                return (title, subtitle)
        # 카테고리/컴포넌트 통합 핸들러
        _cat_info = _CATEGORY_ENTITY_DISPLAY_MAP.get(entity_type)
        if _cat_info:
            import importlib
            mod = importlib.import_module(_cat_info[0])
            getter = getattr(mod, _cat_info[1])
            rec = getter(int(entity_id))
            if rec:
                title = (rec.get(_cat_info[2]) or '').strip()
                subtitle = (rec.get(_cat_info[3]) or '').strip()
                return (title, subtitle)
    except Exception:
        logger.debug('Failed to resolve entity display for %s/%s', entity_type, entity_id, exc_info=True)
    return ('', '')


