def _resolve_file_entity_type(scope_key: str) -> str:
    """scope_key 로부터 변경이력 entity_type 을 결정한다."""
    sk = (scope_key or '').strip()
    if sk in _FILE_SCOPE_ENTITY_MAP:
        return _FILE_SCOPE_ENTITY_MAP[sk]
    if sk.startswith('gov_vpn_policy'):
        return 'network_vpn_line'
    if sk.startswith('gov_dedicatedline_'):
        return 'network_leased_line'
    return 'hardware_asset'


def _try_record_change(
    *,
    action_type: str,
    entity_type: str,
    entity_id,
    asset_category: str = '',
    asset_type: str = '',
    tab_name: str = '',
    old_data: Optional[Dict[str, Any]] = None,
    new_data: Optional[Dict[str, Any]] = None,
    summary: Optional[str] = None,
):
    """변경이력을 안전하게 기록한다. 실패해도 원래 요청을 방해하지 않는다."""
    try:
        actor = _resolve_actor()
        actor_ip = (request.remote_addr or '') if request else ''

        # 탭 이름 결정 우선순위:
        # 1) 호출자가 명시한 tab_name 파라미터
        # 2) payload 에 _tab_name 포함
        # 3) X-Tab-Name 헤더
        # 4) Referer URL 페이지 키 접미사 매핑
        # 5) 기본값 '기본정보'
        if not tab_name and new_data:
            tab_name = str(new_data.get('_tab_name') or '').strip()
        if not tab_name:
            tab_name = (request.headers.get('X-Tab-Name') or '').strip()
        if not tab_name:
            tab_name = _resolve_tab_name_from_referer()
        if not tab_name:
            tab_name = '기본정보'

        # page_key = 탭 이름 (변경항목 컬럼에 표시)
        page_key = tab_name

        # diff 계산
        diffs = []
        if action_type == 'UPDATE' and old_data and new_data:
            # 비교 대상 필드 = payload 에 포함된 키만 (부분 업데이트 고려)
            compare_fields = [
                k for k in new_data.keys()
                if k not in _IGNORE_FIELDS and not k.startswith('_')
            ]
            diffs = _svc_compute_diffs(old_data, new_data, fields=compare_fields)
            if not diffs:
                return  # 실제 변경 없음 → 기록 안 함
        elif action_type == 'UPDATE' and new_data and not old_data:
            # old_data 미제공 → payload(요청 본문)를 new_data 로 간주하여 전체 기록
            diffs = [
                {'field': k, 'old_value': '', 'new_value': str(v) if v is not None else '',
                 'value_type': 'string', 'is_sensitive': False}
                for k, v in new_data.items()
                if k not in _IGNORE_FIELDS and not k.startswith('_')
                and v is not None and str(v).strip() != ''
            ]
        elif action_type == 'CREATE' and new_data:
            diffs = [
                {'field': k, 'old_value': '', 'new_value': str(v) if v is not None else '',
                 'value_type': 'string', 'is_sensitive': False}
                for k, v in new_data.items()
                if k not in _IGNORE_FIELDS and not k.startswith('_')
                and v is not None and str(v).strip() != ''
            ]
        elif action_type == 'DELETE' and old_data:
            diffs = [
                {'field': k, 'old_value': str(v) if v is not None else '', 'new_value': '',
                 'value_type': 'string', 'is_sensitive': False}
                for k, v in old_data.items()
                if k not in _IGNORE_FIELDS and not k.startswith('_')
                and v is not None and str(v).strip() != ''
            ]

        # 코드 값 → 표시 이름 치환 (코드/ID 대신 사람이 읽을 수 있는 이름으로)
        for d in diffs:
            raw_field = d.get('field', '')
            display_field = _CODE_TO_DISPLAY_MAP.get(raw_field)
            if display_field:
                if old_data and display_field in old_data:
                    resolved = str(old_data[display_field] or '').strip()
                    if resolved:
                        d['old_value'] = resolved
                if new_data and display_field in new_data:
                    resolved = str(new_data[display_field] or '').strip()
                    if resolved:
                        d['new_value'] = resolved

        # 안전장치: 한글 라벨이 없는 필드는 절대 사용자에게 노출하지 않음
        _safe_diffs = []
        for d in diffs:
            f = d.get('field', '')
            # _FIELD_LABEL_MAP 에 등록되지 않은 영문 필드 → 제거 (내부 코드/ID 노출 방지)
            if f not in _FIELD_LABEL_MAP:
                continue
            _safe_diffs.append(d)
        diffs = _safe_diffs

        # 탭별 필드 라벨 오버라이드 (동일 필드명이 탭마다 다른 의미)
        _TAB_FIELD_OVERRIDES: Dict[str, Dict[str, str]] = {
            '담당자': {
                'name': '이름',
                'org': '부서',
                'phone': '연락처',
                'is_primary': '수신여부',
            },
        }
        _tab_overrides = _TAB_FIELD_OVERRIDES.get(tab_name, {})

        # 필드명 한글 라벨 치환
        for d in diffs:
            raw = d.get('field', '')
            d['field'] = _tab_overrides.get(raw) or _FIELD_LABEL_MAP.get(raw, raw)

        if not summary:
            if action_type == 'DELETE':
                summary = f'{tab_name} 삭제'
            elif diffs:
                summary = _svc_build_summary(diffs)
            else:
                summary = f'{tab_name} {action_type}'

        # entity_id 로 DB 조회 → 변조 불가한 타이틀/서브타이틀
        display_title, display_subtitle = _resolve_entity_display(entity_type, entity_id)

        # DB 조회 실패 시 (삭제된 엔티티 등) old_data 에서 추출
        if not display_title and old_data:
            _FALLBACK_TITLE_KEYS = {
                'hardware_asset': ('work_name', 'asset_name'),
                'network_ip_policy': ('policy_name',),
                'network_dns_policy': ('domain',),
                'network_leased_line': ('org_name',),
                'org_rack': ('rack_name', 'rack_position', 'rack_code'),
                'biz_work_group': ('group_name', 'wc_name'),
                'vendor_manufacturer': ('manufacturer_name',),
                'vendor_maintenance': ('maintenance_name',),
            }
            _FALLBACK_SUBTITLE_KEYS = {
                'hardware_asset': ('system_name',),
                'network_ip_policy': ('role', 'center_code'),
                'network_dns_policy': ('dns_type',),
                'network_leased_line': ('line_no',),
                'org_rack': ('center_code',),
                'biz_work_group': ('group_code',),
                'vendor_manufacturer': ('business_no',),
                'vendor_maintenance': ('business_no', 'business_number'),
            }
            for k in _FALLBACK_TITLE_KEYS.get(entity_type, ()):
                v = str(old_data.get(k) or '').strip()
                if v:
                    display_title = v
                    break
            for k in _FALLBACK_SUBTITLE_KEYS.get(entity_type, ()):
                v = str(old_data.get(k) or '').strip()
                if v:
                    display_subtitle = v
                    break

        _svc_record_change_event(
            action_type=action_type,
            page_key=page_key,
            title=display_title,
            subtitle=display_subtitle,
            entity_type=entity_type,
            entity_id=str(entity_id),
            actor_id=actor,
            actor_name=actor,
            actor_ip=actor_ip,
            diffs=diffs,
            summary=summary,
        )
    except Exception:
        logger.debug('Failed to record change event (non-fatal)', exc_info=True)


def _try_record_bk_governance_change(
    *,
    action_type: str,
    system_name: str,
    old_data: Optional[Dict[str, Any]] = None,
    new_data: Optional[Dict[str, Any]] = None,
    summary: Optional[str] = None,
):
    """거버넌스 백업 정책 변경을 해당 하드웨어 자산의 변경이력으로 기록한다.

    system_name 으로 hardware_asset 을 조회하여 entity_id 를 결정한다.
    """
    if not system_name:
        return
    try:
        # hardware asset 검색 (system_name 으로)
        result = svc_list_hardware_assets(
            filters={'system_name': system_name}, page=1, page_size=50,
        )
        asset_id = None
        for item in (result or {}).get('items', []):
            if str(item.get('system_name') or '').strip() == system_name:
                asset_id = int(item['id'])
                break
        if not asset_id:
            return
        _try_record_change(
            action_type=action_type,
            entity_type='hardware_asset',
            entity_id=asset_id,
            tab_name='백업정책',
            old_data=old_data,
            new_data=new_data,
            summary=summary,
        )
    except Exception:
        logger.debug('Failed to record governance backup change (non-fatal)', exc_info=True)


