def _resolve_manufacturer_name(code: str) -> str:
    """manufacturer_code 를 사람이 읽을 수 있는 이름으로 변환한다."""
    if not code:
        return ''
    try:
        from app.services.vendor_manufacturer_service import get_vendor_by_code
        row = get_vendor_by_code(code)
        if row:
            return (row.get('manufacturer_name') or row.get('vendor') or code).strip()
    except Exception:
        pass
    return code


def _try_record_cat_hw_change(
    *,
    entity_type: str,
    entity_id,
    old_data: Optional[Dict[str, Any]],
    new_data: Optional[Dict[str, Any]],
):
    """카테고리 하드웨어 유형 변경이력을 안전하게 기록한다."""
    if not old_data or not new_data:
        return
    try:
        actor = _resolve_actor()
        actor_ip = (request.remote_addr or '') if request else ''

        diffs = []
        for field in _CAT_HW_COMPARE_FIELDS:
            ov = str(old_data.get(field) or '').strip()
            nv = str(new_data.get(field) or '').strip()
            if ov == nv:
                continue
            label = _CAT_HW_FIELD_LABELS.get(field, field)
            old_display, new_display = ov, nv
            if field == 'manufacturer_code':
                old_display = _resolve_manufacturer_name(ov) or ov
                new_display = _resolve_manufacturer_name(nv) or nv
                if old_display == new_display:
                    continue
            diffs.append({
                'field': label,
                'old_value': old_display,
                'new_value': new_display,
                'value_type': 'string',
                'is_sensitive': False,
            })

        if not diffs:
            return

        title = str(
            new_data.get('model_name') or new_data.get('db_name')
            or new_data.get('virtual_name') or new_data.get('secsw_name')
            or new_data.get('ha_name')
            or old_data.get('model_name') or old_data.get('db_name')
            or old_data.get('virtual_name') or old_data.get('secsw_name')
            or old_data.get('ha_name') or ''
        ).strip()
        mfr_code = str(new_data.get('manufacturer_code') or old_data.get('manufacturer_code') or '').strip()
        subtitle = _resolve_manufacturer_name(mfr_code) or mfr_code

        _svc_record_change_event(
            action_type='UPDATE',
            page_key='기본정보',
            title=title,
            subtitle=subtitle,
            entity_type=entity_type,
            entity_id=str(entity_id),
            actor_id=actor,
            actor_name=actor,
            actor_ip=actor_ip,
            diffs=diffs,
            summary=_svc_build_summary(diffs),
        )
    except Exception:
        logger.debug('Failed to record cat hw change event (non-fatal)', exc_info=True)


def _parse_bool_arg(value):
    if value is None:
        return None
    token = str(value).strip().lower()
    if token in ('1', 'true', 'yes', 'y', 'on'):
        return True
    if token in ('0', 'false', 'no', 'n', 'off'):
        return False
    return None


def _coerce_positive_int(value) -> Optional[int]:
    if value is None or value == '':
        return None
    try:
        num = int(value)
    except (TypeError, ValueError):
        return None
    return num if num > 0 else None


def _coerce_bool(value, default: bool = False) -> bool:
    if isinstance(value, bool):
        return value
    if value is None:
        return default
    token = str(value).strip().lower()
    if token in ('1', 'true', 'yes', 'y', 'on'):
        return True
    if token in ('0', 'false', 'no', 'n', 'off'):
        return False
    return default


def _coerce_text(value) -> Optional[str]:
    if value is None:
        return None
    s = str(value).strip()
    return s or None


def _json_safe_for_log(value):
    if value is None:
        return None
    if isinstance(value, (str, int, float, bool)):
        return value
    if isinstance(value, (list, tuple)):
        return [_json_safe_for_log(v) for v in value]
    if isinstance(value, dict):
        return {str(k): _json_safe_for_log(v) for k, v in value.items()}
    if hasattr(value, 'isoformat'):
        try:
            return value.isoformat()
        except Exception:
            pass
    try:
        json.dumps(value, ensure_ascii=False)
        return value
    except Exception:
        return str(value)


