def _ensure_access_zone_tables():
    """access_zone / access_permission_zone 테이블 자동 생성 + 기본 구역 시드."""
    try:
        import sqlalchemy as sa
        insp = sa.inspect(db.engine)
        if not insp.has_table('access_zone'):
            DcAccessZone.__table__.create(db.engine, checkfirst=True)
        if not insp.has_table('access_permission_zone'):
            DcAccessPermissionZone.__table__.create(db.engine, checkfirst=True)
        # 기본 4개 구역 시드 (비어 있을 때만)
        if DcAccessZone.query.count() == 0:
            defaults = [
                ('퓨처센터 전산실', 'zone_futurecenter_dc', 1),
                ('퓨처센터 종합상황실', 'zone_futurecenter_ops', 2),
                ('을지트윈타워 전산실', 'zone_eulji_dc', 3),
                ('재해복구센터 전산실', 'zone_drs_dc', 4),
            ]
            for name, key, order in defaults:
                db.session.add(DcAccessZone(zone_name=name, zone_key=key, sort_order=order))
            db.session.commit()
            # 기존 하드코딩 컬럼 데이터를 junction 테이블로 마이그레이션
            _migrate_hardcoded_zones()
    except Exception as e:
        try:
            print('[access-zone] ensure tables failed:', e, flush=True)
        except Exception:
            pass


def _migrate_hardcoded_zones():
    """기존 access_permission 테이블의 하드코딩 zone 컬럼 → access_permission_zone 테이블로 마이그레이션."""
    try:
        zone_map = {
            'dc_future_room': 'zone_futurecenter_dc',
            'dc_future_control': 'zone_futurecenter_ops',
            'dc_eulji_room': 'zone_eulji_dc',
            'dc_disaster_room': 'zone_drs_dc',
        }
        zones = {z.zone_key: z.id for z in DcAccessZone.query.all()}
        permissions = DcAccessPermission.query.all()
        # 기존 junction 행을 일괄 로드하여 N+1 방지
        perm_ids = [p.permission_id for p in permissions]
        existing_set = set()
        if perm_ids:
            existing_rows = DcAccessPermissionZone.query.filter(
                DcAccessPermissionZone.permission_id.in_(perm_ids)
            ).all()
            existing_set = {(pz.permission_id, pz.zone_id) for pz in existing_rows}
        for perm in permissions:
            for col, key in zone_map.items():
                zone_id = zones.get(key)
                if not zone_id:
                    continue
                if (perm.permission_id, zone_id) in existing_set:
                    continue
                val = getattr(perm, col, 'X') or 'X'
                db.session.add(DcAccessPermissionZone(
                    permission_id=perm.permission_id,
                    zone_id=zone_id,
                    value=val.upper() if val.upper() in ('O', 'X') else 'X'
                ))
        db.session.commit()
    except Exception as e:
        try:
            print('[access-zone] migration failed:', e, flush=True)
        except Exception:
            pass


def _dc_access_zone_tables_ready() -> bool:
    try:
        import sqlalchemy as sa
        insp = sa.inspect(db.engine)
        return insp.has_table('access_zone') and insp.has_table('access_permission_zone')
    except Exception:
        return False


def _coerce_ox(value, default: str = 'X') -> str:
    if value is None:
        return default
    token = str(value).strip().upper()
    if token in ('O', 'X'):
        return token
    return default


def _as_ymd(value: Optional[str]) -> Optional[str]:
    if not value:
        return None
    s = str(value).strip()
    if not s:
        return None
    # Accept YYYY-MM-DD or ISO; return YYYY-MM-DD when possible.
    if 'T' in s:
        s = s.split('T', 1)[0]
    if ' ' in s and len(s) >= 10:
        # e.g. YYYY-MM-DD HH:mm
        s = s[:10]
    return s


def _resolve_department_id_from_affiliation(affiliation: Optional[str]) -> Optional[int]:
    aff = (affiliation or '').strip()
    if not aff:
        return None
    try:
        dept = OrgDepartment.query.filter(
            or_(OrgDepartment.dept_code == aff, OrgDepartment.dept_name == aff)
        ).first()
    except Exception:
        logger.exception('Failed to resolve department for affiliation=%s', aff)
        return None
    return dept.id if dept else None


def _resolve_user_id_from_name(name: Optional[str], department_id: Optional[int] = None, affiliation: Optional[str] = None) -> Optional[int]:
    nm = (name or '').strip()
    if not nm:
        return None
    try:
        query = UserProfile.query.filter(UserProfile.name == nm)
        if department_id:
            query = query.filter(UserProfile.department_id == department_id)
        elif affiliation:
            aff = str(affiliation).strip()
            if aff:
                query = query.filter(or_(UserProfile.department == aff, UserProfile.company == aff))
        user = query.first()
    except Exception:
        logger.exception('Failed to resolve user for name=%s', nm)
        return None
    return user.id if user else None


def _dc_access_system_to_dict(row: DcAccessSystem) -> Dict[str, object]:
    if not row:
        return {}
    return {
        'id': row.id,
        'system_code': row.system_code,
        'business_status_code': row.business_status_code,
        'business_name': row.business_name,
        'system_name': row.system_name,
        'system_ip': row.system_ip,
        'manage_ip': row.manage_ip,
        'manufacturer_name': row.manufacturer_name,
        'system_model_name': row.system_model_name,
        'serial_number': row.serial_number,
        'center_code': row.center_code,
        'system_location': row.system_location,
        'system_dept_code': row.system_dept_code,
        'system_manager_id': row.system_manager_id,
        'service_dept_code': row.service_dept_code,
        'service_manager_id': row.service_manager_id,
        'remark': row.remark or '',
        'created_at': row.created_at,
        'created_by': row.created_by,
        'updated_at': row.updated_at,
        'updated_by': row.updated_by,
        'is_deleted': int(row.is_deleted or 0),
        # Compatibility aliases (UI mock keys)
        'work_status': row.business_status_code,
        'work_name': row.business_name,
        'vendor': row.manufacturer_name,
        'model': row.system_model_name,
        'serial': row.serial_number,
        'location_place': row.center_code,
        'location_pos': row.system_location,
        'sys_dept': row.system_dept_code,
        'sys_owner': row.system_manager_id,
        'svc_dept': row.service_dept_code,
        'svc_owner': row.service_manager_id,
    }


def _dc_access_permission_to_dict(row: DcAccessPermission, zone_values: Optional[Dict] = None) -> Dict[str, object]:
    if not row:
        return {}
    auth_changed = None
    if row.last_changed_at:
        auth_changed = _as_ymd(row.last_changed_at)

    payload = {
        'permission_id': row.permission_id,
        'id': row.permission_id,
        'user_id': row.user_id,
        'department_id': row.department_id,
        'person_type': row.person_type or '',
        'access_level': row.access_level or '',
        'status': row.status or '',
        'remark': row.remark or '',
        'permission_start_date': row.permission_start_date or '',
        'permission_end_date': row.permission_end_date or '',
        'last_changed_at': row.last_changed_at,
        'last_changed_by': row.last_changed_by,
        'dc_future_room': (row.dc_future_room or 'X'),
        'dc_future_control': (row.dc_future_control or 'X'),
        'dc_eulji_room': (row.dc_eulji_room or 'X'),
        'dc_disaster_room': (row.dc_disaster_room or 'X'),
        'created_at': row.created_at,
        'updated_at': row.updated_at,
        # Helpful denormalized display fields
        'user_name': (row.user.name if row.user else None),
        'dept_name': (row.department.dept_name if row.department else None),
    }

    # Compatibility aliases for the current Authority Control UI (mock keys)
    payload.update(
        {
            'name': payload.get('user_name') or '',
            'affiliation': payload.get('dept_name') or '',
            'employee_type': payload.get('person_type') or '',
            'note': payload.get('remark') or '',
            'auth_start_date': payload.get('permission_start_date') or '',
            'auth_end_date': payload.get('permission_end_date') or '',
            'auth_changed_date': auth_changed or '',
            'zone_futurecenter_dc': payload.get('dc_future_room') or 'X',
            'zone_futurecenter_ops': payload.get('dc_future_control') or 'X',
            'zone_eulji_dc': payload.get('dc_eulji_room') or 'X',
            'zone_drs_dc': payload.get('dc_disaster_room') or 'X',
        }
    )

    # 동적 구역 값 추가 (access_permission_zone 테이블)
    if zone_values is not None:
        for zone_key, val in zone_values.items():
            payload[zone_key] = val

    return payload


def _load_all_zone_values(permission_ids: List[int]) -> Dict[int, Dict[str, str]]:
    """permission_id 목록에 대한 zone 값을 일괄 로드"""
    result: Dict[int, Dict[str, str]] = {}
    if not permission_ids:
        return result
    try:
        zones = {z.id: z.zone_key for z in DcAccessZone.query.filter_by(is_deleted=0).all()}
        pz_rows = DcAccessPermissionZone.query.filter(
            DcAccessPermissionZone.permission_id.in_(permission_ids)
        ).all()
        for pz in pz_rows:
            key = zones.get(pz.zone_id)
            if not key:
                continue
            if pz.permission_id not in result:
                result[pz.permission_id] = {}
            result[pz.permission_id][key] = pz.value or 'X'
    except Exception:
        pass
    return result


def _save_permission_zone_values(permission_id: int, data: Dict):
    """data 에서 zone_key 에 해당하는 값을 찾아 junction 테이블에 upsert."""
    try:
        if not _dc_access_zone_tables_ready():
            return
        zones = DcAccessZone.query.filter_by(is_deleted=0).all()
        for z in zones:
            val = data.get(z.zone_key)
            if val is None:
                val = 'X'
            val = _coerce_ox(val, default='X')
            existing = DcAccessPermissionZone.query.filter_by(
                permission_id=permission_id, zone_id=z.id
            ).first()
            if existing:
                existing.value = val
            else:
                db.session.add(DcAccessPermissionZone(
                    permission_id=permission_id,
                    zone_id=z.id,
                    value=val
                ))
        db.session.commit()
    except Exception as e:
        try:
            print('[access-zone] save zone values failed:', e, flush=True)
        except Exception:
            pass


@api_bp.route('/api/datacenter/access/permissions', methods=['GET'])
def datacenter_access_permissions_list():
    if not _dc_access_permission_tables_ready():
        return jsonify({'error': 'access_permission table not ready'}), 500

    query = DcAccessPermission.query

    user_id = _coerce_positive_int(request.args.get('user_id'))
    dept_id = _coerce_positive_int(request.args.get('department_id'))
    status = (request.args.get('status') or '').strip()

    if user_id:
        query = query.filter(DcAccessPermission.user_id == user_id)
    if dept_id:
        query = query.filter(DcAccessPermission.department_id == dept_id)
    if status:
        query = query.filter(DcAccessPermission.status == status)

    rows = query.order_by(DcAccessPermission.permission_id.desc())
    result = _paginate_query(rows, default_size=100)

    # 동적 zone 값 일괄 로드
    _ensure_access_zone_tables()
    perm_ids = [r.permission_id for r in result['items']]
    zone_values_map = _load_all_zone_values(perm_ids)

    items = [_dc_access_permission_to_dict(r, zone_values=zone_values_map.get(r.permission_id, {})) for r in result['items']]
    return jsonify({'success': True, 'items': items, 'total': result['total'],
                    'page': result.get('page'), 'pages': result.get('pages')})


@api_bp.route('/api/datacenter/access/permissions', methods=['POST'])
def datacenter_access_permissions_create():
    if not _dc_access_permission_tables_ready():
        return jsonify({'error': 'access_permission table not ready'}), 500

    data = request.get_json(silent=True) or {}

    # Accept both FK ids and the UI's current string fields.
    affiliation = _coerce_text(data.get('affiliation'))
    name = _coerce_text(data.get('name'))

    department_id = data.get('department_id') or _resolve_department_id_from_affiliation(affiliation)
    user_id = data.get('user_id') or _resolve_user_id_from_name(name, department_id=department_id, affiliation=affiliation)
    last_changed_by = data.get('last_changed_by') or data.get('actor_user_id')

    if not department_id:
        return jsonify({'error': 'department_id is required (or provide a valid affiliation)'}), 400
    if not user_id:
        return jsonify({'error': 'user_id is required (or provide a valid name)'}), 400

    user = UserProfile.query.get(user_id)
    if not user:
        return jsonify({'error': 'user not found'}), 400
    dept = OrgDepartment.query.get(department_id)
    if not dept:
        return jsonify({'error': 'department not found'}), 400

    if last_changed_by:
        actor = UserProfile.query.get(last_changed_by)
        if not actor:
            return jsonify({'error': 'last_changed_by user not found'}), 400

    now = datetime.utcnow().isoformat()
    person_type = _coerce_text(data.get('person_type') or data.get('employee_type'))
    remark = _coerce_text(data.get('remark') or data.get('note'))
    start_date = _as_ymd(data.get('permission_start_date') or data.get('auth_start_date'))
    end_date = _as_ymd(data.get('permission_end_date') or data.get('auth_end_date'))

    # Zone keys: support both DB field names and UI mock keys
    future_room = data.get('dc_future_room') if 'dc_future_room' in data else data.get('zone_futurecenter_dc')
    future_control = data.get('dc_future_control') if 'dc_future_control' in data else data.get('zone_futurecenter_ops')
    eulji_room = data.get('dc_eulji_room') if 'dc_eulji_room' in data else data.get('zone_eulji_dc')
    disaster_room = data.get('dc_disaster_room') if 'dc_disaster_room' in data else data.get('zone_drs_dc')

    row = DcAccessPermission(
        user_id=user_id,
        department_id=department_id,
        person_type=person_type,
        access_level=_coerce_text(data.get('access_level')),
        status=_coerce_text(data.get('status')),
        remark=remark,
        permission_start_date=start_date,
        permission_end_date=end_date,
        last_changed_at=now,
        last_changed_by=last_changed_by or None,
        dc_future_room=_coerce_ox(future_room, default='X'),
        dc_future_control=_coerce_ox(future_control, default='X'),
        dc_eulji_room=_coerce_ox(eulji_room, default='X'),
        dc_disaster_room=_coerce_ox(disaster_room, default='X'),
        updated_at=None,
    )

    db.session.add(row)
    db.session.commit()

    # 동적 zone 값 저장 (junction 테이블)
    _save_permission_zone_values(row.permission_id, data)

    return jsonify(_dc_access_permission_to_dict(row)), 201


@api_bp.route('/api/datacenter/access/permissions/<int:permission_id>', methods=['GET'])
def datacenter_access_permissions_get(permission_id: int):
    if not _dc_access_permission_tables_ready():
        return jsonify({'error': 'access_permission table not ready'}), 500

    row = DcAccessPermission.query.get(permission_id)
    if not row:
        return jsonify({'error': 'not found'}), 404
    return jsonify(_dc_access_permission_to_dict(row))


@api_bp.route('/api/datacenter/access/permissions/<int:permission_id>', methods=['PUT'])
def datacenter_access_permissions_update(permission_id: int):
    if not _dc_access_permission_tables_ready():
        return jsonify({'error': 'access_permission table not ready'}), 500

    row = DcAccessPermission.query.get(permission_id)
    if not row:
        return jsonify({'error': 'not found'}), 404

    data = request.get_json(silent=True) or {}

    client_version = data.get('version')
    if client_version is not None and int(client_version) != (row.version or 1):
        return jsonify({'error': '다른 사용자가 이미 수정한 데이터입니다. 새로고침 후 다시 시도해 주세요.', 'error_code': 'VERSION_MISMATCH'}), 409

    last_changed_by = data.get('last_changed_by') or data.get('actor_user_id')
    if not last_changed_by:
        return jsonify({'error': 'last_changed_by is required'}), 400

    actor = UserProfile.query.get(last_changed_by)
    if not actor:
        return jsonify({'error': 'last_changed_by user not found'}), 400

    # Allow updating by either ids or UI strings.
    if 'department_id' in data or 'affiliation' in data:
        new_dept_id = data.get('department_id') or _resolve_department_id_from_affiliation(_coerce_text(data.get('affiliation')))
        if not new_dept_id:
            return jsonify({'error': 'department_id cannot be blank (or provide a valid affiliation)'}), 400
        dept = OrgDepartment.query.get(new_dept_id)
        if not dept:
            return jsonify({'error': 'department not found'}), 400
        row.department_id = new_dept_id

    if 'user_id' in data or 'name' in data:
        new_user_id = data.get('user_id') or _resolve_user_id_from_name(_coerce_text(data.get('name')), department_id=row.department_id, affiliation=_coerce_text(data.get('affiliation')))
        if not new_user_id:
            return jsonify({'error': 'user_id cannot be blank (or provide a valid name)'}), 400
        user = UserProfile.query.get(new_user_id)
        if not user:
            return jsonify({'error': 'user not found'}), 400
        row.user_id = new_user_id

    if 'person_type' in data or 'employee_type' in data:
        row.person_type = _coerce_text(data.get('person_type') or data.get('employee_type'))
    if 'access_level' in data:
        row.access_level = _coerce_text(data.get('access_level'))
    if 'status' in data:
        row.status = _coerce_text(data.get('status'))
    if 'remark' in data or 'note' in data:
        row.remark = _coerce_text(data.get('remark') or data.get('note'))
    if 'permission_start_date' in data or 'auth_start_date' in data:
        row.permission_start_date = _as_ymd(data.get('permission_start_date') or data.get('auth_start_date'))
    if 'permission_end_date' in data or 'auth_end_date' in data:
        row.permission_end_date = _as_ymd(data.get('permission_end_date') or data.get('auth_end_date'))

    if 'dc_future_room' in data or 'zone_futurecenter_dc' in data:
        row.dc_future_room = _coerce_ox(data.get('dc_future_room') if 'dc_future_room' in data else data.get('zone_futurecenter_dc'), default=row.dc_future_room or 'X')
    if 'dc_future_control' in data or 'zone_futurecenter_ops' in data:
        row.dc_future_control = _coerce_ox(data.get('dc_future_control') if 'dc_future_control' in data else data.get('zone_futurecenter_ops'), default=row.dc_future_control or 'X')
    if 'dc_eulji_room' in data or 'zone_eulji_dc' in data:
        row.dc_eulji_room = _coerce_ox(data.get('dc_eulji_room') if 'dc_eulji_room' in data else data.get('zone_eulji_dc'), default=row.dc_eulji_room or 'X')
    if 'dc_disaster_room' in data or 'zone_drs_dc' in data:
        row.dc_disaster_room = _coerce_ox(data.get('dc_disaster_room') if 'dc_disaster_room' in data else data.get('zone_drs_dc'), default=row.dc_disaster_room or 'X')

    now = datetime.utcnow().isoformat()
    row.last_changed_at = now
    row.last_changed_by = last_changed_by
    row.updated_at = now
    row.version = (row.version or 1) + 1

    db.session.commit()

    # 동적 zone 값 업데이트
    _save_permission_zone_values(row.permission_id, data)

    return jsonify(_dc_access_permission_to_dict(row))


