# ── 권한 변경 기록 (dc_authority_record) CRUD ──

def _ensure_authority_record_table():
    """dc_authority_record 테이블 자동 생성."""
    try:
        import sqlalchemy as sa
        insp = sa.inspect(db.engine)
        if not insp.has_table('dc_authority_record'):
            DcAuthorityRecord.__table__.create(db.engine, checkfirst=True)
    except Exception as e:
        try:
            print('[authority-record] ensure table failed:', e, flush=True)
        except Exception:
            pass


def _authority_record_table_ready() -> bool:
    try:
        import sqlalchemy as sa
        insp = sa.inspect(db.engine)
        return insp.has_table('dc_authority_record')
    except Exception:
        return False


def _authority_record_to_dict(row):
    if not row:
        return {}
    return {
        'id': row.id,
        'status': row.status or '',
        'change_datetime': row.change_datetime or '',
        'change_type': row.change_type or '',
        'changed_by': row.changed_by or '',
        'manager': row.manager or '',
        'change_details': row.change_details or '',
        'change_reason': row.change_reason or '',
        'is_deleted': row.is_deleted,
        'created_at': row.created_at,
        'updated_at': row.updated_at,
    }


