@api_bp.route('/api/datacenter/access/systems', methods=['POST'])
def datacenter_access_systems_create():
    if not _dc_access_system_tables_ready():
        return jsonify({'error': 'dc_access_system table not ready'}), 500

    data = request.get_json(silent=True) or {}
    system_code = (data.get('system_code') or '').strip()
    business_status_code = (data.get('business_status_code') or '').strip()
    business_name = (data.get('business_name') or '').strip()
    system_name = (data.get('system_name') or '').strip()
    created_by = data.get('created_by')

    if not system_code:
        return jsonify({'error': 'system_code is required'}), 400
    if not business_status_code:
        return jsonify({'error': 'business_status_code is required'}), 400
    if not business_name:
        return jsonify({'error': 'business_name is required'}), 400
    if not system_name:
        return jsonify({'error': 'system_name is required'}), 400
    if not created_by:
        return jsonify({'error': 'created_by is required'}), 400

    actor = UserProfile.query.get(created_by)
    if not actor:
        return jsonify({'error': 'created_by user not found'}), 400

    existing = DcAccessSystem.query.filter(DcAccessSystem.system_code == system_code).first()
    if existing and int(existing.is_deleted or 0) == 0:
        return jsonify({'error': 'system_code already exists'}), 409
    if existing and int(existing.is_deleted or 0) == 1:
        return jsonify({'error': 'system_code already exists (deleted)'}), 409

    row = DcAccessSystem(
        system_code=system_code,
        business_status_code=business_status_code,
        business_name=business_name,
        system_name=system_name,
        system_ip=(data.get('system_ip') or '').strip() or None,
        manage_ip=(data.get('manage_ip') or '').strip() or None,
        manufacturer_name=(data.get('manufacturer_name') or '').strip() or None,
        system_model_name=(data.get('system_model_name') or '').strip() or None,
        serial_number=(data.get('serial_number') or '').strip() or None,
        center_code=(data.get('center_code') or '').strip() or None,
        system_location=(data.get('system_location') or '').strip() or None,
        system_dept_code=(data.get('system_dept_code') or '').strip() or None,
        system_manager_id=data.get('system_manager_id') or None,
        service_dept_code=(data.get('service_dept_code') or '').strip() or None,
        service_manager_id=data.get('service_manager_id') or None,
        remark=data.get('remark') or None,
        created_by=created_by,
        updated_by=None,
        is_deleted=0,
    )

    db.session.add(row)
    db.session.commit()
    return jsonify(_dc_access_system_to_dict(row)), 201


