# 26 base field names matching data-field keys in tab53-vpn-policy.html
_VPN_POLICY_FIELDS = [
    'model', 'fw',
    'ipsec_life', 'mode', 'method', 'pfs', 'retrans', 'cipher_proto', 'cipher_algo', 'auth_algo',
    'isakmp_life', 'isakmp_mode', 'ike_auth', 'ike_time', 'psk', 'dpd',
    'isakmp_cipher', 'hash_algo', 'dh_group', 'local_id_type', 'local_id_active', 'local_id_standby',
    'cid_active', 'cid_standby',
    'peer_ip',
    'note',
]


def _vpn_policy_to_dict(row: NetVpnLinePolicy) -> dict:
    d: dict = {
        'id': row.id,
        'vpn_line_id': row.vpn_line_id,
    }
    for f in _VPN_POLICY_FIELDS:
        d[f + '_self'] = getattr(row, f + '_self', None) or ''
        d[f + '_org'] = getattr(row, f + '_org', None) or ''
    d['created_at'] = row.created_at
    d['created_by_user_id'] = row.created_by_user_id
    d['updated_at'] = row.updated_at
    d['updated_by_user_id'] = row.updated_by_user_id
    d['is_deleted'] = int(row.is_deleted or 0)
    return d


