@api_bp.route('/api/session/me', methods=['GET'])
def api_session_me():
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    try:
        user = UserProfile.query.get(actor_user_id)
        if not user:
            return jsonify({'success': False, 'message': '사용자 정보를 찾을 수 없습니다.'}), 404

        dept_name = None
        try:
            if user.department_ref is not None and user.department_ref.name:
                dept_name = str(user.department_ref.name).strip() or None
        except Exception:
            dept_name = None
        if not dept_name:
            try:
                dept_name = str(user.department).strip() or None
            except Exception:
                dept_name = None

        return jsonify(
            {
                'success': True,
                'user': {
                    'id': user.id,
                    'emp_no': user.emp_no,
                    'name': user.name,
                    'role': user.role or '',
                    'dept_id': user.department_id,
                    'dept_name': dept_name,
                    'department': dept_name,
                },
            }
        )
    except Exception:
        logger.exception('Failed to load session user')
        return jsonify({'success': False, 'message': '세션 정보 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/session/permissions', methods=['GET'])
def api_session_permissions():
    """현재 로그인 사용자의 최종 권한 반환 (메뉴 기반 effective permissions)."""
    from app.services.permission_service import get_effective_permissions, MENU_SEEDS, can_export
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '세션 만료'}), 401
    sess_role = (session.get('role') or '').upper()
    if sess_role == 'ADMIN':
        perms = {code: 'WRITE' for code, _, _, _ in MENU_SEEDS}
        perms['settings'] = 'WRITE'
        exports = {code: True for code in perms}
        return jsonify({'success': True, 'permissions': perms, 'exports': exports, 'role': 'ADMIN'})
    try:
        perms = get_effective_permissions(actor_user_id)
    except Exception:
        perms = {}
    exports = {code: can_export(code, level) for code, level in perms.items()}
    from app.models import RoleUser, Role
    role_user = RoleUser.query.filter_by(user_id=actor_user_id).first()
    role_name = None
    if role_user:
        role_row = Role.query.get(role_user.role_id)
        if role_row:
            role_name = role_row.name
    return jsonify({'success': True, 'permissions': perms, 'exports': exports, 'role': role_name})


