@api_bp.route('/api/roles', methods=['GET'])
def api_roles_list():
    from app.models import Role, UserProfile
    ROLE_NAME_TO_CODES = {
        'ADMIN': ['ADMIN', 'admin'],
        '관리자': ['ADMIN', 'admin'],
        '사용자': ['USER', 'user'],
        '팀장': ['TEAM_LEADER', 'team_leader'],
        '승인권자': ['APPROVER', 'approver'],
        '감사자': ['AUDITOR', 'auditor'],
    }
    roles = Role.query.order_by(Role.name).all()
    result = []
    for r in roles:
        codes = ROLE_NAME_TO_CODES.get(r.name, [r.name])
        user_count = UserProfile.query.filter(UserProfile.role.in_(codes + [r.name])).count()
        result.append({
            'id': r.id,
            'name': r.name,
            'description': r.description,
            'user_count': user_count,
        })
    return jsonify({'success': True, 'roles': result})


# ── 역할 추가 (권한관리 화면용) ──
@api_bp.route('/api/permission/roles', methods=['POST'])
def api_create_role():
    from app.models import Role
    data = request.get_json(silent=True) or {}
    name = (data.get('name') or '').strip()
    desc = (data.get('description') or '').strip()
    if not name:
        return jsonify({'success': False, 'message': '역할명을 입력해주세요.'}), 400
    if len(name) > 64:
        return jsonify({'success': False, 'message': '역할명은 64자 이내로 입력해주세요.'}), 400
    if Role.query.filter_by(name=name).first():
        return jsonify({'success': False, 'message': '이미 존재하는 역할명입니다.'}), 409
    role = Role(name=name, description=desc)
    db.session.add(role)
    try:
        db.session.commit()
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(e)}), 500
    return jsonify({'success': True, 'role': {'id': role.id, 'name': role.name, 'description': role.description}})


