@api_bp.route('/api/permission/users', methods=['GET'])
def api_users_list():
    from app.models import UserProfile
    q = request.args.get('q', '').strip()
    query = UserProfile.query
    if q:
        query = query.filter(
            db.or_(
                UserProfile.name.ilike(f'%{q}%'),
                UserProfile.emp_no.ilike(f'%{q}%'),
                UserProfile.department.ilike(f'%{q}%'),
            )
        )
    users = query.order_by(UserProfile.name).limit(200).all()
    result = [{
        'id': u.id,
        'name': u.name,
        'emp_no': u.emp_no,
        'department': u.department,
        'department_id': u.department_id,
        'role': u.role,
    } for u in users]
    return jsonify({'success': True, 'users': result})


# ── 감사로그 조회 ──
@api_bp.route('/api/permission-audit-logs', methods=['GET'])
def api_permission_audit_logs():
    if session.get('role', '').upper() not in ('ADMIN', '관리자'):
        return jsonify({'success': False, 'message': '관리자만 조회할 수 있습니다.'}), 403
    from app.models import PermissionAuditLog
    page = max(1, _coerce_positive_int(request.args.get('page')) or 1)
    per_page = min(100, max(10, _coerce_positive_int(request.args.get('per_page')) or 20))
    q = PermissionAuditLog.query.order_by(PermissionAuditLog.changed_at.desc())
    target_type = request.args.get('target_type')
    menu_code = request.args.get('menu_code')
    if target_type:
        q = q.filter_by(target_type=target_type)
    if menu_code:
        q = q.filter_by(menu_code=menu_code)
    total = q.count()
    logs = q.offset((page - 1) * per_page).limit(per_page).all()
    result = [{
        'id': l.id,
        'target_type': getattr(l, 'target_type', 'role'),
        'target_id': getattr(l, 'target_id', 0),
        'menu_code': l.menu_code,
        'before_permission': l.before_permission,
        'after_permission': l.after_permission,
        'changed_by': l.changed_by,
        'changed_at': l.changed_at.isoformat() if l.changed_at else None,
    } for l in logs]
    return jsonify({'success': True, 'logs': result, 'total': total, 'page': page})


