def _parse_iso_datetime(value) -> Optional[datetime]:
    if not value:
        return None
    if isinstance(value, datetime):
        parsed = value
    else:
        token = str(value).strip()
        if not token:
            return None
        if token.endswith('Z'):
            token = f"{token[:-1]}+00:00"
        try:
            parsed = datetime.fromisoformat(token)
        except ValueError:
            for fmt in ('%Y-%m-%d %H:%M', '%Y-%m-%d %H:%M:%S', '%Y-%m-%d'):
                try:
                    parsed = datetime.strptime(token, fmt)
                    break
                except ValueError:
                    parsed = None
            if parsed is None:
                return None
    if parsed.tzinfo:
        return parsed.astimezone(timezone.utc).replace(tzinfo=None)
    return parsed


def _serialize_datetime(value: Optional[datetime]) -> Optional[str]:
    if not value:
        return None
    if value.tzinfo:
        return value.astimezone(timezone.utc).isoformat()
    return value.isoformat()


# =============================================================================
# Project Management (prj_project)
# =============================================================================


_prj_project_table_exists = False
_prj_project_member_table_exists = False
_prj_tab_table_exists: Dict[str, bool] = {}


def _prj_project_table_ready() -> bool:
    """Return True if prj_project table exists."""
    global _prj_project_table_exists
    if _prj_project_table_exists:
        return True
    try:
        import sqlalchemy as sa

        insp = sa.inspect(db.engine)
        _prj_project_table_exists = bool(insp.has_table('prj_project'))
    except Exception:
        _prj_project_table_exists = False
    return bool(_prj_project_table_exists)


def _prj_project_member_table_ready() -> bool:
    """Return True if prj_project_member table exists."""
    global _prj_project_member_table_exists
    if _prj_project_member_table_exists:
        return True
    try:
        import sqlalchemy as sa

        insp = sa.inspect(db.engine)
        _prj_project_member_table_exists = bool(insp.has_table('prj_project_member'))
    except Exception:
        _prj_project_member_table_exists = False
    return bool(_prj_project_member_table_exists)


def _prj_tab_table_ready(table_name: str) -> bool:
    """Return True if the given prj_tab_* table exists."""
    if not table_name:
        return False
    cached = _prj_tab_table_exists.get(table_name)
    if cached is True:
        return True
    try:
        import sqlalchemy as sa

        insp = sa.inspect(db.engine)
        ok = bool(insp.has_table(table_name))
        # Cache only positive results.
        # Negative caching can go stale when the DB is migrated while the server stays up.
        if ok:
            _prj_tab_table_exists[table_name] = True
        return ok
    except Exception:
        return False


def _sync_wrk_report_project_links(project_id: int, payload_obj: object) -> None:
    """WBS scope 탭 저장 시 taskDoc 레퍼런스 기반으로 wrk_report.project_id 동기화.

    - payload_obj 의 rows[].taskDoc 에 해당하는 wrk_report → project_id 설정
    - 기존에 이 project_id 를 갖고 있었지만 더 이상 taskDoc 에 없는 wrk_report → project_id 해제
    """
    try:
        rows = []
        if isinstance(payload_obj, dict):
            rows = payload_obj.get('rows') or []
        if not isinstance(rows, list):
            rows = []

        # 새 payload 에 포함된 doc_no 집합
        new_doc_nos = set()
        for r in rows:
            if isinstance(r, dict):
                doc_no = str(r.get('taskDoc') or '').strip()
                if doc_no and doc_no != '-':
                    new_doc_nos.add(doc_no)

        project = PrjProject.query.get(project_id)
        project_name = (project.project_name or '') if project else ''

        # 1) 새로 연결: doc_no 가 new_doc_nos 에 있지만 아직 project_id 가 다른/NULL 인 wrk_report
        if new_doc_nos:
            reports_to_link = WrkReport.query.filter(
                WrkReport.doc_no.in_(new_doc_nos),
                WrkReport.is_deleted == 0,
                db.or_(
                    WrkReport.project_id != project_id,
                    WrkReport.project_id.is_(None),
                ),
            ).all()
            for rpt in reports_to_link:
                rpt.project_id = project_id
                rpt.project_name = project_name

        # 2) 연결 해제: 이 project_id 를 갖고 있지만 더 이상 taskDoc 에 없는 wrk_report
        unlink_q = WrkReport.query.filter(
            WrkReport.project_id == project_id,
            WrkReport.is_deleted == 0,
        )
        if new_doc_nos:
            unlink_q = unlink_q.filter(
                db.or_(
                    WrkReport.doc_no.notin_(new_doc_nos),
                    WrkReport.doc_no.is_(None),
                )
            )
        reports_to_unlink = unlink_q.all()
        for rpt in reports_to_unlink:
            rpt.project_id = None
            rpt.project_name = None

    except Exception:
        logger.exception('Failed to sync wrk_report project links for project_id=%s', project_id)


def _clear_wrk_report_project_links(project_id: int) -> None:
    """프로젝트 삭제(soft-delete) 시 해당 프로젝트를 참조하는 모든 wrk_report 의 project_id 를 해제."""
    try:
        reports = WrkReport.query.filter(
            WrkReport.project_id == project_id,
            WrkReport.is_deleted == 0,
        ).all()
        for rpt in reports:
            rpt.project_id = None
            rpt.project_name = None
    except Exception:
        logger.exception('Failed to clear wrk_report project links for project_id=%s', project_id)


def _prj_tab_model_for_key(tab_key: str):
    key = (tab_key or '').strip().lower()
    mapping = {
        'integrity': (PrjTabIntegrity, 'prj_tab_integrity'),
        'scope': (PrjTabScope, 'prj_tab_scope'),
        'schedule': (PrjTabSchedule, 'prj_tab_schedule'),
        'cost': (PrjTabCost, 'prj_tab_cost'),
        'quality': (PrjTabQuality, 'prj_tab_quality'),
        'resource': (PrjTabResource, 'prj_tab_resource'),
        'communication': (PrjTabCommunication, 'prj_tab_communication'),
        'risk': (PrjTabRisk, 'prj_tab_risk'),
        'procurement': (PrjTabProcurement, 'prj_tab_procurement'),
        'stakeholder': (PrjTabStakeholder, 'prj_tab_stakeholder'),
    }
    return mapping.get(key)


def _prj_tab_serialize(row) -> dict:
    payload = None
    try:
        payload = json.loads(row.payload_json or 'null')
    except Exception:
        payload = None
    return {
        'id': row.id,
        'project_id': row.project_id,
        'payload': payload,
        'created_at': getattr(row, 'created_at', None),
        'created_by_user_id': getattr(row, 'created_by_user_id', None),
        'updated_at': getattr(row, 'updated_at', None),
        'updated_by_user_id': getattr(row, 'updated_by_user_id', None),
        'is_deleted': getattr(row, 'is_deleted', 0),
    }


def _prj_tab_payload_obj() -> object:
    payload = _prj_payload()
    # Accept either {payload:{...}} or the raw object itself.
    if isinstance(payload, dict) and 'payload' in payload and isinstance(payload.get('payload'), (dict, list)):
        return payload.get('payload')
    return payload


def _ensure_prj_project_exists(project_id: int, *, include_deleted: bool = False) -> Optional[PrjProject]:
    row = PrjProject.query.get(project_id)
    if not row:
        return None
    if (row.is_deleted or 0) and not include_deleted:
        return None
    return row


def _prj_now_text() -> str:
    return datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S')


def _prj_payload() -> dict:
    if request.is_json:
        return request.get_json(silent=True) or {}
    return dict(request.form or {})


def _normalize_date_yyyy_mm_dd(value: object) -> Optional[str]:
    if value is None:
        return None
    text_value = str(value).strip()
    if not text_value:
        return None
    # Accept YYYY-MM-DD or datetime-like strings; keep only the date portion.
    date_part = text_value[:10]
    if len(date_part) != 10:
        return None
    if date_part[4] != '-' or date_part[7] != '-':
        return None
    yyyy, mm, dd = date_part[:4], date_part[5:7], date_part[8:10]
    if not (yyyy.isdigit() and mm.isdigit() and dd.isdigit()):
        return None
    return date_part


def _serialize_prj_project(row: PrjProject) -> dict:
    owner_dept_name = None
    try:
        owner_dept_name = row.owner_dept.dept_name if row.owner_dept else None
    except Exception:
        owner_dept_name = None
    manager_name = None
    try:
        manager_name = row.manager.name if row.manager else None
    except Exception:
        manager_name = None

    # 담당자 소속(company) 폴백: 담당자 본인에 없으면 같은 부서 사용자에서 가져옴
    manager_company = None
    try:
        manager_company = row.manager.company if row.manager and row.manager.company else None
    except Exception:
        pass
    if not manager_company and owner_dept_name:
        try:
            _peer = (
                UserProfile.query
                .filter(
                    UserProfile.department == owner_dept_name,
                    UserProfile.company.isnot(None),
                    UserProfile.company != '',
                )
                .first()
            )
            if _peer:
                manager_company = _peer.company
        except Exception:
            pass

    participant_members = []
    try:
        participant_members = [
            m
            for m in (row.members or [])
            if (m.is_deleted or 0) == 0 and (m.member_role or 'MEMBER').upper() == 'MEMBER'
        ]
    except Exception:
        participant_members = []
    participant_names = []
    participant_user_ids = []
    for m in participant_members:
        if m.user_id:
            participant_user_ids.append(m.user_id)
        if m.user and m.user.name:
            participant_names.append(m.user.name)

    # 이해관계자(stakeholder) 탭에서 참여자 이름/수 가져오기
    stakeholder_names = []
    stakeholder_count = 0
    try:
        latest_sh = (
            PrjTabStakeholder.query
            .filter_by(project_id=row.id, is_deleted=0)
            .order_by(PrjTabStakeholder.id.desc())
            .first()
        )
        if latest_sh and latest_sh.payload_json:
            import json as _json
            sh_payload = _json.loads(latest_sh.payload_json)
            sh_rows = sh_payload.get('rows') if isinstance(sh_payload, dict) else []
            if isinstance(sh_rows, list):
                stakeholder_names = [
                    r.get('name', '').strip()
                    for r in sh_rows
                    if isinstance(r, dict) and r.get('name', '').strip()
                ]
                stakeholder_count = len(stakeholder_names)
    except Exception:
        pass

    return {
        'id': row.id,
        'project_number': row.project_number,
        'project_name': row.project_name,
        'project_type': row.project_type,
        'owner_dept_id': row.owner_dept_id,
        'owner_dept_name': owner_dept_name,
        'manager_user_id': row.manager_user_id,
        'manager_name': manager_name,
        'manager_company': manager_company,
        'manager_dept': (row.manager.department if row.manager and row.manager.department else owner_dept_name),
        'manager_nickname': (row.manager.nickname if row.manager and row.manager.nickname else None),
        'participant_user_ids': participant_user_ids,
        'participants': ','.join(participant_names) if participant_names else None,
        'stakeholder_names': ','.join(stakeholder_names) if stakeholder_names else None,
        'stakeholder_count': stakeholder_count,
        'priority': row.priority,
        'description': row.description,
        'status': row.status,
        'budget_amount': row.budget_amount,
        'start_date': row.start_date,
        'expected_end_date': row.expected_end_date,
        'task_count_cached': row.task_count_cached,
        'progress_percent': row.progress_percent,
        'schedule_progress_rate': row.schedule_progress_rate,
        'gorf_goal': row.gorf_goal,
        'gorf_organization': row.gorf_organization,
        'gorf_research': row.gorf_research,
        'gorf_finance': row.gorf_finance,
        'created_at': row.created_at,
        'created_by_user_id': row.created_by_user_id,
        'created_by_name': (row.created_by.name if row.created_by else None),
        'created_by_company': (row.created_by.company if row.created_by and row.created_by.company else None),
        'created_by_dept': (row.created_by.department if row.created_by and row.created_by.department else None),
        'created_by_nickname': (row.created_by.nickname if row.created_by and row.created_by.nickname else None),
        'updated_at': row.updated_at,
        'updated_by_user_id': row.updated_by_user_id,
        'is_deleted': row.is_deleted,
    }


def _extract_participant_user_ids(payload: dict) -> Optional[List[int]]:
    raw = None
    for k in ('participant_user_ids', 'participantUserIds', 'member_user_ids', 'memberUserIds'):
        if k in payload:
            raw = payload.get(k)
            break
    if raw is None:
        return None
    if isinstance(raw, str):
        # allow comma-separated integers
        parts = [p.strip() for p in raw.split(',')]
        ids = [int(p) for p in parts if p.isdigit()]
        return sorted({i for i in ids if i > 0})
    if isinstance(raw, (list, tuple)):
        ids: List[int] = []
        for v in raw:
            iv = _coerce_positive_int(v)
            if iv:
                ids.append(iv)
        return sorted({i for i in ids if i > 0})
    return None


def _sync_prj_project_members(project_id: int, participant_user_ids: List[int], *, actor_user_id: int) -> None:
    """Replace MEMBER participants for a project with the provided user id list."""
    if not participant_user_ids:
        # clear only MEMBER role
        PrjProjectMember.query.filter(
            PrjProjectMember.project_id == project_id,
            PrjProjectMember.member_role == 'MEMBER',
        ).delete(synchronize_session=False)
        return

    existing = PrjProjectMember.query.filter(
        PrjProjectMember.project_id == project_id,
        PrjProjectMember.member_role == 'MEMBER',
    ).all()
    existing_ids = {m.user_id for m in existing if m.user_id}
    desired_ids = set(participant_user_ids)

    to_remove = [m for m in existing if m.user_id not in desired_ids]
    for m in to_remove:
        db.session.delete(m)

    to_add = sorted(desired_ids - existing_ids)
    for user_id in to_add:
        db.session.add(
            PrjProjectMember(
                project_id=project_id,
                user_id=user_id,
                member_role='MEMBER',
                created_by_user_id=actor_user_id,
            )
        )


def _sync_prj_project_leader(project_id: int, leader_user_id: int, *, actor_user_id: int) -> None:
    """Ensure exactly one LEADER mapping exists for the project's leader (manager_user_id).

    NOTE: prj_project_member has a (project_id, user_id) unique constraint, so a user
    cannot be both LEADER and MEMBER. We treat the leader as LEADER only.
    """
    # Remove any existing leader rows (regardless of deleted flag)
    PrjProjectMember.query.filter(
        PrjProjectMember.project_id == project_id,
        PrjProjectMember.member_role == 'LEADER',
    ).delete(synchronize_session=False)

    # If there is a MEMBER row for the leader, remove it (unique constraint would collide)
    PrjProjectMember.query.filter(
        PrjProjectMember.project_id == project_id,
        PrjProjectMember.user_id == leader_user_id,
        PrjProjectMember.member_role == 'MEMBER',
    ).delete(synchronize_session=False)

    db.session.add(
        PrjProjectMember(
            project_id=project_id,
            user_id=leader_user_id,
            member_role='LEADER',
            created_by_user_id=actor_user_id,
        )
    )


def _serialize_prj_project_members(project: PrjProject) -> dict:
    leader = None
    members = []
    try:
        rows = [m for m in (project.members or []) if (m.is_deleted or 0) == 0]
    except Exception:
        rows = []

    for m in rows:
        payload = {
            'id': m.id,
            'project_id': m.project_id,
            'user_id': m.user_id,
            'member_role': m.member_role,
            'user': {
                'id': m.user.id if m.user else None,
                'name': m.user.name if m.user else None,
                'emp_no': m.user.emp_no if m.user else None,
                'department': m.user.department if m.user else None,
            } if m.user else None,
        }
        if (m.member_role or '').upper() == 'LEADER':
            leader = payload
        else:
            members.append(payload)

    return {'leader': leader, 'members': members}


def _apply_prj_project_fields(row: PrjProject, payload: dict, *, actor_user_id: int, is_create: bool) -> None:
    def pick(*keys: str) -> Optional[object]:
        for k in keys:
            if k in payload:
                return payload.get(k)
        return None

    # Required
    name = pick('project_name', 'projectName')
    if name is not None:
        row.project_name = str(name).strip()
    ptype = pick('project_type', 'projectType')
    if ptype is not None:
        row.project_type = str(ptype).strip()
    status = pick('status')
    if status is not None:
        row.status = str(status).strip()

    owner_dept_id = pick('owner_dept_id', 'ownerDeptId')
    manager_user_id = pick('manager_user_id', 'managerUserId')
    if owner_dept_id is not None:
        row.owner_dept_id = _coerce_positive_int(owner_dept_id)
    if manager_user_id is not None:
        row.manager_user_id = _coerce_positive_int(manager_user_id)

    # Optional fields
    if pick('priority') is not None:
        row.priority = str(pick('priority') or '').strip() or None
    if pick('description') is not None:
        row.description = str(pick('description') or '').strip() or None

    if pick('budget_amount', 'budgetAmount') is not None:
        budget_val = str(pick('budget_amount', 'budgetAmount') or '').strip()
        row.budget_amount = int(budget_val) if budget_val and budget_val.isdigit() else None

    if pick('start_date', 'startDate') is not None:
        row.start_date = _normalize_date_yyyy_mm_dd(pick('start_date', 'startDate'))
    if pick('expected_end_date', 'expectedEndDate', 'end_date', 'endDate') is not None:
        row.expected_end_date = _normalize_date_yyyy_mm_dd(
            pick('expected_end_date', 'expectedEndDate', 'end_date', 'endDate')
        )

    if pick('task_count_cached', 'taskCountCached') is not None:
        row.task_count_cached = max(0, int(pick('task_count_cached', 'taskCountCached') or 0))
    if pick('progress_percent', 'progressPercent') is not None:
        row.progress_percent = max(0, min(100, int(pick('progress_percent', 'progressPercent') or 0)))

    # GORF fields
    for gorf_key in ('gorf_goal', 'gorf_organization', 'gorf_research', 'gorf_finance'):
        gorf_val = pick(gorf_key)
        if gorf_val is not None:
            setattr(row, gorf_key, str(gorf_val).strip() or None)

    # Validate required fields
    if is_create:
        if not row.project_name:
            raise ValueError('프로젝트 이름은 필수입니다.')
        if not row.project_type:
            raise ValueError('프로젝트 유형은 필수입니다.')
        if not row.owner_dept_id:
            raise ValueError('담당부서는 필수입니다.')
        if not row.manager_user_id:
            raise ValueError('담당자는 필수입니다.')
        if not row.status:
            raise ValueError('상태는 필수입니다.')

    # Update meta
    if is_create:
        row.created_by_user_id = actor_user_id
    else:
        row.updated_at = _prj_now_text()
        row.updated_by_user_id = actor_user_id


@api_bp.route('/api/prj/projects', methods=['GET'])
def list_prj_projects():
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _prj_project_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project)'}), 500
    if not _prj_project_member_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project_member)'}), 500

    include_deleted = _coerce_bool(request.args.get('include_deleted'), default=False)
    scope = (request.args.get('scope') or request.args.get('view') or 'all').strip().lower()
    search = (request.args.get('q') or '').strip()
    limit = request.args.get('limit', default=500, type=int) or 500
    limit = max(1, min(limit, 2000))

    try:
        q = PrjProject.query
        if not include_deleted:
            q = q.filter(PrjProject.is_deleted == 0)

        if scope == 'owned':
            q = q.filter(PrjProject.manager_user_id == actor_user_id)
            # 비우기 처리된 완료 프로젝트 숨기기
            q = q.filter(PrjProject.cleared == 0)
        elif scope == 'participating':
            q = q.join(
                PrjProjectMember,
                and_(
                    PrjProjectMember.project_id == PrjProject.id,
                    PrjProjectMember.is_deleted == 0,
                    PrjProjectMember.member_role == 'MEMBER',
                ),
            ).filter(PrjProjectMember.user_id == actor_user_id)
            q = q.filter(PrjProject.manager_user_id != actor_user_id)
            # 비우기 처리된 완료 프로젝트 숨기기 (per-user)
            q = q.filter(PrjProjectMember.cleared == 0)
        elif scope == 'cleared':
            # 완료 프로젝트: 비우기 처리된 프로젝트만 (담당 OR 참여)
            owned_cleared = PrjProject.query.filter(
                PrjProject.is_deleted == 0,
                PrjProject.manager_user_id == actor_user_id,
                PrjProject.cleared == 1,
            )
            participating_cleared = PrjProject.query.join(
                PrjProjectMember,
                and_(
                    PrjProjectMember.project_id == PrjProject.id,
                    PrjProjectMember.is_deleted == 0,
                    PrjProjectMember.member_role == 'MEMBER',
                    PrjProjectMember.cleared == 1,
                ),
            ).filter(
                PrjProjectMember.user_id == actor_user_id,
                PrjProject.is_deleted == 0,
                PrjProject.manager_user_id != actor_user_id,
            )
            q = owned_cleared.union(participating_cleared)
        else:
            # all
            pass

        if search:
            like = f"%{search}%"
            q = q.filter(
                or_(
                    PrjProject.project_name.ilike(like),
                    PrjProject.project_type.ilike(like),
                    PrjProject.status.ilike(like),
                    PrjProject.priority.ilike(like),
                )
            )

        items = q.order_by(PrjProject.id.desc()).limit(limit).all()
        return jsonify({'success': True, 'total': len(items), 'items': [_serialize_prj_project(row) for row in items]}), 200
    except Exception:
        logger.exception('Failed to list prj projects')
        return jsonify({'success': False, 'message': '프로젝트 목록 조회 중 오류가 발생했습니다.'}), 500


