@api_bp.route('/api/prj/projects/<int:project_id>/my-access', methods=['GET'])
def get_prj_project_my_access(project_id: int):
    """현재 로그인 사용자의 프로젝트 접근 권한 확인.

    - manager_user_id == 현재 사용자 → write
    - prj_project_member 에 등록 → write
    - 이해관계자(stakeholder) 탭 payload.name 과 일치 → write
    - ADMIN role → write
    - 그 외 → read
    """
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': True, 'access': 'read', 'reason': 'no_session'})
    try:
        project = PrjProject.query.get(project_id)
        if not project or (project.is_deleted or 0):
            return jsonify({'success': True, 'access': 'read', 'reason': 'not_found'})

        # 1) ADMIN role → always write
        sess_role = (session.get('role') or '').upper()
        if sess_role == 'ADMIN':
            return jsonify({'success': True, 'access': 'write', 'reason': 'admin'})

        # 2) 프로젝트 담당자(manager)
        if project.manager_user_id == actor_user_id:
            return jsonify({'success': True, 'access': 'write', 'reason': 'manager'})

        # 3) 프로젝트 생성자
        if project.created_by_user_id == actor_user_id:
            return jsonify({'success': True, 'access': 'write', 'reason': 'creator'})

        # 4) 프로젝트 참여자(member)
        member = PrjProjectMember.query.filter_by(
            project_id=project_id, user_id=actor_user_id
        ).filter((PrjProjectMember.is_deleted == 0) | (PrjProjectMember.is_deleted.is_(None))).first()
        if member:
            return jsonify({'success': True, 'access': 'write', 'reason': 'member'})

        # 5) 이해관계자(stakeholder) 탭에 이름이 등록되어 있는지 확인
        try:
            actor_profile = UserProfile.query.get(actor_user_id)
            actor_name = (actor_profile.name or '').strip() if actor_profile else ''
            if actor_name:
                stakeholder_tab = PrjTabStakeholder.query.filter_by(
                    project_id=project_id
                ).filter(
                    (PrjTabStakeholder.is_deleted == 0) | (PrjTabStakeholder.is_deleted.is_(None))
                ).order_by(PrjTabStakeholder.id.desc()).first()
                if stakeholder_tab and stakeholder_tab.payload_json:
                    import json as _json_access
                    payload = _json_access.loads(stakeholder_tab.payload_json)
                    rows_data = None
                    if isinstance(payload, dict):
                        rows_data = payload.get('stakeholder', {}).get('rows') or payload.get('rows')
                    if isinstance(rows_data, list):
                        for r in rows_data:
                            rn = (r.get('name') or '').strip() if isinstance(r, dict) else ''
                            if rn == actor_name:
                                return jsonify({'success': True, 'access': 'write', 'reason': 'stakeholder'})
        except Exception:
            pass

        return jsonify({'success': True, 'access': 'read', 'reason': 'not_registered'})
    except Exception:
        logger.exception('Failed to check project access %s', project_id)
        return jsonify({'success': True, 'access': 'read', 'reason': 'error'})

@api_bp.route('/api/prj/projects', methods=['POST'])
def create_prj_project():
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _prj_project_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project)'}), 500
    if not _prj_project_member_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project_member)'}), 500
    payload = _prj_payload()
    try:
        # Auto-resolve owner_dept_id from current user's profile if not provided
        default_dept_id = 1
        if 'owner_dept_id' not in payload and 'ownerDeptId' not in payload:
            try:
                actor_profile = UserProfile.query.get(actor_user_id)
                if actor_profile and actor_profile.department_id:
                    default_dept_id = actor_profile.department_id
            except Exception:
                pass
        row = PrjProject(
            project_name='TEMP',
            project_type='TEMP',
            owner_dept_id=default_dept_id,
            manager_user_id=actor_user_id,
            status='TEMP',
            created_by_user_id=actor_user_id,
        )
        _apply_prj_project_fields(row, payload, actor_user_id=actor_user_id, is_create=True)
        db.session.add(row)
        db.session.flush()

        # Auto-generate unique project_number: PRJ-YYYY-NNNNN
        if not row.project_number:
            from datetime import date as _date
            year_str = _date.today().strftime('%Y')
            prefix = 'PRJ-' + year_str + '-'
            # Find max seq for this year
            existing_max = db.session.query(
                db.func.max(PrjProject.project_number)
            ).filter(
                PrjProject.project_number.like(prefix + '%')
            ).scalar()
            if existing_max:
                try:
                    seq = int(str(existing_max).split('-')[-1]) + 1
                except (ValueError, IndexError):
                    seq = 1
            else:
                seq = 1
            row.project_number = prefix + str(seq).zfill(5)

        # Ensure leader mapping always exists
        _sync_prj_project_leader(row.id, row.manager_user_id, actor_user_id=actor_user_id)

        participant_user_ids = _extract_participant_user_ids(payload)
        if participant_user_ids is not None:
            participant_user_ids = [i for i in participant_user_ids if i != row.manager_user_id]
            _sync_prj_project_members(row.id, participant_user_ids, actor_user_id=actor_user_id)

        db.session.commit()
        fresh = PrjProject.query.get(row.id)
        return jsonify({'success': True, 'item': _serialize_prj_project(fresh)}), 201
    except ValueError as exc:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create prj project')
        return jsonify({'success': False, 'message': '프로젝트 생성 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/prj/projects/<int:project_id>', methods=['PUT'])
def update_prj_project(project_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _prj_project_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project)'}), 500
    if not _prj_project_member_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project_member)'}), 500
    payload = _prj_payload()
    try:
        row = PrjProject.query.get(project_id)
        if not row or (row.is_deleted or 0):
            return jsonify({'success': False, 'message': '프로젝트를 찾을 수 없습니다.'}), 404
        old_manager_user_id = row.manager_user_id
        _apply_prj_project_fields(row, payload, actor_user_id=actor_user_id, is_create=False)

        # If leader changed (or to enforce consistency), resync leader mapping
        if row.manager_user_id and row.manager_user_id != old_manager_user_id:
            _sync_prj_project_leader(row.id, row.manager_user_id, actor_user_id=actor_user_id)

        participant_user_ids = _extract_participant_user_ids(payload)
        if participant_user_ids is not None:
            participant_user_ids = [i for i in participant_user_ids if i != row.manager_user_id]
            _sync_prj_project_members(row.id, participant_user_ids, actor_user_id=actor_user_id)

        db.session.commit()
        fresh = PrjProject.query.get(row.id)
        return jsonify({'success': True, 'item': _serialize_prj_project(fresh)}), 200
    except ValueError as exc:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update prj project %s', project_id)
        return jsonify({'success': False, 'message': '프로젝트 수정 중 오류가 발생했습니다.'}), 500


