@api_bp.route('/api/prj/projects/bulk-delete', methods=['POST'])
def bulk_delete_prj_projects():
    """Soft-delete multiple projects at once (set is_deleted=1).

    Payload:  { "ids": [1, 2, 3] }
    """
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _prj_project_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project)'}), 500

    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids') or []
    if not isinstance(ids, list) or not ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400
    safe_ids = [int(x) for x in ids if str(x).isdigit()]
    if not safe_ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400

    try:
        now_text = _prj_now_text()
        deleted_count = 0
        rows = PrjProject.query.filter(
            PrjProject.id.in_(safe_ids),
            PrjProject.is_deleted == 0,
        ).all()
        for row in rows:
            row.is_deleted = 1
            row.updated_at = now_text
            row.updated_by_user_id = actor_user_id
            # 프로젝트 삭제 시 연결된 wrk_report 의 project_id 해제
            _clear_wrk_report_project_links(row.id)
            deleted_count += 1
        db.session.commit()
        return jsonify({'success': True, 'deleted': deleted_count}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to bulk-delete prj projects')
        return jsonify({'success': False, 'message': '프로젝트 삭제 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/prj/projects/batch-clear', methods=['POST'])
def batch_clear_prj_projects():
    """Batch-set cleared=1 on completed projects (hide from 담당/참여 kanban board).

    Payload:
        scope  – 'owned' | 'participating'  (required)
        ids    – list of project IDs to clear (required)
    """
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _prj_project_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project)'}), 500
    if not _prj_project_member_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project_member)'}), 500

    payload = request.get_json(silent=True) or {}
    scope = (payload.get('scope') or '').strip().lower()
    ids = payload.get('ids') or []
    if not isinstance(ids, list) or not ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400
    safe_ids = [int(x) for x in ids if str(x).isdigit()]
    if not safe_ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400

    try:
        cleared_count = 0

        if scope == 'participating':
            # 참여 프로젝트: mark the member row as cleared (per-user)
            rows = PrjProjectMember.query.filter(
                PrjProjectMember.project_id.in_(safe_ids),
                PrjProjectMember.user_id == actor_user_id,
                PrjProjectMember.is_deleted == 0,
            ).all()
            for row in rows:
                row.cleared = 1
                cleared_count += 1
        else:
            # 담당 프로젝트 (owned): mark the project itself as cleared
            rows = PrjProject.query.filter(
                PrjProject.id.in_(safe_ids),
                PrjProject.is_deleted == 0,
                PrjProject.manager_user_id == actor_user_id,
            ).all()
            for row in rows:
                row.cleared = 1
                row.updated_at = _prj_now_text()
                row.updated_by_user_id = actor_user_id
                cleared_count += 1

        db.session.commit()
        return jsonify({'success': True, 'cleared': cleared_count}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to batch clear prj projects scope=%s', scope)
        return jsonify({'success': False, 'message': '비우기 처리 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/prj/projects/batch-restore', methods=['POST'])
def batch_restore_prj_projects():
    """Batch-set cleared=0 on projects (restore from 완료 프로젝트 tab).

    Payload:
        ids    – list of project IDs to restore (required)
    """
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _prj_project_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project)'}), 500
    if not _prj_project_member_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project_member)'}), 500

    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids') or []
    if not isinstance(ids, list) or not ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400
    safe_ids = [int(x) for x in ids if str(x).isdigit()]
    if not safe_ids:
        return jsonify({'success': False, 'message': 'ids is required'}), 400

    try:
        restored_count = 0

        # 담당 프로젝트 복구
        owned_rows = PrjProject.query.filter(
            PrjProject.id.in_(safe_ids),
            PrjProject.is_deleted == 0,
            PrjProject.manager_user_id == actor_user_id,
            PrjProject.cleared == 1,
        ).all()
        for row in owned_rows:
            row.cleared = 0
            row.updated_at = _prj_now_text()
            row.updated_by_user_id = actor_user_id
            restored_count += 1

        # 참여 프로젝트 복구
        member_rows = PrjProjectMember.query.filter(
            PrjProjectMember.project_id.in_(safe_ids),
            PrjProjectMember.user_id == actor_user_id,
            PrjProjectMember.is_deleted == 0,
            PrjProjectMember.cleared == 1,
        ).all()
        for row in member_rows:
            row.cleared = 0
            restored_count += 1

        db.session.commit()
        return jsonify({'success': True, 'restored': restored_count}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to batch restore prj projects')
        return jsonify({'success': False, 'message': '복구 처리 중 오류가 발생했습니다.'}), 500


