@api_bp.route('/api/prj/projects/<int:project_id>/tabs/<tab_key>', methods=['GET'])
def list_prj_project_tab_items(project_id: int, tab_key: str):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _prj_project_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (prj_project)'}), 500

    mapping = _prj_tab_model_for_key(tab_key)
    if not mapping:
        return jsonify({'success': False, 'message': '지원하지 않는 탭입니다.'}), 404
    model, table_name = mapping
    if not _prj_tab_table_ready(table_name):
        return jsonify({'success': False, 'message': f'DB 마이그레이션이 필요합니다. ({table_name})'}), 500

    include_deleted = _coerce_bool(request.args.get('include_deleted'), default=False)
    limit = request.args.get('limit', default=500, type=int) or 500
    limit = max(1, min(limit, 2000))

    project = _ensure_prj_project_exists(project_id, include_deleted=include_deleted)
    if not project:
        return jsonify({'success': False, 'message': '프로젝트를 찾을 수 없습니다.'}), 404

    try:
        q = model.query.filter(model.project_id == project_id)
        if not include_deleted:
            q = q.filter(model.is_deleted == 0)
        rows = q.order_by(model.id.asc()).limit(limit).all()
        return jsonify({'success': True, 'total': len(rows), 'items': [_prj_tab_serialize(r) for r in rows]}), 200
    except Exception:
        logger.exception('Failed to list prj tab items project_id=%s tab=%s', project_id, tab_key)
        return jsonify({'success': False, 'message': '탭 데이터 조회 중 오류가 발생했습니다.'}), 500


