_prj_cost_detail_table_exists = False


def _prj_cost_detail_table_ready() -> bool:
    """Return True if prj_cost_detail table exists."""
    global _prj_cost_detail_table_exists
    if _prj_cost_detail_table_exists:
        return True
    try:
        import sqlalchemy as sa
        insp = sa.inspect(db.engine)
        _prj_cost_detail_table_exists = bool(insp.has_table('prj_cost_detail'))
    except Exception:
        _prj_cost_detail_table_exists = False
    return bool(_prj_cost_detail_table_exists)


def _serialize_cost_detail(row) -> dict:
    return {
        'id': row.id,
        'project_id': row.project_id,
        'row_key': row.row_key,
        'costDate': row.cost_date or '',
        'costType': row.cost_type or '',
        'content': row.content or '',
        'erpAccount': row.erp_account or '',
        'amount': row.amount or 0,
        'registrant': row.registrant or '',
    }


@api_bp.route('/api/prj/projects/<int:project_id>/cost-details', methods=['GET'])
def list_prj_cost_details(project_id: int):
    """row_key 기준으로 실제비용 상세 항목 조회"""
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _prj_cost_detail_table_ready():
        return jsonify({'success': True, 'total': 0, 'items': []}), 200

    project = _ensure_prj_project_exists(project_id)
    if not project:
        return jsonify({'success': False, 'message': '프로젝트를 찾을 수 없습니다.'}), 404

    row_key = (request.args.get('row_key') or '').strip()
