@api_bp.route('/api/tickets', methods=['POST'])
def create_ticket():
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _ticket_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (svc_ticket)'}), 500
    payload = _ticket_payload()
    try:
        row = SvcTicket(
            title='TEMP',
            ticket_type='TEMP',
            priority='TEMP',
            due_at='TEMP',
            requester_user_id=actor_user_id,
            created_by_user_id=actor_user_id,
        )
        _apply_ticket_fields(row, payload, actor_user_id=actor_user_id, is_create=True)
        db.session.add(row)
        db.session.flush()  # allocate id

        created_files = _ticket_upload_files(row.id, actor_user_id)
        db.session.commit()
        fresh = SvcTicket.query.get(row.id)
        return jsonify({
            'success': True,
            'item': _serialize_ticket(fresh, include_files=True),
            'files': [_serialize_ticket_file(f) for f in created_files],
        }), 201
    except ValueError as exc:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create ticket')
        return jsonify({'success': False, 'message': '티켓 생성 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/tickets/<int:ticket_id>', methods=['PUT'])
def update_ticket(ticket_id: int):
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _ticket_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (svc_ticket)'}), 500
    payload = _ticket_payload()
    try:
        row = SvcTicket.query.get(ticket_id)
        if not row or (row.is_deleted or 0):
            return jsonify({'success': False, 'message': '티켓을 찾을 수 없습니다.'}), 404

        old_status = row.status
        _apply_ticket_fields(row, payload, actor_user_id=actor_user_id, is_create=False)
        new_status = row.status

        created_files = _ticket_upload_files(row.id, actor_user_id)
        db.session.commit()

        # 상태 변경 알림
        if old_status != new_status:
            try:
                from app.services.notification_service import notify_ticket_status_change
                notify_ticket_status_change(row, old_status, new_status, actor_user_id)
                db.session.commit()
            except Exception:
                logger.exception('ticket notification failed')

        fresh = SvcTicket.query.get(row.id)
        return jsonify({
            'success': True,
            'item': _serialize_ticket(fresh, include_files=True),
            'files_added': [_serialize_ticket_file(f) for f in created_files],
        }), 200
    except ValueError as exc:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update ticket %s', ticket_id)
        return jsonify({'success': False, 'message': '티켓 수정 중 오류가 발생했습니다.'}), 500


