def _hardware_asset_create_response(asset_type: str, log_label: str, failure_message: str, asset_category: str = 'SERVER'):
    payload = request.get_json(silent=True) or {}
    payload['asset_category'] = asset_category
    payload['asset_type'] = asset_type

    def _network_requires_core_fields(t: str) -> bool:
        return t in {'AP', 'CIRCUIT'}

    # Per-page required fields (UI also enforces this).
    # SECURITY and selected NETWORK pages require the same core business/system identifiers.
    if asset_category == 'SECURITY' or (asset_category == 'NETWORK' and _network_requires_core_fields(asset_type)):
        required = {
            'work_status': '업무 상태',
            'work_name': '업무 이름',
            'system_name': '시스템 이름',
        }

        missing = [label for key, label in required.items() if str(payload.get(key, '') or '').strip() == '']
        if missing:
            return jsonify({'success': False, 'message': f"필수 값이 누락되어 저장할 수 없습니다: {', '.join(missing)}"}), 400
    try:
        record = svc_create_hardware_asset(payload, _resolve_actor())

        # ── 변경이력: CREATE 기록 ──
        _try_record_change(
            action_type='CREATE',
            entity_type='hardware_asset',
            entity_id=record.get('id', ''),
            asset_category=asset_category,
            asset_type=asset_type,
            tab_name='자산 생성',
            new_data=record,
        )

        return jsonify({'success': True, 'item': record}), 201
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError as exc:
        msg = str(exc) if exc is not None else ''
        msg_l = msg.lower()
        # NOTE: sqlite3 integrity errors can be raised for UNIQUE, FK, NOT NULL, etc.
        # Prior behavior always returned "duplicate asset code" which can be misleading.
        if ('unique' in msg_l or 'unique constraint' in msg_l) and 'asset_code' in msg_l:
            logger.exception('Duplicate %s asset_code detected', log_label)
            return jsonify({'success': False, 'message': '동일한 자산 코드가 이미 존재합니다.'}), 400
        if 'foreign key constraint failed' in msg_l:
            logger.exception('Foreign key constraint failed while creating %s hardware asset', log_label)
            return jsonify({'success': False, 'message': '선택한 값(업무/조직/장비/위치 등)이 마스터 데이터에 없어 저장할 수 없습니다. 목록을 새로고침 후 다시 선택해 주세요.'}), 400
        if 'not null' in msg_l:
            logger.exception('NOT NULL constraint failed while creating %s hardware asset', log_label)
            return jsonify({'success': False, 'message': '필수 값이 누락되어 저장할 수 없습니다. 입력값을 확인해 주세요.'}), 400
        logger.exception('IntegrityError while creating %s hardware asset: %s', log_label, msg)
        return jsonify({'success': False, 'message': '저장 중 데이터 무결성 오류가 발생했습니다. 입력값을 확인해 주세요.'}), 400
    except Exception:
        logger.exception('Failed to create %s hardware asset', log_label)
        return jsonify({'success': False, 'message': failure_message}), 500


def _hardware_asset_update_response(asset_id: int, asset_type: Union[str, Sequence[str]], log_label: str, failure_message: str, asset_category: str = 'SERVER'):
    payload = request.get_json(silent=True) or {}

    # ── 가상화 값 → asset_type 자동 매핑 (서버 자산만) ──
    if asset_category == 'SERVER':
        _VIRT_TO_ASSET = {'물리서버': 'ON_PREMISE', '가상서버': 'WORKSTATION', '클라우드': 'CLOUD'}
        vt = (payload.get('virtualization_type') or '').strip()
        if vt in _VIRT_TO_ASSET:
            payload['asset_type'] = _VIRT_TO_ASSET[vt]

    # Per-page required fields: allow partial updates, but forbid explicitly blanking.
    def _is_network_ap(t: Union[str, Sequence[str]]) -> bool:
        if isinstance(t, (list, tuple, set)):
            return 'AP' in t
        return t == 'AP'

    def _is_network_circuit(t: Union[str, Sequence[str]]) -> bool:
        if isinstance(t, (list, tuple, set)):
            return 'CIRCUIT' in t
        return t == 'CIRCUIT'

    if asset_category == 'SECURITY' or (asset_category == 'NETWORK' and (_is_network_ap(asset_type) or _is_network_circuit(asset_type))):
        required = {
            'work_status': '업무 상태',
            'work_name': '업무 이름',
            'system_name': '시스템 이름',
        }
        missing = [label for key, label in required.items() if key in payload and str(payload.get(key, '') or '').strip() == '']
        if missing:
            return jsonify({'success': False, 'message': f"필수 값이 누락되어 저장할 수 없습니다: {', '.join(missing)}"}), 400

    # ── 변경이력: before 상태 캡처 ──
    _atype_str = asset_type if isinstance(asset_type, str) else (asset_type[0] if asset_type else '')
    old_data = None
    try:
        old_data = svc_get_hardware_asset(asset_id, asset_category=asset_category, asset_type=_atype_str)
    except Exception:
        pass  # before 캡처 실패해도 원래 업데이트는 계속 진행

    try:
        record = svc_update_hardware_asset(
            asset_id,
            payload,
            _resolve_actor(),
            asset_category=asset_category,
            asset_type=asset_type,
        )
        if not record:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        # ── 변경이력: after 상태 기록 ──
        _try_record_change(
            action_type='UPDATE',
            entity_type='hardware_asset',
            entity_id=asset_id,
            asset_category=asset_category,
            asset_type=_atype_str,
            old_data=old_data,
            new_data=record,
        )

        return jsonify({'success': True, 'item': record})
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError as exc:
        msg = str(exc) if exc is not None else ''
        msg_l = msg.lower()
        if ('unique' in msg_l or 'unique constraint' in msg_l) and 'asset_code' in msg_l:
            logger.exception('Duplicate %s asset_code detected (update)', log_label)
            return jsonify({'success': False, 'message': '동일한 자산 코드가 이미 존재합니다.'}), 400
        if 'foreign key constraint failed' in msg_l:
            logger.exception('Foreign key constraint failed while updating %s hardware asset', log_label)
            return jsonify({'success': False, 'message': '선택한 값(업무/조직/장비/위치 등)이 마스터 데이터에 없어 저장할 수 없습니다. 목록을 새로고침 후 다시 선택해 주세요.'}), 400
        if 'not null' in msg_l:
            logger.exception('NOT NULL constraint failed while updating %s hardware asset', log_label)
            return jsonify({'success': False, 'message': '필수 값이 누락되어 저장할 수 없습니다. 입력값을 확인해 주세요.'}), 400
        logger.exception('IntegrityError while updating %s hardware asset: %s', log_label, msg)
        return jsonify({'success': False, 'message': '저장 중 데이터 무결성 오류가 발생했습니다. 입력값을 확인해 주세요.'}), 400
    except Exception:
        logger.exception('Failed to update %s hardware asset', log_label)
        return jsonify({'success': False, 'message': failure_message}), 500


def _hardware_authority_require_asset(asset_id: int, asset_type: str, asset_category: str = 'SERVER') -> bool:
    """Lightweight existence check — no JOINs, so it cannot fail due to missing satellite tables."""
    try:
        from app.services import hardware_asset_service as _ha_svc
        with _ha_svc._get_connection() as conn:  # noqa: SLF001
            row = conn.execute(
                "SELECT 1 FROM hardware WHERE id = ? AND is_deleted = 0 AND asset_category = ? AND asset_type = ?",
                (asset_id, asset_category, asset_type),
            ).fetchone()
            return row is not None
    except Exception:
        logger.exception('Failed to check hardware asset existence asset_id=%s asset_type=%s', asset_id, asset_type)
        return False


