def _hardware_authority_delete_response(authority_id: int, asset_id: int, asset_type: str, failure_message: str, asset_category: str = 'SERVER'):
    try:
        # 삭제 전 데이터 캡처
        _auth_old = svc_get_hardware_authority(
            authority_id=authority_id, asset_id=asset_id, asset_type=asset_type)
        _auth_label = ''
        if _auth_old:
            _auth_label = (_auth_old.get('type', '') + ' / ' + _auth_old.get('target', '')).strip(' /')

        ok = svc_delete_hardware_authority(
            authority_id=authority_id,
            asset_id=asset_id,
            asset_type=asset_type,
            actor=_resolve_actor(),
        )
        if not ok:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        # ── 변경이력: 권한 DELETE ──
        _try_record_change(
            action_type='DELETE',
            entity_type='hardware_asset',
            entity_id=asset_id,
            asset_category=asset_category,
            asset_type=asset_type,
            tab_name='권한관리',
            old_data=_auth_old,
            summary='권한 삭제: ' + _auth_label,
        )

        return jsonify({'success': True})
    except Exception:
        logger.exception('Failed to delete hardware authority id=%s asset_id=%s asset_type=%s', authority_id, asset_id, asset_type)
        return jsonify({'success': False, 'message': failure_message}), 500


def _hardware_asset_delete_response(asset_type: Union[str, Sequence[str]], log_label: str, failure_message: str, asset_category: str = 'SERVER'):
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids')
    if not isinstance(ids, (list, tuple)) or not ids:
        return jsonify({'success': False, 'message': '삭제할 자산을 선택하세요.'}), 400
    try:
        deleted = svc_soft_delete_hardware_assets(
            ids,
            _resolve_actor(),
            asset_category=asset_category,
            asset_type=asset_type,
        )

        # ── 변경이력: DELETE 기록 ──
        _atype_str = asset_type if isinstance(asset_type, str) else (asset_type[0] if asset_type else '')
        for _did in ids:
            _try_record_change(
                action_type='DELETE',
                entity_type='hardware_asset',
                entity_id=_did,
                asset_category=asset_category,
                asset_type=_atype_str,
                tab_name='자산 삭제',
                summary=f'자산 ID {_did} 삭제',
            )

        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        logger.exception('Failed to delete %s hardware assets', log_label)
        return jsonify({'success': False, 'message': failure_message}), 500


# ── 불용처리 (Dispose) helper ──────────────────────────────────────
_DISPOSE_CATEGORY_MAP = {
    'server': 'SERVER', 'storage': 'STORAGE', 'san': 'SAN',
    'network': 'NETWORK', 'security': 'SECURITY',
}

@api_bp.route('/api/hardware/assets/dispose', methods=['POST'])
def hardware_assets_dispose():
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids')
    category_key = (payload.get('category') or '').strip().lower()
    asset_category = _DISPOSE_CATEGORY_MAP.get(category_key)
    if not isinstance(ids, (list, tuple)) or not ids:
        return jsonify({'success': False, 'message': '불용처리할 자산을 선택하세요.'}), 400
    if not asset_category:
        return jsonify({'success': False, 'message': '자산 카테고리가 올바르지 않습니다.'}), 400
    try:
        disposed = svc_dispose_hardware_assets(
            ids, _resolve_actor(), asset_category=asset_category,
        )
        for _did in ids:
            _try_record_change(
                action_type='DISPOSE',
                entity_type='hardware_asset',
                entity_id=_did,
                asset_category=asset_category,
                asset_type='',
                tab_name='불용처리',
                summary=f'자산 ID {_did} 불용처리',
            )
        return jsonify({'success': True, 'disposed': disposed})
    except Exception:
        logger.exception('Failed to dispose hardware assets')
        return jsonify({'success': False, 'message': '불용처리 중 오류가 발생했습니다.'}), 500


