    blocked = _require_login_for_write()
    if blocked is not None:
        return blocked
    try:
        data = request.get_json(silent=True) or {}
        system_key = str(data.get('system_key') or data.get('systemKey') or data.get('hostname') or data.get('host_name') or '').strip()
        if not system_key:
            system_key = f"onpremise:{asset_id}"

        # ── 변경이력: before 캡처 ──
        _acct_old = None
        try:
            _acct_old = next((r for r in (list_asset_accounts(asset_scope='onpremise', asset_id=asset_id, system_key=system_key) or []) if r.get('id') == account_id), None)
        except Exception:
            pass

        updated = update_asset_account(
            asset_scope='onpremise',
            asset_id=asset_id,
            account_id=account_id,
            system_key=system_key,
            status=(data.get('status') or ''),
            account_name=(data.get('account_name') or ''),
            uid=(data.get('uid') if data.get('uid') not in ('', None) else None),
            group_name=(data.get('group_name') or ''),
            gid=(data.get('gid') if data.get('gid') not in ('', None) else None),
            admin=(data.get('admin') or ''),
            login_allowed=bool(data.get('login_allowed')),
            su_allowed=bool(data.get('su_allowed')),
            remark=(data.get('remark') or ''),
        )
        if not updated:
            return jsonify({'success': False, 'message': '대상을 찾지 못했습니다.'}), 404

        # ── 변경이력 ──
        _try_record_change(action_type='UPDATE', entity_type='hardware_asset',
                           entity_id=asset_id,
                           asset_type='ON_PREMISE', tab_name='계정관리', old_data=_acct_old, new_data=updated,
                           summary='계정 수정: ' + (updated.get('account_name', '') if updated else ''))

        return jsonify({'success': True, 'item': updated})
    except Exception:
        logger.exception('Failed to update onpremise asset account asset_id=%s account_id=%s', asset_id, account_id)
        return jsonify({'success': False, 'message': '계정을 수정하지 못했습니다.'}), 500

