@api_bp.route('/api/asset-accounts', methods=['GET'])
def api_asset_accounts_list():
    asset_scope = (request.args.get('asset_scope') or request.args.get('scope') or '').strip()
    system_key = (request.args.get('system_key') or request.args.get('systemKey') or request.args.get('hostname') or request.args.get('host_name') or '').strip()
    asset_id_raw = request.args.get('asset_id')
    try:
        asset_id = int(asset_id_raw) if asset_id_raw is not None else None
    except (TypeError, ValueError):
        asset_id = None

    if not asset_scope or asset_id is None:
        return jsonify({'success': False, 'message': 'asset_scope and asset_id are required'}), 400

    # Scoping is mandatory for this API: system_key isolates accounts per host.
    if not system_key:
        return jsonify({'success': False, 'message': 'system_key is required (hostname/subtitle)'}), 400

    try:
        items = list_asset_accounts(asset_scope=asset_scope, asset_id=asset_id, system_key=system_key)
        return jsonify({'success': True, 'items': items})
    except Exception:
        logger.exception('Failed to list asset accounts asset_scope=%s asset_id=%s system_key=%s', asset_scope, asset_id, system_key)
        return jsonify({'success': False, 'message': '계정 목록을 불러오지 못했습니다.'}), 500


@api_bp.route('/api/asset-accounts', methods=['POST'])
def api_asset_accounts_create():
    blocked = _require_login_for_write()
    if blocked is not None:
        return blocked

    data = request.get_json(silent=True) or {}
    asset_scope = str(data.get('asset_scope') or data.get('scope') or '').strip()
    system_key = str(data.get('system_key') or data.get('systemKey') or data.get('hostname') or data.get('host_name') or '').strip()
    try:
        asset_id = int(data.get('asset_id'))
    except (TypeError, ValueError):
        asset_id = None
    if not asset_scope or asset_id is None:
        return jsonify({'success': False, 'message': 'asset_scope and asset_id are required'}), 400
    if not system_key:
        return jsonify({'success': False, 'message': 'system_key is required (hostname/subtitle)'}), 400

    account_name = str(data.get('account_name') or data.get('account') or '').strip()
    if not account_name:
        return jsonify({'success': False, 'message': 'account_name is required'}), 400
    if not re.fullmatch(r"[A-Za-z0-9]+", account_name):
        return jsonify({'success': False, 'message': '계정명은 영문/숫자만 입력 가능합니다.'}), 400

    account_type = str(data.get('account_type') or data.get('accountType') or data.get('type') or data.get('role') or '').strip()
    if not account_type:
        return jsonify({'success': False, 'message': 'account_type is required'}), 400

    status = str(data.get('status') or '').strip()
    if status not in {'활성', '비활성', '고스트', '예외'}:
        return jsonify({'success': False, 'message': '상태는 활성/비활성/고스트/예외 중 하나여야 합니다.'}), 400
    group_name = str(data.get('group_name') or data.get('group') or '').strip()
    if group_name and not re.fullmatch(r"[A-Za-z0-9]+", group_name):
        return jsonify({'success': False, 'message': '그룹명은 영문/숫자만 입력 가능합니다.'}), 400

    user_name = str(data.get('user_name') or data.get('user') or '').strip()
    if not user_name:
        return jsonify({'success': False, 'message': 'user_name is required'}), 400

    # Legacy/unused columns kept for backward compatibility.
    uid = _coerce_positive_int(data.get('uid'))
    gid = _coerce_positive_int(data.get('gid'))
    admin = str(data.get('admin') or '').strip()
    role = str(data.get('role') or '').strip()
    privilege_level = str(data.get('privilege_level') or data.get('privilege') or '').strip()
    purpose = str(data.get('purpose') or '').strip()

    login_allowed = _coerce_bool(data.get('login_allowed'), default=False)
    admin_allowed = _coerce_bool(data.get('admin_allowed'), default=False)
    su_allowed = _coerce_bool(data.get('su_allowed'), default=admin_allowed)
    remark = str(data.get('remark') or '').strip()

    try:
        item = create_asset_account(
            asset_scope=asset_scope,
            asset_id=asset_id,
            system_key=system_key,
            status=status,
            account_type=account_type,
            account_name=account_name,
            uid=uid,
            group_name=group_name,
            gid=gid,
            admin=admin,
            role=(role or account_type),
            user_name=user_name,
            privilege_level=privilege_level,
            purpose=purpose,
            login_allowed=login_allowed,
            su_allowed=su_allowed,
            admin_allowed=admin_allowed,
            remark=remark,
        )

        # ── 변경이력 ──
        _try_record_change(action_type='CREATE', entity_type='hardware_asset',
                           entity_id=asset_id,
                           tab_name='계정관리', new_data=item,
                           summary='계정 추가: ' + (account_name or ''))

        return jsonify({'success': True, 'item': item})
    except Exception:
        logger.exception('Failed to create asset account asset_scope=%s asset_id=%s system_key=%s', asset_scope, asset_id, system_key)
        return jsonify({'success': False, 'message': '계정을 저장하지 못했습니다.'}), 500


