# -----------------------------------------------------------------------------
# Hardware: Server detail - Backup policy (tab03-backup)
# -----------------------------------------------------------------------------


@api_bp.route('/api/hardware/server/backup-policies', methods=['GET'])
def list_hw_server_backup_policies():
    """List backup policies for a specific server asset.

    Query params:
    - asset_category: ON_PREMISE/CLOUD/WORKSTATION
    - asset_id: hardware_asset.db id
    - include_deleted: bool
    """

    if not _hw_server_bk_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (hw_server_backup_policy)'}), 500

    asset_category = (request.args.get('asset_category') or request.args.get('assetCategory') or '').strip().upper()
    asset_id = _coerce_positive_int(request.args.get('asset_id') or request.args.get('assetId'))
    include_deleted = _parse_bool_arg(request.args.get('include_deleted') or request.args.get('includeDeleted'))
    if asset_category not in _HW_SERVER_BK_ALLOWED_CATEGORIES:
        return jsonify({'success': False, 'message': 'asset_category is invalid'}), 400
    if not asset_id:
        return jsonify({'success': False, 'message': 'asset_id is required'}), 400

    try:
        query = HwServerBackupPolicy.query.filter(
            HwServerBackupPolicy.asset_category == asset_category,
            HwServerBackupPolicy.asset_id == asset_id,
        )
        if not include_deleted:
            query = query.filter((HwServerBackupPolicy.is_deleted == 0) | (HwServerBackupPolicy.is_deleted.is_(None)))
        rows = query.order_by(HwServerBackupPolicy.id.asc()).all()
        items = [_hw_server_bk_policy_to_dict(r) for r in rows]
        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to list hw server backup policies')
        return jsonify({'success': False, 'message': '백업 정책 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/server/backup-policies', methods=['POST'])
def create_hw_server_backup_policy():
    if not _hw_server_bk_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (hw_server_backup_policy)'}), 500

    payload = request.get_json(silent=True) or {}
