# -----------------------------------------------------------------------------
# Hardware: Server detail - Vulnerability (tab12-vulnerability)
# -----------------------------------------------------------------------------


@api_bp.route('/api/hardware/server/vulnerabilities', methods=['GET'])
def list_hw_server_vulnerabilities():
    """List vulnerability rows.

    Two modes:
    1) Detail mode (tab12-vulnerability)
        - asset_category: supported hardware subtype token
        - asset_id: hardware_asset.db id
    2) Global mode (governance vulnerability list/dashboard)
        - omit asset_category/asset_id to list all rows

    Query params:
    - include_deleted: bool
    """

    if not _hw_server_vl_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (hw_server_vulnerability)'}), 500

    asset_category = (request.args.get('asset_category') or request.args.get('assetCategory') or '').strip().upper()
    asset_id = _coerce_positive_int(request.args.get('asset_id') or request.args.get('assetId'))
    include_deleted = _parse_bool_arg(request.args.get('include_deleted') or request.args.get('includeDeleted'))

    # Compatibility: some clients send asset_category=SERVER to mean “all server types”.
    if asset_category == 'SERVER':
        if asset_id:
            return jsonify({
                'success': False,
                'message': 'asset_category must specify a supported subtype when asset_id is provided'
            }), 400
        asset_category = ''

    if asset_category and asset_category not in _HW_SERVER_VL_ALLOWED_CATEGORIES:
        return jsonify({'success': False, 'message': 'asset_category is invalid'}), 400
    if asset_id and not asset_category:
        return jsonify({'success': False, 'message': 'asset_category is required when asset_id is provided'}), 400

    try:
        meta = None
        if asset_category and asset_id:
            asset_target = _hw_vl_asset_target(asset_category)
            try:
                asset = svc_get_hardware_asset(
                    int(asset_id),
                    asset_category=asset_target[0] if asset_target else None,
                    asset_type=asset_target[1] if asset_target else None,
                ) or {}
                meta = {
                    'work_name': str((asset or {}).get('work_name') or '').strip(),
                    'system_name': str((asset or {}).get('system_name') or (asset or {}).get('asset_name') or '').strip(),
                }
            except Exception:
                meta = {'work_name': '', 'system_name': ''}

        query = HwServerVulnerability.query
        if asset_category and asset_id:
            query = query.filter(
                HwServerVulnerability.asset_category == asset_category,
                HwServerVulnerability.asset_id == asset_id,
            )
        elif asset_category:
            query = query.filter(HwServerVulnerability.asset_category == asset_category)
        if not include_deleted:
            query = query.filter((HwServerVulnerability.is_deleted == 0) | (HwServerVulnerability.is_deleted.is_(None)))

        # Detail tab tends to prefer stable order; global listing tends to prefer newest first.
        if asset_category and asset_id:
            rows = query.order_by(HwServerVulnerability.id.asc()).all()
        else:
            rows = query.order_by(HwServerVulnerability.id.desc()).all()

        # Enrich with (work_name, system_name) from hardware_asset.db when available.
        asset_cache: Dict[tuple, dict] = {}
        items = []
        for r in rows:
            d = _hw_server_vl_to_dict(r)
            key = (str(r.asset_category or '').strip().upper(), int(r.asset_id))
            asset = asset_cache.get(key)
            if asset is None:
                asset_target = _hw_vl_asset_target(key[0])
                try:
                    asset = svc_get_hardware_asset(
                        int(r.asset_id),
                        asset_category=asset_target[0] if asset_target else None,
                        asset_type=asset_target[1] if asset_target else None,
                    ) or {}
                except Exception:
                    asset = {}
                asset_cache[key] = asset

            d['work_name'] = str((asset or {}).get('work_name') or '').strip()
            d['system_name'] = str((asset or {}).get('system_name') or (asset or {}).get('asset_name') or '').strip()
            items.append(d)

        return jsonify({'success': True, 'items': items, 'total': len(items), 'meta': meta})
    except Exception:
        logger.exception('Failed to list hw server vulnerabilities')
        return jsonify({'success': False, 'message': '취약점 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/server/vulnerabilities', methods=['POST'])
def create_hw_server_vulnerability():
    if not _hw_server_vl_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (hw_server_vulnerability)'}), 500

    payload = request.get_json(silent=True) or {}
    asset_category = str((payload.get('asset_category') or payload.get('assetCategory') or '')).strip().upper()
    asset_id = _coerce_positive_int(payload.get('asset_id') or payload.get('assetId'))
    work_name = (_s(payload, 'work_name') or _s(payload, 'workName') or '').strip()
    system_name = (_s(payload, 'system_name') or _s(payload, 'systemName') or '').strip()
    category = _s(payload, 'category') or _s(payload, 'check_category') or _s(payload, 'checkCategory')
    item = _s(payload, 'item') or _s(payload, 'check_topic') or _s(payload, 'checkTopic')
    severity = _s(payload, 'severity')
    result = _s(payload, 'result')

    # Compatibility: some clients send asset_category=SERVER to mean “all server types”.
    if asset_category == 'SERVER':
        if asset_id:
            return jsonify({
                'success': False,
                'message': 'asset_category must specify a supported subtype when asset_id is provided'
            }), 400
        asset_category = ''

    # The storage schema requires (asset_category, asset_id). If the client doesn't
    # provide them (governance UI), resolve them from hardware_asset.db using
    # (work_name, system_name).
    if not asset_id:
        if not work_name or not system_name:
            return jsonify({'success': False, 'message': 'work_name and system_name are required when asset_id is missing'}), 400

        # Optionally, if client provided a valid asset_category, narrow search to it.
        search_asset_category = 'SERVER'
        search_types = ['ON_PREMISE', 'CLOUD', 'WORKSTATION']
        if asset_category:
            asset_target = _hw_vl_asset_target(asset_category)
            if asset_target is None:
                return jsonify({'success': False, 'message': 'asset_category is invalid'}), 400
            search_asset_category = asset_target[0]
            search_types = asset_target[1]

        items = []
        try:
            # Primary: match on system_name (newer DBs / properly populated rows)
            res = svc_list_hardware_assets(
                asset_category=search_asset_category,
                asset_type=search_types,
                filters={'work_name': work_name, 'system_name': system_name},
                page=1,
                page_size=50,
            )
            items = list(res.get('items') or [])
        except Exception:
            logger.exception('Failed to resolve asset by work_name/system_name')
            return jsonify({'success': False, 'message': '자산 조회 중 오류가 발생했습니다.'}), 500

        # Fallback: legacy DBs often keep user-visible system identifier in asset_name.
        # If system_name-based filtering yields nothing, run a broader search and then
        # tighten in memory.
        if not items and system_name.strip():
            try:
                res2 = svc_list_hardware_assets(
                    asset_category=search_asset_category,
                    asset_type=search_types,
                    search=system_name,
                    filters={'work_name': work_name},
                    page=1,
                    page_size=100,
                )
                items = list(res2.get('items') or [])
            except Exception:
                logger.exception('Failed to resolve asset by legacy asset_name fallback')
                return jsonify({'success': False, 'message': '자산 조회 중 오류가 발생했습니다.'}), 500
        wn = work_name.strip()
        sn = system_name.strip()
        def _asset_system_label(it: dict) -> str:
            return str((it or {}).get('system_name') or (it or {}).get('asset_name') or '').strip()

        exact = [
            it for it in items
            if str((it or {}).get('work_name') or '').strip() == wn
            and _asset_system_label(it) == sn
        ]

        picked = None
        if len(exact) == 1:
            picked = exact[0]
        elif len(exact) > 1:
            return jsonify({'success': False, 'message': '동일한 업무명/시스템명의 자산이 여러 개입니다. 입력값을 더 구체적으로 작성해 주세요.'}), 400
        elif len(items) == 1:
            picked = items[0]
        elif len(items) == 0:
            return jsonify({'success': False, 'message': '업무명/시스템명에 해당하는 자산을 찾을 수 없습니다.'}), 400
        else:
            return jsonify({'success': False, 'message': '업무명/시스템명으로 자산이 여러 개 조회됩니다. 입력값을 더 구체적으로 작성해 주세요.'}), 400

        resolved_type = str((picked or {}).get('asset_type') or '').strip().upper()
        resolved_category_key = _hw_vl_category_from_asset((picked or {}).get('asset_category'), resolved_type)
        resolved_id = _coerce_positive_int((picked or {}).get('id'))
        if resolved_category_key not in _HW_SERVER_VL_ALLOWED_CATEGORIES or not resolved_id:
            return jsonify({'success': False, 'message': '자산 정보가 올바르지 않습니다.'}), 400

        asset_category = resolved_category_key
        asset_id = resolved_id

    if asset_category not in _HW_SERVER_VL_ALLOWED_CATEGORIES:
        return jsonify({'success': False, 'message': 'asset_category is invalid'}), 400
    if not asset_id:
        return jsonify({'success': False, 'message': 'asset_id is required'}), 400
    if not category:
        return jsonify({'success': False, 'message': 'check_category (or category) is required'}), 400
    if not item:
        return jsonify({'success': False, 'message': 'check_topic (or item) is required'}), 400

    action_status = (_s(payload, 'action_status') or _s(payload, 'actionStatus') or '').strip()
    if action_status and action_status not in ('완료', '미완료'):
        # Allow legacy signals.
        up = action_status.upper()
        if up in ('O', 'Y', 'YES'):
            action_status = '완료'
        elif up in ('X', 'N', 'NO'):
            action_status = '미완료'

    # Legacy schema requires these fields to be non-null; default them when new UI doesn't provide.
    if not severity:
        severity = '중'
    if not result:
        result = '양호' if action_status == '완료' else '취약'

    action_yn = (_s(payload, 'action_yn') or _s(payload, 'action') or '').strip()
    if not action_yn and action_status:
        action_yn = 'O' if action_status == '완료' else ('X' if action_status == '미완료' else '')

    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        check_category = _s(payload, 'check_category') or _s(payload, 'checkCategory') or category
        check_code = _s(payload, 'check_code') or _s(payload, 'checkCode') or _s(payload, 'code')
        check_topic = _s(payload, 'check_topic') or _s(payload, 'checkTopic') or item
        check_subtopic = _s(payload, 'check_subtopic') or _s(payload, 'checkSubtopic')

        check_overview = _s(payload, 'check_overview') or _s(payload, 'checkOverview') or _s(payload, 'content')
        check_standard = _s(payload, 'check_standard') or _s(payload, 'checkStandard')
        check_result = _s(payload, 'check_result') or _s(payload, 'checkResult')
        action_method = _s(payload, 'action_method') or _s(payload, 'actionMethod')
        action_due_date = _s(payload, 'action_due_date') or _s(payload, 'actionDueDate')
        worker_name = _s(payload, 'worker_name') or _s(payload, 'workerName')

        row = HwServerVulnerability(
            asset_category=asset_category,
            asset_id=asset_id,
            category=category,
            item=item,
            severity=severity,
            code=_s(payload, 'code') or check_code,
            content=_s(payload, 'content') or check_overview,
            result=result,
            action_yn=action_yn,
            remark=_s(payload, 'remark'),

            check_category=check_category,
            check_code=check_code,
            check_topic=check_topic,
            check_subtopic=check_subtopic,
            check_overview=check_overview,
            check_standard=check_standard,
            check_result=check_result,
            action_method=action_method,
            action_status=action_status,
            action_due_date=action_due_date,
            worker_name=worker_name,

            updated_at=now,
            is_deleted=0,
        )
        db.session.add(row)
        db.session.commit()

        # ── 변경이력 ──
        _try_record_change(action_type='CREATE', entity_type='hardware_asset',
                           entity_id=asset_id,
                           tab_name='취약점', new_data=_hw_server_vl_to_dict(row),
                           summary='취약점 추가: ' + (str(item or '')))

        return jsonify({'success': True, 'item': _hw_server_vl_to_dict(row)}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create hw server vulnerability')
        return jsonify({'success': False, 'message': '취약점 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/server/vulnerabilities/<int:vuln_id>', methods=['PUT'])
def update_hw_server_vulnerability(vuln_id: int):
    if not _hw_server_vl_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (hw_server_vulnerability)'}), 500

    payload = request.get_json(silent=True) or {}
    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        row = HwServerVulnerability.query.filter(HwServerVulnerability.id == vuln_id).first()
        if not row or int(row.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        # ── 변경이력: before 캡처 ──
        _vl_old_data = _hw_server_vl_to_dict(row)

        if 'category' in payload:
            cand = _s(payload, 'category')
            if not cand:
                return jsonify({'success': False, 'message': 'category is required'}), 400
            row.category = cand
        if 'item' in payload:
            cand = _s(payload, 'item')
            if not cand:
                return jsonify({'success': False, 'message': 'item is required'}), 400
            row.item = cand
        if 'severity' in payload:
            cand = _s(payload, 'severity')
            if not cand:
                return jsonify({'success': False, 'message': 'severity is required'}), 400
            row.severity = cand
        if 'result' in payload:
            cand = _s(payload, 'result')
            if not cand:
                return jsonify({'success': False, 'message': 'result is required'}), 400
            row.result = cand

        for k in ('code', 'content', 'remark'):
            if k in payload:
                setattr(row, k, _s(payload, k))

        if 'action_yn' in payload or 'action' in payload:
            row.action_yn = _s(payload, 'action_yn') or _s(payload, 'action')

        # Extended fields
        for k in (
            'check_category',
            'check_code',
            'check_topic',
            'check_subtopic',
            'check_overview',
            'check_standard',
            'check_result',
            'action_method',
            'action_due_date',
            'worker_name',
        ):
            if k in payload:
                setattr(row, k, _s(payload, k))

        if 'action_status' in payload:
            cand = (_s(payload, 'action_status') or '').strip()
            if not cand:
                row.action_status = None
            else:
                if cand not in ('완료', '미완료'):
                    up = cand.upper()
                    if up in ('O', 'Y', 'YES'):
                        cand = '완료'
                    elif up in ('X', 'N', 'NO'):
                        cand = '미완료'
                row.action_status = cand

        row.updated_at = now
        db.session.commit()

        # ── 변경이력 ──
        _try_record_change(action_type='UPDATE', entity_type='hardware_asset',
                           entity_id=int(row.asset_id),
                           tab_name='취약점', old_data=_vl_old_data, new_data=_hw_server_vl_to_dict(row),
                           summary='취약점 수정: ' + (str(row.item or '')))

        return jsonify({'success': True, 'item': _hw_server_vl_to_dict(row)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update hw server vulnerability')
        return jsonify({'success': False, 'message': '취약점 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/server/vulnerabilities/<int:vuln_id>', methods=['DELETE'])
def delete_hw_server_vulnerability(vuln_id: int):
    if not _hw_server_vl_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (hw_server_vulnerability)'}), 500

    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        row = HwServerVulnerability.query.filter(HwServerVulnerability.id == vuln_id).first()
        if not row or int(row.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        _vl_old_data = _hw_server_vl_to_dict(row)
        _vl_label = str(row.check_topic or row.item or '')

        row.is_deleted = 1
        row.updated_at = now
        db.session.commit()

        # ── 변경이력 ──
        _try_record_change(action_type='DELETE', entity_type='hardware_asset',
                           entity_id=int(row.asset_id),
                           tab_name='취약점',
                           old_data=_vl_old_data,
                           summary='취약점 삭제: ' + _vl_label)

        return jsonify({'success': True, 'deleted': vuln_id})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete hw server vulnerability')
        return jsonify({'success': False, 'message': '취약점 삭제 중 오류가 발생했습니다.'}), 500


