@api_bp.route('/api/hardware/storage/assets/<int:asset_id>/basic', methods=['PUT'])
def upsert_hardware_storage_asset_basic(asset_id: int):
    try:
        payload = request.get_json(silent=True) or {}

        # ── 변경이력: before 캡처 ──
        _stb_old = None
        try:
            _old_row = svc_get_hw_storage_basic('STORAGE', asset_id)
            if _old_row:
                _stb_old = svc_hw_storage_basic_to_dict(_old_row)
        except Exception:
            pass

        row = svc_upsert_hw_storage_basic('STORAGE', asset_id, payload)
        db.session.commit()

        # ── 변경이력 ──
        _try_record_change(action_type='UPDATE', entity_type='hardware_asset',
                           entity_id=asset_id,
                           tab_name='스토리지 기본', old_data=_stb_old, new_data=svc_hw_storage_basic_to_dict(row),
                           summary='스토리지 구성/관리 정보 수정')

        return jsonify({'success': True, 'item': svc_hw_storage_basic_to_dict(row)})
    except ValueError as ve:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(ve)}), 400
    except Exception:
        db.session.rollback()
        logger.exception('Failed to upsert storage basic info')
        return jsonify({'success': False, 'message': '스토리지 구성/관리 정보 저장 중 오류가 발생했습니다.'}), 500


