@api_bp.route('/api/work-categories', methods=['GET'])
def list_work_categories():
    search = (request.args.get('q') or '').strip() or None
    try:
        rows = svc_list_work_categories(search=search)
        return jsonify({'success': True, 'items': rows, 'total': len(rows)})
    except Exception:
        logger.exception('Failed to fetch work categories')
        return jsonify({'success': False, 'message': '업무 분류 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/work-categories', methods=['POST'])
def create_work_category():
    payload = request.get_json(silent=True) or {}
    try:
        record = svc_create_work_category(payload, _resolve_actor())
        return jsonify({'success': True, 'item': record}), 201
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError:
        logger.exception('Duplicate work category code')
        return jsonify({'success': False, 'message': '동일한 업무 분류 코드가 이미 존재합니다.'}), 400
    except Exception:
        logger.exception('Failed to create work category')
        return jsonify({'success': False, 'message': '업무 분류 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/work-categories/<int:category_id>', methods=['PUT'])
def update_work_category(category_id: int):
    payload = request.get_json(silent=True) or {}
    try:
        record = svc_update_work_category(category_id, payload, _resolve_actor())
        if not record:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404
        return jsonify({'success': True, 'item': record})
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to update work category')
        return jsonify({'success': False, 'message': '업무 분류 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/work-categories/bulk-delete', methods=['POST'])
def delete_work_categories():
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids')
    if not isinstance(ids, (list, tuple)) or not ids:
        return jsonify({'success': False, 'message': '삭제할 항목을 선택하세요.'}), 400
    try:
        deleted = svc_soft_delete_work_categories(ids, _resolve_actor())
        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        logger.exception('Failed to delete work categories')
        return jsonify({'success': False, 'message': '업무 분류 삭제 중 오류가 발생했습니다.'}), 500


