@api_bp.route('/api/wrk/vendor-staff-suggest', methods=['GET'])
def suggest_wrk_vendor_staff():
    """협력직원 자동완성(작업보고서 누적 기록 + 카테고리 벤더 매니저 통합 검색)."""
    actor_user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not actor_user_id:
        return jsonify({'success': False, 'message': '사용자 세션이 만료되었습니다.'}), 401
    if not _wrk_report_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (wrk_report)'}), 500

    q = (request.args.get('q') or '').strip()
    vendor_names = [str(v or '').strip() for v in request.args.getlist('vendor_name')]
    vendor_names = [v for v in vendor_names if v]
    # Back-compat: accept single vendor_name
    if not vendor_names:
        single_vendor_name = (request.args.get('vendor_name') or '').strip() or None
        if single_vendor_name:
            vendor_names = [single_vendor_name]
    limit = request.args.get('limit', default=20, type=int) or 20
    limit = max(1, min(limit, 200))

    if not q:
        return jsonify({'success': True, 'items': [], 'total': 0})

    try:
        like = f"%{q}%"
        # --- 1) 기존: 작업보고서에 누적된 vendor staff 검색 ---
        query = (
            db.session.query(WrkReportVendorStaff.staff_name, WrkReportVendor.vendor_name)
            .join(WrkReportVendor, WrkReportVendorStaff.vendor_id == WrkReportVendor.id)
            .filter(WrkReportVendorStaff.staff_name.ilike(like))
        )
        if vendor_names:
            if len(vendor_names) == 1:
                query = query.filter(WrkReportVendor.vendor_name == vendor_names[0])
            else:
                query = query.filter(WrkReportVendor.vendor_name.in_(vendor_names))
        rows = query.order_by(WrkReportVendorStaff.staff_name.asc()).limit(limit).all()
        seen = set()
        items = []
        for (staff_name, vname) in rows:
            if not staff_name:
                continue
            dedup_key = (staff_name.strip().lower(), (vname or '').strip().lower())
            if dedup_key not in seen:
                seen.add(dedup_key)
                items.append({'staff_name': staff_name, 'vendor_name': vname})

        # --- 2) 카테고리 > 벤더 > 제조사/유지보수사 매니저 테이블 검색 ---
        remaining = max(0, limit - len(items))
        if remaining > 0:
            try:
                _vendor_mgr_queries = []
                # (base_sql, vendor_name_column_for_WHERE)
                # 제조사 매니저
                _vendor_mgr_queries.append((
                    "SELECT m.name AS staff_name, v.manufacturer_name AS vendor_name "
                    "FROM biz_vendor_manufacturer_manager m "
                    "JOIN biz_vendor_manufacturer v ON m.vendor_id = v.id "
                    "WHERE m.name LIKE :like AND (m.is_deleted = 0 OR m.is_deleted IS NULL) "
                    "AND (v.is_deleted = 0 OR v.is_deleted IS NULL)",
                    "v.manufacturer_name",
                ))
                # 유지보수사 매니저
                _vendor_mgr_queries.append((
                    "SELECT m.name AS staff_name, v.maintenance_name AS vendor_name "
                    "FROM biz_vendor_maintenance_manager m "
                    "JOIN biz_vendor_maintenance v ON m.vendor_id = v.id "
                    "WHERE m.name LIKE :like AND (m.is_deleted = 0 OR m.is_deleted IS NULL) "
                    "AND (v.is_deleted = 0 OR v.is_deleted IS NULL)",
                    "v.maintenance_name",
                ))
                for base_sql, vn_col in _vendor_mgr_queries:
                    if remaining <= 0:
                        break
                    sql = base_sql
                    params = {'like': like}
                    if vendor_names:
                        if len(vendor_names) == 1:
                            sql += f" AND {vn_col} = :vn0"
                            params['vn0'] = vendor_names[0]
                        else:
                            placeholders = []
                            for idx, vn in enumerate(vendor_names):
                                key = f'vn{idx}'
                                placeholders.append(f':{key}')
                                params[key] = vn
                            sql += f" AND {vn_col} IN ({','.join(placeholders)})"
                    sql += f" ORDER BY m.name ASC LIMIT :lim"
                    params['lim'] = remaining
                    mgr_rows = db.session.execute(text(sql), params).fetchall()
                    for row in mgr_rows:
                        sn = (row[0] or '').strip()
                        vn = (row[1] or '').strip()
                        if not sn:
                            continue
                        dedup_key = (sn.lower(), vn.lower())
                        if dedup_key not in seen:
                            seen.add(dedup_key)
                            items.append({'staff_name': sn, 'vendor_name': vn})
                            remaining -= 1
            except Exception:
                logger.debug('Vendor manager table lookup skipped (tables may not exist yet)')

        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to suggest vendor staff')
        return jsonify({'success': False, 'message': '협력직원 검색 중 오류가 발생했습니다.'}), 500


