@api_bp.route('/api/org-racks/bulk-delete', methods=['POST'])
def delete_org_racks():
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids')
    if not isinstance(ids, (list, tuple)) or not ids:
        return jsonify({'success': False, 'message': '삭제할 항목을 선택하세요.'}), 400
    try:
        before_list = {}
        for rid in ids:
            try:
                _r = svc_fetch_single_org_rack(int(rid))
                if _r:
                    before_list[int(rid)] = _r
            except Exception:
                pass
        deleted = svc_hard_delete_org_racks(ids, _resolve_actor())
        for rid, bdata in before_list.items():
            _try_record_rack_change(
                action_type='DELETE',
                rack_id=rid,
                old_data=bdata,
                summary=f"RACK 삭제 ({bdata.get('rack_code', '')})",
            )
        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        logger.exception('Failed to delete org racks')
        return jsonify({'success': False, 'message': '랙 삭제 중 오류가 발생했습니다.'}), 500


