@api_bp.route('/api/org-cctvs', methods=['GET'])
def list_org_cctvs_api():
    search = (request.args.get('q') or request.args.get('search') or '').strip() or None
    include_deleted = (request.args.get('include_deleted') or request.args.get('includeDeleted') or '').lower() in ('1', 'true', 'yes')
    center_name = (request.args.get('center') or request.args.get('center_name') or request.args.get('place') or '').strip() or None
    business_name = (request.args.get('business_name') or request.args.get('name') or '').strip() or None
    limit_raw = request.args.get('limit') or request.args.get('page_size')
    limit = None
    if limit_raw:
        try:
            parsed = int(limit_raw)
            if parsed > 0:
                limit = min(parsed, 50)
        except (TypeError, ValueError):
            limit = None
    try:
        rows = svc_list_org_cctvs(
            search=search,
            include_deleted=include_deleted,
            center_name=center_name,
            business_name=business_name,
            limit=limit,
        )
        return jsonify({'success': True, 'items': rows, 'total': len(rows)})
    except Exception:
        logger.exception('Failed to fetch org cctvs')
        return jsonify({'success': False, 'message': 'CCTV 목록 조회 중 오류가 발생했습니다.'}), 500


