@api_bp.route('/api/vendor-manufacturers', methods=['POST'])
def create_vendor_manufacturer():
    payload = request.get_json(silent=True) or {}
    try:
        record = svc_create_vendor(payload, _resolve_actor())
        _try_record_change(
            action_type='CREATE',
            entity_type='vendor_manufacturer',
            entity_id=record.get('id'),
            tab_name='기본정보',
            new_data=record,
        )
        return jsonify({'success': True, 'item': record}), 201
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError:
        logger.exception('Duplicate vendor manufacturer code')
        return jsonify({'success': False, 'message': '동일한 제조사 코드가 이미 존재합니다.'}), 400
    except Exception:
        logger.exception('Failed to create vendor manufacturer')
        return jsonify({'success': False, 'message': '제조사 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/vendor-manufacturers/<int:vendor_id>', methods=['PUT'])
def update_vendor_manufacturer(vendor_id: int):
    payload = request.get_json(silent=True) or {}
    try:
        old_data = svc_get_vendor(vendor_id)
        record = svc_update_vendor(vendor_id, payload, _resolve_actor())
        if not record:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404
        _try_record_change(
            action_type='UPDATE',
            entity_type='vendor_manufacturer',
            entity_id=vendor_id,
            tab_name='기본정보',
            old_data=old_data,
            new_data=record,
        )
        return jsonify({'success': True, 'item': record})
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError:
        logger.exception('Duplicate vendor manufacturer code on update')
        return jsonify({'success': False, 'message': '동일한 제조사 코드가 이미 존재합니다.'}), 400
    except Exception:
        logger.exception('Failed to update vendor manufacturer')
        return jsonify({'success': False, 'message': '제조사 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/vendor-manufacturers/bulk-delete', methods=['POST'])
def delete_vendor_manufacturers():
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids')
    if not isinstance(ids, (list, tuple)) or not ids:
        return jsonify({'success': False, 'message': '삭제할 항목을 선택하세요.'}), 400
    try:
        old_rows = [svc_get_vendor(int(i)) for i in ids if i]
        deleted = svc_soft_delete_vendors(ids, _resolve_actor())
        if deleted <= 0:
            return jsonify({'success': False, 'message': '삭제할 유효한 제조사를 찾지 못했습니다.'}), 404
        for row in old_rows:
            if row:
                _try_record_change(
                    action_type='DELETE',
                    entity_type='vendor_manufacturer',
                    entity_id=row.get('id'),
                    tab_name='기본정보',
                    old_data=row,
                )
        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        logger.exception('Failed to delete vendor manufacturers')
        return jsonify({'success': False, 'message': '제조사 삭제 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/vendor-maintenance', methods=['GET'])
def list_vendor_maintenance_partners():
    search = (request.args.get('q') or '').strip() or None
    include_deleted = (request.args.get('include_deleted') or request.args.get('includeDeleted') or '').lower() in ('1', 'true', 'yes')
    try:
        rows = svc_list_maintenance_vendors(search=search, include_deleted=include_deleted)
        # Enrich HW/SW/Component counts from tab61 (OPEX 계약정보)
        for row in rows:
            vid = row.get('id')
            if vid:
                try:
                    cnts = _maint_vendor_tab61_counts(vid)
                    row['hardware_qty'] = cnts['hw']
                    row['software_qty'] = cnts['sw']
                    row['component_qty'] = cnts['comp']
                except Exception:
                    pass
        return jsonify({'success': True, 'items': rows, 'total': len(rows)})
    except Exception:
        logger.exception('Failed to fetch vendor maintenance partners')
        return jsonify({'success': False, 'message': '유지보수사 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/vendor-maintenance/<int:vendor_id>', methods=['GET'])
def get_vendor_maintenance_detail(vendor_id: int):
    """유지보수사 단건 조회 – HW/SW/Component 수량은 tab61 기반 동적 집계."""
    try:
        row = svc_get_maintenance_vendor(vendor_id)
        if not row:
            return jsonify({'success': False, 'message': '유지보수사를 찾을 수 없습니다.'}), 404
        cnts = _maint_vendor_tab61_counts(vendor_id)
        row['hardware_qty'] = cnts['hw']
        row['software_qty'] = cnts['sw']
        row['component_qty'] = cnts['comp']
        return jsonify({'success': True, 'item': row})
    except Exception:
        logger.exception('Failed to fetch vendor maintenance detail %s', vendor_id)
        return jsonify({'success': False, 'message': '유지보수사 조회 중 오류가 발생했습니다.'}), 500


