# ───────────────────────────────────────────────────────────
# Vendor Manufacturer – Asset Lookups (read-only)
# Queries server_hw_component / server_software tables
# joined with hardware table by manufacturer name.
# ───────────────────────────────────────────────────────────

_ASSET_CATEGORY_KR = {
    'SERVER': '서버', 'STORAGE': '스토리지', 'SAN': 'SAN',
    'NETWORK': '네트워크', 'SECURITY': '보안장비',
}
_ASSET_TYPE_KR = {
    'ON_PREMISE': '물리서버', 'CLOUD': '클라우드', 'FRAME': '프레임',
    'WORKSTATION': '가상서버', 'STORAGE': '스토리지', 'BACKUP': '백업장치',
    'DIRECTOR': 'SAN 디렉터', 'SWITCH': 'SAN 스위치',
    'L2': 'L2', 'L3': 'L3', 'L4': 'L4', 'L7': 'L7',
    'CIRCUIT': '회선장비', 'AP': '무선장비',
    'FIREWALL': '방화벽', 'VPN': 'VPN', 'IDS': 'IDS', 'IPS': 'IPS',
    'HSM': 'HSM', 'KMS': 'KMS', 'WIPS': 'WIPS', 'ETC': '기타',
}


def _vendor_asset_db_conn():
    """Return a sqlite3 connection to the main DB (shared by hardware / server_hw_component / server_software)."""
    from app.services.server_component_service import _resolve_db_path as _sc_db_path
    db_path = _sc_db_path()
    conn = sqlite3.connect(db_path)
    conn.row_factory = sqlite3.Row
    # Ensure server_software has the subtype column (lightweight migration)
    try:
        cols = {r['name'] for r in conn.execute("PRAGMA table_info(server_software)").fetchall()}
        if 'subtype' not in cols:
            conn.execute("ALTER TABLE server_software ADD COLUMN subtype TEXT")
            conn.commit()
    except Exception:
        pass
    return conn


def _enrich_sw_usage_count(rows, name_field='model_name'):
    """Enrich SW-type list rows with real usage_count from server_software."""
    if not rows:
        return
    try:
        conn = _vendor_asset_db_conn()
        try:
            counts: dict = {}
            for r in conn.execute(
                "SELECT s.name, COUNT(*) AS cnt "
                "FROM server_software s "
                "JOIN hardware h ON s.hardware_id = h.id "
                "WHERE h.is_deleted = 0 "
                "GROUP BY s.name"
            ).fetchall():
                counts[r['name']] = r['cnt']
        finally:
            conn.close()
        for r in rows:
            name = ''
            if isinstance(r, dict):
                name = (r.get(name_field) or '').strip()
                r['usage_count'] = counts.get(name, 0)
    except Exception:
        pass


def _enrich_cmp_usage_count(rows, name_field='model_name'):
    """Enrich Component-type list rows with real usage_count from server_hw_component."""
    if not rows:
        return
    try:
        conn = _vendor_asset_db_conn()
        try:
            counts: dict = {}
            for r in conn.execute(
                "SELECT c.model, COUNT(*) AS cnt "
                "FROM server_hw_component c "
                "JOIN hardware h ON c.hardware_id = h.id "
                "WHERE h.is_deleted = 0 "
                "GROUP BY c.model"
            ).fetchall():
                counts[r['model']] = r['cnt']
        finally:
            conn.close()
        for r in rows:
            name = ''
            if isinstance(r, dict):
                name = (r.get(name_field) or '').strip()
                r['usage_count'] = counts.get(name, 0)
    except Exception:
        pass


def _work_status_dot_cls(status_name: str, status_level: str) -> str:
    """Return the CSS dot class from status_level (DB), falling back to name-based mapping."""
    lvl = (status_level or '').strip()
    if lvl:
        return lvl
    s = (status_name or '').strip()
    if s == '가동':   return 'ws-run'
    if s == '유휴':   return 'ws-c3'
    if s == '폐기':   return 'ws-c1'
    if s == '보류':   return 'ws-c5'
    if s == '오픈대기': return 'ws-c8'
    return 'ws-c10'  # 대기 etc.


_WS_COLOR_MAP = {
    'ws-run': '#6366f1', 'ws-idle': '#0ea5e9', 'ws-wait': '#94a3b8',
    'ws-c1': '#ef4444', 'ws-c2': '#f97316', 'ws-c3': '#f59e0b',
    'ws-c4': '#84cc16', 'ws-c5': '#10b981', 'ws-c6': '#06b6d4',
    'ws-c7': '#3b82f6', 'ws-c8': '#a855f7', 'ws-c9': '#ec4899',
    'ws-c10': '#6b7280',
}


def _work_status_color(status_name: str, status_level: str) -> str:
    """Return hex color for work-status dot."""
    cls = _work_status_dot_cls(status_name, status_level)
    return _WS_COLOR_MAP.get(cls, '#6b7280')


@api_bp.route('/api/vendor-manufacturers/<int:vendor_id>/hw-assets', methods=['GET'])
def list_vendor_manufacturer_hw_assets(vendor_id: int):
    """하드웨어 탭: hardware WHERE manufacturer_code = 제조사 코드."""
    try:
        vendor = svc_get_vendor(vendor_id)
        if not vendor:
            return jsonify({'success': False, 'message': '제조사를 찾을 수 없습니다.'}), 404
        mfr_code = vendor.get('manufacturer_code') or ''
        if not mfr_code:
            return jsonify({'success': True, 'items': [], 'total': 0})

        conn = _vendor_asset_db_conn()
        try:
            rows = conn.execute(
                """
                SELECT
                    h.asset_category,
                    h.asset_type,
                    h.asset_name,
                    h.serial_number,
                    h.work_name,
                    h.system_name,
                    h.work_status_code,
                    COALESCE(ws.status_name, h.work_status_code, '') AS work_status_name,
                    COALESCE(ws.status_level, '') AS work_status_level,
                    COALESCE(wo.operation_name, h.work_operation_code, '') AS work_operation_name
                FROM hardware h
                LEFT JOIN biz_work_status ws
                       ON ws.status_code = h.work_status_code
                      AND ws.is_deleted = 0
                LEFT JOIN biz_work_operation wo
                       ON wo.operation_code = h.work_operation_code
                      AND wo.is_deleted = 0
                WHERE h.manufacturer_code = ?
                  AND h.is_deleted = 0
                ORDER BY h.asset_category, h.asset_type, h.asset_name
                """,
                (mfr_code,),
            ).fetchall()
        finally:
            conn.close()

        items = []
        for r in rows:
            cat_raw = (r['asset_category'] or '').strip()
            type_raw = (r['asset_type'] or '').strip()
            items.append({
                'category': _ASSET_CATEGORY_KR.get(cat_raw, cat_raw),
                'type': _ASSET_TYPE_KR.get(type_raw, type_raw),
                'model': r['asset_name'] or '',
                'spec': r['serial_number'] or '',
                'work_name': r['work_name'] or '',
                'system_name': r['system_name'] or '',
                'work_status': r['work_status_name'] or '',
                'work_status_cls': _work_status_dot_cls(r['work_status_name'], r['work_status_level']),
                'work_status_color': _work_status_color(r['work_status_name'], r['work_status_level']),
                'work_operation': r['work_operation_name'] or '',
                'qty': 1,
                'remark': '',
            })
        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to fetch vendor manufacturer hw-assets')
        return jsonify({'success': False, 'message': '제조사 하드웨어 자산 조회 중 오류가 발생했습니다.'}), 500


