# ---------------------------------------------------------------------------
# Maintenance-vendor asset lookup (read-only)
#   – Data source: 비용관리 > OPEX > cost_contract_tab61 (계약정보 line items)
#   – Flow: opex_contract(vendor_id, opex_type) → cost_contract_tab61(contract_id)
#   – 구분 = contract_type, 유형 = contract_vendor,
#     모델명 = contract_model, 일련번호 = contract_serial,
#     업무이름 = work_name, 시스템이름 = system_name,
#     관리번호 = parent opex_contract.contract_code,
#     할당수량 = contract_qty
# ---------------------------------------------------------------------------


# ── maintenance-vendor tab61 classification helpers (module-level) ──────
_MAINT_COMP_TYPES = frozenset({
    'CPU', 'GPU', 'MEMORY', 'RAM', 'MEMORY(RAM)', 'HDD', 'SSD',
    'NIC', 'HBA', 'POWER', 'FAN',
})
_MAINT_SW_TYPES = frozenset({
    '운영체제', 'OS', 'DB', '데이터베이스', '미들웨어', 'MW',
    '고가용성', 'WAS', 'WEB', '소프트웨어',
})

def _maint_classify_line(contract_type: str, parent_opex_type: str) -> str:
    """Classify a tab61 line into HW / SW / ETC based on contract_type."""
    ct = (contract_type or '').strip().upper()
    if ct in _MAINT_COMP_TYPES:
        return 'ETC'
    if ct in _MAINT_SW_TYPES:
        return 'SW'
    return (parent_opex_type or 'HW').strip().upper() or 'HW'


def _maint_vendor_tab61_counts(vendor_id: int) -> dict:
    """Return {'hw': N, 'sw': N, 'comp': N} from tab61 lines for the vendor."""
    import datetime as _dt
    counts = {'hw': 0, 'sw': 0, 'comp': 0}
    try:
        contracts = svc_list_opex_contracts()
        vendor_contracts = [c for c in contracts if c.get('vendor_id') == vendor_id]
        now_year = _dt.date.today().year
        for ct in vendor_contracts:
            contract_pk = ct.get('id') or 0
            if not contract_pk:
                continue
            ct_opex_type = (ct.get('opex_type') or 'HW').strip().upper()
            lines = svc_list_tab61_lines(
                scope='OPEX', cost_type=ct_opex_type,
                contract_id=contract_pk, year=now_year,
            )
            for ln in lines:
                cls = _maint_classify_line(ln.get('contract_type') or '', ct_opex_type)
                if cls == 'HW':
                    counts['hw'] += 1
                elif cls == 'SW':
                    counts['sw'] += 1
                else:
                    counts['comp'] += 1
    except Exception:
        logger.debug('_maint_vendor_tab61_counts(%s) failed', vendor_id, exc_info=True)
    return counts


def _maint_vendor_tab61_assets(vendor_id: int, asset_tab: str):
    """Return OPEX tab61 line items for the given maintenance vendor.

    Lines are classified by their *contract_type* (계약 유형) rather than the
    parent contract's opex_type so that e.g. a CPU line inside an HW contract
    correctly appears in the Component (ETC) tab.
    """
    import datetime as _dt

    try:
        # 1. ALL OPEX contracts for this vendor (across HW / SW / ETC)
        contracts = svc_list_opex_contracts()          # no opex_type filter
        vendor_contracts = [c for c in contracts if c.get('vendor_id') == vendor_id]

        # 2. Collect tab61 lines, classify each by contract_type
        now_year = _dt.date.today().year
        items = []
        work_names = set()
        for ct in vendor_contracts:
            contract_pk = ct.get('id') or 0
            if not contract_pk:
                continue
            manage_no = ct.get('manage_no') or ct.get('contract_code') or '-'
            ct_opex_type = (ct.get('opex_type') or 'HW').strip().upper()
            lines = svc_list_tab61_lines(
                scope='OPEX',
                cost_type=ct_opex_type,
                contract_id=contract_pk,
                year=now_year,
            )
            for ln in lines:
                line_category = ln.get('contract_type') or '-'
                if _maint_classify_line(line_category, ct_opex_type) != asset_tab:
                    continue          # belongs to a different tab

                wn = ln.get('work_name') or ''
                if wn:
                    work_names.add(wn)
                line_qty = ln.get('contract_qty')
                line_status = ln.get('contract_status') or ''
                items.append({
                    'category': line_category,
                    'type': ln.get('contract_vendor') or '-',
                    'model': ln.get('contract_model') or '-',
                    'serial': ln.get('contract_serial') or '-',
                    'work_name': wn or '-',
                    'system_name': ln.get('system_name') or '-',
                    'manage_no': manage_no,
                    'contract_status': line_status,
                    'qty': line_qty if line_qty else 1,
                })

        # 3. Resolve work_status colors from hardware table by work_name
        ws_color_map = {}
        if work_names:
            try:
                conn = _vendor_asset_db_conn()
                try:
                    placeholders = ','.join(['?'] * len(work_names))
                    rows = conn.execute(
                        f"""
                        SELECT DISTINCT h.work_name,
                               COALESCE(ws.status_name, h.work_status_code, '') AS ws_name,
                               COALESCE(ws.status_level, '') AS ws_level
                        FROM hardware h
                        LEFT JOIN biz_work_status ws
                               ON ws.status_code = h.work_status_code AND ws.is_deleted = 0
                        WHERE h.work_name IN ({placeholders})
                          AND h.is_deleted = 0
                        """,
                        tuple(work_names),
                    ).fetchall()
                    for r in rows:
                        wn = r['work_name']
                        if wn and wn not in ws_color_map:
                            ws_color_map[wn] = _work_status_color(r['ws_name'], r['ws_level'])
                finally:
                    conn.close()
            except Exception:
                logger.debug('Could not resolve work_status colors', exc_info=True)

        # 4. Attach colors
        _CONTRACT_STATUS_COLOR = {
            '진행': '#6366f1', '계약': '#6366f1',
            '해지': '#ef4444',
            '만료': '#94a3b8',
            '예정': '#f59e0b',
        }
        for it in items:
            it['work_status_color'] = ws_color_map.get(it['work_name'], '#6b7280')
            it['contract_status_color'] = _CONTRACT_STATUS_COLOR.get(
                (it.get('contract_status') or '').strip(), '#6b7280'
            )

        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to fetch maintenance vendor %s assets (type=%s)', vendor_id, opex_type)
        return jsonify({'success': False, 'message': '유지보수사 자산 조회 중 오류가 발생했습니다.'}), 500


