@api_bp.route('/api/vendor-maintenance/<int:vendor_id>/cost-stats', methods=['GET'])
def get_vendor_maintenance_cost_stats(vendor_id: int):
    """유지보수사 비용 통계: 선택 연도의 월별 유지보수 비용.

    Query params:
        year (int, optional): 대상 연도. 기본값은 올해.

    Returns {year, months: [{month, hw, sw, etc, total}, ...], available_years: [...]}.
    """
    import datetime as _dt
    try:
        now_year = _dt.date.today().year
        req_year = request.args.get('year', type=int) or now_year

        contracts = svc_list_opex_contracts()
        vendor_contracts = [c for c in contracts if c.get('vendor_id') == vendor_id]

        # --- Determine available_years (any year with data) ---
        years_scan = range(now_year - 9, now_year + 2)  # generous scan window
        avail_set = set()
        for ct in vendor_contracts:
            cpk = ct.get('id') or 0
            if not cpk:
                continue
            ct_opex = (ct.get('opex_type') or 'HW').strip().upper()
            for yr in years_scan:
                lines = svc_list_tab61_lines(
                    scope='OPEX', cost_type=ct_opex,
                    contract_id=cpk, year=yr,
                )
                if lines:
                    avail_set.add(yr)
        if not avail_set:
            avail_set.add(now_year)
        available_years = sorted(avail_set)

        # Clamp requested year to available range
        if req_year not in avail_set:
            req_year = max(available_years)

        # --- Build monthly breakdown for req_year ---
        monthly = {m: {'month': m, 'hw': 0, 'sw': 0, 'etc': 0, 'total': 0} for m in range(1, 13)}
        MONTH_KEYS = ['m{:02d}'.format(i) for i in range(1, 13)]

        for ct in vendor_contracts:
            cpk = ct.get('id') or 0
            if not cpk:
                continue
            ct_opex = (ct.get('opex_type') or 'HW').strip().upper()
            lines = svc_list_tab61_lines(
                scope='OPEX', cost_type=ct_opex,
                contract_id=cpk, year=req_year,
            )
            for ln in lines:
                cls_key = _maint_classify_line(ln.get('contract_type') or '', ct_opex)
                bucket = 'hw' if cls_key == 'HW' else ('sw' if cls_key == 'SW' else 'etc')
                for mi, mk in enumerate(MONTH_KEYS):
                    val = ln.get(mk) or 0
                    monthly[mi + 1][bucket] += val
                    monthly[mi + 1]['total'] += val

        result = [monthly[m] for m in range(1, 13)]
        return jsonify({
            'success': True,
            'year': req_year,
            'months': result,
            'available_years': available_years,
        })
    except Exception:
        logger.exception('Failed to fetch vendor maintenance cost stats %s', vendor_id)
        return jsonify({'success': False, 'message': '비용 통계 조회 중 오류가 발생했습니다.'}), 500


