def _enrich_opex_qty_from_tab61(record: dict) -> None:
    """Override tab61-sourced fields with tab61 aggregates.

    The tab61 '계약정보' lines are the single source of truth for:
    - maint_qty_total  = total rows in tab61 for the current year
    - maint_qty_active = rows whose contract_status == '계약'
    - maint_amount     = sum of tab61 line totals for the current year
    """
    if not isinstance(record, dict):
        return
    try:
        import datetime as _dt
        from ..services.cost_contract_tab61_service import list_tab61_lines as _list_tab61

        now_year = _dt.date.today().year
        contract_pk = int(record.get('id') or 0)
        ct = (record.get('opex_type') or '').strip().upper()
        if contract_pk <= 0 or not ct:
            return
        lines = _list_tab61(scope='OPEX', cost_type=ct, contract_id=contract_pk, year=now_year)
        if isinstance(lines, list):
            total_cnt = len(lines)
            active_cnt = sum(1 for it in lines if (it or {}).get('contract_status') == '계약')
            record['total_license_count'] = total_cnt
            record['active_license_count'] = active_cnt
            record['maint_qty_total'] = total_cnt
            record['maint_qty_active'] = active_cnt
            try:
                tab61_sum = sum(int((it or {}).get('sum') or 0) for it in lines)
            except Exception:
                tab61_sum = None
            if tab61_sum is not None:
                record['maintenance_amount'] = tab61_sum
                record['maint_amount'] = tab61_sum
    except Exception:
        pass


@api_bp.route('/api/opex-contracts', methods=['GET'])
def list_opex_contracts():
    opex_type = (request.args.get('opex_type') or request.args.get('type') or '').strip() or None
    search = (request.args.get('q') or request.args.get('search') or '').strip() or None
    include_deleted = (request.args.get('include_deleted') or request.args.get('includeDeleted') or '').lower() in ('1', 'true', 'yes')
    try:
        from ..utils.page_tokens import encode_manage_no
    except Exception:
        encode_manage_no = None

    try:
        rows = svc_list_opex_contracts(opex_type=opex_type, search=search, include_deleted=include_deleted)

        # Align maint_qty_total / maint_qty_active with the tab61 aggregates
        # (same source of truth used by the detail page).
        for r in rows or []:
            _enrich_opex_qty_from_tab61(r)

        # Add an opaque, signed token so clients can navigate without exposing manage_no in URL.
        if encode_manage_no:
            for r in rows or []:
                try:
                    if not isinstance(r, dict):
                        continue
                    mn = (r.get('manage_no') or '').strip()
                    if not mn:
                        continue
                    r['page_token'] = encode_manage_no(mn)
                except Exception:
                    continue

        return jsonify({'success': True, 'items': rows, 'total': len(rows)})
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to fetch opex contracts')
        return jsonify({'success': False, 'message': 'OPEX 계약 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/cost/detail-context', methods=['POST'])
def set_cost_detail_context():
    """Set the currently selected cost detail manage_no into session.

    Canonical cost detail pages do not include any identifier in the URL.
    Clients should call this endpoint before navigating to /p/<key>.
    """
    auth = _require_login_for_write()
    if auth:
        return auth

    payload = request.get_json(silent=True) or {}
    raw_key = (payload.get('key') or '').strip()
    raw_token = (payload.get('token') or payload.get('page_token') or payload.get('pageToken') or '').strip()
    raw_manage_no = (payload.get('manage_no') or payload.get('manageNo') or payload.get('id') or '').strip()

    # Only allow cost detail keys.
    COST_DETAIL_KEYS = {
        'cost_opex_hardware_detail',
        'cost_opex_hardware_contract',
        'cost_opex_hardware_log',
        'cost_opex_hardware_file',
        'cost_opex_software_detail',
        'cost_opex_software_contract',
        'cost_opex_software_log',
        'cost_opex_software_file',
        'cost_opex_etc_detail',
        'cost_opex_etc_contract',
        'cost_opex_etc_log',
        'cost_opex_etc_file',
        'cost_capex_hardware_detail',
        'cost_capex_hardware_contract',
        'cost_capex_hardware_log',
        'cost_capex_hardware_file',
        'cost_capex_software_detail',
        'cost_capex_software_contract',
        'cost_capex_software_log',
        'cost_capex_software_file',
        'cost_capex_etc_detail',
        'cost_capex_etc_contract',
        'cost_capex_etc_log',
        'cost_capex_etc_file',
    }
    if not raw_key or raw_key not in COST_DETAIL_KEYS:
        return jsonify({'success': False, 'message': '유효하지 않은 페이지 키입니다.'}), 400

    def _cost_base_key(k: str) -> str:
        base = k
        for suf in ('_detail', '_system', '_contract', '_log', '_file'):
            if base.endswith(suf):
                base = base[: -len(suf)]
                break
        return base

    base_key = _cost_base_key(raw_key)

    manage_no = raw_manage_no
    if not manage_no and raw_token:
        try:
            from ..utils.page_tokens import decode_manage_no
        except Exception:
            decode_manage_no = None
        if not decode_manage_no:
            return jsonify({'success': False, 'message': '토큰 처리를 사용할 수 없습니다.'}), 500
        try:
            manage_no = (decode_manage_no(raw_token) or '').strip()
        except Exception:
            manage_no = ''

    if not manage_no:
        return jsonify({'success': False, 'message': '관리번호가 필요합니다.'}), 400

    ctx = session.get('cost_detail_ctx_v1')
    if not isinstance(ctx, dict):
        ctx = {}
    ctx[base_key] = manage_no
    session['cost_detail_ctx_v1'] = ctx
    session.modified = True

    return jsonify({'success': True, 'base_key': base_key, 'manage_no': manage_no})


