    if not raw_key or not raw_key.startswith('cat_'):
        return jsonify({'success': False, 'message': '유효하지 않은 페이지 키입니다.'}), 400

    base_key = _cat_base_key(raw_key)

    # Accept a generic 'id' or typed IDs (os_id, db_id, …)
