@api_bp.route('/api/capex-dashboard', methods=['GET'])
def capex_dashboard():
    """CAPEX Executive Dashboard: KPI + 트렌드 + 분석 + 계약 테이블."""
    try:
        from app.services.capex_contract_service import _resolve_db_path as _capex_db_path
        import sqlite3 as _sq
        db_path = _capex_db_path()
        conn = _sq.connect(db_path)
        conn.row_factory = _sq.Row

        current_year = int(__import__('datetime').datetime.utcnow().strftime('%Y'))
        years = list(range(current_year - 4, current_year + 1))
        year_strs = [str(y) for y in years]
        cur_yr = str(current_year)
        prev_yr = str(current_year - 1)

        # ── optional year + quarter filter ──
        filter_year = request.args.get('year', '').strip()
        filter_quarter = request.args.get('quarter', '').strip().upper()
        _Q_MONTHS = {'Q1': ('01', '03'), 'Q2': ('04', '06'), 'Q3': ('07', '09'), 'Q4': ('10', '12')}
        valid_quarter = filter_quarter if (filter_quarter in _Q_MONTHS and filter_year and filter_year in year_strs) else ''

        # ── helpers: aggregate in date range ──
        def _q_amount(qs, qe):
            row = conn.execute("""
                SELECT IFNULL(SUM(tab.total_price), 0) AS amt
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND cc.contract_date >= ? AND cc.contract_date <= ?
            """, (qs, qe)).fetchone()
            return int(row['amt']) if row else 0

        def _q_count(qs, qe):
            row = conn.execute("""
                SELECT COUNT(DISTINCT cc.id) AS cnt
                FROM capex_contract cc
                LEFT JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND cc.contract_date >= ? AND cc.contract_date <= ?
            """, (qs, qe)).fetchone()
            return int(row['cnt']) if row else 0

        # ── KPI (yearly totals for 5 years) ──
        kpi_rows = conn.execute("""
            SELECT SUBSTR(cc.contract_date, 1, 4) AS yr,
                   IFNULL(SUM(tab.total_price), 0) AS total_amount,
                   COUNT(DISTINCT cc.id) AS cnt
            FROM capex_contract cc
            LEFT JOIN cost_capex_contract_tab62 tab
                ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
            WHERE cc.is_deleted = 0
              AND SUBSTR(cc.contract_date, 1, 4) IN ({})
            GROUP BY yr
        """.format(','.join('?' * len(year_strs))), year_strs).fetchall()

        amount_map = {str(r['yr']): int(r['total_amount']) for r in kpi_rows}
        count_map = {str(r['yr']): int(r['cnt']) for r in kpi_rows}
        total_capex = sum(amount_map.values())

        if valid_quarter:
            # ── Quarter-specific KPI ──
            q_sm, q_em = _Q_MONTHS[valid_quarter]
            q_ds = f"{filter_year}-{q_sm}-01"
            q_de = f"{filter_year}-{q_em}-31"
            this_q_amt = _q_amount(q_ds, q_de)
            this_q_cnt = _q_count(q_ds, q_de)
            kpi_prev_yr = str(int(filter_year) - 1)
            prev_same_q_amt = _q_amount(f"{kpi_prev_yr}-{q_sm}-01", f"{kpi_prev_yr}-{q_em}-31")
            yoy_pct = round(((this_q_amt - prev_same_q_amt) / prev_same_q_amt) * 100, 1) if prev_same_q_amt else None
            q_num = int(valid_quarter[1])
            if q_num == 1:
                pq_yr = str(int(filter_year) - 1)
                pq_sm, pq_em = _Q_MONTHS['Q4']
            else:
                pq_yr = filter_year
                pq_sm, pq_em = _Q_MONTHS[f'Q{q_num - 1}']
            prev_q_amt = _q_amount(f"{pq_yr}-{pq_sm}-01", f"{pq_yr}-{pq_em}-31")
            qoq_pct = round(((this_q_amt - prev_q_amt) / prev_q_amt) * 100, 1) if prev_q_amt else None
            kpi = {
                'total_capex': total_capex,
                'contract_count': sum(count_map.values()),
                'kpi_year': filter_year,
                'kpi_prev_year': kpi_prev_yr,
                'this_year': this_q_amt,
                'prev_year': prev_same_q_amt,
                'yoy_pct': yoy_pct,
                'cur_q_amount': this_q_amt,
                'prev_q_amount': prev_q_amt,
                'qoq_pct': qoq_pct,
                'qoq_quarter': valid_quarter,
                'this_year_count': this_q_cnt,
            }
        else:
            # ── Year or 전체 KPI ──
            kpi_yr = filter_year if (filter_year and filter_year in year_strs) else cur_yr
            kpi_prev_yr = str(int(kpi_yr) - 1)
            this_year_amount = amount_map.get(kpi_yr, 0)
            prev_year_amount = amount_map.get(kpi_prev_yr, 0)
            yoy_pct = round(((this_year_amount - prev_year_amount) / prev_year_amount) * 100, 1) if prev_year_amount else None
            import datetime as _dt
            _now = _dt.datetime.utcnow()
            kpi_year_int = int(filter_year) if (filter_year and filter_year in year_strs) else _now.year
            cur_q = (_now.month - 1) // 3 + 1
            cur_q_start = f"{kpi_year_int}-{(cur_q - 1) * 3 + 1:02d}-01"
            cur_q_end = f"{kpi_year_int}-{cur_q * 3:02d}-31" if cur_q <= 3 else f"{kpi_year_int}-12-31"
            if cur_q == 1:
                prev_q_start = f"{kpi_year_int - 1}-10-01"
                prev_q_end = f"{kpi_year_int - 1}-12-31"
            else:
                prev_q_start = f"{kpi_year_int}-{(cur_q - 2) * 3 + 1:02d}-01"
                prev_q_end = f"{kpi_year_int}-{(cur_q - 1) * 3:02d}-31"
            cur_q_amt = _q_amount(cur_q_start, cur_q_end)
            prev_q_amt = _q_amount(prev_q_start, prev_q_end)
            qoq_pct = round(((cur_q_amt - prev_q_amt) / prev_q_amt) * 100, 1) if prev_q_amt else None
            kpi = {
                'total_capex': total_capex,
                'kpi_year': kpi_yr,
                'kpi_prev_year': kpi_prev_yr,
                'this_year': this_year_amount,
                'prev_year': prev_year_amount,
                'yoy_pct': yoy_pct,
                'cur_q_amount': cur_q_amt,
                'prev_q_amount': prev_q_amt,
                'qoq_pct': qoq_pct,
                'qoq_quarter': f"Q{cur_q}",
                'contract_count': sum(count_map.values()),
                'this_year_count': count_map.get(kpi_yr, 0),
            }

        # ── 연도별 트렌드 (품목별 stacked) ──
        rows_item = conn.execute("""
            SELECT SUBSTR(cc.contract_date, 1, 4) AS yr,
                   tab.item_type AS name,
                   SUM(IFNULL(tab.total_price, 0)) AS sum_amount
            FROM capex_contract cc
            JOIN cost_capex_contract_tab62 tab
                ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
            WHERE cc.is_deleted = 0
              AND IFNULL(tab.item_type, '') != ''
              AND SUBSTR(cc.contract_date, 1, 4) IN ({})
            GROUP BY yr, tab.item_type
            ORDER BY yr, sum_amount DESC
        """.format(','.join('?' * len(year_strs))), year_strs).fetchall()
        item_data = [{'year': str(r['yr']), 'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows_item]

        # ── chart date filter ──
        if valid_quarter:
            _csm, _cem = _Q_MONTHS[valid_quarter]
            chart_date_start = f"{filter_year}-{_csm}-01"
            chart_date_end = f"{filter_year}-{_cem}-31"
            chart_year_strs = [filter_year]
        elif filter_year and filter_year in year_strs:
            chart_date_start = None
            chart_date_end = None
            chart_year_strs = [filter_year]
        else:
            chart_date_start = None
            chart_date_end = None
            chart_year_strs = year_strs
        _use_date_range = chart_date_start is not None

        # ── 공급업체 ──
        if _use_date_range:
            rows_supplier = conn.execute("""
                SELECT tab.supplier AS name,
                       SUM(IFNULL(tab.total_price, 0)) AS sum_amount
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND IFNULL(tab.supplier, '') != ''
                  AND cc.contract_date >= ? AND cc.contract_date <= ?
                GROUP BY tab.supplier ORDER BY sum_amount DESC
            """, (chart_date_start, chart_date_end)).fetchall()
        else:
            rows_supplier = conn.execute("""
                SELECT tab.supplier AS name,
                       SUM(IFNULL(tab.total_price, 0)) AS sum_amount
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND IFNULL(tab.supplier, '') != ''
                  AND SUBSTR(cc.contract_date, 1, 4) IN ({})
                GROUP BY tab.supplier ORDER BY sum_amount DESC
            """.format(','.join('?' * len(chart_year_strs))), chart_year_strs).fetchall()
        supplier_data = [{'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows_supplier]

        # ── 제조업체 ──
        if _use_date_range:
            rows_mfr = conn.execute("""
                SELECT tab.manufacturer AS name,
                       SUM(IFNULL(tab.total_price, 0)) AS sum_amount
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND IFNULL(tab.manufacturer, '') != ''
                  AND cc.contract_date >= ? AND cc.contract_date <= ?
                GROUP BY tab.manufacturer ORDER BY sum_amount DESC
            """, (chart_date_start, chart_date_end)).fetchall()
        else:
            rows_mfr = conn.execute("""
                SELECT tab.manufacturer AS name,
                       SUM(IFNULL(tab.total_price, 0)) AS sum_amount
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND IFNULL(tab.manufacturer, '') != ''
                  AND SUBSTR(cc.contract_date, 1, 4) IN ({})
                GROUP BY tab.manufacturer ORDER BY sum_amount DESC
            """.format(','.join('?' * len(chart_year_strs))), chart_year_strs).fetchall()
        mfr_data = [{'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows_mfr]

        # ── 계약 구분 ──
        if valid_quarter:
            # Monthly breakdown within quarter (3 months)
            rows_div = conn.execute("""
                SELECT SUBSTR(cc.contract_date, 6, 2) AS month,
                       IFNULL(tab.contract_division, '미분류') AS name,
                       SUM(IFNULL(tab.total_price, 0)) AS sum_amount
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND cc.contract_date >= ? AND cc.contract_date <= ?
                GROUP BY month, name ORDER BY month, sum_amount DESC
            """, (chart_date_start, chart_date_end)).fetchall()
            division_data = [{'month': r['month'], 'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows_div]
        elif filter_year and filter_year in year_strs:
            # Monthly breakdown for selected year (12 months)
            rows_div = conn.execute("""
                SELECT SUBSTR(cc.contract_date, 6, 2) AS month,
                       IFNULL(tab.contract_division, '미분류') AS name,
                       SUM(IFNULL(tab.total_price, 0)) AS sum_amount
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND SUBSTR(cc.contract_date, 1, 4) = ?
                GROUP BY month, name ORDER BY month, sum_amount DESC
            """, (filter_year,)).fetchall()
            division_data = [{'month': r['month'], 'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows_div]
        else:
            # Yearly breakdown (default)
            rows_div = conn.execute("""
                SELECT SUBSTR(cc.contract_date, 1, 4) AS year,
                       IFNULL(tab.contract_division, '미분류') AS name,
                       SUM(IFNULL(tab.total_price, 0)) AS sum_amount
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND SUBSTR(cc.contract_date, 1, 4) IN ({})
                GROUP BY year, name ORDER BY year, sum_amount DESC
            """.format(','.join('?' * len(year_strs))), year_strs).fetchall()
            division_data = [{'year': r['year'], 'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows_div]

        # ── 계약 유형 ──
        if _use_date_range:
            rows_ctype = conn.execute("""
                SELECT IFNULL(tab.contract_type, '미분류') AS name,
                       SUM(IFNULL(tab.total_price, 0)) AS sum_amount
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND cc.contract_date >= ? AND cc.contract_date <= ?
                GROUP BY name ORDER BY sum_amount DESC
            """, (chart_date_start, chart_date_end)).fetchall()
        else:
            rows_ctype = conn.execute("""
                SELECT IFNULL(tab.contract_type, '미분류') AS name,
                       SUM(IFNULL(tab.total_price, 0)) AS sum_amount
                FROM capex_contract cc
                JOIN cost_capex_contract_tab62 tab
                    ON tab.capex_type = cc.capex_type AND tab.manage_no = cc.contract_code AND tab.is_deleted = 0
                WHERE cc.is_deleted = 0
                  AND SUBSTR(cc.contract_date, 1, 4) IN ({})
                GROUP BY name ORDER BY sum_amount DESC
            """.format(','.join('?' * len(chart_year_strs))), chart_year_strs).fetchall()
        contract_type_data = [{'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows_ctype]

        conn.close()
        return jsonify({
            'success': True,
            'current_year': cur_yr,
            'years': year_strs,
            'filter_year': filter_year if filter_year in year_strs else '',
            'filter_quarter': valid_quarter,
            'kpi': kpi,
            'item_data': item_data,
            'supplier_data': supplier_data,
            'manufacturer_data': mfr_data,
            'division_data': division_data,
            'contract_type_data': contract_type_data,
        })
    except Exception:
        logger.exception('Failed to build CAPEX dashboard')
        return jsonify({'success': False, 'message': 'CAPEX 대시보드 데이터를 불러오지 못했습니다.'}), 500


# ═══════════════════════════════════════════════════════════
#  OPEX Executive Dashboard
# ═══════════════════════════════════════════════════════════
@api_bp.route('/api/opex-dashboard', methods=['GET'])
def opex_dashboard():
    """OPEX Executive Dashboard: KPI + 트렌드 + 분석 (cost_contract_tab61 기반)."""
    try:
        from app.services.opex_contract_service import _resolve_db_path as _opex_db_path
        import sqlite3 as _sq
        db_path = _opex_db_path()
        conn = _sq.connect(db_path)
        conn.row_factory = _sq.Row

        _OPEX_TYPE_MAP = {'HW': '하드웨어', 'SW': '소프트웨어', 'ETC': '기타'}
        _TAB = 'cost_contract_tab61'
        _SCOPE = 'OPEX'
        # sum of all 12 month columns
        _M_SUM = '+'.join(f'IFNULL(m{i:02d},0)' for i in range(1, 13))
        _Q_MCOLS = {
            'Q1': [f'm{i:02d}' for i in range(1, 4)],
            'Q2': [f'm{i:02d}' for i in range(4, 7)],
            'Q3': [f'm{i:02d}' for i in range(7, 10)],
            'Q4': [f'm{i:02d}' for i in range(10, 13)],
        }

        current_year = int(__import__('datetime').datetime.utcnow().strftime('%Y'))
        years = list(range(current_year - 4, current_year + 1))
        year_strs = [str(y) for y in years]
        cur_yr = str(current_year)

        # ── optional year + quarter filter ──
        filter_year = request.args.get('year', '').strip()
        filter_quarter = request.args.get('quarter', '').strip().upper()
        _Q_MONTHS = {'Q1': ('01', '03'), 'Q2': ('04', '06'), 'Q3': ('07', '09'), 'Q4': ('10', '12')}
        valid_quarter = filter_quarter if (filter_quarter in _Q_MONTHS and filter_year and filter_year in year_strs) else ''

        # ── helpers: aggregate by year / quarter from tab61 ──
        def _q_sum_expr(q):
            return '+'.join(f'IFNULL({c},0)' for c in _Q_MCOLS[q])

        def _q_amount(yr, q):
            expr = _q_sum_expr(q)
            row = conn.execute(f"""
                SELECT IFNULL(SUM({expr}), 0) AS amt
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ? AND year = ?
            """, (_SCOPE, int(yr))).fetchone()
            return int(row['amt']) if row else 0

        def _q_count(yr, q):
            expr = _q_sum_expr(q)
            row = conn.execute(f"""
                SELECT COUNT(DISTINCT contract_id) AS cnt
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ? AND year = ?
                  AND ({expr}) > 0
            """, (_SCOPE, int(yr))).fetchone()
            return int(row['cnt']) if row else 0

        # ── KPI (yearly totals for 5 years from tab61) ──
        kpi_rows = conn.execute(f"""
            SELECT year AS yr,
                   IFNULL(SUM({_M_SUM}), 0) AS total_amount,
                   COUNT(DISTINCT contract_id) AS cnt
            FROM {_TAB}
            WHERE is_deleted = 0 AND scope = ?
              AND year IN ({','.join('?' * len(year_strs))})
            GROUP BY year
        """, [_SCOPE] + [int(y) for y in year_strs]).fetchall()

        amount_map = {str(r['yr']): int(r['total_amount']) for r in kpi_rows}
        count_map = {str(r['yr']): int(r['cnt']) for r in kpi_rows}
        total_opex = sum(amount_map.values())
        total_count = sum(count_map.values())

        if valid_quarter:
            this_q_amt = _q_amount(filter_year, valid_quarter)
            this_q_cnt = _q_count(filter_year, valid_quarter)
            kpi_prev_yr = str(int(filter_year) - 1)
            prev_same_q_amt = _q_amount(kpi_prev_yr, valid_quarter)
            yoy_pct = round(((this_q_amt - prev_same_q_amt) / prev_same_q_amt) * 100, 1) if prev_same_q_amt else None
            q_num = int(valid_quarter[1])
            if q_num == 1:
                pq_yr = str(int(filter_year) - 1)
                prev_q_key = 'Q4'
            else:
                pq_yr = filter_year
                prev_q_key = f'Q{q_num - 1}'
            prev_q_amt = _q_amount(pq_yr, prev_q_key)
            qoq_pct = round(((this_q_amt - prev_q_amt) / prev_q_amt) * 100, 1) if prev_q_amt else None
            kpi = {
                'total_opex': total_opex,
                'contract_count': total_count,
                'kpi_year': filter_year,
                'kpi_prev_year': kpi_prev_yr,
                'this_year': this_q_amt,
                'prev_year': prev_same_q_amt,
                'yoy_pct': yoy_pct,
                'cur_q_amount': this_q_amt,
                'prev_q_amount': prev_q_amt,
                'qoq_pct': qoq_pct,
                'qoq_quarter': valid_quarter,
                'this_year_count': this_q_cnt,
            }
        else:
            kpi_yr = filter_year if (filter_year and filter_year in year_strs) else cur_yr
            kpi_prev_yr = str(int(kpi_yr) - 1)
            this_year_amount = amount_map.get(kpi_yr, 0)
            prev_year_amount = amount_map.get(kpi_prev_yr, 0)
            yoy_pct = round(((this_year_amount - prev_year_amount) / prev_year_amount) * 100, 1) if prev_year_amount else None
            import datetime as _dt
            _now = _dt.datetime.utcnow()
            kpi_year_int = int(filter_year) if (filter_year and filter_year in year_strs) else _now.year
            cur_q = (_now.month - 1) // 3 + 1
            cur_q_key = f'Q{cur_q}'
            cur_q_amt = _q_amount(str(kpi_year_int), cur_q_key)
            if cur_q == 1:
                prev_q_yr = str(kpi_year_int - 1)
                prev_q_key = 'Q4'
            else:
                prev_q_yr = str(kpi_year_int)
                prev_q_key = f'Q{cur_q - 1}'
            prev_q_amt = _q_amount(prev_q_yr, prev_q_key)
            qoq_pct = round(((cur_q_amt - prev_q_amt) / prev_q_amt) * 100, 1) if prev_q_amt else None
            kpi = {
                'total_opex': total_opex,
                'kpi_year': kpi_yr,
                'kpi_prev_year': kpi_prev_yr,
                'this_year': this_year_amount,
                'prev_year': prev_year_amount,
                'yoy_pct': yoy_pct,
                'cur_q_amount': cur_q_amt,
                'prev_q_amount': prev_q_amt,
                'qoq_pct': qoq_pct,
                'qoq_quarter': f"Q{cur_q}",
                'contract_count': total_count,
                'this_year_count': count_map.get(kpi_yr, 0),
            }

        # ── chart filter setup ──
        if valid_quarter:
            chart_year_strs = [filter_year]
        elif filter_year and filter_year in year_strs:
            chart_year_strs = [filter_year]
        else:
            chart_year_strs = year_strs

        # ── 유지보수업체 (vendor from tab61.contract_vendor) ──
        if valid_quarter:
            q_expr = _q_sum_expr(valid_quarter)
            rows_vendor = conn.execute(f"""
                SELECT IFNULL(contract_vendor, '미지정') AS name,
                       SUM({q_expr}) AS sum_amount
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ? AND year = ?
                GROUP BY contract_vendor
                HAVING sum_amount > 0
                ORDER BY sum_amount DESC
            """, (_SCOPE, int(filter_year))).fetchall()
        elif len(chart_year_strs) == 1:
            rows_vendor = conn.execute(f"""
                SELECT IFNULL(contract_vendor, '미지정') AS name,
                       SUM({_M_SUM}) AS sum_amount
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ? AND year = ?
                GROUP BY contract_vendor
                HAVING sum_amount > 0
                ORDER BY sum_amount DESC
            """, (_SCOPE, int(chart_year_strs[0]))).fetchall()
        else:
            rows_vendor = conn.execute(f"""
                SELECT IFNULL(contract_vendor, '미지정') AS name,
                       SUM({_M_SUM}) AS sum_amount
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ?
                  AND year IN ({','.join('?' * len(chart_year_strs))})
                GROUP BY contract_vendor
                HAVING sum_amount > 0
                ORDER BY sum_amount DESC
            """, [_SCOPE] + [int(y) for y in chart_year_strs]).fetchall()
        vendor_data = [{'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows_vendor]

        # ── 계약 구분 (cost_type → 하드웨어/소프트웨어/기타, monthly from m01~m12) ──
        if valid_quarter:
            q_months = _Q_MCOLS[valid_quarter]
            division_data = []
            for ct_row in conn.execute(f"""
                SELECT cost_type, {', '.join(f'SUM(IFNULL({c},0)) AS {c}' for c in q_months)}
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ? AND year = ?
                GROUP BY cost_type
            """, (_SCOPE, int(filter_year))).fetchall():
                ct = ct_row['cost_type']
                name = _OPEX_TYPE_MAP.get(ct, ct)
                for mc in q_months:
                    m_num = mc[1:]  # 'm01' -> '01'
                    val = int(ct_row[mc])
                    if val:
                        division_data.append({'month': m_num, 'name': name, 'amount': val})
        elif len(chart_year_strs) == 1:
            all_mcols = [f'm{i:02d}' for i in range(1, 13)]
            division_data = []
            for ct_row in conn.execute(f"""
                SELECT cost_type, {', '.join(f'SUM(IFNULL({c},0)) AS {c}' for c in all_mcols)}
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ? AND year = ?
                GROUP BY cost_type
            """, (_SCOPE, int(chart_year_strs[0]))).fetchall():
                ct = ct_row['cost_type']
                name = _OPEX_TYPE_MAP.get(ct, ct)
                for mc in all_mcols:
                    m_num = mc[1:]
                    val = int(ct_row[mc])
                    if val:
                        division_data.append({'month': m_num, 'name': name, 'amount': val})
        else:
            division_data = []
            for ct_row in conn.execute(f"""
                SELECT year, cost_type, SUM({_M_SUM}) AS sum_amount
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ?
                  AND year IN ({','.join('?' * len(chart_year_strs))})
                GROUP BY year, cost_type
                HAVING sum_amount > 0
                ORDER BY year, sum_amount DESC
            """, [_SCOPE] + [int(y) for y in chart_year_strs]).fetchall():
                division_data.append({
                    'year': str(ct_row['year']),
                    'name': _OPEX_TYPE_MAP.get(ct_row['cost_type'], ct_row['cost_type']),
                    'amount': int(ct_row['sum_amount']),
                })

        # ── 계약 상태 (contract_status from tab61) ──
        if valid_quarter:
            q_expr = _q_sum_expr(valid_quarter)
            rows_status = conn.execute(f"""
                SELECT IFNULL(contract_status, '미지정') AS name,
                       SUM({q_expr}) AS sum_amount
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ? AND year = ?
                GROUP BY contract_status
                HAVING sum_amount > 0
                ORDER BY sum_amount DESC
            """, (_SCOPE, int(filter_year))).fetchall()
        elif len(chart_year_strs) == 1:
            rows_status = conn.execute(f"""
                SELECT IFNULL(contract_status, '미지정') AS name,
                       SUM({_M_SUM}) AS sum_amount
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ? AND year = ?
                GROUP BY contract_status
                HAVING sum_amount > 0
                ORDER BY sum_amount DESC
            """, (_SCOPE, int(chart_year_strs[0]))).fetchall()
        else:
            rows_status = conn.execute(f"""
                SELECT IFNULL(contract_status, '미지정') AS name,
                       SUM({_M_SUM}) AS sum_amount
                FROM {_TAB}
                WHERE is_deleted = 0 AND scope = ?
                  AND year IN ({','.join('?' * len(chart_year_strs))})
                GROUP BY contract_status
                HAVING sum_amount > 0
                ORDER BY sum_amount DESC
            """, [_SCOPE] + [int(y) for y in chart_year_strs]).fetchall()
        status_data = [{'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows_status]

        # ── 소프트웨어 / 기타 상세 (contract_type 별) ──
        def _type_detail(cost_type_code):
            if valid_quarter:
                q_expr = _q_sum_expr(valid_quarter)
                rows = conn.execute(f"""
                    SELECT IFNULL(contract_type, '미지정') AS name,
                           SUM({q_expr}) AS sum_amount
                    FROM {_TAB}
                    WHERE is_deleted = 0 AND scope = ? AND cost_type = ? AND year = ?
                    GROUP BY contract_type
                    HAVING sum_amount > 0
                    ORDER BY sum_amount DESC
                """, (_SCOPE, cost_type_code, int(filter_year))).fetchall()
            elif len(chart_year_strs) == 1:
                rows = conn.execute(f"""
                    SELECT IFNULL(contract_type, '미지정') AS name,
                           SUM({_M_SUM}) AS sum_amount
                    FROM {_TAB}
                    WHERE is_deleted = 0 AND scope = ? AND cost_type = ? AND year = ?
                    GROUP BY contract_type
                    HAVING sum_amount > 0
                    ORDER BY sum_amount DESC
                """, (_SCOPE, cost_type_code, int(chart_year_strs[0]))).fetchall()
            else:
                rows = conn.execute(f"""
                    SELECT IFNULL(contract_type, '미지정') AS name,
                           SUM({_M_SUM}) AS sum_amount
                    FROM {_TAB}
                    WHERE is_deleted = 0 AND scope = ? AND cost_type = ?
                      AND year IN ({','.join('?' * len(chart_year_strs))})
                    GROUP BY contract_type
                    HAVING sum_amount > 0
                    ORDER BY sum_amount DESC
                """, [_SCOPE, cost_type_code] + [int(y) for y in chart_year_strs]).fetchall()
            return [{'name': r['name'], 'amount': int(r['sum_amount'])} for r in rows]

        # ── 하드웨어 상세: "시스템"→asset_category JOIN, 나머지→"부품" ──
        _HW_CAT_MAP = {
            'SERVER': '서버', 'STORAGE': '스토리지', 'SAN': 'SAN',
            'NETWORK': '네트워크', 'SECURITY': '보안장비',
        }
        def _hw_detail():
            # amount expression
            if valid_quarter:
                amt_expr = _q_sum_expr(valid_quarter)
                year_filter = 'AND t.year = ?'
                year_params = [int(filter_year)]
            elif len(chart_year_strs) == 1:
                amt_expr = _M_SUM.replace('m', 't.m').replace('IFNULL(t.', 'IFNULL(t.')
                # rebuild with t. prefix
                amt_expr = '+'.join(f'IFNULL(t.m{i:02d},0)' for i in range(1, 13))
                year_filter = 'AND t.year = ?'
                year_params = [int(chart_year_strs[0])]
            else:
                amt_expr = '+'.join(f'IFNULL(t.m{i:02d},0)' for i in range(1, 13))
                year_filter = f"AND t.year IN ({','.join('?' * len(chart_year_strs))})"
                year_params = [int(y) for y in chart_year_strs]

            if valid_quarter:
                # rebuild with t. prefix for quarter
                amt_expr = '+'.join(f'IFNULL(t.{c},0)' for c in _Q_MCOLS[valid_quarter])

            # 시스템 rows: JOIN hardware to get asset_category
            rows_sys = conn.execute(f"""
                SELECT IFNULL(h.asset_category, '미지정') AS cat,
                       SUM({amt_expr}) AS sum_amount
                FROM {_TAB} t
                LEFT JOIN hardware h
                    ON h.serial_number = t.contract_serial AND h.is_deleted = 0
                WHERE t.is_deleted = 0 AND t.scope = ? AND t.cost_type = 'HW'
                  AND t.contract_type = '시스템'
                  {year_filter}
                GROUP BY cat
                HAVING sum_amount > 0
                ORDER BY sum_amount DESC
            """, [_SCOPE] + year_params).fetchall()

            # 비시스템(부품) rows: 모든 non-시스템 contract_type 합산
            rows_parts = conn.execute(f"""
                SELECT SUM({amt_expr}) AS sum_amount
                FROM {_TAB} t
                WHERE t.is_deleted = 0 AND t.scope = ? AND t.cost_type = 'HW'
                  AND (t.contract_type != '시스템' OR t.contract_type IS NULL)
                  {year_filter}
            """, [_SCOPE] + year_params).fetchone()

            result = []
            for r in rows_sys:
                cat = r['cat']
                name = _HW_CAT_MAP.get(cat, cat)
                result.append({'name': name, 'amount': int(r['sum_amount'])})
            parts_amt = int(rows_parts['sum_amount']) if rows_parts and rows_parts['sum_amount'] else 0
            if parts_amt > 0:
                result.append({'name': '부품', 'amount': parts_amt})
            return result

        hw_detail = _hw_detail()
        sw_detail = _type_detail('SW')
        etc_detail = _type_detail('ETC')

        # ── 계약 목록 (신규 / 변경 / 만료) ──
        _OC = 'opex_contract'
        _BVM = 'biz_vendor_maintenance'

        def _contract_list(where_clause, params):
            rows = conn.execute(f"""
                SELECT oc.contract_name, oc.contract_code,
                       v.maintenance_name AS vendor_name,
                       oc.total_license_count AS qty,
                       oc.maintenance_amount AS amount
                FROM {_TAB} t
                JOIN {_OC} oc ON oc.id = t.contract_id
                LEFT JOIN {_BVM} v ON v.id = oc.vendor_id
                WHERE t.is_deleted = 0 AND t.scope = ?
                  AND t.year IN ({','.join('?' * len(chart_year_strs))})
                  AND {where_clause}
                GROUP BY t.contract_id
                ORDER BY oc.updated_at DESC
                LIMIT 20
            """, [_SCOPE] + [int(y) for y in chart_year_strs] + params).fetchall()
            return [{
                'name': r['contract_name'] or '',
                'code': r['contract_code'] or '',
                'vendor': r['vendor_name'] or '',
                'qty': r['qty'] if r['qty'] is not None else '-',
                'amount': r['amount'] or 0,
            } for r in rows]

        new_contracts = _contract_list(
            "oc.contract_status = '진행' AND (oc.updated_at IS NULL OR oc.updated_at = oc.created_at OR SUBSTR(oc.updated_at,1,16) = SUBSTR(oc.created_at,1,16))", [])
        changed_contracts = _contract_list(
            "oc.contract_status = '진행' AND oc.updated_at IS NOT NULL AND SUBSTR(oc.updated_at,1,16) != SUBSTR(oc.created_at,1,16)", [])
        expired_contracts = _contract_list(
            "oc.contract_status IN ('만료','해지')", [])

        conn.close()
        return jsonify({
            'success': True,
            'current_year': cur_yr,
            'years': year_strs,
            'filter_year': filter_year if filter_year in year_strs else '',
            'filter_quarter': valid_quarter,
            'kpi': kpi,
            'division_data': division_data,
            'status_data': status_data,
            'hw_detail': hw_detail,
            'sw_detail': sw_detail,
            'etc_detail': etc_detail,
            'vendor_data': vendor_data,
            'new_contracts': new_contracts,
            'changed_contracts': changed_contracts,
            'expired_contracts': expired_contracts,
        })
    except Exception:
        logger.exception('Failed to build OPEX dashboard')
        return jsonify({'success': False, 'message': 'OPEX 대시보드 데이터를 불러오지 못했습니다.'}), 500


