@api_bp.route('/api/network/ip-policies/<int:policy_id>/addresses', methods=['PUT'])
def save_network_ip_policy_addresses(policy_id: int):
    auth = _require_login_for_write()
    if auth:
        return auth
    payload = request.get_json(silent=True) or {}
    items = payload.get('items') or []
    try:
        # 변경 전 상태 캡처
        _addr_before = {}
        for raw_item in (items or []):
            ip_text = (raw_item.get('ip_address') or '').strip()
            if ip_text:
                try:
                    _existing = svc_list_network_ip_policy_addresses(
                        policy_id=policy_id, page=1, page_size=500)
                    for a in (_existing or {}).get('items', []):
                        if a.get('ip_address') == ip_text:
                            _addr_before[ip_text] = a
                            break
                except Exception:
                    pass

        result = svc_save_network_ip_policy_addresses(policy_id=policy_id, items=items, actor=_resolve_actor())

        # 각 변경된 IP에 대해 중앙 변경이력 기록
        for raw_item in (items or []):
            ip_text = (raw_item.get('ip_address') or '').strip()
            if not ip_text:
                continue
            old = _addr_before.get(ip_text, {})
            new = {k: (raw_item.get(k) or '').strip() for k in ('status', 'role', 'dns_domain', 'system_name', 'port', 'note')}
            new['ip_address'] = ip_text
            old_cmp = {k: (old.get(k) or '').strip() for k in ('status', 'role', 'dns_domain', 'system_name', 'port', 'note')}
            if any(old_cmp.get(k, '') != new.get(k, '') for k in old_cmp):
                _try_record_ip_policy_change(
                    action_type='UPDATE' if old_cmp.get('status') or old_cmp.get('role') or old_cmp.get('dns_domain') or old_cmp.get('system_name') or old_cmp.get('port') or old_cmp.get('note') else 'CREATE',
                    policy_id=policy_id,
                    tab_name='IP 범위',
                    old_data={**old_cmp, 'ip_address': ip_text} if any(old_cmp.values()) else None,
                    new_data=new,
                    summary=f"IP {ip_text} 수정" if any(old_cmp.values()) else f"IP {ip_text} 등록",
                )

        return jsonify({'success': True, **result})
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to save network IP policy addresses')
        return jsonify({'success': False, 'message': 'IP 범위 저장 중 오류가 발생했습니다.'}), 500


