@api_bp.route('/api/network/dns-policies/<int:policy_id>', methods=['PUT'])
def update_network_dns_policy(policy_id: int):
    payload = request.get_json(silent=True) or {}
    try:
        before = None
        try:
            before = svc_get_network_dns_policy(policy_id)
        except Exception:
            before = None
        record = svc_update_network_dns_policy(policy_id, payload, _resolve_actor())
        if not record:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404
        try:
            before_dict = before if isinstance(before, dict) else (before or {})
            after_dict = record if isinstance(record, dict) else (record or {})

            changes = {}
            changed_fields = 0
            if isinstance(payload, dict):
                for key in payload.keys():
                    b = before_dict.get(key) if isinstance(before_dict, dict) else None
                    a = after_dict.get(key) if isinstance(after_dict, dict) else None
                    if b != a:
                        changes[str(key)] = {'before': _json_safe_for_log(b), 'after': _json_safe_for_log(a)}
                        changed_fields += 1

            svc_append_network_dns_policy_log(
                policy_id,
                tab_key='gov_dns_policy_detail',
                entity='POLICY',
                entity_id=policy_id,
                action='UPDATE',
                actor=_resolve_actor(),
                message='DNS 정책 수정',
                diff={'payload': _json_safe_for_log(payload), 'changes': changes, 'changed_fields': changed_fields},
            )
        except Exception:
            logger.exception('Failed to append DNS policy log (update)')

        _try_record_dns_policy_change(
            action_type='UPDATE',
            policy_id=policy_id,
            tab_name='기본정보',
            old_data=before,
            new_data=record,
            summary='DNS 정책 수정: ' + (record.get('domain') or ''),
        )

        return jsonify({'success': True, 'item': record})
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError:
        logger.exception('Integrity error on DNS policy update')
        return jsonify({'success': False, 'message': 'DNS 정책 저장 중 중복 데이터가 발견되었습니다.'}), 400
    except Exception:
        logger.exception('Failed to update network DNS policy')
        return jsonify({'success': False, 'message': 'DNS 정책 수정 중 오류가 발생했습니다.'}), 500


