@api_bp.route('/api/network/dns-policies/<int:policy_id>/records', methods=['POST'])
def create_network_dns_policy_record(policy_id: int):
    auth = _require_login_for_write()
    if auth:
        return auth
    payload = request.get_json(silent=True) or {}
    try:
        item = svc_create_network_dns_record(policy_id, payload, _resolve_actor())
        try:
            record_changes = {}
            record_changed_fields = 0
            # Only include record-tab fields (avoid meta like id/policy_id/created_at).
            if isinstance(item, dict):
                for key in [
                    'fqdn', 'host', 'host_name', 'record_type', 'type',
                    'ip', 'ip_address', 'address', 'value', 'ttl',
                    'priority', 'service_name', 'remark',
                    'status', 'enabled', 'is_active',
                ]:
                    if key not in item:
                        continue
                    after_val = item.get(key)
                    if after_val is None:
                        continue
                    if isinstance(after_val, str) and after_val.strip() == '':
                        continue
                    record_changes[str(key)] = {'before': None, 'after': _json_safe_for_log(after_val)}
                record_changed_fields = len(record_changes)

            # Message: include FQDN like "도메인 222.example.com 레코드 등록".
            fqdn_display = ''
            try:
                if isinstance(item, dict):
                    fqdn_display = (item.get('fqdn') or '').strip()
                if not fqdn_display:
                    host = ''
                    if isinstance(item, dict):
                        host = (item.get('host_name') or item.get('host') or '').strip()
                    if not host and isinstance(payload, dict):
                        host = (payload.get('host_name') or payload.get('hostName') or payload.get('host') or '').strip()
                    domain = ''
                    pol = None
                    try:
                        pol = svc_get_network_dns_policy(policy_id)
                    except Exception:
                        pol = None
                    if isinstance(pol, dict):
                        domain = (pol.get('domain') or '').strip()
                    if domain:
                        if host in ('', '@'):
                            fqdn_display = domain
                        else:
                            fqdn_display = f"{host}.{domain}".replace('..', '.').strip('.')
            except Exception:
                fqdn_display = ''

            msg = f"도메인 {fqdn_display} 레코드 등록" if fqdn_display else "DNS 레코드 등록"

            svc_append_network_dns_policy_log(
                policy_id,
                tab_key='gov_dns_policy_dns_record',
                entity='RECORD',
                entity_id=item.get('id'),
                action='CREATE',
                actor=_resolve_actor(),
                message=msg,
                diff={
                    'payload': _json_safe_for_log(payload),
                    'item': _json_safe_for_log(item),
                    'changes': record_changes,
                    'changed_fields': record_changed_fields,
                },
            )
        except Exception:
            logger.exception('Failed to append DNS policy log (record create)')

        _try_record_dns_policy_change(
            action_type='CREATE',
            policy_id=policy_id,
            tab_name='레코드',
            new_data=item,
            summary=msg if msg else 'DNS 레코드 등록',
        )

        return jsonify({'success': True, 'item': item}), 201
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to create DNS record')
        return jsonify({'success': False, 'message': 'DNS 레코드 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/network/dns-policies/<int:policy_id>/records/<int:record_id>', methods=['PUT'])
def update_network_dns_policy_record(policy_id: int, record_id: int):
    auth = _require_login_for_write()
    if auth:
        return auth
    payload = request.get_json(silent=True) or {}
    try:
        snapshots = None
        item = None
        try:
            snapshots = svc_update_network_dns_record_with_before(policy_id, record_id, payload, _resolve_actor())
            item = (snapshots or {}).get('after') if isinstance(snapshots, dict) else None
        except Exception:
            snapshots = None
            item = None

        if not item:
            item = svc_update_network_dns_record(policy_id, record_id, payload, _resolve_actor())
        if not item:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404
        try:
            before_dict = ((snapshots or {}).get('before') if isinstance(snapshots, dict) else None) or {}
            after_dict = item if isinstance(item, dict) else (item or {})
            changes = {}
            changed_fields = 0
            allowed_keys = {
                'fqdn', 'host', 'host_name', 'record_type', 'type',
                'ip', 'ip_address', 'address', 'value', 'ttl',
                'priority', 'service_name', 'remark',
                'status', 'enabled', 'is_active',
            }
            if isinstance(payload, dict):
                for key in payload.keys():
                    if str(key) not in allowed_keys:
                        continue
                    b = before_dict.get(key) if isinstance(before_dict, dict) else None
                    a = after_dict.get(key) if isinstance(after_dict, dict) else None
                    if b != a:
                        changes[str(key)] = {'before': _json_safe_for_log(b), 'after': _json_safe_for_log(a)}
                        changed_fields += 1
            svc_append_network_dns_policy_log(
                policy_id,
                tab_key='gov_dns_policy_dns_record',
                entity='RECORD',
                entity_id=record_id,
                action='UPDATE',
                actor=_resolve_actor(),
                message='DNS 레코드 수정',
                diff={'payload': _json_safe_for_log(payload), 'changes': changes, 'changed_fields': changed_fields},
            )
        except Exception:
            logger.exception('Failed to append DNS policy log (record update)')

        _try_record_dns_policy_change(
            action_type='UPDATE',
            policy_id=policy_id,
            tab_name='레코드',
            old_data=((snapshots or {}).get('before') if isinstance(snapshots, dict) else None),
            new_data=item,
            summary='DNS 레코드 수정',
        )

        return jsonify({'success': True, 'item': item})
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to update DNS record')
        return jsonify({'success': False, 'message': 'DNS 레코드 수정 중 오류가 발생했습니다.'}), 500


