def _map_dns_log_item(item: Dict[str, Any]) -> Dict[str, Any]:
    log_id = item.get('log_id') if isinstance(item, dict) else None
    if log_id is None:
        log_id = item.get('id') if isinstance(item, dict) else None
    diff = item.get('diff') if isinstance(item, dict) else None
    detail = ''
    if diff is not None:
        try:
            detail = json.dumps(diff, ensure_ascii=False, indent=2)
        except Exception:
            detail = str(diff)
    if not detail:
        detail = (item.get('message') or '') if isinstance(item, dict) else ''
    return {
        'id': int(log_id) if log_id is not None else None,
        'policy_id': item.get('policy_id'),
        'tab_key': item.get('tab_key') or '',
        'entity': item.get('entity') or '',
        'entity_id': item.get('entity_id'),
        'action': item.get('action') or '',
        'actor': item.get('actor') or '',
        'message': item.get('message') or '',
        'reason': item.get('reason') or '',
        'created_at': item.get('created_at') or '',
        'detail': detail,
    }


