@api_bp.route('/api/network/dns-records/lookup-by-ips', methods=['POST'])
def lookup_dns_records_by_ips():
    """Given a list of IPs, return {ip: {fqdn, record_type, domain}} from DNS records."""
    try:
        payload = request.get_json(silent=True) or {}
        ips = payload.get('ips') or []
        if not isinstance(ips, list):
            ips = [str(ips)]
        ips = [str(ip).strip() for ip in ips if ip and str(ip).strip()][:500]
        result = svc_lookup_dns_records_by_ips(ips)
        return jsonify({'success': True, 'mapping': result})
    except Exception as exc:
        logger.exception('Failed to lookup DNS records by IPs')
        return jsonify({'success': False, 'error': str(exc)}), 400


