@api_bp.route('/api/network/dns-diagrams', methods=['POST'])
def create_network_dns_diagram():
    auth = _require_login_for_write()
    if auth:
        return auth
    payload = request.get_json(silent=True) or {}
    try:
        record = svc_create_network_dns_diagram(payload, _resolve_actor())
        try:
            policy_id = int((record or {}).get('policy_id') or payload.get('policy_id') or 0)
            if policy_id:
                diagram_changes = {}
                diagram_changed_fields = 0
                if isinstance(payload, dict) and isinstance(record, dict):
                    for key in payload.keys():
                        after_val = record.get(key)
                        if after_val is None:
                            continue
                        if isinstance(after_val, str) and after_val.strip() == '':
                            continue
                        diagram_changes[str(key)] = {'before': None, 'after': _json_safe_for_log(after_val)}
                if not diagram_changes and isinstance(record, dict):
                    # Fallback: show primary file attributes.
                    for key in ['entry_type', 'type', 'file_name', 'fileName', 'original_filename', 'originalFilename', 'is_primary', 'isPrimary', 'remark', 'note', 'description']:
                        if key not in record:
                            continue
                        after_val = record.get(key)
                        if after_val is None:
                            continue
                        if isinstance(after_val, str) and after_val.strip() == '':
                            continue
                        diagram_changes[str(key)] = {'before': None, 'after': _json_safe_for_log(after_val)}
                diagram_changed_fields = len(diagram_changes)

                # Message: include filename like "구성/파일 등록 (future_5f.PNG)".
                filename_display = ''
                try:
                    if isinstance(record, dict):
                        for k in ('original_filename', 'originalFilename', 'file_name', 'fileName'):
                            v = record.get(k)
                            if isinstance(v, str) and v.strip():
                                filename_display = v.strip()
                                break
                    if not filename_display and isinstance(payload, dict):
                        for k in ('original_filename', 'originalFilename', 'file_name', 'fileName'):
                            v = payload.get(k)
                            if isinstance(v, str) and v.strip():
                                filename_display = v.strip()
                                break
                except Exception:
                    filename_display = ''

                msg = f"구성/파일 등록 ({filename_display})" if filename_display else "구성/파일 등록"

                svc_append_network_dns_policy_log(
                    policy_id,
                    tab_key='gov_dns_policy_file',
                    entity='DIAGRAM',
                    entity_id=record.get('id') if isinstance(record, dict) else None,
                    action='CREATE',
                    actor=_resolve_actor(),
                    message=msg,
                    diff={
                        'payload': _json_safe_for_log(payload),
                        'item': _json_safe_for_log(record),
                        'changes': diagram_changes,
                        'changed_fields': diagram_changed_fields,
                    },
                )
        except Exception:
            logger.exception('Failed to append DNS policy log (diagram create)')

        _try_record_dns_policy_change(
            action_type='CREATE',
            policy_id=int((record or {}).get('policy_id') or payload.get('policy_id') or 0),
            tab_name='구성/파일',
            new_data=record,
            summary=msg if msg else '구성/파일 등록',
        )

        return jsonify({'success': True, 'item': record}), 201
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to create network DNS diagram')
        return jsonify({'success': False, 'message': '구성/파일 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/network/dns-diagrams/<int:diagram_id>', methods=['PUT'])
def update_network_dns_diagram(diagram_id: int):
    auth = _require_login_for_write()
    if auth:
        return auth
    payload = request.get_json(silent=True) or {}
    try:
        before = None
        try:
            before = svc_get_network_dns_diagram(diagram_id)
        except Exception:
            before = None
        record = svc_update_network_dns_diagram(diagram_id, payload, _resolve_actor())
        if not record:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404
        try:
            policy_id = int((record or {}).get('policy_id') or 0)
            if policy_id:
                before_dict = before if isinstance(before, dict) else (before or {})
                after_dict = record if isinstance(record, dict) else (record or {})
                changes = {}
                changed_fields = 0
                allowed_keys = {
                    'policy_id',  # kept for service compat; filtered out in UI anyway
                    'entry_type', 'type',
                    'title', 'description', 'note', 'remark',
                    'file_name', 'file_size', 'mime_type',
                    'is_primary',
                }
                if isinstance(payload, dict):
                    for key in payload.keys():
                        if str(key) not in allowed_keys:
                            continue
                        b = before_dict.get(key) if isinstance(before_dict, dict) else None
                        a = after_dict.get(key) if isinstance(after_dict, dict) else None
                        if b != a:
                            changes[str(key)] = {'before': _json_safe_for_log(b), 'after': _json_safe_for_log(a)}
                            changed_fields += 1
                svc_append_network_dns_policy_log(
                    policy_id,
                    tab_key='gov_dns_policy_file',
                    entity='DIAGRAM',
                    entity_id=diagram_id,
                    action='UPDATE',
                    actor=_resolve_actor(),
                    message='DNS 구성/파일 수정',
                    diff={'payload': _json_safe_for_log(payload), 'changes': changes, 'changed_fields': changed_fields},
                )
        except Exception:
            logger.exception('Failed to append DNS policy log (diagram update)')

        _try_record_dns_policy_change(
            action_type='UPDATE',
            policy_id=int((record or {}).get('policy_id') or 0),
            tab_name='구성/파일',
            old_data=before,
            new_data=record,
            summary='구성/파일 수정',
        )

        return jsonify({'success': True, 'item': record})
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to update network DNS diagram')
        return jsonify({'success': False, 'message': '구성/파일 수정 중 오류가 발생했습니다.'}), 500


