@api_bp.route('/api/work-groups', methods=['POST'])
def create_work_group():
    payload = request.get_json(silent=True) or {}
    try:
        record = svc_create_work_group(payload, _resolve_actor())
        _try_record_wg_change(
            action_type='CREATE', group_id=record.get('id'),
            tab_name='기본정보', new_data=record,
            summary='업무 그룹 생성: ' + (record.get('group_name') or ''),
        )
        return jsonify({'success': True, 'item': record}), 201
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError as exc:
        msg = str(exc or '')
        upper = msg.upper()
        if 'FOREIGN KEY' in upper:
            logger.exception('Work group FK constraint failed')
            return jsonify({'success': False, 'message': '참조 데이터가 없어 등록할 수 없습니다. (업무 상태/부서 코드 확인)'}), 400
        if 'UNIQUE' in upper:
            logger.exception('Duplicate work group code')
            return jsonify({'success': False, 'message': '동일한 업무 그룹 코드가 이미 존재합니다.'}), 400
        logger.exception('Work group integrity error')
        return jsonify({'success': False, 'message': '업무 그룹 등록 중 무결성 오류가 발생했습니다.'}), 400
    except Exception:
        logger.exception('Failed to create work group')
        return jsonify({'success': False, 'message': '업무 그룹 등록 중 오류가 발생했습니다.'}), 500


