@api_bp.route('/api/work-groups/<int:group_id>/services', methods=['POST'])
def create_work_group_service(group_id: int):
    auth = _require_login_for_write()
    if auth:
        return auth

    payload = request.get_json(silent=True) or {}
    actor_user_id = _coerce_positive_int(
        request.args.get('actor_user_id')
        or payload.pop('actor_user_id', None)
        or payload.pop('updated_by_user_id', None)
    )
    if not actor_user_id:
        actor_user_id = _coerce_positive_int(_resolve_actor_user_id(None))
    if not actor_user_id:
        return jsonify({'success': False, 'message': '로그인이 필요합니다.'}), 401

    try:
        wg = svc_get_work_group(group_id)
        if not wg:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        item = svc_create_work_group_service(group_id, payload, actor_user_id)
        _try_record_wg_change(
            action_type='CREATE', group_id=group_id,
            tab_name='서비스', new_data=item,
            summary='서비스 생성: ' + (item.get('service_name') or ''),
        )
        return jsonify({'success': True, 'item': item}), 201
    except ValueError as ve:
        return jsonify({'success': False, 'message': str(ve)}), 400
    except sqlite3.IntegrityError as ie:
        if 'FOREIGN KEY' in str(ie).upper():
            logger.exception('Work group service FK constraint failed')
            return jsonify({'success': False, 'message': '참조 무결성 오류입니다.'}), 400
        logger.exception('Work group service integrity error')
        return jsonify({'success': False, 'message': '서비스 저장 중 무결성 오류가 발생했습니다.'}), 400
    except Exception:
        logger.exception('Failed to create work group service')
        return jsonify({'success': False, 'message': '서비스 생성 중 오류가 발생했습니다.'}), 500


