@api_bp.route('/api/work-groups/<int:group_id>', methods=['PUT'])
def update_work_group(group_id: int):
    payload = request.get_json(silent=True) or {}
    try:
        old_data = svc_get_work_group(group_id) or {}
        record = svc_update_work_group(group_id, payload, _resolve_actor())
        if not record:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404
        _try_record_wg_change(
            action_type='UPDATE', group_id=group_id,
            tab_name='기본정보', old_data=old_data, new_data=record,
        )
        return jsonify({'success': True, 'item': record})
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError as exc:
        msg = str(exc or '')
        upper = msg.upper()
        if 'FOREIGN KEY' in upper:
            logger.exception('Work group FK constraint failed on update')
            return jsonify({'success': False, 'message': '참조 데이터가 없어 저장할 수 없습니다. (업무 상태/업무 구분/부서 코드 확인)'}), 400
        if 'UNIQUE' in upper:
            logger.exception('Duplicate work group code on update')
            return jsonify({'success': False, 'message': '동일한 업무 그룹 코드가 이미 존재합니다.'}), 400
        logger.exception('Work group integrity error on update')
        return jsonify({'success': False, 'message': '업무 그룹 저장 중 무결성 오류가 발생했습니다.'}), 400
    except Exception:
        logger.exception('Failed to update work group')
        return jsonify({'success': False, 'message': '업무 그룹 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/work-groups/bulk-delete', methods=['POST'])
def delete_work_groups():
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids')
    if not isinstance(ids, (list, tuple)) or not ids:
        return jsonify({'success': False, 'message': '삭제할 항목을 선택하세요.'}), 400
    try:
        old_items = {}
        for gid in ids:
            try:
                old_items[gid] = svc_get_work_group(int(gid)) or {}
            except Exception:
                pass
        deleted = svc_soft_delete_work_groups(ids, _resolve_actor())
        for gid in ids:
            old = old_items.get(int(gid), {})
            if old:
                _try_record_wg_change(
                    action_type='DELETE', group_id=int(gid),
                    tab_name='기본정보', old_data=old,
                    summary='업무 그룹 삭제: ' + (old.get('group_name') or ''),
                )
        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        logger.exception('Failed to delete work groups')
        return jsonify({'success': False, 'message': '업무 그룹 삭제 중 오류가 발생했습니다.'}), 500


