@api_bp.route('/api/software/<category_slug>/<type_slug>/assets', methods=['POST'])
def create_software_asset_api(category_slug: str, type_slug: str):
    category, sw_type, error = _software_route_context(category_slug, type_slug)
    if error:
        return jsonify({'success': False, 'message': error}), 400
    payload = request.get_json(silent=True) or {}
    try:
        record = svc_create_software_asset(
            payload,
            _resolve_actor(),
            asset_category=category,
            asset_type=sw_type,
        )
        return jsonify({'success': True, 'item': record}), 201
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError as exc:
        raw = str(exc) or ''
        lowered = raw.lower()
        logger.warning(
            'IntegrityError creating %s/%s software asset: %s',
            category,
            sw_type,
            raw,
        )

        # Keep the legacy message for UNIQUE collisions (tests/UI may depend on it).
        if 'unique constraint failed' in lowered:
            return jsonify({'success': False, 'message': '이미 존재하는 코드가 있습니다.'}), 400
        if 'foreign key constraint failed' in lowered or 'foreign key mismatch' in lowered:
            return jsonify({'success': False, 'message': '참조 값이 존재하지 않습니다. (외래 키 오류)'}), 400
        if 'not null constraint failed' in lowered:
            return jsonify({'success': False, 'message': '필수 값이 누락되었습니다.'}), 400

        return jsonify({'success': False, 'message': '데이터 무결성 오류가 발생했습니다.'}), 400
    except Exception:
        logger.exception('Failed to create %s/%s software asset', category, sw_type)
        return jsonify({'success': False, 'message': '소프트웨어 자산 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/software/<category_slug>/<type_slug>/assets/<int:asset_id>', methods=['PUT'])
def update_software_asset_api(category_slug: str, type_slug: str, asset_id: int):
    category, sw_type, error = _software_route_context(category_slug, type_slug)
    if error:
        return jsonify({'success': False, 'message': error}), 400
    payload = request.get_json(silent=True) or {}
    try:
        record = svc_update_software_asset(
            asset_id,
            payload,
            _resolve_actor(),
            asset_category=category,
            asset_type=sw_type,
        )
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except sqlite3.IntegrityError as exc:
        raw = str(exc) or ''
        lowered = raw.lower()
        logger.warning(
            'IntegrityError updating %s/%s software asset id=%s: %s',
            category,
            sw_type,
            asset_id,
            raw,
        )
        if 'unique constraint failed' in lowered:
            return jsonify({'success': False, 'message': '이미 존재하는 코드가 있습니다.'}), 400
        if 'foreign key constraint failed' in lowered or 'foreign key mismatch' in lowered:
            return jsonify({'success': False, 'message': '참조 값이 존재하지 않습니다. (외래 키 오류)'}), 400
        if 'not null constraint failed' in lowered:
            return jsonify({'success': False, 'message': '필수 값이 누락되었습니다.'}), 400
        return jsonify({'success': False, 'message': '데이터 무결성 오류가 발생했습니다.'}), 400
    except Exception:
        logger.exception('Failed to update %s/%s software asset', category, sw_type)
        return jsonify({'success': False, 'message': '소프트웨어 자산 수정 중 오류가 발생했습니다.'}), 500
    if not record:
        return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404
    return jsonify({'success': True, 'item': record})


