@api_bp.route('/api/hardware/software-catalog/models', methods=['GET'])
def list_server_software_model_catalog_api():
    """Searchable dropdown source for server-detail software tab (models).

        This derives suggestions from the Software category master tables
        ("카테고리 > 소프트웨어") by category.
    Query params:
      - type: software type filter (optional)
      - q: search query (optional)
      - limit: max items (optional, default 50, max 200)
    """

    try:
        # `type` here means software category (OS/DATABASE/...) derived from the UI.
        raw_type = (request.args.get('type') or '').strip() or None
        q = (request.args.get('q') or request.args.get('query') or '').strip() or None
        raw_limit = request.args.get('limit')
        try:
            limit = int(raw_limit) if raw_limit is not None and str(raw_limit).strip() != '' else 50
        except Exception:
            limit = 50
        if limit < 1:
            limit = 1
        if limit > 200:
            limit = 200

        category = None
        if raw_type:
            try:
                category = _software_category_value(raw_type)
            except Exception:
                category = raw_type

        # Category -> software master table rows
        # NOTE: These services return full rows; we de-dupe and apply `limit` here.
        rows = []
        name_key = None
        if category:
            cat = str(category).strip().upper()
            if cat == 'OS':
                rows = svc_list_sw_os_types(search=q, include_deleted=False)
                name_key = 'model_name'
            elif cat == 'DATABASE':
                rows = svc_list_sw_db_types(search=q, include_deleted=False)
                name_key = 'db_name'
            elif cat == 'MIDDLEWARE':
                rows = svc_list_sw_middleware_types(search=q, include_deleted=False)
                # sw_middleware_type uses `model_name`
                name_key = 'model_name'
            elif cat == 'VIRTUALIZATION':
                rows = svc_list_sw_virtual_types(search=q, include_deleted=False)
                name_key = 'virtual_name'
            elif cat == 'SECURITY':
                rows = svc_list_sw_security_types(search=q, include_deleted=False)
                name_key = 'secsw_name'
            elif cat in ('HIGH_AVAILABILITY', 'HIGH AVAILABILITY', 'HA'):
                rows = svc_list_sw_ha_types(search=q, include_deleted=False)
                name_key = 'ha_name'

        # When no category is selected, return empty to avoid mixing unrelated catalogs.
        if not category or not name_key:
            return jsonify({'success': True, 'items': [], 'total': 0})

        # De-dupe by name while preserving order.
        seen_names = set()
        normalized_rows = []
        for r in rows or []:
            try:
                name = (r.get(name_key) or '').strip()
            except Exception:
                name = ''
            if not name:
                continue
            if name in seen_names:
                continue
            seen_names.add(name)
            normalized_rows.append(r)
            if len(normalized_rows) >= limit:
                break
        rows = normalized_rows

        # Resolve manufacturer_name from main DB table (biz_vendor_manufacturer)
        codes = sorted({(r.get('manufacturer_code') or '').strip() for r in rows if (r.get('manufacturer_code') or '').strip()})
        code_to_name = {}
        if codes:
            try:
                placeholders = ",".join([":c" + str(i) for i in range(len(codes))])
                params = {"c" + str(i): codes[i] for i in range(len(codes))}
                vendor_rows = db.session.execute(
                    text(
                        f"SELECT manufacturer_code, manufacturer_name FROM biz_vendor_manufacturer "
                        f"WHERE is_deleted = 0 AND manufacturer_code IN ({placeholders})"
                    ),
                    params,
                ).fetchall()
                for vr in vendor_rows:
                    m = getattr(vr, '_mapping', None)
                    code = (m['manufacturer_code'] if m and 'manufacturer_code' in m else vr[0])
                    name = (m['manufacturer_name'] if m and 'manufacturer_name' in m else vr[1])
                    if code:
                        code_to_name[str(code)] = str(name or '').strip()
            except Exception:
                # best-effort
                pass

        items = []
        for r in rows:
            name = (r.get(name_key) or '').strip()
            if not name:
                continue
            code = (r.get('manufacturer_code') or '').strip() or None
            vendor_name = (code_to_name.get(code) if code else None) or ''
            items.append({'name': name, 'vendor': vendor_name or None})

        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to fetch server software model catalog')
        return jsonify({'success': False, 'message': '소프트웨어 모델 목록 조회 중 오류가 발생했습니다.'}), 500


