# ===== Hardware detail: model-based hardware lookup (tab43-hardware) =====
@api_bp.route('/api/hardware/model-assets', methods=['GET'])
def list_hardware_model_assets():
    """tab43 하드웨어 탭: 동일 모델(server_code)을 사용하는 하드웨어 자산 목록 조회.

    현재 하드웨어의 server_code를 기준으로 hardware 테이블에서
    동일 모델을 사용하는 모든 자산을 찾아 반환합니다.

    Query params (우선순위):
        server_code (str, 1순위): 직접 server_code 지정 → 동일 모델 검색
        model (str, 2순위): 모델명 → hw_server_type에서 server_code 조회
    Returns:
        items[]: 구분, 유형, 업무운영, 업무그룹, 업무명, 시스템명, 할당수량
    """
    server_code_raw = (request.args.get('server_code') or '').strip()
    model_name = (request.args.get('model') or '').strip()

    if not server_code_raw and not model_name:
        return jsonify({'success': True, 'items': [], 'total': 0})

    try:
        conn = _vendor_asset_db_conn()
        try:
            server_code = server_code_raw or None

            # model_name → hw_server_type에서 server_code 조회 (fallback)
            if not server_code and model_name:
                sc_row = conn.execute(
                    "SELECT server_code FROM hw_server_type "
                    "WHERE model_name = ? AND is_deleted = 0 LIMIT 1",
                    (model_name,),
                ).fetchone()
                if sc_row:
                    server_code = (sc_row['server_code'] or '').strip() or None

            if not server_code:
                return jsonify({'success': True, 'items': [], 'total': 0})

            # 3) 동일 server_code를 가진 모든 하드웨어 자산 조회
            rows = conn.execute(
                """
                SELECT
                    h.id,
                    h.asset_category,
                    h.asset_type,
                    COALESCE(wo.operation_name, h.work_operation_code, '') AS work_operation,
                    COALESCE(wg.group_name, h.work_group_code, '') AS work_group,
                    COALESCE(h.work_name, '')   AS work_name,
                    COALESCE(h.system_name, '') AS system_name,
                    COALESCE(h.serial_number, '') AS serial_number,
                    COALESCE(h.firmware, '')     AS firmware,
                    h.work_status_code,
                    COALESCE(ws.status_name, h.work_status_code, '') AS work_status_name,
                    COALESCE(ws.status_level, '') AS work_status_level
                FROM hardware h
                LEFT JOIN biz_work_operation wo
                       ON wo.operation_code = h.work_operation_code
                      AND wo.is_deleted = 0
                LEFT JOIN biz_work_group wg
                       ON wg.group_code = h.work_group_code
                      AND wg.is_deleted = 0
                LEFT JOIN biz_work_status ws
                       ON ws.status_code = h.work_status_code
                      AND ws.is_deleted = 0
                WHERE h.server_code = ?
                  AND h.is_deleted = 0
                ORDER BY h.asset_category, h.asset_type, h.work_name
                """,
                (server_code,),
            ).fetchall()
        finally:
            conn.close()

        items = []
        for r in rows:
            cat_raw = (r['asset_category'] or '').strip()
            type_raw = (r['asset_type'] or '').strip()
            items.append({
                'category': _ASSET_CATEGORY_KR.get(cat_raw, cat_raw),
                'type': _ASSET_TYPE_KR.get(type_raw, type_raw),
                'work_operation': r['work_operation'] or '',
                'work_group': r['work_group'] or '',
                'work_name': r['work_name'] or '',
                'system_name': r['system_name'] or '',
                'serial_number': r['serial_number'] or '',
                'firmware': r['firmware'] or '',
                'work_status': r['work_status_name'] or '',
                'work_status_color': _work_status_color(r['work_status_name'], r['work_status_level']),
                'qty': 1,
            })
        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to fetch hardware model assets')
        return jsonify({'success': False, 'message': '모델별 하드웨어 자산 조회 중 오류가 발생했습니다.'}), 500


