@api_bp.route('/api/hardware/assets/<int:hardware_id>/components', methods=['GET'])
def list_server_components_api(hardware_id: int):
    try:
        items = svc_list_server_components(hardware_id)
        return jsonify({'success': True, 'total': len(items), 'items': items})
    except Exception:
        logger.exception('Failed to fetch server components for hardware_id=%s', hardware_id)
        return jsonify({'success': False, 'message': '하드웨어 구성 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/assets/<int:hardware_id>/components', methods=['POST'])
def create_server_component_api(hardware_id: int):
    payload = request.get_json(silent=True) or {}
    try:
        item = svc_create_server_component(hardware_id, payload, _resolve_actor())

        # ── 변경이력 ──
        _try_record_change(action_type='CREATE', entity_type='hardware_asset',
                           entity_id=hardware_id,
                           tab_name='하드웨어', new_data=item,
                           summary='하드웨어 구성 추가: ' + str((item or {}).get('type') or (item or {}).get('model') or ''))

        # ── TPMC 자동 재계산 (CPU 변경 시) ──
        if (item or {}).get('type', '').upper() == 'CPU':
            try:
                from app.services.tpmc_service import recalculate_and_store
                recalculate_and_store(hardware_id)
            except Exception:
                logger.debug('TPMC recalculation skipped after component create for hardware_id=%s', hardware_id)

        return jsonify({'success': True, 'item': item}), 201
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to create server component for hardware_id=%s', hardware_id)
        return jsonify({'success': False, 'message': '하드웨어 구성 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/assets/<int:hardware_id>/components/<int:component_id>', methods=['PUT'])
def update_server_component_api(hardware_id: int, component_id: int):
    payload = request.get_json(silent=True) or {}

    # ── 변경이력: before 캡처 ──
    old_data = None
    try:
        _items = svc_list_server_components(hardware_id)
        old_data = next((i for i in (_items or []) if i.get('id') == component_id), None)
    except Exception:
        pass

    try:
        item = svc_update_server_component(hardware_id, component_id, payload, _resolve_actor())
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to update server component id=%s for hardware_id=%s', component_id, hardware_id)
        return jsonify({'success': False, 'message': '하드웨어 구성 수정 중 오류가 발생했습니다.'}), 500
    if not item:
        return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

    # ── 변경이력 ──
    _try_record_change(action_type='UPDATE', entity_type='hardware_asset',
                       entity_id=hardware_id,
                       tab_name='하드웨어', old_data=old_data, new_data=item,
                       summary='하드웨어 구성 수정: ' + str((item or {}).get('type') or (item or {}).get('model') or ''))

    # ── TPMC 자동 재계산 (CPU 변경 시) ──
    comp_type = (item or {}).get('type', '') or (old_data or {}).get('type', '')
    if comp_type.upper() == 'CPU':
        try:
            from app.services.tpmc_service import recalculate_and_store
            recalculate_and_store(hardware_id)
        except Exception:
            logger.debug('TPMC recalculation skipped after component update for hardware_id=%s', hardware_id)

    return jsonify({'success': True, 'item': item})


@api_bp.route('/api/hardware/assets/<int:hardware_id>/components/<int:component_id>', methods=['DELETE'])
def delete_server_component_api(hardware_id: int, component_id: int):
    # ── 삭제 전 데이터 캡처 (변경이력용) ──
    old_comp = None
    try:
        old_comp = svc_get_server_component(hardware_id, component_id)
    except Exception:
        pass

    try:
        deleted = svc_delete_server_component(hardware_id, component_id)
        if deleted <= 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        # ── 변경이력 ──
        comp_type = (old_comp or {}).get('type') or (old_comp or {}).get('model') or ''
        _try_record_change(action_type='DELETE', entity_type='hardware_asset',
                           entity_id=hardware_id,
                           tab_name='하드웨어',
                           old_data=old_comp,
                           summary='하드웨어 구성 삭제: ' + comp_type)

        # ── TPMC 자동 재계산 (CPU 삭제 시) ──
        if (old_comp or {}).get('type', '').upper() == 'CPU':
            try:
                from app.services.tpmc_service import recalculate_and_store
                recalculate_and_store(hardware_id)
            except Exception:
                logger.debug('TPMC recalculation skipped after component delete for hardware_id=%s', hardware_id)

        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        logger.exception('Failed to delete server component id=%s for hardware_id=%s', component_id, hardware_id)
        return jsonify({'success': False, 'message': '하드웨어 구성 삭제 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/assets/<int:asset_id>/system-info', methods=['PATCH'])
def patch_hardware_asset_system_info(asset_id: int):
    """Partial update for system-level fields (firmware) on the hardware asset row."""
    payload = request.get_json(silent=True) or {}
    allowed = {'firmware'}
    filtered = {k: v for k, v in payload.items() if k in allowed}
    if not filtered:
        return jsonify({'success': True, 'message': 'No changes'})
    try:
        record = svc_update_hardware_asset(asset_id, filtered, _resolve_actor())
        if not record:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        # ── 변경이력 ──
        _try_record_change(action_type='UPDATE', entity_type='hardware_asset',
                           entity_id=asset_id,
                           tab_name='하드웨어', new_data=filtered,
                           summary='하드웨어 구성 수정: 시스템')

        return jsonify({'success': True, 'item': record})
    except Exception:
        logger.exception('Failed to patch hardware asset system info id=%s', asset_id)
        return jsonify({'success': False, 'message': '시스템 정보 저장 중 오류가 발생했습니다.'}), 500


# ===== TPMC calculation endpoints =====
@api_bp.route('/api/hardware/assets/<int:hardware_id>/tpmc', methods=['GET'])
def get_hardware_tpmc(hardware_id: int):
    """Get TPMC calculation details for a hardware asset."""
    try:
        from app.services.tpmc_service import calculate_tpmc
        result = calculate_tpmc(hardware_id)
        return jsonify({'success': True, **result})
    except Exception:
        logger.exception('Failed to calculate TPMC for hardware_id=%s', hardware_id)
        return jsonify({'success': False, 'message': 'TPMC 계산 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/assets/<int:hardware_id>/tpmc/recalculate', methods=['POST'])
def recalculate_hardware_tpmc(hardware_id: int):
    """Recalculate and persist TPMC snapshot for a hardware asset."""
    try:
        from app.services.tpmc_service import recalculate_and_store
        result = recalculate_and_store(hardware_id)
        return jsonify({'success': True, **result})
    except Exception:
        logger.exception('Failed to recalculate TPMC for hardware_id=%s', hardware_id)
