@api_bp.route('/api/hardware/assets/<int:hardware_id>/tab61-maintenance', methods=['GET'])
def get_server_tab61_maintenance_contract(hardware_id: int):
    """Resolve tab61 maintenance contract manage number for a hardware asset.

    The UI wants to show the tab61 '계약정보' 관리번호 (contract_code / manage_no)
    in the hardware tab's '유지보수' cell, read-only.
    """

    try:
        # 1) Fetch the hardware asset to get (work_name, system_name)
        # NOTE: do NOT force asset_category='SERVER'. This endpoint is used by the shared
        # tab01-hardware.js on multiple hardware detail pages (SERVER/CLOUD/FIREWALL/etc.).
        asset = svc_get_hardware_asset(hardware_id)
        if not asset:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        work_name = (asset.get('work_name') or '').strip()
        system_name = (asset.get('system_name') or '').strip()
        if not work_name and not system_name:
            return jsonify({'success': True, 'found': False, 'manage_no': '', 'contract_id': 0})

        # 2) Determine search params
        req_scope = (request.args.get('scope') or '').strip().upper()
        req_type = (request.args.get('cost_type') or request.args.get('type') or '').strip().upper() or 'HW'
        req_year = request.args.get('year', type=int)

        now_year = datetime.now().year
        years = [req_year] if req_year else [now_year, now_year - 1]
        # Requirement: only OPEX '계약정보' mappings should drive maintenance display by default.
        scopes = [req_scope] if req_scope in ('OPEX', 'CAPEX') else ['OPEX']

        # 3) List tab61 lines for this (work, system) and map to contract manage numbers.
        # The client performs strict per-row matching (type/vendor/model/serial).
        out_lines = []
        best_manage_no = ''
        best_status = ''

        for year in years:
            for scope in scopes:
                lines = svc_list_tab61_lines_for_work_system(
                    scope=scope,
                    cost_type=req_type,
                    year=year,
                    work_name=work_name,
                    system_name=system_name,
                    include_deleted=False,
                )
                if not lines:
                    continue

                contract_cache = {}
                for ln in lines:
                    try:
                        contract_pk = int(ln.get('contract_id') or 0)
                    except Exception:
                        contract_pk = 0
                    if contract_pk <= 0:
                        continue

                    if contract_pk not in contract_cache:
                        contract = None
                        if scope == 'OPEX':
                            contract = svc_get_opex_contract(contract_pk)
                        else:
                            contract = svc_get_capex_contract(contract_pk)
                        manage_no = ''
                        if isinstance(contract, dict):
                            manage_no = (contract.get('manage_no') or contract.get('contract_code') or '').strip()
                        contract_cache[contract_pk] = manage_no

                    manage_no = contract_cache.get(contract_pk, '')
                    if not manage_no:
                        continue

                    status = (ln.get('contract_status') or '').strip()
                    out_lines.append(
                        {
                            'line_id': int(ln.get('id') or 0),
                            'scope': scope,
                            'cost_type': req_type,
                            'year': int(ln.get('year') or year),
                            'contract_id': contract_pk,
                            'manage_no': manage_no,
                            'contract_status': status,
                            'work_name': (ln.get('work_name') or '').strip(),
                            'system_name': (ln.get('system_name') or '').strip(),
                            'contract_type': (ln.get('contract_type') or '').strip(),
                            'contract_vendor': (ln.get('contract_vendor') or '').strip(),
                            'contract_model': (ln.get('contract_model') or '').strip(),
                            'contract_serial': (ln.get('contract_serial') or '').strip(),
                        }
                    )

                    # Backward compatible single value (best-effort): keep the first manage_no.
                    if not best_manage_no:
                        best_manage_no = manage_no
                        best_status = status

        if out_lines:
            return jsonify(
                {
                    'success': True,
                    'found': True,
                    'work_name': work_name,
                    'system_name': system_name,
                    'scope': scopes[0] if scopes else 'OPEX',
                    'cost_type': req_type,
                    'manage_no': best_manage_no,
                    'contract_status': best_status,
                    'lines': out_lines,
                }
            )

        return jsonify(
            {
                'success': True,
                'found': False,
                'manage_no': '',
                'contract_id': 0,
                'work_name': work_name,
                'system_name': system_name,
                'lines': [],
            }
        )
    except Exception:
        logger.exception('Failed to resolve tab61 maintenance contract for hardware_id=%s', hardware_id)
        return jsonify({'success': False, 'message': '유지보수(계약정보) 매핑 중 오류가 발생했습니다.'}), 500


