def _ensure_folder():
    folder = current_app.config.get('UPLOAD_FOLDER') or 'uploads'
    if not os.path.isabs(folder):
        folder = os.path.join(current_app.root_path, '..', folder)
    os.makedirs(folder, exist_ok=True)
    return folder

def _get_store():
    # In-memory cache on app; production should persist in DB
    store = current_app.config.setdefault('_UPLOAD_META', {})
    return store


def _get_store_with_fallback(fid: str):
    store = _get_store()
    rec = store.get(fid)
    if rec:
        return rec
    try:
        meta = svc_get_upload_meta(fid)
        if meta:
            store[fid] = {
                'id': meta['id'],
                'name': meta['name'],
                'size': meta['size'],
                'mime_type': meta.get('mime_type') or '',
                'disk_name': meta.get('disk_name') or '',
            }
            return store[fid]
    except Exception:
        # Ignore DB fallback failures
        pass
    return None


def _delete_uploaded_file(fid: str) -> bool:
    if not fid:
        return False
    store = _get_store()
    rec = store.get(fid)
    if not rec:
        rec = _get_store_with_fallback(fid)
    if not rec:
        return False

    folder = _ensure_folder()
    deleted_disk = False
    try:
        for entry in os.listdir(folder):
            if entry.startswith(fid):
                try:
                    os.remove(os.path.join(folder, entry))
                    deleted_disk = True
                except Exception:
                    pass
                break
    except Exception:
        pass

    store.pop(fid, None)
    try:
        svc_delete_upload_meta(fid)
    except Exception:
        pass
    return deleted_disk

@api_bp.route('/api/uploads', methods=['GET'])
def list_uploads():
    # Prefer DB-backed list (most stable), but keep in-memory cache too.
    try:
        metas = svc_list_upload_metas(limit=5000)
        return jsonify([{'id': m['id'], 'name': m['name'], 'size': m['size']} for m in metas])
    except Exception:
        store = _get_store()
        return jsonify(list(store.values()))

@api_bp.route('/api/uploads', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error':'no file field'}), 400
    f = request.files['file']
    if not f.filename:
        return jsonify({'error':'empty filename'}), 400
    folder = _ensure_folder()
    fid = uuid.uuid4().hex
    safe_name = f.filename
    # Basic sanitization
    safe_name = safe_name.replace('..','_').replace('/','_').replace('\\','_')
    ext = os.path.splitext(safe_name)[1]
    disk_name = fid + ext
    path = os.path.join(folder, disk_name)
    f.save(path)
    size = os.path.getsize(path)
    mime_type = getattr(f, 'mimetype', '') or ''
    rec = { 'id': fid, 'name': safe_name, 'size': size, 'mime_type': mime_type, 'disk_name': disk_name }
    store = _get_store(); store[fid] = rec
    try:
        svc_save_upload_meta(fid, file_name=safe_name, file_size=size, mime_type=mime_type, disk_name=disk_name)
    except Exception:
        # Keep upload working even if DB persistence fails
        pass
    return jsonify(rec), 201

@api_bp.route('/api/uploads/<fid>', methods=['DELETE'])
def delete_upload(fid):
    ok = _delete_uploaded_file(fid)
    if not ok:
        # might exist in DB but disk missing; treat as deleted if DB row existed
        try:
            existed = svc_delete_upload_meta(fid)
        except Exception:
            existed = False
        if not existed:
            return jsonify({'error': 'not found'}), 404
    return jsonify({'ok': True})

@api_bp.route('/api/uploads/<fid>/download', methods=['GET'])
def download_upload(fid):
    store = _get_store()
    rec = store.get(fid)
    if not rec:
        rec = _get_store_with_fallback(fid)
    if not rec:
        return jsonify({'error':'not found'}), 404
    folder = _ensure_folder()
    # locate the file (prefix match)
    disk_name = rec.get('disk_name') or ''
    candidates = [disk_name] if disk_name else os.listdir(folder)
    inline = str(request.args.get('inline', '')).strip().lower() in ('1', 'true', 'yes', 'y')
    mime_type = (rec.get('mime_type') or '').strip() or mimetypes.guess_type(rec.get('name') or '')[0] or None
    for entry in candidates:
        if entry and entry.startswith(fid):
            resp = send_from_directory(
                folder,
                entry,
                as_attachment=not inline,
                download_name=rec['name'],
                mimetype=mime_type,
            )
            if inline:
                resp.headers['Cache-Control'] = 'private, max-age=300'
                resp.headers['X-Content-Type-Options'] = 'nosniff'
                resp.headers['Accept-Ranges'] = 'bytes'
            return resp
    return jsonify({'error':'file missing'}), 404


