@api_bp.route('/api/tab15-files', methods=['POST'])
def create_tab15_file_api():
    payload = request.get_json(silent=True) or {}
    scope_key = (payload.get('scope_key') or payload.get('scopeKey') or '').strip()
    owner_key = (payload.get('owner_key') or payload.get('ownerKey') or '').strip()
    entry_type = (payload.get('entry_type') or payload.get('entryType') or '').strip() or 'ATTACHMENT'
    upload_token = (payload.get('upload_token') or payload.get('uploadToken') or '').strip()
    file_name = (payload.get('file_name') or payload.get('fileName') or '').strip()
    mime_type = (payload.get('mime_type') or payload.get('mimeType') or '').strip()
    kind = (payload.get('kind') or '').strip()
    description = (payload.get('description') or payload.get('desc') or '').strip()
    try:
        file_size = int(payload.get('file_size') or payload.get('fileSize') or 0)
    except Exception:
        file_size = 0
    is_primary = bool(payload.get('is_primary') or payload.get('isPrimary') or False)

    try:
        if not file_name and upload_token:
            meta = svc_get_upload_meta(upload_token)
            if meta:
                file_name = meta.get('name') or file_name
                file_size = file_size or int(meta.get('size') or 0)
                mime_type = mime_type or (meta.get('mime_type') or '')

        # 대표 구성도 교체 감지: 기존 DIAGRAM 파일이 있으면 old 정보 캡처
        _old_diagram = None
        _norm_et = (entry_type or '').strip().upper()
        if _norm_et in ('DIAGRAM', 'PRIMARY', 'DIAGRAMS') and scope_key and owner_key:
            try:
                _existing = svc_list_tab15_file_entries(
                    scope_key=scope_key, owner_key=owner_key, entry_type='DIAGRAM')
                if _existing:
                    _old_diagram = _existing[0]
            except Exception:
                pass

        item = svc_create_tab15_file_entry(
            scope_key=scope_key,
            owner_key=owner_key,
            entry_type=entry_type,
            upload_token=upload_token,
            file_name=file_name,
            file_size=file_size,
            mime_type=mime_type,
            is_primary=is_primary,
            kind=kind,
            description=description,
            replace_primary=True,
        )

        # ── 변경이력 ──
        # owner_key 에서 asset_id 추출 (“{scope}:{asset_id}” 형식)
        _file_asset_id = None
        if owner_key:
            _ok_part = owner_key.rsplit(':', 1)[-1] if ':' in owner_key else owner_key
            try:
                _file_asset_id = int(_ok_part)
            except (ValueError, IndexError):
                pass
        # scope_key 기반 entity_type 결정
        _file_entity_type = _resolve_file_entity_type(scope_key)
        if _old_diagram:
            # 대표 구성도 교체 → UPDATE로 기록 (이전 파일 → 새 파일)
            _try_record_change(
                action_type='UPDATE', entity_type=_file_entity_type,
                entity_id=_file_asset_id, tab_name='구성/파일',
                old_data={'file_name': _old_diagram.get('file_name', '')},
                new_data={'file_name': file_name},
                summary='대표 구성도 변경: ' + (_old_diagram.get('file_name', '') or '') + ' → ' + (file_name or ''),
            )
        else:
            _try_record_change(
                action_type='CREATE', entity_type=_file_entity_type,
                entity_id=_file_asset_id, tab_name='구성/파일',
                new_data={'file_name': file_name, 'entry_type': entry_type, 'kind': kind, 'description': description},
                summary='파일 추가: ' + (file_name or ''),
            )

        # For tab63-config: keep updated_at in sync with diagram changes.
        try:
            if (
                (scope_key or '').strip() == 'cost_opex_hardware_config'
                and (entry_type or '').strip().upper() == 'DIAGRAM'
                and (owner_key or '').strip()
            ):
                current = svc_get_cost_opex_hardware_config(owner_key=owner_key)
                memo_now = (current.get('memo') or '') if isinstance(current, dict) else ''
                svc_upsert_cost_opex_hardware_config(owner_key=owner_key, memo=memo_now)
        except Exception:
            pass
        return jsonify({'success': True, 'item': _tab15_file_item_to_dict(item)}), 201
    except ValueError as exc:
        return jsonify({'success': False, 'message': str(exc)}), 400
    except Exception:
        logger.exception('Failed to create tab15 file')
        return jsonify({'success': False, 'message': '파일 저장 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/tab15-files/<int:entry_id>', methods=['DELETE'])
def delete_tab15_file_api(entry_id: int):
    delete_upload = (request.args.get('delete_upload') or request.args.get('deleteUpload') or '1').strip().lower() in ('1', 'true', 'yes')
    try:
        item = svc_delete_tab15_file_entry(entry_id)
        if not item:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        # ── 변경이력 ──
        _del_owner = (item.get('owner_key') or '')
        _del_scope = (item.get('scope_key') or '')
        _del_asset_id = None
        if _del_owner:
            _ok_part = _del_owner.rsplit(':', 1)[-1] if ':' in _del_owner else _del_owner
            try:
                _del_asset_id = int(_ok_part)
            except (ValueError, IndexError):
                pass
        # scope_key 기반 entity_type 결정
        _del_entity_type = _resolve_file_entity_type(_del_scope)
        _del_fname = item.get('file_name') or ''
        _try_record_change(
            action_type='DELETE', entity_type=_del_entity_type,
            entity_id=_del_asset_id, tab_name='구성/파일',
            old_data={'file_name': _del_fname, 'entry_type': item.get('entry_type', ''), 'kind': item.get('kind', ''), 'description': item.get('description', '')},
            summary='파일 삭제: ' + _del_fname,
        )

        if delete_upload:
            token = item.get('upload_token') or ''
            if token:
                try:
                    _delete_uploaded_file(token)
                except Exception:
                    pass
        return jsonify({'success': True, 'deleted': 1, 'item': _tab15_file_item_to_dict(item)})
    except Exception:
        logger.exception('Failed to delete tab15 file entry')
        return jsonify({'success': False, 'message': '파일 삭제 중 오류가 발생했습니다.'}), 500


