# --- Governance / VPN Policy (DB-backed) ---


@api_bp.route('/api/network/vpn-partners', methods=['GET'])
def list_network_vpn_partners():
    if not _vpn_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_vpn_partner/net_vpn_line/net_vpn_line_device)'}), 500
    search = (request.args.get('q') or '').strip() or None
    partner_type = (request.args.get('partner_type') or request.args.get('partnerType') or '').strip() or None
    include_deleted = (request.args.get('include_deleted') or request.args.get('includeDeleted') or '').lower() in ('1', 'true', 'yes')
    try:
        query = NetVpnPartner.query
        if not include_deleted:
            query = query.filter((NetVpnPartner.is_deleted == 0) | (NetVpnPartner.is_deleted.is_(None)))
        if partner_type:
            query = query.filter(NetVpnPartner.partner_type == partner_type)
        if search:
            like = f"%{search}%"
            query = query.filter(NetVpnPartner.org_name.like(like))
        rows = query.order_by(NetVpnPartner.id.desc()).all()
        items = [_vpn_partner_to_dict(r) for r in rows]
        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to list VPN partners')
