@api_bp.route('/api/network/vpn-lines', methods=['POST'])
def create_network_vpn_line():
    if not _vpn_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_vpn_line)'}), 500
    payload = request.get_json(silent=True) or {}
    vpn_partner_id = _coerce_positive_int(payload.get('vpn_partner_id') or payload.get('partner_id'))
    created_by_user_id = _coerce_positive_int(payload.get('created_by_user_id') or payload.get('actor_user_id'))
    scope = (payload.get('scope') or payload.get('vpn_scope') or 'VPN1')
    scope = str(scope).strip() if scope is not None else 'VPN1'
    if not scope:
        scope = 'VPN1'
    if not vpn_partner_id:
        return jsonify({'success': False, 'message': 'vpn_partner_id is required'}), 400
    if not created_by_user_id:
        return jsonify({'success': False, 'message': 'created_by_user_id is required'}), 400
    try:
        partner = NetVpnPartner.query.filter(NetVpnPartner.id == vpn_partner_id).first()
        if not partner or int(partner.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': 'vpn_partner_id 대상이 존재하지 않습니다.'}), 400
        row = NetVpnLine(
            vpn_partner_id=vpn_partner_id,
            scope=scope,
            status=(payload.get('status') or '').strip() or None,
            line_speed=(payload.get('line_speed') or '').strip() or None,
            line_count=_coerce_positive_int(payload.get('line_count')),
            protocol=(payload.get('protocol') or '').strip() or None,
            manager=(payload.get('manager') or '').strip() or None,
            cipher=(payload.get('cipher') or '').strip() or None,
            upper_country=(payload.get('upper_country') or '').strip() or None,
            upper_country_address=(payload.get('upper_country_address') or '').strip() or None,
            lower_country=(payload.get('lower_country') or '').strip() or None,
            lower_country_address=(payload.get('lower_country_address') or '').strip() or None,
            note=(payload.get('note') or '').strip() or None,
            created_by_user_id=created_by_user_id,
            updated_by_user_id=created_by_user_id,
            updated_at=datetime.utcnow(),
            is_deleted=0,
        )
        db.session.add(row)
        db.session.commit()
        _try_record_vpn_change(
            action_type='CREATE',
            line_id=row.id,
            new_data=_vpn_line_to_dict(row),
            summary=f"VPN 회선 등록 ({row.scope})",
        )
        return jsonify({'success': True, 'item': _vpn_line_to_dict(row)}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create VPN line')
        return jsonify({'success': False, 'message': 'VPN 회선 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/network/vpn-lines/<int:line_id>', methods=['PUT'])
def update_network_vpn_line(line_id: int):
    if not _vpn_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_vpn_line)'}), 500
    payload = request.get_json(silent=True) or {}
    updated_by_user_id = _coerce_positive_int(payload.get('updated_by_user_id') or payload.get('actor_user_id'))
    if not updated_by_user_id:
        return jsonify({'success': False, 'message': 'updated_by_user_id is required'}), 400
    try:
        row = NetVpnLine.query.filter(NetVpnLine.id == line_id).first()
        if not row or int(row.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404
        old_data = _vpn_line_to_dict(row)
        updatable_fields = (
            'scope',
            'status',
            'line_speed',
            'line_count',
            'protocol',
            'manager',
            'cipher',
            'upper_country',
            'upper_country_address',
            'lower_country',
            'lower_country_address',
            'note',
        )
        for field in updatable_fields:
            if field not in payload:
                continue
            if field == 'line_count':
                setattr(row, field, _coerce_positive_int(payload.get(field)))
            elif field == 'scope':
                val = payload.get(field)
                if isinstance(val, str):
                    val = val.strip()
                setattr(row, field, (val or 'VPN1'))
            else:
                val = payload.get(field)
                if isinstance(val, str):
                    val = val.strip()
                setattr(row, field, val or None)
        row.updated_by_user_id = updated_by_user_id
        row.updated_at = datetime.utcnow()
        db.session.commit()
        _try_record_vpn_change(
            action_type='UPDATE',
            line_id=line_id,
            old_data=old_data,
            new_data=_vpn_line_to_dict(row),
        )
        return jsonify({'success': True, 'item': _vpn_line_to_dict(row)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update VPN line')
        return jsonify({'success': False, 'message': 'VPN 회선 수정 중 오류가 발생했습니다.'}), 500


