@api_bp.route('/api/network/vpn-lines/<int:line_id>/managers', methods=['POST'])
def create_network_vpn_line_manager(line_id: int):
    if not _vpn_tables_ready() or not _vpn_line_manager_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_vpn_line_manager)'}), 500

    auth = _require_login_for_write()
    if auth:
        return auth

    payload = request.get_json(silent=True) or {}
    actor_user_id = _coerce_positive_int(
        request.args.get('actor_user_id')
        or payload.get('actor_user_id')
        or payload.get('created_by_user_id')
        or payload.get('created_by')
    )
    if not actor_user_id:
        actor_user_id = _coerce_positive_int(_resolve_actor_user_id(None))
    if not actor_user_id:
        return jsonify({'success': False, 'message': '로그인이 필요합니다.'}), 401

    def _s(key: str) -> Optional[str]:
        val = payload.get(key)
        if val is None:
            return None
        token = str(val).strip()
        return token or None

    try:
        line = NetVpnLine.query.filter(NetVpnLine.id == line_id).first()
        if not line or int(line.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        email = _s('email')
        if not _is_valid_basic_email(email):
            return jsonify({'success': False, 'message': '이메일 형식이 올바르지 않습니다.'}), 400

        now = datetime.utcnow().isoformat(timespec='seconds')
        row = NetVpnLineManager(
            vpn_line_id=line_id,
            org=_s('org'),
            name=_s('name'),
            role=_s('role'),
            phone=_s('phone'),
            email=email,
            remark=_s('remark'),
            created_at=now,
            created_by_user_id=actor_user_id,
            updated_at=now,
            updated_by_user_id=actor_user_id,
            is_deleted=0,
        )
        db.session.add(row)
        db.session.commit()
        _try_record_vpn_change(
            action_type='CREATE',
            line_id=line_id,
            tab_name='담당자',
            new_data=_vpn_line_manager_to_dict(row),
            summary=f"담당자 등록 ({row.name or ''})",
        )
        return jsonify({'success': True, 'item': _vpn_line_manager_to_dict(row)}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create vpn line manager')
        return jsonify({'success': False, 'message': '담당자 등록 중 오류가 발생했습니다.'}), 500


