@api_bp.route('/api/network/vpn-line-devices/bulk-delete', methods=['POST'])
def bulk_delete_network_vpn_line_devices():
    if not _vpn_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_vpn_line_device)'}), 500
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids')
    actor_user_id = _coerce_positive_int(payload.get('actor_user_id') or payload.get('updated_by_user_id'))
    if not isinstance(ids, (list, tuple)) or not ids:
        return jsonify({'success': False, 'message': '삭제할 항목을 선택하세요.'}), 400
    if not actor_user_id:
        return jsonify({'success': False, 'message': 'actor_user_id is required'}), 400
    try:
        clean_ids = [int(x) for x in ids if _coerce_positive_int(x)]
        if not clean_ids:
            return jsonify({'success': False, 'message': '삭제할 항목을 선택하세요.'}), 400
        rows = NetVpnLineDevice.query.filter(NetVpnLineDevice.id.in_(clean_ids)).all()
        deleted: List[int] = []
        for row in rows:
            if int(row.is_deleted or 0) != 0:
                continue
            row.is_deleted = 1
            row.updated_by_user_id = actor_user_id
            row.updated_at = datetime.utcnow()
            deleted.append(row.id)
        db.session.commit()
        return jsonify({'success': True, 'deleted': deleted})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to bulk delete VPN line devices')
        return jsonify({'success': False, 'message': 'VPN 장비 삭제 중 오류가 발생했습니다.'}), 500


