@api_bp.route('/api/network/leased-lines', methods=['GET'])
def list_network_leased_lines():
    if not _leased_line_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_leased_line)'}), 500

    line_group = (request.args.get('line_group') or request.args.get('group') or '').strip()
    include_deleted = (request.args.get('include_deleted') or request.args.get('includeDeleted') or '').lower() in (
        '1',
        'true',
        'yes',
    )
    try:
        query = NetLeasedLine.query
        if line_group:
            query = query.filter(NetLeasedLine.line_group == line_group)
        if not include_deleted:
            query = query.filter((NetLeasedLine.is_deleted == 0) | (NetLeasedLine.is_deleted.is_(None)))
        rows = query.order_by(NetLeasedLine.id.desc()).all()
        items = [_leased_line_to_dict(r) for r in rows]
        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to list leased lines')
        return jsonify({'success': False, 'message': '전용회선 목록 조회 중 오류가 발생했습니다.'}), 500


