@api_bp.route('/api/network/leased-lines/<int:line_id>/tasks', methods=['POST'])
def create_network_leased_line_task(line_id: int):
    if not _leased_line_tables_ready() or not _leased_line_task_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_leased_line_task)'}), 500

    auth = _require_login_for_write()
    if auth:
        return auth

    payload = request.get_json(silent=True) or {}
    actor_user_id = _coerce_positive_int(
        request.args.get('actor_user_id')
        or payload.get('actor_user_id')
        or payload.get('created_by_user_id')
        or payload.get('created_by')
    )
    if not actor_user_id:
        actor_user_id = _coerce_positive_int(_resolve_actor_user_id(None))
    if not actor_user_id:
        return jsonify({'success': False, 'message': '로그인이 필요합니다.'}), 401

    def _s(key: str) -> Optional[str]:
        val = payload.get(key)
