def _ui_task_to_dict(row: UiTaskHistory) -> dict:
    payload = row.to_dict() if hasattr(row, 'to_dict') else {}
    payload.setdefault('id', row.id)
    payload.setdefault('scope_type', row.scope_type)
    payload.setdefault('scope_id', row.scope_id)
    payload.setdefault('scope_ref', row.scope_ref)
    payload.setdefault('status', row.status)
    payload.setdefault('task_no', row.task_no)
    payload.setdefault('name', row.name)
    payload.setdefault('type', row.type)
    payload.setdefault('category', row.category)
    payload.setdefault('start', row.start)
    payload.setdefault('end', row.end)
    payload['is_deleted'] = int(getattr(row, 'is_deleted', 0) or 0)
    return payload


def _ui_scope_type() -> str:
    s = (request.args.get('scope_type') or request.args.get('scopeType') or '').strip()
    return s


def _ui_scope_id() -> Optional[int]:
    return _coerce_positive_int(request.args.get('scope_id') or request.args.get('scopeId'))


def _ui_scope_ref() -> Optional[str]:
    s = (request.args.get('scope_ref') or request.args.get('scopeRef') or '').strip()
    return s or None


@api_bp.route('/api/ui/task-history', methods=['GET'])
def list_ui_task_history():
    if not _ui_task_history_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (ui_task_history)'}), 500

    scope_type = _ui_scope_type()
    scope_id = _ui_scope_id()
    scope_ref = _ui_scope_ref()
    if not scope_type:
        return jsonify({'success': False, 'message': 'scope_type는 필수입니다.'}), 400
    if not scope_id and not scope_ref:
        return jsonify({'success': False, 'message': 'scope_id 또는 scope_ref는 필수입니다.'}), 400

    include_deleted = (request.args.get('include_deleted') or request.args.get('includeDeleted') or '').lower() in (
        '1',
        'true',
        'yes',
    )

    try:
        query = UiTaskHistory.query.filter(UiTaskHistory.scope_type == scope_type)
        if scope_id:
            query = query.filter(UiTaskHistory.scope_id == scope_id)
        if scope_ref:
            query = query.filter(UiTaskHistory.scope_ref == scope_ref)
        if not include_deleted:
            query = query.filter((UiTaskHistory.is_deleted == 0) | (UiTaskHistory.is_deleted.is_(None)))
        rows = query.order_by(UiTaskHistory.id.asc()).all()
        items = [_ui_task_to_dict(r) for r in rows]
        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to list ui task history')
        return jsonify({'success': False, 'message': '작업이력 조회 중 오류가 발생했습니다.'}), 500


