    if not scope_id and not scope_ref:
        return jsonify({'success': False, 'message': 'scope_id 또는 scope_ref는 필수입니다.'}), 400

    payload = request.get_json(silent=True) or {}
    actor_user_id = _coerce_positive_int(
        request.args.get('actor_user_id')
        or payload.get('actor_user_id')
        or payload.get('updated_by_user_id')
        or payload.get('updated_by')
    )
    if not actor_user_id:
        actor_user_id = _coerce_positive_int(_resolve_actor_user_id(None))
    if not actor_user_id:
        return jsonify({'success': False, 'message': '로그인이 필요합니다.'}), 401

    def _s_if_present(key: str) -> Optional[str]:
        if key not in payload:
            return None
        val = payload.get(key)
        if val is None:
            return None
        token = str(val).strip()
        return token or None

    try:
        query = UiTaskHistory.query.filter(
            UiTaskHistory.id == task_id,
            UiTaskHistory.scope_type == scope_type,
        )
        if scope_id:
            query = query.filter(UiTaskHistory.scope_id == scope_id)
        if scope_ref:
            query = query.filter(UiTaskHistory.scope_ref == scope_ref)
        row = query.first()
        if not row or int(row.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        _task_old = _ui_task_to_dict(row)
        _task_old_status = row.status

        if 'status' in payload:
            v = _s_if_present('status')
            if not v:
                return jsonify({'success': False, 'message': '상태는 필수입니다.'}), 400
            row.status = v
        if 'task_no' in payload:
            row.task_no = _s_if_present('task_no')
        if 'name' in payload:
            v = _s_if_present('name')
            if not v:
                return jsonify({'success': False, 'message': '작업 이름은 필수입니다.'}), 400
            row.name = v
        if 'type' in payload:
            v = _s_if_present('type')
            if not v:
                return jsonify({'success': False, 'message': '작업 유형은 필수입니다.'}), 400
            row.type = v
        if 'category' in payload:
            v = _s_if_present('category')
            if not v:
                return jsonify({'success': False, 'message': '작업 구분은 필수입니다.'}), 400
            row.category = v
        if 'start' in payload:
            v = _s_if_present('start')
            if not v:
                return jsonify({'success': False, 'message': '시작일시는 필수입니다.'}), 400
            row.start = v
        if 'end' in payload:
            row.end = _s_if_present('end')

        row.updated_at = datetime.utcnow().isoformat(timespec='seconds')
        row.updated_by_user_id = actor_user_id
        db.session.commit()

        # 작업 상태 변경 알림
        if _task_old_status != row.status:
            try:
                from app.services.notification_service import notify_task_status_change
                notify_task_status_change(row, _task_old_status, row.status, actor_user_id)
                db.session.commit()
            except Exception:
                logger.exception('task notification failed')

        # ── 변경이력 ── (name → task_name 으로 리매핑)
        if 'name' in _task_old:
            _task_old['task_name'] = _task_old.pop('name')
        _task_new_u = _ui_task_to_dict(row)
        if 'name' in _task_new_u:
            _task_new_u['task_name'] = _task_new_u.pop('name')
        _try_record_change(
            action_type='UPDATE', entity_type='hardware_asset',
            entity_id=scope_id, tab_name='작업이력',
            old_data=_task_old, new_data=_task_new_u,
        )

        return jsonify({'success': True, 'item': _ui_task_to_dict(row)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update ui task history')
        return jsonify({'success': False, 'message': '작업이력 수정 중 오류가 발생했습니다.'}), 500


