# ──────────────────────────────────────────────────
# 작업보고서 → SMTP 이메일 발송
# ──────────────────────────────────────────────────
import smtplib as _smtplib
from email.mime.multipart import MIMEMultipart as _MIMEMultipart
from email.mime.text import MIMEText as _MIMEText
from html.parser import HTMLParser as _HTMLParser


def _inline_css_for_email(html_body: str) -> str:
    """이메일 전용 인라인 스타일을 적용한다.

    웹 CSS를 파싱하지 않고, 이메일 클라이언트에서 안전하게 동작하는
    스타일만 직접 매핑한다. (Gmail/Outlook/Naver 호환)
    """
    import re as _re

    # ── 0. <style> 블록에서 CSS 변수만 추출 ───────────────────
    css_vars = {}
    for raw in _re.findall(r'<style[^>]*>(.*?)</style>', html_body, _re.DOTALL | _re.IGNORECASE):
        for vm in _re.finditer(r'(--[\w-]+)\s*:\s*([^;]+);', raw):
            css_vars[vm.group(1)] = vm.group(2).strip()

    # ── 1. <style> 블록 제거 ──────────────────────────────────
    result = _re.sub(r'<style[^>]*>.*?</style>', '', html_body, flags=_re.DOTALL | _re.IGNORECASE)

    # ── 2. 기존 style 속성 모두 제거 (웹 전용 스타일 초기화) ──
    result = _re.sub(r'\s*style="[^"]*"', '', result)

    # ── 3. 이메일 전용 클래스→스타일 매핑 ─────────────────────
    _S = {
        'report-only':
            'margin:0;padding:0;background:#f3f4f6;'
            'font-family:Pretendard,Malgun Gothic,sans-serif;font-size:13px;color:#1f2937;',
        'report-main':
            'padding:24px 18px;',
        'report-sheet':
            'width:100%;max-width:780px;margin:0 auto;background:#ffffff;color:#1f2937;'
            'padding:45px 50px 60px;border:1px solid #d1d5db;'
            'box-shadow:0 10px 30px rgba(0,0,0,.08);',
        'report-header':
            'margin-bottom:28px;',
        'report-title-row':
            'margin-bottom:6px;',
        'report-title':
            'margin:0;font-size:40px;letter-spacing:1px;font-weight:800;color:#111827;',
        'status-pill':
            'display:inline-block;padding:5px 14px;border:1px solid #e5e7eb;'
            'border-radius:999px;background:#ffffff;color:#374151;font-size:13px;'
            'vertical-align:middle;margin-left:12px;line-height:1;'
            'box-shadow:0 1px 2px rgba(0,0,0,.04);',
        'status-dot':
            'display:inline-block;width:11px;height:11px;border-radius:50%;'
            'vertical-align:middle;margin-right:6px;',
        'status-text':
            'font-weight:600;font-size:13px;',
        'ws-run': 'background:#6366f1;',
        'ws-idle': 'background:#0ea5e9;',
        'ws-wait': 'background:#94a3b8;',
        'approval-grid':
            '',
        'approval-card':
            'border:2px solid #e5e7eb;border-radius:6px;overflow:hidden;background:#fff;',
        'approval-role':
            'font-size:12px;color:#111;padding:7px 10px;border-bottom:1px solid #e5e7eb;'
            'background:#f5f5f5;text-align:center;font-weight:700;letter-spacing:0.5px;',
        'sign-area':
            'height:88px;padding:10px;text-align:center;vertical-align:middle;',
        'approval-footer':
            'border-top:1px solid #e5e7eb;',
        'approval-name':
            'display:block;text-align:center;padding:5px 4px;font-size:12px;color:#1f2937;',
        'approval-date':
            'display:block;text-align:center;padding:5px 4px;font-size:11px;color:#6b7280;'
            'border-top:1px solid #e5e7eb;',
        'meta-table':
            'width:100%;border-collapse:collapse;',
        'section':
            'margin:0 0 20px;',
        'boxed':
            'border:2px solid #e5e7eb;border-radius:10px;background:#fff;overflow:hidden;',
        'section-title':
            'font-weight:700;margin:0;padding:10px 14px;border-bottom:2px solid #e5e7eb;'
            'background:#f8fafc;font-size:14px;color:#1e293b;letter-spacing:0.3px;',
        'editor':
            'display:block;width:100%;min-height:28px;padding:6px 10px;'
            'font-size:13px;line-height:1.7;color:#1f2937;',
        'checkbox-group':
            'padding:4px 8px;',
        'check':
            'display:inline-block;margin-right:12px;white-space:nowrap;font-size:13px;color:#374151;',
        'chip':
            'display:inline-block;padding:2px 8px;border-radius:4px;background:#f3f4f6;'
            'font-size:12px;margin:2px;',
        'preview-value':
            'font-size:13px;color:#1f2937;',
        'attach-name':
            'font-size:13px;color:#1f2937;',
        'report-toolbar':
            'display:none;',
        'thick-divider':
            'border:none;border-top:3px solid #e5e7eb;margin:24px 0;',
    }

    def _apply_class_styles(m):
        tag = m.group(0)
        ca = _re.search(r'class="([^"]*)"', tag)
        if not ca:
            return tag
        pieces = ''
        for cls in ca.group(1).split():
            s = _S.get(cls, '')
            if s:
                pieces += s
        if not pieces:
            return tag
        idx = tag.rfind('>')
        return tag[:idx] + f' style="{pieces}"' + tag[idx:]

    result = _re.sub(r'<[a-zA-Z][^>]*class="[^"]*"[^>]*>', _apply_class_styles, result)

    # ── 4. th/td 기본 스타일 ──────────────────────────────────
    _th_s = ('border:1px solid #e5e7eb;padding:9px 12px;font-size:13px;vertical-align:middle;'
             'background:#f8fafc;color:#374151;white-space:nowrap;font-weight:600;'
             'text-align:left;width:105px;')
    _td_s = ('border:1px solid #e5e7eb;padding:9px 12px;font-size:13px;vertical-align:middle;'
             'color:#1f2937;text-align:left;')

    def _style_th(m):
        tag = m.group(0)
        if 'style="' in tag:
            return tag
        idx = tag.rfind('>')
        return tag[:idx] + f' style="{_th_s}"' + tag[idx:]

    def _style_td(m):
        tag = m.group(0)
        if 'style="' in tag:
            return tag
        idx = tag.rfind('>')
        return tag[:idx] + f' style="{_td_s}"' + tag[idx:]

    result = _re.sub(r'<th\b[^>]*>', _style_th, result)
    result = _re.sub(r'<td\b[^>]*>', _style_td, result)

    # ── 4b. boxed 섹션 내부 테이블 외곽 border 제거 (웹과 동일) ──
    # 각 boxed 섹션 안의 <table> 내에서 첫 행 상단, 마지막 행 하단,
    # 첫 열 좌측, 마지막 열 우측 border를 제거한다.
    def _remove_outer_borders(box_html):
        rows = _re.findall(r'<tr[^>]*>.*?</tr>', box_html, _re.DOTALL)
        if not rows:
            return box_html
        for i, row in enumerate(rows):
            new_row = row
            cells = _re.findall(r'<(?:th|td)\b[^>]*>', row)
            for j, cell in enumerate(cells):
                new_cell = cell
                if i == 0:
                    new_cell = new_cell.replace('border:1px solid #e5e7eb', 'border:1px solid #e5e7eb;border-top:0')
                if i == len(rows) - 1:
                    new_cell = new_cell.replace('border:1px solid #e5e7eb', 'border:1px solid #e5e7eb;border-bottom:0')
                if j == 0:
                    if 'border-top:0' in new_cell or 'border-bottom:0' in new_cell:
                        new_cell = new_cell.replace('border:1px solid #e5e7eb;', 'border:1px solid #e5e7eb;border-left:0;')
                    else:
                        new_cell = new_cell.replace('border:1px solid #e5e7eb', 'border:1px solid #e5e7eb;border-left:0')
                if j == len(cells) - 1:
                    if 'border-top:0' in new_cell or 'border-bottom:0' in new_cell or 'border-left:0' in new_cell:
                        new_cell = new_cell.replace('border:1px solid #e5e7eb;', 'border:1px solid #e5e7eb;border-right:0;')
                    else:
                        new_cell = new_cell.replace('border:1px solid #e5e7eb', 'border:1px solid #e5e7eb;border-right:0')
                if new_cell != cell:
                    new_row = new_row.replace(cell, new_cell, 1)
            if new_row != row:
                box_html = box_html.replace(row, new_row, 1)
        return box_html
    # boxed 섹션에만 적용 (id="box-1", id="task-details-box", id="box-3")
    for box_id in ('box-1', 'task-details-box', 'box-3'):
        box_m = _re.search(
            rf'<div\b[^>]*id="{box_id}"[^>]*>.*?</table>\s*</div>',
            result, _re.DOTALL,
        )
        if box_m:
            result = result[:box_m.start()] + _remove_outer_borders(box_m.group(0)) + result[box_m.end():]

    # ── 5. 폼 요소 → 텍스트 변환 ─────────────────────────────
    def _replace_input(m):
        tag = m.group(0)
        vm = _re.search(r'value="([^"]*)"', tag)
        val = vm.group(1) if vm else ''
        tm = _re.search(r'type="([^"]*)"', tag)
        itype = tm.group(1).lower() if tm else 'text'
        if itype in ('checkbox', 'radio'):
            checked = 'checked' in tag.lower()
            if checked:
                return ('<span style="display:inline-block;width:16px;height:16px;'
                        'border-radius:3px;background:#6366f1;color:#fff;text-align:center;'
                        'line-height:16px;font-size:12px;vertical-align:middle;margin-right:3px;">&#10003;</span>')
            else:
                return ('<span style="display:inline-block;width:16px;height:16px;'
                        'border:1.5px solid #cbd5e1;border-radius:3px;background:#fff;'
                        'vertical-align:middle;margin-right:3px;">&nbsp;</span>')
        if itype == 'hidden':
            return ''
        # approval-name / approval-date 클래스 확인
        if 'approval-name' in tag:
            return f'<span style="display:block;text-align:center;padding:4px;font-size:12px;color:#1f2937;">{val}</span>'
        if 'approval-date' in tag:
            return f'<span style="display:block;text-align:center;padding:4px;font-size:11px;color:#6b7280;border-top:1px solid #e5e7eb;">{val}</span>'
        return f'<span style="font-size:13px;color:#1f2937;">{val}</span>'

    result = _re.sub(r'<input\b[^>]*/?\s*>', _replace_input, result)

    def _replace_select(m):
        full = m.group(0)
        sm = _re.search(r'<option[^>]*selected[^>]*>([^<]*)</option>', full, _re.IGNORECASE)
        val = sm.group(1) if sm else ''
        if not val:
            om = _re.search(r'<option[^>]*>([^<]*)</option>', full)
            val = om.group(1) if om else ''
        return f'<span style="font-size:13px;color:#1f2937;">{val}</span>'

    result = _re.sub(r'<select\b[^>]*>.*?</select>', _replace_select, result, flags=_re.DOTALL)

    def _replace_textarea(m):
        content = m.group(1) or ''
        return f'<span style="font-size:13px;color:#1f2937;white-space:pre-wrap;">{content}</span>'
    result = _re.sub(r'<textarea\b[^>]*>(.*?)</textarea>', _replace_textarea, result, flags=_re.DOTALL)

    # ── 5b. is-checked 라벨: 빈 체크박스 → 체크된 체크박스 변환 ──
    _unchecked_box = 'border:1.5px solid #cbd5e1;border-radius:3px;background:#fff;'
    _checked_box = 'border-radius:3px;background:#6366f1;color:#fff;text-align:center;'
    def _fix_checked_label(m):
        inner = m.group(1)
        inner = inner.replace(_unchecked_box, _checked_box)
        inner = inner.replace('>&nbsp;</span>', '>&#10003;</span>')
        return '<label' + inner
    result = _re.sub(r'<label\b([^>]*\bis-checked\b[^>]*>.*?</label>)', _fix_checked_label, result, flags=_re.DOTALL)

    # ── 5c. 이메일 불필요 요소 제거 ──────────────────────────
    result = _re.sub(r'<button\b[^>]*>.*?</button>', '', result, flags=_re.DOTALL)
    # hidden="" boolean 속성 가진 요소 제거 (aria-hidden, data-chip-hidden 등은 제외)
    result = _re.sub(
        r'<(\w+)\b([^>]*?\s)hidden(?:=""|\s|>)([^>]*)>.*?</\1>',
        '', result, flags=_re.DOTALL,
    )

    # ── 6. report-header → table 레이아웃 ─────────────────────
    hdr_m = _re.search(
        r'<header\b[^>]*report-header[^>]*>(.*?)</header>',
        result, _re.DOTALL,
    )
    if hdr_m:
        hdr_inner = hdr_m.group(1)
        appr_idx = hdr_inner.find('approval-grid')
        if appr_idx > 0:
            appr_div_start = hdr_inner.rfind('<div', 0, appr_idx)
            title_html = hdr_inner[:appr_div_start].strip()
            approval_html = hdr_inner[appr_div_start:].strip()
        else:
            title_html = hdr_inner
            approval_html = ''

        # approval cards → inline table
        if approval_html:
            cards = _re.findall(
                r'<div\b[^>]*approval-card[^>]*>(.*?)</div>\s*</div>',
                approval_html, _re.DOTALL)
            if cards:
                card_cells = ''
                for card in cards:
                    card_cells += (
                        '<td style="border:2px solid #e5e7eb;border-radius:6px;'
                        'vertical-align:top;width:160px;background:#fff;padding:0;">'
                        f'{card}</div></td>'
                    )
                approval_table = (
                    '<table style="border:none;border-collapse:separate;border-spacing:12px 0;"'
                    f' cellpadding="0" cellspacing="0"><tr>{card_cells}</tr></table>'
                )
            else:
                approval_table = approval_html
        else:
            approval_table = ''

        new_hdr = (
            '<table style="width:100%;border:none;border-collapse:collapse;'
            'margin-bottom:28px;" cellpadding="0" cellspacing="0"><tr>'
            '<td style="border:none;vertical-align:bottom;padding:0;width:50%;">'
            f'{title_html}'
            '</td>'
            '<td style="border:none;vertical-align:top;padding:0;text-align:right;">'
            f'{approval_table}'
            '</td></tr></table>'
        )
        result = result[:hdr_m.start()] + new_hdr + result[hdr_m.end():]

    # ── 7. HTML5 시맨틱 태그 → div ────────────────────────────
    result = _re.sub(r'<(main|section|nav|article|aside|footer)(\b[^>]*>)', r'<div\2', result)
    result = _re.sub(r'</(main|section|nav|article|aside|footer)>', '</div>', result)

    # ── 8. CSS var() 해석 ─────────────────────────────────────
    if css_vars:
        def _resolve_var(m):
            vn = m.group(1)
            fb = m.group(2)
            val = css_vars.get(vn, '')
            if not val and fb:
                val = fb.strip()
            return val if val else m.group(0)
        result = _re.sub(r'var\((--[\w-]+)(?:\s*,\s*([^)]+))?\)', _resolve_var, result)

    # ── 9. <img> 서명 크기 제한 ───────────────────────────────
    def _fix_img(m):
        tag = m.group(0)
        if 'style="' not in tag:
            idx = tag.rfind('>')
            return tag[:idx] + ' style="max-width:100%;max-height:70px;display:block;margin:0 auto;"' + tag[idx:]
        return tag
    result = _re.sub(r'<img\b[^>]*>', _fix_img, result)

    # ── 10. HTML 정리 (이메일에 불필요한 속성/요소 제거) ──────

    # share-section 래퍼 단순화: chip-label 텍스트만 추출 (class 제거 전 수행)
    def _simplify_share_sections(html):
        while True:
            m = _re.search(r'<div[^>]*share-section[^>]*>', html)
            if not m:
                break
            start = m.start()
            depth, pos = 0, start
            end = len(html)
            while pos < len(html):
                o = html.find('<div', pos)
                c = html.find('</div>', pos)
                if c < 0:
                    break
                if 0 <= o < c:
                    depth += 1
                    pos = o + 4
                else:
                    depth -= 1
                    if depth == 0:
                        end = c + 6
                        break
                    pos = c + 6
            block = html[start:end]
            labels = _re.findall(r'share-chip-label[^>]*>([^<]+)<', block)
            html = html[:start] + ', '.join(labels) + html[end:]
        return html
    result = _simplify_share_sections(result)

    # field-with-more 래퍼 → preview-value 텍스트만 (class 제거 전 수행)
    def _simplify_field_more(m):
        block = m.group(0)
        vm = _re.search(r'preview-value[^>]*>([^<]*)<', block)
        return vm.group(1).strip() if vm else ''
    result = _re.sub(
        r'<div[^>]*field-with-more[^>]*>.*?</div>',
        _simplify_field_more, result, flags=_re.DOTALL,
    )

    # data-*, aria-*, spellcheck, autocorrect, autocapitalize, role, placeholder, contenteditable, title
    result = _re.sub(r'\s(?:data-[\w-]+|aria-[\w-]+|spellcheck|autocorrect|autocapitalize|role|placeholder|contenteditable|title)="[^"]*"', '', result)
    # class 속성 제거 (이미 인라인 스타일 적용됨)
    result = _re.sub(r'\sclass="[^"]*"', '', result)
    # HTML 주석 제거
    result = _re.sub(r'<!--.*?-->', '', result, flags=_re.DOTALL)
    # 빈 span/div 제거 (반복 적용)
    for _ in range(3):
        result = _re.sub(r'<(span|div)[^>]*>\s*</\1>', '', result)
    # 빈 내용 <td ...></td> 안의 불필요한 래퍼 제거 안 함 (테이블 구조 유지)
    # <span><span>text</span></span> → <span>text</span> 단순화
    result = _re.sub(r'<span[^>]*><span[^>]*>([^<]*)</span></span>', r'<span>\1</span>', result)
    # 빈 comments-list, comments-section 제거
    result = _re.sub(r'<div id="comments-[^"]*"[^>]*>\s*</div>', '', result)

    # 연속 공백/빈줄 축소
    result = _re.sub(r'\n\s*\n', '\n', result)
    result = _re.sub(r'\t+', '', result)

    return result

# ── SMTP 설정 (DB 우선, 환경변수 폴백) ──────────────────────────────
def _get_smtp_config():
    """DB의 smtp_config(id=1) 행을 읽어 dict 로 반환. 없으면 환경변수/기본값."""
    try:
        row = SmtpConfig.query.filter_by(id=1).first()
    except Exception:
        row = None
    if row and row.host:
        enc = (row.encryption or 'STARTTLS').upper()
        _use_auth = getattr(row, 'use_auth', True)
        if _use_auth is None:
            _use_auth = True
        _verify_cert = getattr(row, 'verify_cert', True)
        if _verify_cert is None:
            _verify_cert = True
        return {
            'host': row.host or 'smtp.gmail.com',
            'port': row.port or 587,
            'user': row.username or '',
            'password': row.password or '',
            'from_name': row.from_name or 'Blossom',
            'from_email': row.from_email or '',
            'use_tls': enc == 'STARTTLS',
            'use_ssl': enc == 'SSL',
            'use_auth': bool(_use_auth),
            'verify_cert': bool(_verify_cert),
            'reply_to': getattr(row, 'reply_to', '') or '',
        }
    # DB에 저장이 없으면 환경변수 폴백
    return {
        'host': os.environ.get('SMTP_HOST', 'smtp.gmail.com'),
        'port': int(os.environ.get('SMTP_PORT', '587')),
        'user': os.environ.get('SMTP_USER', ''),
        'password': os.environ.get('SMTP_PASSWORD', ''),
        'from_name': os.environ.get('SMTP_FROM_NAME', 'Blossom'),
        'from_email': '',
        'use_tls': True,
        'use_ssl': False,
        'use_auth': True,
        'verify_cert': True,
        'reply_to': '',
    }


@api_bp.route('/api/task/smtp-config', methods=['GET'])
def get_smtp_config():
    """현재 SMTP 설정 상태를 확인한다 (비밀번호 제외)."""
    cfg = _get_smtp_config()
    return jsonify({
        'success': True,
        'configured': bool(cfg['host']) and (bool(cfg['user'] and cfg['password']) or not cfg.get('use_auth', True)),
        'host': cfg['host'],
        'port': cfg['port'],
        'user': cfg['user'],
        'from_name': cfg['from_name'],
        'use_auth': cfg.get('use_auth', True),
    })


@api_bp.route('/api/task/smtp-config', methods=['PUT'])
def update_smtp_config():
    """SMTP 설정을 런타임에 업데이트한다 (DB에 저장)."""
    payload = request.get_json(silent=True) or {}
    try:
        row = SmtpConfig.query.filter_by(id=1).first()
        if not row:
            row = SmtpConfig(id=1)
            db.session.add(row)
        if 'host' in payload:
            row.host = payload['host']
        if 'port' in payload:
            row.port = int(payload['port'])
        if 'user' in payload:
            row.username = payload['user']
        if 'password' in payload and payload['password'] != '********':
            row.password = payload['password']
        if 'from_name' in payload:
            row.from_name = payload['from_name']
        from datetime import datetime as _dt_smtp
        row.updated_at = _dt_smtp.now().strftime('%Y-%m-%d %H:%M:%S')
        db.session.commit()
    except Exception as e:
        db.session.rollback()
        return jsonify({'success': False, 'message': str(e)}), 500
    return jsonify({'success': True, 'message': 'SMTP 설정이 업데이트되었습니다.'})


@api_bp.route('/api/task/send-email', methods=['POST'])
def send_task_email():
    """HTML 보고서를 이메일로 직접 발송한다."""
    cfg = _get_smtp_config()
    _use_auth = cfg.get('use_auth', True)
    if _use_auth and (not cfg['user'] or not cfg['password']):
        return jsonify({
            'success': False,
            'message': 'SMTP 설정이 필요합니다. 관리자에게 문의하거나 설정 페이지에서 SMTP를 구성하세요.',
            'need_config': True,
        }), 400
    if not cfg.get('host'):
        return jsonify({
            'success': False,
            'message': 'SMTP 호스트가 설정되지 않았습니다.',
            'need_config': True,
        }), 400

    payload = request.get_json(silent=True) or {}
    to_raw = payload.get('to', '').strip()
    cc_raw = payload.get('cc', '').strip()
    subject = payload.get('subject', '[작업보고서]').strip()
    html_body = payload.get('html', '')

    if not to_raw:
        return jsonify({'success': False, 'message': '받는 사람을 입력하세요.'}), 400
    if not html_body:
        return jsonify({'success': False, 'message': '본문 HTML이 없습니다.'}), 400

    # 여러 수신자 지원 (쉼표·세미콜론 구분)
    import re as _re_email
    to_addrs = [a.strip() for a in _re_email.split(r'[,;]', to_raw) if a.strip()]
    cc_addrs = [a.strip() for a in _re_email.split(r'[,;]', cc_raw) if a.strip()] if cc_raw else []

    try:
        # 이메일 클라이언트 호환: <style>→인라인 style 변환
        inlined_html = _inline_css_for_email(html_body)

        # DEBUG: 발송 HTML 덤프
        logger.info('[EMAIL] input html len=%d, inlined len=%d', len(html_body), len(inlined_html))
        try:
            with open('_tmp_email_debug_input.html', 'w', encoding='utf-8') as _df:
                _df.write(html_body)
            with open('_tmp_email_debug_output.html', 'w', encoding='utf-8') as _df:
                _df.write(inlined_html)
        except Exception:
            pass

        sender = cfg.get('from_email') or cfg.get('user') or 'noreply@localhost'
        msg = _MIMEMultipart('alternative')
        msg['Subject'] = subject
        msg['From'] = f'{cfg["from_name"]} <{sender}>'
        msg['To'] = ', '.join(to_addrs)
        if cc_addrs:
            msg['Cc'] = ', '.join(cc_addrs)
        # Reply-To 헤더 (사내 메일: 발신 주소와 회신 주소가 다를 수 있음)
        _reply_to = cfg.get('reply_to', '')
        if _reply_to:
            msg['Reply-To'] = _reply_to

        # HTML 파트
        html_part = _MIMEText(inlined_html, 'html', 'utf-8')
        msg.attach(html_part)

        all_recipients = to_addrs + cc_addrs

        # SSL context (자체서명 인증서 지원)
        import ssl as _ssl_mod
        _verify = cfg.get('verify_cert', True)
        _ssl_ctx = _ssl_mod.create_default_context()
        if not _verify:
            _ssl_ctx.check_hostname = False
            _ssl_ctx.verify_mode = _ssl_mod.CERT_NONE

        if cfg.get('use_ssl'):
            with _smtplib.SMTP_SSL(cfg['host'], cfg['port'], timeout=15, context=_ssl_ctx) as smtp:
                if _use_auth:
                    smtp.login(cfg['user'], cfg['password'])
                smtp.sendmail(sender, all_recipients, msg.as_string())
        else:
            with _smtplib.SMTP(cfg['host'], cfg['port'], timeout=15) as smtp:
                smtp.ehlo()
                if cfg.get('use_tls'):
                    smtp.starttls(context=_ssl_ctx)
                    smtp.ehlo()
                if _use_auth:
                    smtp.login(cfg['user'], cfg['password'])
                smtp.sendmail(sender, all_recipients, msg.as_string())

        logger.info('Email sent to %s (cc: %s) subject: %s', to_addrs, cc_addrs, subject)
        return jsonify({'success': True, 'message': '메일이 발송되었습니다.'})
    except _smtplib.SMTPAuthenticationError:
        logger.exception('SMTP auth failed')
        return jsonify({'success': False, 'message': 'SMTP 인증 실패. 이메일/비밀번호를 확인하세요.'}), 401
    except Exception as exc:
        logger.exception('Failed to send email')
        return jsonify({'success': False, 'message': f'메일 발송 실패: {exc}'}), 500


@api_bp.route('/api/network/leased-lines/<int:line_id>/managers', methods=['GET'])
def list_network_leased_line_managers(line_id: int):
    if not _leased_line_tables_ready() or not _leased_line_manager_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_leased_line_manager)'}), 500

    include_deleted = (request.args.get('include_deleted') or request.args.get('includeDeleted') or '').lower() in (
        '1',
        'true',
        'yes',
    )
    try:
        line = NetLeasedLine.query.filter(NetLeasedLine.id == line_id).first()
        if not line or int(line.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        query = NetLeasedLineManager.query.filter(NetLeasedLineManager.line_id == line_id)
        if not include_deleted:
            query = query.filter((NetLeasedLineManager.is_deleted == 0) | (NetLeasedLineManager.is_deleted.is_(None)))
        rows = query.order_by(NetLeasedLineManager.id.asc()).all()
        items = [_leased_line_manager_to_dict(r) for r in rows]
        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to list leased line managers')
        return jsonify({'success': False, 'message': '담당자 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/network/leased-lines/<int:line_id>/managers', methods=['POST'])
def create_network_leased_line_manager(line_id: int):
    if not _leased_line_tables_ready() or not _leased_line_manager_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_leased_line_manager)'}), 500

    auth = _require_login_for_write()
    if auth:
        return auth

    payload = request.get_json(silent=True) or {}
    actor_user_id = _coerce_positive_int(
        request.args.get('actor_user_id')
        or payload.get('actor_user_id')
        or payload.get('created_by_user_id')
        or payload.get('created_by')
    )
    if not actor_user_id:
        actor_user_id = _coerce_positive_int(_resolve_actor_user_id(None))
    if not actor_user_id:
        return jsonify({'success': False, 'message': '로그인이 필요합니다.'}), 401

    def _s(key: str) -> Optional[str]:
        val = payload.get(key)
        if val is None:
            return None
        token = str(val).strip()
        return token or None

    try:
        line = NetLeasedLine.query.filter(NetLeasedLine.id == line_id).first()
        if not line or int(line.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        email = _s('email')
        if not _is_valid_basic_email(email):
            return jsonify({'success': False, 'message': '이메일 형식이 올바르지 않습니다.'}), 400

        now = datetime.utcnow().isoformat(timespec='seconds')
        row = NetLeasedLineManager(
            line_id=line_id,
            org=_s('org'),
            name=_s('name'),
            role=_s('role'),
            phone=_s('phone'),
            email=email,
            remark=_s('remark'),
            created_at=now,
            created_by_user_id=actor_user_id,
            updated_at=now,
            updated_by_user_id=actor_user_id,
            is_deleted=0,
        )
        db.session.add(row)
        db.session.commit()
        _try_record_leased_line_change(
            action_type='CREATE',
            line_id=line_id,
            tab_name='담당자',
            new_data=_leased_line_manager_to_dict(row),
            summary=f"담당자 등록 ({row.name or ''})",
        )
        return jsonify({'success': True, 'item': _leased_line_manager_to_dict(row)}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create leased line manager')
        return jsonify({'success': False, 'message': '담당자 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/network/leased-lines/<int:line_id>/managers/<int:manager_id>', methods=['PUT'])
def update_network_leased_line_manager(line_id: int, manager_id: int):
    if not _leased_line_tables_ready() or not _leased_line_manager_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (net_leased_line_manager)'}), 500

    auth = _require_login_for_write()
    if auth:
        return auth

    payload = request.get_json(silent=True) or {}
    actor_user_id = _coerce_positive_int(
        request.args.get('actor_user_id')
        or payload.get('actor_user_id')
        or payload.get('updated_by_user_id')
        or payload.get('updated_by')
    )
    if not actor_user_id:
        actor_user_id = _coerce_positive_int(_resolve_actor_user_id(None))
    if not actor_user_id:
        return jsonify({'success': False, 'message': '로그인이 필요합니다.'}), 401

    def _s(key: str) -> Optional[str]:
        if key not in payload:
            return None
        val = payload.get(key)
        if val is None:
            return None
        token = str(val).strip()
        return token or None

    try:
        line = NetLeasedLine.query.filter(NetLeasedLine.id == line_id).first()
        if not line or int(line.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        row = NetLeasedLineManager.query.filter(
            NetLeasedLineManager.id == manager_id,
            NetLeasedLineManager.line_id == line_id,
        ).first()
        if not row or int(row.is_deleted or 0) != 0:
            return jsonify({'success': False, 'message': '대상을 찾을 수 없습니다.'}), 404

        old_data = _leased_line_manager_to_dict(row)

        if 'org' in payload:
            row.org = _s('org')
        if 'name' in payload:
            row.name = _s('name')
        if 'role' in payload:
            row.role = _s('role')
        if 'phone' in payload:
            row.phone = _s('phone')
        if 'email' in payload:
            email = _s('email')
            if not _is_valid_basic_email(email):
                return jsonify({'success': False, 'message': '이메일 형식이 올바르지 않습니다.'}), 400
            row.email = email
        if 'remark' in payload:
            row.remark = _s('remark')

        row.updated_at = datetime.utcnow().isoformat(timespec='seconds')
        row.updated_by_user_id = actor_user_id
        db.session.commit()
        _try_record_leased_line_change(
            action_type='UPDATE',
            line_id=line_id,
            tab_name='담당자',
            old_data=old_data,
            new_data=_leased_line_manager_to_dict(row),
        )
        return jsonify({'success': True, 'item': _leased_line_manager_to_dict(row)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update leased line manager')
        return jsonify({'success': False, 'message': '담당자 수정 중 오류가 발생했습니다.'}), 500


