# -----------------------------------------------------------------------------
# Settings: Memo (user memo groups + memos)
# -----------------------------------------------------------------------------


def _memo_tables_ready() -> bool:
    try:
        insp = db.inspect(db.engine)
        return insp.has_table('user_memo_group') and insp.has_table('user_memo')
    except Exception:
        logger.exception('Failed to inspect memo tables')
        return False


def _memo_require_auth_user_id():
    """Resolve current AuthUser.id from session.

    Returns:
        (user_id, error_response)
    """
    raw_uid = session.get('user_id')
    if raw_uid is not None:
        try:
            uid = int(raw_uid)
        except (TypeError, ValueError):
            uid = None
        if uid:
            return uid, None

    emp_no = (session.get('emp_no') or '').strip()
    if emp_no:
        try:
            u = AuthUser.query.filter_by(emp_no=emp_no).first()
        except Exception:
            logger.exception('Failed to resolve AuthUser for emp_no=%s', emp_no)
            u = None
        if u and u.id:
            return int(u.id), None

    return None, (jsonify({'success': False, 'message': '로그인이 필요합니다.'}), 401)


def _memo_group_to_item(row: UserMemoGroup, memo_count: int = 0) -> dict:
    return {
        'id': int(row.id),
        'name': (row.name or '').strip(),
        'memo_count': int(memo_count or 0),
        'sort_order': int(getattr(row, 'sort_order', 0) or 0),
        'created_at': row.created_at,
        'updated_at': row.updated_at,
    }


def _memo_to_item(row: UserMemo) -> dict:
    return {
        'id': int(row.id),
        'group_id': int(row.group_id),
        'sort_order': int(getattr(row, 'sort_order', 0) or 0),
        'title': row.title or '',
        'body': row.body or '',
        'starred': bool(int(row.starred or 0)),
        'pinned': bool(int(row.pinned or 0)),
        'created_at': row.created_at,
        'updated_at': row.updated_at,
    }


@api_bp.route('/api/memo/groups', methods=['GET'])
def list_user_memo_groups():
    if not _memo_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (user_memo_group/user_memo)'}), 500

    uid, err = _memo_require_auth_user_id()
    if err:
        return err

    try:
        groups = (
            UserMemoGroup.query
            .filter(UserMemoGroup.owner_user_id == uid)
            .filter(UserMemoGroup.is_deleted == 0)
            .order_by(UserMemoGroup.id.asc())
            .all()
        )
        # Ensure a stable default group exists.
        default = None
        for g in groups:
            if (g.name or '').strip() == '기본보기':
                default = g
                break
        if not groups or default is None:
            default = UserMemoGroup(owner_user_id=uid, name='기본보기', sort_order=0)
            db.session.add(default)
            db.session.commit()
            # Re-load to keep ordering stable
            groups = (
                UserMemoGroup.query
                .filter(UserMemoGroup.owner_user_id == uid)
                .filter(UserMemoGroup.is_deleted == 0)
                .order_by(UserMemoGroup.id.asc())
                .all()
            )

        # Return '기본보기' first, then honor manual ordering.
        groups = sorted(
            groups,
            key=lambda g: (
                0 if (g.name or '').strip() == '기본보기' else 1,
                int(getattr(g, 'sort_order', 0) or 0),
                int(g.id),
            ),
        )

        rows = (
            db.session.query(UserMemo.group_id, func.count(UserMemo.id))
            .filter(UserMemo.owner_user_id == uid)
            .filter(UserMemo.is_deleted == 0)
            .group_by(UserMemo.group_id)
            .all()
        )
        counts = {int(gid): int(cnt) for gid, cnt in rows}
        items = [_memo_group_to_item(g, counts.get(int(g.id), 0)) for g in groups]
        return jsonify({'success': True, 'items': items, 'limits': {'max_groups': 11, 'max_memos_per_group': 50}})
    except Exception:
        logger.exception('Failed to list memo groups')
        return jsonify({'success': False, 'message': '그룹 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/memo/groups', methods=['POST'])
def create_user_memo_group():
    if not _memo_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (user_memo_group/user_memo)'}), 500

    auth = _require_login_for_write()
    if auth:
        return auth

    uid, err = _memo_require_auth_user_id()
    if err:
        return err

    payload = request.get_json(silent=True) or {}
    name = (payload.get('name') or '').strip()
    if not name:
        return jsonify({'success': False, 'message': '그룹 이름이 필요합니다.'}), 400
    if len(name) > 50:
        return jsonify({'success': False, 'message': '그룹 이름은 50자 이내여야 합니다.'}), 400

    try:
        existing = (
            UserMemoGroup.query
            .filter(UserMemoGroup.owner_user_id == uid)
            .filter(UserMemoGroup.is_deleted == 0)
            .count()
        )

        # Policy: group total (including '기본보기') must be <= 11.
        # Some flows may create groups before the default is auto-created by the list API,
        # so we reserve one slot for '기본보기' if it doesn't exist yet.
        has_default = (
            UserMemoGroup.query
            .filter(UserMemoGroup.owner_user_id == uid)
            .filter(UserMemoGroup.is_deleted == 0)
            .filter(func.trim(UserMemoGroup.name) == '기본보기')
            .count()
        )
        effective_total = int(existing or 0) + (0 if int(has_default or 0) > 0 else 1)
        if effective_total >= 11:
            return jsonify({'success': False, 'message': '그룹은 최대 11개까지 만들 수 있습니다.'}), 400

        # Append at the end of current group order (excluding default group)
        max_sort = (
            db.session.query(func.max(UserMemoGroup.sort_order))
            .filter(UserMemoGroup.owner_user_id == uid)
            .filter(UserMemoGroup.is_deleted == 0)
            .filter(func.trim(UserMemoGroup.name) != '기본보기')
            .scalar()
        )
        next_sort = int(max_sort or 0) + 1
        row = UserMemoGroup(owner_user_id=uid, name=name, sort_order=next_sort)
        db.session.add(row)
        db.session.commit()
        return jsonify({'success': True, 'item': _memo_group_to_item(row, 0)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create memo group')
        return jsonify({'success': False, 'message': '그룹 생성 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/memo/groups/<int:group_id>', methods=['DELETE'])
def delete_user_memo_group(group_id: int):
    if not _memo_tables_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (user_memo_group/user_memo)'}), 500

    auth = _require_login_for_write()
    if auth:
        return auth

    uid, err = _memo_require_auth_user_id()
    if err:
        return err

    try:
        grp = (
            UserMemoGroup.query
            .filter(UserMemoGroup.id == int(group_id))
            .filter(UserMemoGroup.owner_user_id == int(uid))
            .filter(UserMemoGroup.is_deleted == 0)
            .first()
        )
        if not grp:
            return jsonify({'success': False, 'message': '그룹을 찾을 수 없습니다.'}), 404

        if (grp.name or '').strip() == '기본보기':
            return jsonify({'success': False, 'message': '기본 그룹은 삭제할 수 없습니다.'}), 400

        now = func.current_timestamp()
        grp.is_deleted = 1
        grp.updated_at = now

        # Soft-delete memos in the group as well
        (
            UserMemo.query
            .filter(UserMemo.owner_user_id == int(uid))
            .filter(UserMemo.group_id == int(group_id))
            .filter(UserMemo.is_deleted == 0)
            .update({'is_deleted': 1, 'updated_at': now}, synchronize_session=False)
        )

        db.session.add(grp)
        db.session.commit()
        return jsonify({'success': True})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete memo group')
        return jsonify({'success': False, 'message': '그룹 삭제 중 오류가 발생했습니다.'}), 500


