# -----------------------------------------------------------------------------
# Insight: IT Blog (blog)
# -----------------------------------------------------------------------------


def _blog_is_admin_session() -> bool:
    try:
        role = (session.get('role') or '').strip()
    except Exception:
        role = ''
    if role in ('admin', 'ADMIN', '관리자'):
        return True
    # Fallback: check AuthUser role when available
    try:
        uid = session.get('user_id')
        if uid is not None:
            try:
                uid_int = int(uid)
            except (TypeError, ValueError):
                uid_int = None
            if uid_int:
                from app.models import AuthUser

                u = AuthUser.query.get(uid_int)
                if u and (u.role or '').strip().upper() == 'ADMIN':
                    return True
    except Exception:
        pass
    return False


def _blog_resolve_current_author() -> str:
    # Prefer name-ish keys
    for k in ('user_name', 'username', 'name'):
        try:
            v = session.get(k)
        except Exception:
            v = None
        if v is None:
            continue
        s = str(v).strip()
        if s:
            return s

    # Prefer UserProfile by emp_no (most stable)
    try:
        emp_no = (session.get('emp_no') or '').strip()
    except Exception:
        emp_no = ''
    if emp_no:
        try:
            prof = UserProfile.query.filter_by(emp_no=emp_no).first()
        except Exception:
            prof = None
        if prof:
            name = (prof.name or '').strip()
            if name:
                return name
        return emp_no

    # Fallback: AuthUser via user_id
    try:
        uid = session.get('user_id')
        uid_int = int(uid) if uid is not None else None
    except (TypeError, ValueError):
        uid_int = None
    if uid_int:
        try:
            from app.models import AuthUser

            u = AuthUser.query.get(uid_int)
        except Exception:
            u = None
        if u:
            cand = (u.emp_no or '').strip()
            if cand:
                return cand
            if u.email:
                prefix = (u.email.split('@')[0] or '').strip()
                if prefix:
                    return prefix
    return ''


def _blog_resolve_author_meta(author_val: str) -> dict:
    """Resolve author metadata (department + avatar).

    Blog rows only store `author` as a string, so we best-effort map it to org_user:
    - emp_no match (preferred)
    - name match (fallback)
    """

    author = (author_val or '').strip()
    if not author:
        return {'department': '', 'avatarUrl': ''}

    prof = None
    try:
        prof = UserProfile.query.filter_by(emp_no=author).first()
    except Exception:
        prof = None

    if not prof:
        try:
            prof = UserProfile.query.filter(UserProfile.name == author).first()
        except Exception:
            prof = None

    if not prof:
        return {'department': '', 'avatarUrl': ''}

    dept_name = ''
    try:
        ref = getattr(prof, 'department_ref', None)
        if ref is not None:
            dept_name = (getattr(ref, 'dept_name', '') or '').strip()
    except Exception:
        dept_name = ''

    if not dept_name:
        try:
            dept_name = (getattr(prof, 'department', '') or '').strip()
        except Exception:
            dept_name = ''

    avatar_url = ''
    try:
        avatar_url = (getattr(prof, 'profile_image', '') or '').strip()
    except Exception:
        avatar_url = ''

    return {'department': dept_name, 'avatarUrl': avatar_url}


def _blog_tags_normalize(tags_val) -> str:
    if tags_val is None:
        return ''
    if isinstance(tags_val, list):
        parts = [str(x).strip() for x in tags_val]
        parts = [p for p in parts if p]
        return ','.join(parts)[:500]
    raw = str(tags_val).strip()
    if not raw:
        return ''
    # allow comma separated
    parts = [p.strip() for p in raw.split(',')]
    parts = [p for p in parts if p]
    return ','.join(parts)[:500]


def _blog_attachments_to_json_text(val) -> str:
    """Serialize attachments list as JSON text.

    Keeps payload bounded without truncating mid-JSON.
    """

    if val is None:
        return ''
    if isinstance(val, str):
        # Assume caller already provided JSON text.
        return val[:20000]
    if not isinstance(val, list):
        return ''

    safe_items: List[dict] = []
    for it in val[:10]:
        if not isinstance(it, dict):
            continue
        # Back-compat: accept both name/original_name keys.
        name = (it.get('original_name') or it.get('name') or '').strip()
        stored = (it.get('stored_name') or '').strip()
        download_url = (it.get('download_url') or '').strip()
        content_type = (it.get('content_type') or it.get('type') or '').strip()
        try:
            size = int(it.get('size') or it.get('file_size') or 0)
        except Exception:
            size = 0

        safe_items.append({
            'name': name[:512],
            'original_name': name[:512],
            'stored_name': stored[:255],
            'size': max(0, size),
            'content_type': content_type[:255],
            'download_url': download_url[:1024],
        })

    # Ensure final JSON fits into DB without breaking JSON.
    while safe_items:
        try:
            txt = json.dumps(safe_items, ensure_ascii=False)
        except Exception:
            return ''
        if len(txt) <= 20000:
            return txt
        safe_items.pop()
    return '[]'


def _blog_json_text_to_obj(val: str):
    if not val:
        return []
    try:
        parsed = json.loads(val)
    except Exception:
        return []
    return parsed if isinstance(parsed, list) else []


def _blog_normalize_attachments_for_response(post_id: int, attachments):
    items = attachments if isinstance(attachments, list) else []
    out: List[dict] = []
    for it in items:
        if not isinstance(it, dict):
            continue
        name = (it.get('original_name') or it.get('name') or '').strip()
        stored = (it.get('stored_name') or '').strip()
        download_url = (it.get('download_url') or '').strip()
        if stored and not download_url:
            download_url = f"/api/insight/blog/posts/{post_id}/attachments/{stored}/download"

        try:
            size = int(it.get('size') or it.get('file_size') or 0)
        except Exception:
            size = 0

        out.append({
            'name': name or '첨부파일',
            'original_name': name or '첨부파일',
            'stored_name': stored,
            'size': max(0, size),
            'content_type': (it.get('content_type') or it.get('type') or '').strip(),
            'download_url': download_url,
        })
    return out


_BLOG_INSIGHT_IMAGES_CACHE = {
    'mtime': None,
    'urls': [],
}


def _blog_insight_image_urls() -> List[str]:
    """Return available insight image URLs from /static/image/insight.

    This is used to:
    - assign a stable image when creating a post
    - normalize/repair stale image urls stored in DB

    It auto-adapts when new images are added to the folder.
    """

    try:
        static_root = current_app.static_folder or ''
        insight_dir = os.path.join(static_root, 'image', 'insight')
        if not insight_dir or not os.path.isdir(insight_dir):
            return []

        try:
            mtime = os.path.getmtime(insight_dir)
        except Exception:
            mtime = None

        if (
            _BLOG_INSIGHT_IMAGES_CACHE.get('urls')
            and _BLOG_INSIGHT_IMAGES_CACHE.get('mtime') == mtime
        ):
            return list(_BLOG_INSIGHT_IMAGES_CACHE.get('urls') or [])

        exts = ('.jpg', '.jpeg', '.png', '.gif', '.webp', '.svg')
        names: List[str] = []
        for name in os.listdir(insight_dir):
            if not name or name.startswith('.'):  # ignore hidden
                continue
            low = name.lower()
            if not low.endswith(exts):
                continue
            full = os.path.join(insight_dir, name)
            if os.path.isfile(full):
                names.append(name)
        names.sort()

        urls = [f"/static/image/insight/{n}" for n in names]
        _BLOG_INSIGHT_IMAGES_CACHE['mtime'] = mtime
        _BLOG_INSIGHT_IMAGES_CACHE['urls'] = urls
        return list(urls)
    except Exception:
        return []


def _blog_pick_insight_image_deterministic(seed: str) -> str:
    urls = _blog_insight_image_urls()
    if not urls:
        return ''

    s = (seed or '').strip()
    if not s:
        return urls[0]

    h = 0
    for ch in s:
        h = ((h * 31) + ord(ch)) & 0xFFFFFFFF
    return urls[h % len(urls)]


def _blog_is_valid_insight_image_url(url: str) -> bool:
    u = (url or '').strip()
    if not u:
        return False
    if u.startswith('data:image/'):
        return True
    if not u.startswith('/static/image/insight/'):
        return False

    base = os.path.basename(u.split('?', 1)[0])
    if not base:
        return False
    urls = _blog_insight_image_urls()
    allowed = {os.path.basename(x) for x in urls}
    return base in allowed


def _blog_normalize_image_url(url: str, seed: str) -> str:
    u = (url or '').strip()
    if not u:
        return _blog_pick_insight_image_deterministic(seed)
    if u.startswith('data:image/'):
        return u
    if _blog_is_valid_insight_image_url(u):
        base = os.path.basename(u.split('?', 1)[0])
        return f"/static/image/insight/{base}"
    return _blog_pick_insight_image_deterministic(seed)


@api_bp.route('/api/insight/blog/posts', methods=['GET'])
def list_blog_posts():
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    q = (request.args.get('q') or '').strip()
    try:
        limit = int(request.args.get('limit') or 0)
    except (TypeError, ValueError):
        limit = 0
    try:
        offset = int(request.args.get('offset') or 0)
    except (TypeError, ValueError):
        offset = 0
    if limit <= 0:
        limit = 200
    limit = max(1, min(50, limit))
    offset = max(0, offset)
    try:
        query = Blog.query
        if q:
            like = f"%{q}%"
            query = query.filter(or_(Blog.title.ilike(like), Blog.content_html.ilike(like), Blog.tags.ilike(like)))

        total = None
        try:
            total = query.count()
        except Exception:
            total = None

        rows = query.order_by(Blog.id.desc()).offset(offset).limit(limit).all()

        like_counts = {}
        liked_post_ids = set()
        comment_counts = {}
        if _blog_like_table_ready():
            try:
                post_ids = [int(r.id) for r in rows if getattr(r, 'id', None) is not None]
            except Exception:
                post_ids = []

            if post_ids:
                try:
                    like_counts = dict(
                        db.session.query(BlogLike.post_id, func.count(BlogLike.id))
                        .filter(BlogLike.post_id.in_(post_ids))
                        .group_by(BlogLike.post_id)
                        .all()
                    )
                except Exception:
                    like_counts = {}

                # likedByMe depends on current session emp_no -> UserProfile
                try:
                    emp_no = (session.get('emp_no') or '').strip()
                except Exception:
                    emp_no = ''
                if emp_no:
                    try:
                        prof = UserProfile.query.filter_by(emp_no=emp_no).first()
                    except Exception:
                        prof = None
                    if prof is not None:
                        try:
                            liked_rows = (
                                db.session.query(BlogLike.post_id)
                                .filter(BlogLike.post_id.in_(post_ids), BlogLike.created_by_user_id == prof.id)
                                .all()
                            )
                            liked_post_ids = {int(pid) for (pid,) in liked_rows if pid is not None}
                        except Exception:
                            liked_post_ids = set()

        # commentTotal (includes replies; excludes soft-deleted)
        if _blog_comment_table_ready():
            try:
                if 'post_ids' not in locals():
                    post_ids = [int(r.id) for r in rows if getattr(r, 'id', None) is not None]
            except Exception:
                post_ids = []

            if post_ids:
                try:
                    comment_counts = dict(
                        db.session.query(BlogComment.post_id, func.count(BlogComment.id))
                        .filter(BlogComment.post_id.in_(post_ids), BlogComment.is_deleted == 0)
                        .group_by(BlogComment.post_id)
                        .all()
                    )
                except Exception:
                    comment_counts = {}
        items = []
        for r in rows:
            item = r.to_item(include_content=False)
            try:
                item['imageDataUrl'] = _blog_normalize_image_url(r.image_data_url or '', str(r.id))
            except Exception:
                pass
            # Provide a small preview text for the card.
            try:
                preview = re.sub(r'<[^>]+>', ' ', r.content_html or '')
                preview = re.sub(r'\s+', ' ', preview).strip()
            except Exception:
                preview = ''
            item['contentPreview'] = preview[:200]
            item['tagsList'] = [t for t in (r.tags or '').split(',') if t]

            try:
                pid = int(r.id)
                item['likeTotal'] = int(like_counts.get(pid, 0) or 0)
                item['likedByMe'] = bool(pid in liked_post_ids)
                item['commentTotal'] = int(comment_counts.get(pid, 0) or 0)
            except Exception:
                item['likeTotal'] = 0
                item['likedByMe'] = False
                item['commentTotal'] = 0
            items.append(item)

        payload = {'success': True, 'items': items, 'total': len(items), 'offset': offset, 'limit': limit}
        if total is not None:
            payload['totalCount'] = total
        return jsonify(payload)
    except Exception:
        logger.exception('Failed to list blog posts')
        return jsonify({'success': False, 'message': '블로그 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/tags/top', methods=['GET'])
def list_blog_top_tags():
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    try:
        limit = int(request.args.get('limit') or 10)
    except (TypeError, ValueError):
        limit = 10
    limit = max(1, min(20, limit))

    try:
        # SQLite doesn't have a convenient split function for comma strings,
        # so compute counts in Python from recent rows.
        rows = Blog.query.with_entities(Blog.tags).order_by(Blog.id.desc()).limit(500).all()
        counts = {}
        for (tags_val,) in rows:
            raw = (tags_val or '').strip()
            if not raw:
                continue
            for part in raw.split(','):
                t = part.strip()
                if not t:
                    continue
                counts[t] = counts.get(t, 0) + 1
        top = sorted(counts.items(), key=lambda kv: (-kv[1], kv[0]))[:limit]
        items = [{'tag': k, 'count': v} for k, v in top]
        return jsonify({'success': True, 'items': items})
    except Exception:
        logger.exception('Failed to list top blog tags')
        return jsonify({'success': False, 'message': '태그 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/posts/<int:post_id>', methods=['GET'])
def get_blog_post(post_id: int):
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    try:
        row = Blog.query.filter(Blog.id == post_id).first()
        if not row:
            return jsonify({'success': False, 'message': '게시글을 찾을 수 없습니다.'}), 404

        item = row.to_item(include_content=True)
        try:
            item['imageDataUrl'] = _blog_normalize_image_url(row.image_data_url or '', str(row.id))
        except Exception:
            pass
        item['attachments'] = _blog_normalize_attachments_for_response(
            post_id,
            _blog_json_text_to_obj(row.attachments_json or ''),
        )
        item['tagsList'] = [t for t in (row.tags or '').split(',') if t]

        meta = _blog_resolve_author_meta(item.get('author') or '')
        item['authorDepartment'] = meta.get('department') or ''
        item['authorAvatarUrl'] = meta.get('avatarUrl') or ''
        return jsonify({'success': True, 'item': item})
    except Exception:
        logger.exception('Failed to get blog post')
        return jsonify({'success': False, 'message': '게시글 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/posts', methods=['POST'])
def create_blog_post():
    login_required = _require_login_for_write()
    if login_required is not None:
        return login_required
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    payload = request.get_json(silent=True) or {}
    title = (payload.get('title') or '').strip()
    content_html = (payload.get('contentHtml') or '').strip()
    tags = _blog_tags_normalize(payload.get('tags'))
    image_data_url = (payload.get('imageDataUrl') or '').strip()[:200000]
    attachments_json = _blog_attachments_to_json_text(payload.get('attachments'))

    if not title:
        return jsonify({'success': False, 'message': '제목을 입력하세요.'}), 400
    if not content_html:
        return jsonify({'success': False, 'message': '내용을 입력하세요.'}), 400

    try:
        author = _blog_resolve_current_author() or '나'

        # Prefer server-side assignment so the chosen image remains fixed for the post,
        # and automatically adapts when insight images are added/changed.
        chosen_image_url = None
        try:
            if image_data_url and _blog_is_valid_insight_image_url(image_data_url):
                chosen_image_url = _blog_normalize_image_url(image_data_url, seed='')
            elif image_data_url and image_data_url.startswith('data:image/'):
                chosen_image_url = image_data_url
            else:
                urls = _blog_insight_image_urls()
                if urls:
                    import secrets

                    chosen_image_url = secrets.choice(urls)
        except Exception:
            chosen_image_url = None

        row = Blog(
            title=title,
            content_html=content_html,
            tags=tags,
            image_data_url=chosen_image_url or None,
            attachments_json=attachments_json or None,
            author=author,
            created_at=datetime.utcnow(),
            updated_at=None,
        )
        db.session.add(row)
        db.session.commit()

        item = row.to_item(include_content=False)
        try:
            item['imageDataUrl'] = _blog_normalize_image_url(row.image_data_url or '', str(row.id))
        except Exception:
            pass
        item['contentPreview'] = re.sub(r'\s+', ' ', re.sub(r'<[^>]+>', ' ', content_html)).strip()[:200]
        item['tagsList'] = [t for t in (row.tags or '').split(',') if t]
        return jsonify({'success': True, 'item': item}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create blog post')
        return jsonify({'success': False, 'message': '게시글 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/posts/<int:post_id>', methods=['DELETE'])
def delete_blog_post(post_id: int):
    login_required = _require_login_for_write()
    if login_required is not None:
        return login_required
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    try:
        row = Blog.query.filter(Blog.id == post_id).first()
        if not row:
            return jsonify({'success': False, 'message': '게시글을 찾을 수 없습니다.'}), 404

        if not _blog_is_admin_session():
            actor = _blog_resolve_current_author()
            emp_no = ''
            try:
                emp_no = (session.get('emp_no') or '').strip()
            except Exception:
                emp_no = ''

            author_val = (row.author or '').strip()
            allowed = bool(author_val) and (
                (actor and author_val == actor)
                or (emp_no and author_val == emp_no)
            )
            if not allowed:
                return jsonify({'success': False, 'message': '삭제 권한이 없습니다.'}), 403

        db.session.delete(row)
        db.session.commit()
        return jsonify({'success': True, 'deleted': [post_id]}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete blog post')
