@api_bp.route('/api/insight/blog/posts/<int:post_id>', methods=['PATCH'])
def update_blog_post(post_id: int):
    """Update title/content/tags/attachments for an existing blog post."""

    login_required = _require_login_for_write()
    if login_required is not None:
        return login_required
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    payload = request.get_json(silent=True) or {}
    title = (payload.get('title') or '').strip()
    content_html = (payload.get('contentHtml') or '').strip()
    tags = _blog_tags_normalize(payload.get('tags'))
    attachments_provided = 'attachments' in payload
    attachments_json = _blog_attachments_to_json_text(payload.get('attachments')) if attachments_provided else ''

    if not title:
        return jsonify({'success': False, 'message': '제목을 입력하세요.'}), 400
    if not content_html:
        return jsonify({'success': False, 'message': '내용을 입력하세요.'}), 400

    try:
        row = Blog.query.filter(Blog.id == post_id).first()
        if not row:
            return jsonify({'success': False, 'message': '게시글을 찾을 수 없습니다.'}), 404

        # Permission: author or admin (same pattern as delete/image)
        if not _blog_is_admin_session():
            actor = _blog_resolve_current_author()
            emp_no = ''
            try:
                emp_no = (session.get('emp_no') or '').strip()
            except Exception:
                emp_no = ''

            author_val = (row.author or '').strip()
            allowed = bool(author_val) and (
                (actor and author_val == actor)
                or (emp_no and author_val == emp_no)
            )
            if not allowed:
                return jsonify({'success': False, 'message': '수정 권한이 없습니다.'}), 403

        row.title = title
        row.content_html = content_html
        row.tags = tags
        if attachments_provided:
            row.attachments_json = attachments_json or None
        row.updated_at = datetime.utcnow()
        db.session.commit()

        item = row.to_item(include_content=False)
        try:
            item['imageDataUrl'] = _blog_normalize_image_url(row.image_data_url or '', str(row.id))
        except Exception:
            pass
        try:
            preview = re.sub(r'<[^>]+>', ' ', row.content_html or '')
            preview = re.sub(r'\s+', ' ', preview).strip()
        except Exception:
            preview = ''
        item['contentPreview'] = preview[:200]
        item['tagsList'] = [t for t in (row.tags or '').split(',') if t]
        return jsonify({'success': True, 'item': item}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update blog post')
        return jsonify({'success': False, 'message': '게시글 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/posts/<int:post_id>/attachments', methods=['POST'])
def upload_blog_post_attachments(post_id: int):
    """Upload attachments for a blog post.

    Stores files under instance/uploads/insight_blog/posts/<post_id>/ and
    persists metadata (including download_url) in blog.attachments_json.
    """

    login_required = _require_login_for_write()
    if login_required is not None:
        return login_required
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    try:
        row = Blog.query.filter(Blog.id == post_id).first()
        if not row:
            return jsonify({'success': False, 'message': '게시글을 찾을 수 없습니다.'}), 404

        # Permission: author or admin (same pattern as edit/delete)
        if not _blog_is_admin_session():
            actor = _blog_resolve_current_author()
            emp_no = ''
            try:
                emp_no = (session.get('emp_no') or '').strip()
            except Exception:
                emp_no = ''

            author_val = (row.author or '').strip()
            allowed = bool(author_val) and (
                (actor and author_val == actor)
                or (emp_no and author_val == emp_no)
            )
            if not allowed:
                return jsonify({'success': False, 'message': '수정 권한이 없습니다.'}), 403

        files = []
        try:
            files.extend(request.files.getlist('attachments'))
        except Exception:
            files = []
        files = [f for f in files if f and getattr(f, 'filename', None)]
        if not files:
            return jsonify({'success': False, 'message': '첨부파일이 없습니다.'}), 400

        replace = (request.args.get('replace') or '').strip().lower() in ('1', 'true', 'yes', 'y')
        existing = _blog_json_text_to_obj(row.attachments_json or '')
        existing_norm = _blog_normalize_attachments_for_response(post_id, existing)
        if replace:
            # Best-effort delete old stored files
            try:
                base_dir = os.path.join(current_app.instance_path, 'uploads', 'insight_blog', 'posts', str(post_id))
                for it in existing_norm:
                    stored = (it.get('stored_name') or '').strip()
                    if stored:
                        try:
                            os.remove(os.path.join(base_dir, stored))
                        except Exception:
                            pass
            except Exception:
                pass
            existing_norm = []

        remaining = max(0, 10 - len(existing_norm))
        if remaining <= 0:
            return jsonify({'success': False, 'message': '첨부파일은 최대 10개까지 가능합니다.'}), 400

        from werkzeug.utils import secure_filename
        import uuid

        base_dir = os.path.join(current_app.instance_path, 'uploads', 'insight_blog', 'posts', str(post_id))
        os.makedirs(base_dir, exist_ok=True)

        new_items: List[dict] = []
        for f in files[:remaining]:
            original = (f.filename or '').strip() or 'attachment'
            safe = secure_filename(original) or 'file'
            stored = f"{uuid.uuid4().hex}_{safe}"[:255]
            full_path = os.path.join(base_dir, stored)
            f.save(full_path)
            try:
                size = int(os.path.getsize(full_path))
            except Exception:
                size = 0

            new_items.append({
                'name': original,
                'original_name': original,
                'stored_name': stored,
                'size': max(0, size),
                'content_type': (getattr(f, 'mimetype', '') or '').strip(),
                'download_url': f"/api/insight/blog/posts/{post_id}/attachments/{stored}/download",
            })

        merged = (existing_norm + new_items)[:10]
        row.attachments_json = _blog_attachments_to_json_text(merged) or None
        try:
            row.updated_at = datetime.utcnow()
        except Exception:
            pass
        db.session.commit()

        # RAG 인덱스 잡 등록 (best-effort — 실패해도 응답에 영향 없음)
        try:
            from app.services.rag_enqueue import enqueue_attachment_job
            new_abs_paths = [os.path.join(base_dir, it['stored_name']) for it in new_items]
            enqueue_attachment_job(
                instance_path=current_app.instance_path,
                abs_paths=new_abs_paths,
                source_domain='인사이트',
                source_id=f'blog:{post_id}',
                route_hint=f'/p/insight_blog_it_detail?id={post_id}',
                menu_code='insight',
                page_key='insight_blog_it',
            )
        except Exception:
            pass

        return jsonify({'success': True, 'attachments': _blog_normalize_attachments_for_response(post_id, merged)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to upload blog attachments post_id=%s', post_id)
        return jsonify({'success': False, 'message': '첨부파일 업로드 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/posts/<int:post_id>/attachments/<path:stored_name>/download', methods=['GET'])
def download_blog_post_attachment(post_id: int, stored_name: str):
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    try:
        row = Blog.query.filter(Blog.id == post_id).first()
        if not row:
            return jsonify({'success': False, 'message': '게시글을 찾을 수 없습니다.'}), 404

        stored = os.path.basename((stored_name or '').replace('\\', '/')).strip()
        if not stored:
            return jsonify({'success': False, 'message': '첨부파일을 찾을 수 없습니다.'}), 404

        atts = _blog_normalize_attachments_for_response(post_id, _blog_json_text_to_obj(row.attachments_json or ''))
        rec = None
        for it in atts:
            if (it.get('stored_name') or '') == stored:
                rec = it
                break
        if not rec:
            return jsonify({'success': False, 'message': '첨부파일을 찾을 수 없습니다.'}), 404

        folder = os.path.join(current_app.instance_path, 'uploads', 'insight_blog', 'posts', str(post_id))
        return send_from_directory(
            folder,
            stored,
            as_attachment=True,
            download_name=rec.get('original_name') or rec.get('name') or stored,
        )
    except Exception:
        logger.exception('Failed to download blog attachment post_id=%s stored=%s', post_id, stored_name)
        return jsonify({'success': False, 'message': '첨부파일 다운로드 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/posts/<int:post_id>/attachments/<path:stored_name>', methods=['DELETE'])
def delete_blog_post_attachment(post_id: int, stored_name: str):
    """Delete a single blog post attachment.

    Removes the attachment metadata from blog.attachments_json and best-effort deletes
    the stored file under instance/uploads/insight_blog/posts/<post_id>/.
    """

    login_required = _require_login_for_write()
    if login_required is not None:
        return login_required
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    try:
        row = Blog.query.filter(Blog.id == post_id).first()
        if not row:
            return jsonify({'success': False, 'message': '게시글을 찾을 수 없습니다.'}), 404

        # Permission: author or admin (same pattern as edit/delete/image)
        if not _blog_is_admin_session():
            actor = _blog_resolve_current_author()
            emp_no = ''
            try:
                emp_no = (session.get('emp_no') or '').strip()
            except Exception:
                emp_no = ''

            author_val = (row.author or '').strip()
            allowed = bool(author_val) and (
                (actor and author_val == actor)
                or (emp_no and author_val == emp_no)
            )
            if not allowed:
                return jsonify({'success': False, 'message': '수정 권한이 없습니다.'}), 403

        stored = os.path.basename((stored_name or '').replace('\\', '/')).strip()
        if not stored:
            return jsonify({'success': False, 'message': '첨부파일을 찾을 수 없습니다.'}), 404

        existing = _blog_json_text_to_obj(row.attachments_json or '')
        existing_norm = _blog_normalize_attachments_for_response(post_id, existing)

        found = False
        remaining: List[dict] = []
        for it in existing_norm:
            if (it.get('stored_name') or '') == stored:
                found = True
                continue
            remaining.append(it)
        if not found:
            return jsonify({'success': False, 'message': '첨부파일을 찾을 수 없습니다.'}), 404

        # Best-effort delete stored file
        try:
            folder = os.path.join(current_app.instance_path, 'uploads', 'insight_blog', 'posts', str(post_id))
            os.remove(os.path.join(folder, stored))
        except Exception:
            pass

        row.attachments_json = _blog_attachments_to_json_text(remaining) or None
        try:
            row.updated_at = datetime.utcnow()
        except Exception:
            pass
        db.session.commit()

        return jsonify({'success': True, 'deleted': stored, 'attachments': _blog_normalize_attachments_for_response(post_id, remaining)}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete blog attachment post_id=%s stored=%s', post_id, stored_name)
        return jsonify({'success': False, 'message': '첨부파일 삭제 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/posts/<int:post_id>/image', methods=['PATCH'])
def update_blog_post_image(post_id: int):
    """Update (cycle/random/set) a blog post image.

    Persists the chosen image URL to DB so it remains fixed.
    """

    login_required = _require_login_for_write()
    if login_required is not None:
        return login_required
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500

    payload = request.get_json(silent=True) or {}
    mode = (payload.get('mode') or '').strip().lower()
    requested = (payload.get('imageDataUrl') or '').strip()

    try:
        row = Blog.query.filter(Blog.id == post_id).first()
        if not row:
            return jsonify({'success': False, 'message': '게시글을 찾을 수 없습니다.'}), 404

        # Permission: author or admin
        if not _blog_is_admin_session():
            actor = _blog_resolve_current_author()
            emp_no = ''
            try:
                emp_no = (session.get('emp_no') or '').strip()
            except Exception:
                emp_no = ''

            author_val = (row.author or '').strip()
            allowed = bool(author_val) and (
                (actor and author_val == actor)
                or (emp_no and author_val == emp_no)
            )
            if not allowed:
                return jsonify({'success': False, 'message': '수정 권한이 없습니다.'}), 403

        urls = _blog_insight_image_urls()
        if not urls:
            return jsonify({'success': False, 'message': '사용 가능한 이미지가 없습니다.'}), 400

        new_url = ''
        # Explicit set (must be a valid insight image URL)
        if requested and _blog_is_valid_insight_image_url(requested):
            new_url = _blog_normalize_image_url(requested, seed='')
        elif mode == 'random':
            import secrets

            new_url = secrets.choice(urls)
        else:
            # Default: cycle to next image in folder order.
            current_norm = _blog_normalize_image_url(row.image_data_url or '', str(row.id))
            current_base = os.path.basename((current_norm or '').split('?', 1)[0])
            try:
                cur_idx = urls.index(f"/static/image/insight/{current_base}")
            except Exception:
                cur_idx = -1
            new_url = urls[(cur_idx + 1) % len(urls)]

        row.image_data_url = new_url or None
        try:
            row.updated_at = datetime.utcnow()
        except Exception:
            pass
        db.session.commit()

        return jsonify({'success': True, 'id': post_id, 'imageDataUrl': new_url}), 200
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update blog post image')
        return jsonify({'success': False, 'message': '이미지 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/posts/<int:post_id>/comments', methods=['GET'])
def list_blog_post_comments(post_id: int):
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500
    if not _blog_comment_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog_comment)'}), 500

    try:
        post = Blog.query.filter(Blog.id == post_id).first()
        if not post:
            return jsonify({'success': False, 'message': '게시글을 찾을 수 없습니다.'}), 404

        rows = (
            BlogComment.query
            .filter(BlogComment.post_id == post_id, BlogComment.is_deleted == 0)
            .order_by(BlogComment.created_at.asc(), BlogComment.id.asc())
            .all()
        )
        # reply counts (direct children)
        reply_totals: dict[int, int] = {}
        try:
            for r in rows:
                pid = getattr(r, 'parent_id', None)
                if pid is None:
                    continue
                try:
                    reply_totals[int(pid)] = int(reply_totals.get(int(pid), 0)) + 1
                except Exception:
                    continue
        except Exception:
            reply_totals = {}

        like_totals: dict[int, int] = {}
        liked_by_me: set[int] = set()
        if _blog_comment_like_table_ready():
            like_totals, liked_by_me = _blog_comment_like_summaries(post_id)

        items = []
        for r in rows:
            base = _blog_comment_to_item(r)
            cid = base.get('id')
            try:
                cid_int = int(cid)
            except Exception:
                cid_int = None
            base['likeTotal'] = int(like_totals.get(cid_int, 0)) if cid_int is not None else 0
            base['likedByMe'] = bool(cid_int is not None and cid_int in liked_by_me)
            base['replyTotal'] = int(reply_totals.get(cid_int, 0)) if cid_int is not None else 0
            items.append(base)
        return jsonify({'success': True, 'items': items, 'total': len(items)})
    except Exception:
        logger.exception('Failed to list blog comments post_id=%s', post_id)
        return jsonify({'success': False, 'message': '댓글 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/insight/blog/posts/<int:post_id>/comments', methods=['POST'])
def create_blog_post_comment(post_id: int):
    login_required = _require_login_for_write()
    if login_required is not None:
        return login_required
    if not _blog_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog)'}), 500
    if not _blog_comment_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (blog_comment)'}), 500

    payload = request.get_json(silent=True) or {}
    content = (payload.get('content') or payload.get('text') or '').strip()
    parent_id_raw = payload.get('parentId', payload.get('parent_id'))
    parent_id = None
    if parent_id_raw is not None and str(parent_id_raw).strip() != '':
        try:
            parent_id = int(parent_id_raw)
        except (TypeError, ValueError):
            parent_id = None

    if not content:
        return jsonify({'success': False, 'message': '댓글을 입력하세요.'}), 400
    if len(content) > 2000:
        return jsonify({'success': False, 'message': '댓글은 2000자 이하로 입력하세요.'}), 400

    try:
        post = Blog.query.filter(Blog.id == post_id).first()
        if not post:
            return jsonify({'success': False, 'message': '게시글을 찾을 수 없습니다.'}), 404

        prof, err = _blog_require_current_user_profile()
        if err:
            body, code = err
            return jsonify(body), code

        if parent_id is not None:
            parent = (
                BlogComment.query
                .filter(BlogComment.id == parent_id, BlogComment.post_id == post_id, BlogComment.is_deleted == 0)
                .first()
            )
            if not parent:
                return jsonify({'success': False, 'message': '대댓글 대상 댓글을 찾을 수 없습니다.'}), 404

        row = BlogComment(
            post_id=post_id,
            parent_id=parent_id,
            content=content,
            created_by_user_id=getattr(prof, 'id', None),
            created_at=datetime.utcnow(),
            is_deleted=0,
        )
        db.session.add(row)
        db.session.commit()

        item = _blog_comment_to_item(row)
        item['likeTotal'] = 0
        item['likedByMe'] = False
        item['replyTotal'] = 0
        return jsonify({'success': True, 'item': item}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create blog comment post_id=%s', post_id)
        return jsonify({'success': False, 'message': '댓글 등록 중 오류가 발생했습니다.'}), 500


