# ============================================================= #
#  전광판 (Ticker) API — ticker_message / ticker_config          #
# ============================================================= #

_ticker_table_exists = False


def _ticker_table_ready() -> bool:
    global _ticker_table_exists
    if _ticker_table_exists:
        return True
    try:
        import sqlalchemy as sa
        insp = sa.inspect(db.engine)
        _ticker_table_exists = bool(insp.has_table('ticker_message') and insp.has_table('ticker_config'))
    except Exception:
        _ticker_table_exists = False
    return bool(_ticker_table_exists)


def _ensure_ticker_config() -> 'TickerConfig':
    """Return the singleton TickerConfig row, creating it if absent."""
    cfg = TickerConfig.query.get(1)
    if not cfg:
        cfg = TickerConfig(id=1, speed=35, paused=0)
        db.session.add(cfg)
        db.session.flush()
    return cfg


@api_bp.route('/api/ticker/messages', methods=['GET'])
def list_ticker_messages():
    if not _ticker_table_ready():
        return jsonify({'success': True, 'items': [], 'config': {'speed': 35, 'paused': False}})
    try:
        rows = TickerMessage.query.filter_by(is_deleted=0).order_by(TickerMessage.sort_order.asc(), TickerMessage.id.asc()).all()
        cfg = _ensure_ticker_config()
        items = [{'id': r.id, 'text': r.text, 'sev': r.severity, 'sort_order': r.sort_order} for r in rows]
        return jsonify({
            'success': True,
            'items': items,
            'config': {'speed': cfg.speed, 'paused': bool(cfg.paused)},
        })
    except Exception:
        logger.exception('Failed to list ticker messages')
        return jsonify({'success': False, 'message': '전광판 메시지 조회 실패'}), 500


@api_bp.route('/api/ticker/messages', methods=['POST'])
def create_ticker_message():
    if not _ticker_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다. (ticker)'}), 500
    payload = request.get_json(silent=True) or {}
    txt = (payload.get('text') or '').strip()
    sev = (payload.get('sev') or 'info').strip().lower()
    if sev not in ('info', 'warn', 'crit'):
        sev = 'info'
    if not txt:
        return jsonify({'success': False, 'message': '메시지를 입력하세요.'}), 400
    try:
        max_order = db.session.query(func.coalesce(func.max(TickerMessage.sort_order), 0)).filter_by(is_deleted=0).scalar()
        row = TickerMessage(text=txt, severity=sev, sort_order=max_order + 1)
        db.session.add(row)
        db.session.commit()
        return jsonify({'success': True, 'item': {'id': row.id, 'text': row.text, 'sev': row.severity, 'sort_order': row.sort_order}}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create ticker message')
        return jsonify({'success': False, 'message': '전광판 메시지 생성 실패'}), 500


@api_bp.route('/api/ticker/messages/<int:msg_id>', methods=['PUT'])
def update_ticker_message(msg_id: int):
    if not _ticker_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다.'}), 500
    payload = request.get_json(silent=True) or {}
    try:
        row = TickerMessage.query.filter_by(id=msg_id, is_deleted=0).first()
        if not row:
            return jsonify({'success': False, 'message': '메시지를 찾을 수 없습니다.'}), 404
        if 'text' in payload:
            txt = (payload['text'] or '').strip()
            if not txt:
                return jsonify({'success': False, 'message': '메시지를 입력하세요.'}), 400
            row.text = txt
        if 'sev' in payload:
            sev = (payload['sev'] or 'info').strip().lower()
            row.severity = sev if sev in ('info', 'warn', 'crit') else 'info'
        row.updated_at = datetime.utcnow().isoformat()
        db.session.commit()
        return jsonify({'success': True, 'item': {'id': row.id, 'text': row.text, 'sev': row.severity, 'sort_order': row.sort_order}})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update ticker message')
        return jsonify({'success': False, 'message': '전광판 메시지 수정 실패'}), 500


@api_bp.route('/api/ticker/messages/<int:msg_id>', methods=['DELETE'])
def delete_ticker_message(msg_id: int):
    if not _ticker_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다.'}), 500
    try:
        row = TickerMessage.query.filter_by(id=msg_id, is_deleted=0).first()
        if not row:
            return jsonify({'success': False, 'message': '메시지를 찾을 수 없습니다.'}), 404
        row.is_deleted = 1
        row.updated_at = datetime.utcnow().isoformat()
        db.session.commit()
        return jsonify({'success': True})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete ticker message')
        return jsonify({'success': False, 'message': '전광판 메시지 삭제 실패'}), 500


@api_bp.route('/api/ticker/messages/reorder', methods=['PUT'])
def reorder_ticker_messages():
    """Bulk update sort_order.  Body: {"order": [id1, id2, ...]}"""
    if not _ticker_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다.'}), 500
    payload = request.get_json(silent=True) or {}
    ids = payload.get('order')
    if not isinstance(ids, list):
        return jsonify({'success': False, 'message': 'order 배열이 필요합니다.'}), 400
    try:
        for idx, mid in enumerate(ids):
            row = TickerMessage.query.filter_by(id=mid, is_deleted=0).first()
            if row:
                row.sort_order = idx
        db.session.commit()
        return jsonify({'success': True})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to reorder ticker messages')
        return jsonify({'success': False, 'message': '순서 변경 실패'}), 500


@api_bp.route('/api/ticker/config', methods=['GET'])
def get_ticker_config():
    if not _ticker_table_ready():
        return jsonify({'success': True, 'config': {'speed': 35, 'paused': False}})
    try:
        cfg = _ensure_ticker_config()
        return jsonify({'success': True, 'config': {'speed': cfg.speed, 'paused': bool(cfg.paused)}})
    except Exception:
        logger.exception('Failed to get ticker config')
        return jsonify({'success': False, 'message': '전광판 설정 조회 실패'}), 500


@api_bp.route('/api/ticker/config', methods=['PUT'])
def update_ticker_config():
    if not _ticker_table_ready():
        return jsonify({'success': False, 'message': 'DB 마이그레이션이 필요합니다.'}), 500
    payload = request.get_json(silent=True) or {}
    try:
        cfg = _ensure_ticker_config()
        if 'speed' in payload and isinstance(payload['speed'], (int, float)):
            cfg.speed = max(5, min(120, int(payload['speed'])))
        if 'paused' in payload:
            cfg.paused = 1 if payload['paused'] else 0
        cfg.updated_at = datetime.utcnow().isoformat()
        db.session.commit()
        return jsonify({'success': True, 'config': {'speed': cfg.speed, 'paused': bool(cfg.paused)}})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update ticker config')
        return jsonify({'success': False, 'message': '전광판 설정 저장 실패'}), 500


