@api_bp.route('/api/quality-types/upload', methods=['POST'])
def upload_quality_types():
    """엑셀/CSV 파일로 품질유형 일괄 업로드."""
    import io
    f = request.files.get('file')
    if not f or not f.filename:
        return jsonify({'success': False, 'message': '파일이 첨부되지 않았습니다.'}), 400
    fname = f.filename.lower()
    actor = _resolve_actor()

    # CSV 처리 (한국어 헤더 → key 매핑)
    HEADER_MAP = {
        '그룹': 'group_name', '품질유형': 'quality_type', '항목': 'item_name',
        '측정지표': 'metric', '단위': 'unit', '기본목표값': 'target_value', '설명': 'description',
    }

    try:
        if fname.endswith('.csv'):
            import csv
            stream = io.StringIO(f.stream.read().decode('utf-8-sig'))
            reader = csv.DictReader(stream)
            rows = []
            for row in reader:
                mapped = {}
                for ko, en in HEADER_MAP.items():
                    mapped[en] = (row.get(ko) or '').strip()
                if mapped.get('quality_type'):
                    rows.append(mapped)
        elif fname.endswith('.xls') or fname.endswith('.xlsx'):
            try:
                import openpyxl
            except ImportError:
                return jsonify({'success': False, 'message': 'openpyxl 패키지가 설치되어 있지 않습니다.'}), 500
            wb = openpyxl.load_workbook(io.BytesIO(f.read()), read_only=True, data_only=True)
            ws = wb.active
            header_row = [str(cell.value or '').strip() for cell in next(ws.iter_rows(min_row=1, max_row=1))]
            col_map = {}
            for idx, h in enumerate(header_row):
                if h in HEADER_MAP:
                    col_map[idx] = HEADER_MAP[h]
            rows = []
            for row in ws.iter_rows(min_row=2, values_only=True):
                mapped = {}
                for idx, key in col_map.items():
                    mapped[key] = str(row[idx] or '').strip() if idx < len(row) and row[idx] is not None else ''
                if mapped.get('quality_type'):
                    rows.append(mapped)
            wb.close()
        else:
            return jsonify({'success': False, 'message': '지원하지 않는 파일 형식입니다.'}), 400

        imported = 0
        for data in rows:
            try:
                svc_create_quality_type(data, actor)
                imported += 1
            except Exception:
                logger.warning('Skipping quality type row: %s', data)
        return jsonify({'success': True, 'imported': imported, 'total': len(rows)})
    except Exception:
        logger.exception('Failed to upload quality types')
        return jsonify({'success': False, 'message': '업로드 처리 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/quality-types/cascade', methods=['GET'])
def cascade_quality_types():
    """품질유형 캐스케이드 조회 API.

    Query params:
      - level: 'group' | 'type' | 'item' | 'metric'
      - group_name: 그룹 필터 (level=type, item, metric)
      - quality_type: 품질유형 필터 (level=item, metric)
      - item_name: 항목 필터 (level=metric)
    """
    level = (request.args.get('level') or 'group').strip().lower()
    group_filter = (request.args.get('group_name') or '').strip() or None
    type_filter = (request.args.get('quality_type') or '').strip() or None
    item_filter = (request.args.get('item_name') or '').strip() or None

    try:
        all_rows = svc_list_quality_types(search=None, include_deleted=False)

        if level == 'group':
            seen = set()
            items = []
            for r in all_rows:
                g = (r.get('group_name') or '').strip()
                if g and g not in seen:
                    seen.add(g)
                    items.append({'name': g})
            return jsonify({'success': True, 'items': items})

        elif level == 'type':
            filtered = all_rows
            if group_filter:
                filtered = [r for r in filtered if (r.get('group_name') or '').strip() == group_filter]
            seen = set()
            items = []
            for r in filtered:
                v = (r.get('quality_type') or '').strip()
                if v and v not in seen:
                    seen.add(v)
                    items.append({'name': v})
            return jsonify({'success': True, 'items': items})

        elif level == 'item':
            filtered = all_rows
            if group_filter:
                filtered = [r for r in filtered if (r.get('group_name') or '').strip() == group_filter]
            if type_filter:
                filtered = [r for r in filtered if (r.get('quality_type') or '').strip() == type_filter]
            seen = set()
            items = []
            for r in filtered:
                v = (r.get('item_name') or '').strip()
                if v and v not in seen:
                    seen.add(v)
                    items.append({'name': v})
            return jsonify({'success': True, 'items': items})

        elif level == 'metric':
            filtered = all_rows
            if group_filter:
                filtered = [r for r in filtered if (r.get('group_name') or '').strip() == group_filter]
            if type_filter:
                filtered = [r for r in filtered if (r.get('quality_type') or '').strip() == type_filter]
            if item_filter:
                filtered = [r for r in filtered if (r.get('item_name') or '').strip() == item_filter]
            seen = set()
            items = []
            for r in filtered:
                v = (r.get('metric') or '').strip()
                if v and v not in seen:
                    seen.add(v)
                    items.append({'name': v})
            return jsonify({'success': True, 'items': items})

        else:
            return jsonify({'success': False, 'message': '유효하지 않은 level 입니다.'}), 400

    except Exception:
        logger.exception('Failed to cascade quality types')
        return jsonify({'success': False, 'message': '품질유형 캐스케이드 조회 중 오류가 발생했습니다.'}), 500


