import json as _json
from app.services.wf_design_service import (
    list_workflows as _wf_list, get_workflow as _wf_get,
    create_workflow as _wf_create, update_workflow as _wf_update,
    delete_workflows as _wf_delete, save_version as _wf_save_ver,
    get_version as _wf_get_ver, list_versions as _wf_list_vers,
)
from app.models import WfDesign, WfDesignLike, WfDesignComment, WfDesignView


def _wf_session_uid():
    """현재 세션의 사용자 ID 반환 (user_profile_id > user_id)"""
    return session.get('user_profile_id') or session.get('user_id')


# ── 시청자 프레즌스 (in-memory) ──
_wf_viewers = {}  # { workflow_id: { user_id: { 'name': str, 'ts': float } } }

def _wf_viewers_cleanup(wf_id, ttl=15):
    """TTL(초) 지난 시청자 제거"""
    import time
    bucket = _wf_viewers.get(wf_id, {})
    now = time.time()
    expired = [uid for uid, v in bucket.items() if now - v['ts'] > ttl]
    for uid in expired:
        bucket.pop(uid, None)


@api_bp.route('/api/wf-designs/<wf_id>/viewers', methods=['POST'])
def api_wf_designs_viewer_heartbeat(wf_id):
    """시청자 하트비트 (read-only 사용자가 5초마다 호출)"""
    import time
    try:
        uid = _wf_session_uid()
        if not uid:
            return jsonify({'success': False}), 401
        name = ''
        from app.models import UserProfile
        u = UserProfile.query.get(uid)
        if u:
            name = getattr(u, 'name', '') or ''
        if wf_id not in _wf_viewers:
            _wf_viewers[wf_id] = {}
        _wf_viewers[wf_id][uid] = {'name': name, 'ts': time.time()}
        _wf_viewers_cleanup(wf_id)
        return jsonify({'success': True})
    except Exception:
        return jsonify({'success': False}), 500


@api_bp.route('/api/wf-designs/<wf_id>/viewers', methods=['DELETE'])
def api_wf_designs_viewer_leave(wf_id):
    """시청자 탈퇴 (페이지 이탈 시)"""
    try:
        uid = _wf_session_uid()
        if uid and wf_id in _wf_viewers:
            _wf_viewers[wf_id].pop(uid, None)
        return jsonify({'success': True})
    except Exception:
        return jsonify({'success': False}), 500


@api_bp.route('/api/wf-designs/<wf_id>/viewers', methods=['GET'])
def api_wf_designs_viewer_list(wf_id):
    """현재 시청자 목록 (편집자가 폴링)"""
    try:
        _wf_viewers_cleanup(wf_id)
        bucket = _wf_viewers.get(wf_id, {})
        viewers = [{'id': uid, 'name': v['name']} for uid, v in bucket.items()]
        return jsonify({'success': True, 'viewers': viewers, 'count': len(viewers)})
    except Exception:
        return jsonify({'success': False}), 500


@api_bp.route('/api/wf-designs', methods=['GET'])
def api_wf_designs_list():
    """워크플로우 목록 조회"""
    try:
        uid = _wf_session_uid()
        page = request.args.get('page', 1, type=int)
        per_page = request.args.get('per_page', 20, type=int)
        status = request.args.get('status')
        search = request.args.get('search')
        my_only = request.args.get('my_only', '0')

        shared = request.args.get('shared')
        shared_val = int(shared) if shared is not None and shared != '' else None
        owner = uid if my_only == '1' else None
        try:
            items, total = _wf_list(
                status=status, owner_user_id=owner,
                page=page, per_page=per_page, search=search,
                shared=shared_val,
            )
        except Exception:
            # 구버전 스키마(예: shared 컬럼 미적용)에서도 목록 화면이 동작하도록
            # shared 필터 없이 1회 폴백한다.
            if shared_val is not None:
                logger.exception('wf-designs list failed with shared filter; fallback without shared')
                items, total = _wf_list(
                    status=status, owner_user_id=owner,
                    page=page, per_page=per_page, search=search,
                    shared=None,
                )
            else:
                raise
        # 좋아요 정보 집계
        wf_ids = [w.id for w in items]
        like_counts = {}
        my_likes = set()
        if wf_ids:
            try:
                from sqlalchemy import func as _sa_func
                count_rows = db.session.query(
                    WfDesignLike.workflow_id, _sa_func.count(WfDesignLike.id)
                ).filter(WfDesignLike.workflow_id.in_(wf_ids)).group_by(WfDesignLike.workflow_id).all()
                like_counts = {r[0]: r[1] for r in count_rows}
                if uid:
                    my_rows = db.session.query(WfDesignLike.workflow_id).filter(
                        WfDesignLike.workflow_id.in_(wf_ids), WfDesignLike.user_id == uid
                    ).all()
                    my_likes = {r[0] for r in my_rows}
            except Exception:
                logger.exception('wf-designs like aggregate failed; continue without like meta')
                like_counts = {}
                my_likes = set()
        rows = []
        for w in items:
            # 최신 버전의 definition_json 에서 nodes/edges 추출 (미니 프리뷰용)
            def_json = None
            if w.versions:
                try:
                    raw = w.versions[0].definition_json
                    if isinstance(raw, str):
                        def_json = _json.loads(raw)
                    elif isinstance(raw, dict):
                        def_json = raw
                except Exception:
                    def_json = None
            owner_name = ''
            try:
                owner_obj = getattr(w, 'owner', None)
                owner_name = getattr(owner_obj, 'name', '') if owner_obj else ''
            except Exception:
                owner_name = ''

            rows.append({
                'id': w.id,
                'name': w.name,
                'description': w.description or '',
                'status': w.status,
                'latest_version': w.latest_version,
                'owner_user_id': w.owner_user_id,
                'owner_name': owner_name,
                'thumbnail': w.thumbnail or '',
                'shared': getattr(w, 'shared', 0) or 0,
                'created_at': w.created_at,
                'updated_at': w.updated_at or '',
                'like_count': getattr(w, 'like_count', 0) or like_counts.get(w.id, 0),
                'view_count': getattr(w, 'view_count', 0) or 0,
                'liked': w.id in my_likes,
                'definition_json': def_json,
            })
        return jsonify({'success': True, 'rows': rows, 'total': total})
    except Exception:
        logger.exception('wf-designs list failed')
        return jsonify({'success': False, 'error': '목록 조회 실패'}), 500


@api_bp.route('/api/wf-designs', methods=['POST'])
def api_wf_designs_create():
    """워크플로우 생성"""
    try:
        uid = _wf_session_uid()
        if not uid:
            return jsonify({'success': False, 'error': '인증 필요'}), 401
        data = request.get_json(force=True)
        name = (data.get('name') or '').strip()
        if not name:
            return jsonify({'success': False, 'error': '이름은 필수입니다.'}), 400

        definition = data.get('definition_json')
        wf = _wf_create(
            name=name,
            description=data.get('description', ''),
            owner_user_id=uid,
            definition_json=definition,
        )
        return jsonify({
            'success': True,
            'item': {
                'id': wf.id, 'name': wf.name,
                'status': wf.status, 'latest_version': wf.latest_version,
            }
        }), 201
    except Exception:
        logger.exception('wf-designs create failed')
        return jsonify({'success': False, 'error': '생성 실패'}), 500


