@api_bp.route('/api/wf-designs/<wf_id>/lock', methods=['POST'])
def api_wf_designs_lock(wf_id):
    """워크플로우 편집 잠금 획득"""
    try:
        uid = _wf_session_uid()
        if not uid:
            return jsonify({'success': False, 'error': '인증 필요'}), 401
        wf = WfDesign.query.filter_by(id=wf_id, is_deleted=0).first()
        if not wf:
            return jsonify({'success': False, 'error': '워크플로우를 찾을 수 없습니다.'}), 404
        # 이미 다른 사용자가 편집 중이면 거부 (30분 초과 시 자동 해제)
        if wf.editing_user_id and wf.editing_user_id != uid:
            from datetime import datetime, timedelta
            if wf.editing_since:
                try:
                    since = datetime.fromisoformat(wf.editing_since)
                    if datetime.utcnow() - since < timedelta(minutes=30):
                        editor_name = ''
                        from app.models import UserProfile
                        editor = UserProfile.query.get(wf.editing_user_id)
                        if editor:
                            editor_name = getattr(editor, 'name', '')
                        return jsonify({'success': False, 'error': '다른 사용자가 편집 중입니다.', 'editing_user': editor_name}), 409
                except Exception:
                    pass
        wf.editing_user_id = uid
        wf.editing_since = _json.dumps(None)  # placeholder
        from datetime import datetime as _dt
        wf.editing_since = _dt.utcnow().isoformat()
        db.session.commit()
        return jsonify({'success': True, 'editing': True})
    except Exception:
        logger.exception('wf-designs lock failed')
        return jsonify({'success': False, 'error': '잠금 실패'}), 500


@api_bp.route('/api/wf-designs/<wf_id>/lock', methods=['DELETE'])
def api_wf_designs_unlock(wf_id):
    """워크플로우 편집 잠금 해제"""
    try:
        uid = _wf_session_uid()
        if not uid:
            return jsonify({'success': False, 'error': '인증 필요'}), 401
        wf = WfDesign.query.filter_by(id=wf_id, is_deleted=0).first()
        if not wf:
            return jsonify({'success': False, 'error': '워크플로우를 찾을 수 없습니다.'}), 404
        if wf.editing_user_id == uid:
            wf.editing_user_id = None
            wf.editing_since = None
            db.session.commit()
        return jsonify({'success': True})
    except Exception:
        logger.exception('wf-designs unlock failed')
        return jsonify({'success': False, 'error': '잠금 해제 실패'}), 500


