@api_bp.route('/api/page-tabs', methods=['POST'])
def create_page_tab():
    """탭 추가."""
    payload = request.get_json(silent=True) or {}
    page_code = (payload.get('page_code') or '').strip()
    tab_code = (payload.get('tab_code') or '').strip()
    tab_name = (payload.get('tab_name') or '').strip()
    if not page_code or not tab_code or not tab_name:
        return jsonify({'success': False, 'message': 'page_code, tab_code, tab_name 은 필수입니다.'}), 400

    # 중복 검사
    dup = PageTabConfig.query.filter(
        PageTabConfig.page_code == page_code,
        PageTabConfig.tab_code == tab_code,
        PageTabConfig.is_deleted == 0,
    ).first()
    if dup:
        return jsonify({'success': False, 'message': '동일 page_code 내에 중복된 tab_code 가 있습니다.'}), 409

    # tab_order 자동 부여 (현재 최대값 + 1)
    max_order = db.session.execute(db.text(
        "SELECT COALESCE(MAX(tab_order),0) FROM page_tab_config WHERE page_code=:pc AND is_deleted=0"
    ), {'pc': page_code}).scalar()
    tab_order = payload.get('tab_order')
    if tab_order is None:
        tab_order = (max_order or 0) + 1
    else:
        tab_order = int(tab_order)

    try:
        row = PageTabConfig(
            page_code=page_code,
            tab_code=tab_code,
            tab_name=tab_name,
            tab_order=tab_order,
            is_active=int(payload.get('is_active', 1)),
            description=payload.get('description'),
            tab_color=payload.get('tab_color'),
            permission_code=payload.get('permission_code'),
            route_key=payload.get('route_key'),
            extra_options=payload.get('extra_options'),
            created_by=payload.get('created_by') or session.get('emp_no'),
        )
        db.session.add(row)
        db.session.commit()
        _settings_log_api('페이지관리', f'{page_code}:{tab_code} 생성', '-', tab_name)
        return jsonify({'success': True, 'item': _page_tab_to_dict(row)}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create page tab')
        return jsonify({'success': False, 'message': '탭 생성 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/page-tabs/<int:tab_id>', methods=['PUT'])
def update_page_tab(tab_id):
    """탭 수정."""
    payload = request.get_json(silent=True) or {}
    try:
        row = PageTabConfig.query.filter(
            PageTabConfig.id == tab_id,
            PageTabConfig.is_deleted == 0,
        ).first()
        if not row:
            return jsonify({'success': False, 'message': '대상 탭을 찾을 수 없습니다.'}), 404
        before = _page_tab_to_dict(row)

        if 'tab_name' in payload:
            row.tab_name = payload['tab_name']
        if 'tab_order' in payload:
            row.tab_order = int(payload['tab_order'])
        if 'is_active' in payload:
            row.is_active = int(payload['is_active'])
        if 'description' in payload:
            row.description = payload['description']
        if 'tab_color' in payload:
            row.tab_color = payload['tab_color']
        if 'permission_code' in payload:
            row.permission_code = payload['permission_code']
        if 'route_key' in payload:
            row.route_key = payload['route_key']
        if 'extra_options' in payload:
            row.extra_options = payload['extra_options']
        if 'tab_image' in payload:
            row.tab_image = payload['tab_image']
        if 'tab_code' in payload:
            new_code = (payload['tab_code'] or '').strip()
            if new_code and new_code != row.tab_code:
                dup = PageTabConfig.query.filter(
                    PageTabConfig.page_code == row.page_code,
                    PageTabConfig.tab_code == new_code,
                    PageTabConfig.is_deleted == 0,
                    PageTabConfig.id != tab_id,
                ).first()
                if dup:
                    return jsonify({'success': False, 'message': '동일 page_code 내에 중복된 tab_code 가 있습니다.'}), 409
                row.tab_code = new_code

        row.updated_by = payload.get('updated_by') or session.get('emp_no')
        row.updated_at = datetime.utcnow().isoformat()
        for k, v in payload.items():
            _settings_log_api('페이지관리', f'탭#{tab_id} {k}', before.get(k), v)
        db.session.commit()
        return jsonify({'success': True, 'item': _page_tab_to_dict(row)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update page tab')
        return jsonify({'success': False, 'message': '탭 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/page-tabs/<int:tab_id>', methods=['DELETE'])
def delete_page_tab(tab_id):
    """탭 소프트 삭제. 페이지별 최소 1개 탭은 유지."""
    try:
        row = PageTabConfig.query.filter(
            PageTabConfig.id == tab_id,
            PageTabConfig.is_deleted == 0,
        ).first()
        if not row:
            return jsonify({'success': False, 'message': '대상 탭을 찾을 수 없습니다.'}), 404
        # 페이지별 최소 1개 탭 유지
        sibling_count = PageTabConfig.query.filter(
            PageTabConfig.page_code == row.page_code,
            PageTabConfig.is_deleted == 0,
        ).count()
        if sibling_count <= 1:
            return jsonify({'success': False, 'message': '각 페이지에는 최소 1개의 탭이 있어야 합니다.'}), 400
        row.is_deleted = 1
        row.updated_at = datetime.utcnow().isoformat()
        row.updated_by = session.get('emp_no')
        _settings_log_api('페이지관리', f'{row.page_code}:{row.tab_code} 삭제', row.tab_name, '-')
        db.session.commit()
        return jsonify({'success': True, 'deleted': [tab_id]})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete page tab')
        return jsonify({'success': False, 'message': '탭 삭제 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/page-tabs/<int:tab_id>/toggle', methods=['PUT'])
def toggle_page_tab(tab_id):
    """탭 활성/비활성 토글."""
    try:
        row = PageTabConfig.query.filter(
            PageTabConfig.id == tab_id,
            PageTabConfig.is_deleted == 0,
        ).first()
        if not row:
            return jsonify({'success': False, 'message': '대상 탭을 찾을 수 없습니다.'}), 404
        old_active = row.is_active
        row.is_active = 0 if row.is_active else 1
        row.updated_at = datetime.utcnow().isoformat()
        row.updated_by = session.get('emp_no')
        _settings_log_api('페이지관리', f'{row.page_code}:{row.tab_code} 활성여부', old_active, row.is_active)
        db.session.commit()
        return jsonify({'success': True, 'item': _page_tab_to_dict(row)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to toggle page tab')
        return jsonify({'success': False, 'message': '탭 토글 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/page-tabs/reorder', methods=['PUT'])
def reorder_page_tabs():
    """탭 순서 일괄 저장.  body: { orders: [ {id, tab_order}, ... ] }"""
    payload = request.get_json(silent=True) or {}
    orders = payload.get('orders')
    if not isinstance(orders, list) or not orders:
        return jsonify({'success': False, 'message': 'orders 배열이 필요합니다.'}), 400
    try:
        for item in orders:
            tid = int(item.get('id', 0))
            new_order = int(item.get('tab_order', 0))
            if tid:
                row = PageTabConfig.query.get(tid)
                if row and row.is_deleted == 0:
                    old_order = row.tab_order
                    row.tab_order = new_order
                    row.updated_at = datetime.utcnow().isoformat()
                    _settings_log_api('페이지관리', f'{row.page_code}:{row.tab_code} 순서', old_order, new_order)
        db.session.commit()
        return jsonify({'success': True})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to reorder page tabs')
        return jsonify({'success': False, 'message': '순서 저장 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/page-tabs/<int:tab_id>/image', methods=['POST'])
def upload_page_tab_image(tab_id):
    """탭 실장도 이미지 업로드."""
    try:
        row = PageTabConfig.query.filter(
            PageTabConfig.id == tab_id,
            PageTabConfig.is_deleted == 0,
        ).first()
        if not row:
            return jsonify({'success': False, 'message': '대상 탭을 찾을 수 없습니다.'}), 404

        file = request.files.get('image')
        if not file or not file.filename:
            return jsonify({'success': False, 'message': '이미지 파일이 없습니다.'}), 400

        allowed = {'png', 'jpg', 'jpeg', 'gif', 'webp', 'svg'}
        ext = (file.filename.rsplit('.', 1)[-1] if '.' in file.filename else '').lower()
        if ext not in allowed:
            return jsonify({'success': False, 'message': '허용되지 않는 파일 형식입니다. (png, jpg, jpeg, gif, webp, svg)'}), 400

        max_bytes = 10 * 1024 * 1024
        base_dir = os.path.join(current_app.instance_path, 'uploads', 'page_tabs')
        os.makedirs(base_dir, exist_ok=True)

        safe = secure_filename(file.filename) or 'image'
        stored = f"{uuid.uuid4().hex}_{safe}"
        abs_path = os.path.join(base_dir, stored)
        file.save(abs_path)

        try:
            size = os.path.getsize(abs_path)
        except OSError:
            size = 0
        if size > max_bytes:
            try:
                os.remove(abs_path)
            except OSError:
                pass
            return jsonify({'success': False, 'message': '파일 용량은 10MB 이하만 업로드할 수 있습니다.'}), 400

        # 이전 이미지 삭제
        if row.tab_image:
            old_path = os.path.join(current_app.instance_path, row.tab_image.lstrip('/'))
            try:
                os.remove(old_path)
            except OSError:
                pass

        rel_path = f"uploads/page_tabs/{stored}"
        row.tab_image = rel_path
        row.updated_at = datetime.utcnow().isoformat()
        row.updated_by = session.get('emp_no')
        db.session.commit()
        return jsonify({'success': True, 'item': _page_tab_to_dict(row), 'image_url': f"/instance-file/{rel_path}"})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to upload page tab image')
        return jsonify({'success': False, 'message': '이미지 업로드 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/page-tabs/<int:tab_id>/image', methods=['DELETE'])
def delete_page_tab_image(tab_id):
    """탭 실장도 이미지 삭제."""
    try:
        row = PageTabConfig.query.filter(
            PageTabConfig.id == tab_id,
            PageTabConfig.is_deleted == 0,
        ).first()
        if not row:
            return jsonify({'success': False, 'message': '대상 탭을 찾을 수 없습니다.'}), 404
        if row.tab_image:
            old_path = os.path.join(current_app.instance_path, row.tab_image.lstrip('/'))
            try:
                os.remove(old_path)
            except OSError:
                pass
            row.tab_image = None
            row.updated_at = datetime.utcnow().isoformat()
            row.updated_by = session.get('emp_no')
            db.session.commit()
        return jsonify({'success': True, 'item': _page_tab_to_dict(row)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to delete page tab image')
        return jsonify({'success': False, 'message': '이미지 삭제 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/page-tabs/<int:tab_id>/image', methods=['GET'])
def get_page_tab_image(tab_id):
    """탭 실장도 이미지 서빙."""
    try:
        row = PageTabConfig.query.filter(
            PageTabConfig.id == tab_id,
            PageTabConfig.is_deleted == 0,
        ).first()
        if not row or not row.tab_image:
            return jsonify({'success': False, 'message': '이미지를 찾을 수 없습니다.'}), 404
        folder = os.path.join(current_app.instance_path, 'uploads', 'page_tabs')
        filename = os.path.basename(row.tab_image.replace('\\', '/'))
        return send_from_directory(folder, filename, mimetype=None)
    except Exception:
        logger.exception('Failed to serve page tab image')
        return jsonify({'success': False, 'message': '이미지 조회 중 오류가 발생했습니다.'}), 500


