@api_bp.route('/api/file-policy', methods=['GET'])
def get_file_policy():
    """파일 관리 정책을 반환한다."""
    try:
        # 기본 정책 (DB나 설정파일에서 조회하지 않으면 기본값 반환)
        policy = {
            'success': True,
            'item': {
                'max_file_size_mb': 20,
                'allowed_extensions': 'pdf,doc,docx,xls,xlsx,ppt,pptx,txt,hwp,jpg,jpeg,png,gif,zip',
                'blocked_extensions': 'exe,bat,cmd,com,scr,vbs,js,jar,dll',
                'file_name_pattern': '',
                'allow_duplicate_upload': False,
                'block_executable_upload': True,
                'validate_mime_type': True,
                'validate_magic_bytes': False,
                'detect_extension_spoofing': True,
                'enable_virus_scan': False,
                'inherit_record_permission': True,
                'enable_download_log': True,
                'allow_external_share': False,
                'allow_admin_force_access': True,
                'retention_days_after_closed': 365,
                'archive_days_if_unaccessed': 180,
                'exclude_important_from_retention': True,
                'enable_expiry_notification': True,
            }
        }
        return jsonify(policy)
    except Exception as e:
        logger.exception('file-policy get')
        return jsonify({'success': False, 'error': str(e)}), 500


@api_bp.route('/api/file-policy', methods=['PUT'])
def update_file_policy():
    """파일 관리 정책을 저장한다 (관리자 전용)."""
    if session.get('role', '').upper() not in ('ADMIN', '관리자'):
        return jsonify({'success': False, 'error': 'forbidden'}), 403
    
    payload = request.get_json(silent=True) or {}
    if not payload:
        return jsonify({'success': False, 'error': '요청 데이터가 없습니다.'}), 400
    
    try:
        _now = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        _by = session.get('emp_no', '') or session.get('user_id', '') or 'admin'
        
        # 주요 필드별 로깅
        old_max_size = 20  # 기본값 (실제로는 DB에서 조회해야 함)
        new_max_size = payload.get('max_file_size_mb', old_max_size)
        if new_max_size != old_max_size:
            _settings_log_api('파일관리', '최대파일크기', str(old_max_size), str(new_max_size))
        
        old_allowed = 'pdf,doc,docx,xls,xlsx'  # 기본값
        new_allowed = payload.get('allowed_extensions', old_allowed)
        if new_allowed and new_allowed != old_allowed:
            _settings_log_api('파일관리', '허용확장자', old_allowed[:30]+'...', new_allowed[:30]+'...')
        
        old_blocked = 'exe,bat,cmd,com,scr'  # 기본값
        new_blocked = payload.get('blocked_extensions', old_blocked)
        if new_blocked and new_blocked != old_blocked:
            _settings_log_api('파일관리', '금지확장자', old_blocked[:30]+'...', new_blocked[:30]+'...')
        
        # 보안 옵션 로깅
        security_flags = {
            'block_executable_upload': '실행파일차단',
            'validate_mime_type': 'MIME검증',
            'validate_magic_bytes': '매직바이트검사',
            'detect_extension_spoofing': '확장자위장탐지',
            'enable_virus_scan': '바이러스검사',
        }
        for key, label in security_flags.items():
            old_val = True if key == 'block_executable_upload' else False  # 기본값
            new_val = bool(payload.get(key, old_val))
            if new_val != old_val:
                _settings_log_api('파일관리', label, 'OFF', 'ON' if new_val else 'OFF')
        
        db.session.commit()
        
        return jsonify({
            'success': True,
            'item': payload,
            'message': '파일 정책이 저장되었습니다.'
        })
    except Exception as e:
        db.session.rollback()
        logger.exception('file-policy update')
        return jsonify({'success': False, 'error': str(e)}), 500


def _web_access_current_actor() -> tuple[Optional[Dict[str, Any]], Optional[tuple[dict, int]]]:
    user_id = _coerce_positive_int(_resolve_actor_user_id())
    if not user_id:
        return None, ({'success': False, 'message': '로그인이 필요합니다.'}, 401)
    user = UserProfile.query.get(user_id)
    if not user:
        return None, ({'success': False, 'message': '사용자 정보를 찾을 수 없습니다.'}, 404)
    dept = None
    if getattr(user, 'department_id', None):
        dept = OrgDepartment.query.get(user.department_id)
    actor = {
        'user_id': user.id,
        'emp_no': (user.emp_no or '').strip(),
        'name': (user.name or '').strip(),
        'role': (user.role or '').strip(),
        'department_id': getattr(user, 'department_id', None),
        'department_name': ((dept.dept_name if dept else '') or getattr(user, 'department', '') or '').strip(),
        'manager_emp_no': ((dept.manager_emp_no if dept else '') or '').strip(),
        'manager_name': ((dept.manager_name if dept else '') or '').strip(),
        'ip_address': (request.remote_addr or '').strip(),
    }
    return actor, None


def _is_admin_actor(actor: Dict[str, Any]) -> bool:
    return str(actor.get('role') or '').strip().upper() in ('ADMIN', '관리자')


def _resource_access_state(resource: Dict[str, Any], actor: Dict[str, Any]) -> Dict[str, Any]:
    resource_id = int(resource.get('id') or 0)
    user_id = int(actor.get('user_id') or 0)
    has_grant = svc_has_web_access_grant(user_id, resource_id)
    has_pending = svc_has_web_access_pending_request(user_id, resource_id)
    grants = svc_list_web_access_grants(user_id=user_id, resource_id=resource_id)
    grant_row = grants[0] if grants else None
    if int(resource.get('active_flag') or 0) != 1:
        state = '차단'
    elif has_grant:
        state = '사용 가능'
    elif has_pending:
        state = '승인 대기'
    elif grant_row:
        state = '만료'
    else:
        state = '차단'
    return {
        'access_status': state,
        'can_access': bool(has_grant and int(resource.get('active_flag') or 0) == 1),
        'can_request': bool(not has_grant and not has_pending and int(resource.get('active_flag') or 0) == 1),
        'request_pending': bool(has_pending),
        'grant_end_date': (grant_row or {}).get('grant_end_date', ''),
        'last_accessed_at': (grant_row or {}).get('last_accessed_at', ''),
        'requested': bool(has_pending or grant_row),
    }


@api_bp.route('/api/access-control/resources', methods=['GET'])
def api_access_control_resources():
    actor, err = _web_access_current_actor()
    if err:
        body, code = err
        return jsonify(body), code
    rows = svc_list_web_access_resources(
        search=(request.args.get('search') or '').strip(),
        status=(request.args.get('status') or '').strip(),
        resource_type=(request.args.get('resource_type') or '').strip(),
    )
    items = []
    for row in rows:
        merged = dict(row)
        merged.update(_resource_access_state(row, actor))
        items.append(merged)
    return jsonify({'success': True, 'rows': items, 'total': len(items)})


@api_bp.route('/api/access-control/resources/<int:resource_id>', methods=['GET'])
def api_access_control_resource_detail(resource_id: int):
    actor, err = _web_access_current_actor()
    if err:
        body, code = err
        return jsonify(body), code
    row = svc_get_web_access_resource(resource_id)
    if not row:
        return jsonify({'success': False, 'message': '자원 정보를 찾을 수 없습니다.'}), 404
    detail = dict(row)
    detail.update(_resource_access_state(row, actor))
    my_requests = svc_list_web_access_requests(user_id=actor['user_id'])
    detail['request_history'] = [item for item in my_requests if int(item.get('resource_id') or 0) == resource_id]
    return jsonify({'success': True, 'item': detail})


