# ──────────────────────────────────────────────────────────────
# SAN Zone 구성 (tab33) — SAN 디렉터/스위치 상세 탭
# ──────────────────────────────────────────────────────────────

def _hw_san_zone_to_dict(z):
    """HwSanZone → dict (멤버 수 포함)."""
    members = HwSanZoneMember.query.filter(
        HwSanZoneMember.zone_id == z.id,
        (HwSanZoneMember.is_deleted == 0) | (HwSanZoneMember.is_deleted.is_(None)),
    ).all()
    initiators = [m for m in members if (m.role or '').lower() == 'initiator']
    targets    = [m for m in members if (m.role or '').lower() == 'target']
    return {
        'id': z.id,
        'asset_category': z.asset_category or '',
        'asset_id': int(z.asset_id),
        'zone_name': z.zone_name or '',
        'entry_type': z.entry_type or 'zone',
        'fabric': z.fabric or '',
        'status': z.status or 'Active',
        'member_count': len(members),
        'initiator_count': len(initiators),
        'target_count': len(targets),
        'remark': z.remark or '',
        'initiators': [{'id': m.id, 'alias': m.alias or '', 'wwn': m.wwn or ''} for m in initiators],
        'targets':    [{'id': m.id, 'alias': m.alias or '', 'wwn': m.wwn or ''} for m in targets],
        'created_at': z.created_at,
        'updated_at': z.updated_at,
    }


@api_bp.route('/api/hardware/assets/<int:asset_id>/zones', methods=['GET'])
def list_hw_san_zones(asset_id: int):
    """SAN Zone 목록 조회."""
    try:
        query = HwSanZone.query.filter(
            HwSanZone.asset_id == asset_id,
            (HwSanZone.is_deleted == 0) | (HwSanZone.is_deleted.is_(None)),
        ).order_by(HwSanZone.id.asc())
        rows = [_hw_san_zone_to_dict(z) for z in query.all()]
        return jsonify({'success': True, 'rows': rows, 'total': len(rows)})
    except Exception:
        logger.exception('Failed to list SAN zones')
        return jsonify({'success': False, 'error': 'Zone 목록 조회 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/assets/<int:asset_id>/zones', methods=['POST'])
def create_hw_san_zone(asset_id: int):
    """SAN Zone 등록."""
    payload = request.get_json(silent=True) or {}
    zone_name = (payload.get('zone_name') or '').strip()
    if not zone_name:
        return jsonify({'success': False, 'error': 'zone_name은 필수 입력 항목입니다.'}), 400

    fabric = (payload.get('fabric') or '').strip()
    entry_type = (payload.get('entry_type') or 'zone').strip().lower()
    if entry_type not in ('cfg', 'zone', 'alias'):
        entry_type = 'zone'
    status = (payload.get('status') or 'Active').strip()
    remark = (payload.get('remark') or '').strip()
    asset_category = (payload.get('asset_category') or 'SAN').strip().upper()

    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        zone = HwSanZone(
            asset_category=asset_category,
            asset_id=asset_id,
            zone_name=zone_name,
            entry_type=entry_type,
            fabric=fabric,
            status=status,
            remark=remark,
            created_at=now,
            updated_at=now,
            is_deleted=0,
        )
        db.session.add(zone)
        db.session.commit()

        _try_record_change(
            action_type='CREATE', entity_type='hardware_asset',
            entity_id=asset_id, tab_name='Zone 구성',
            new_data=_hw_san_zone_to_dict(zone),
            summary='Zone 추가: ' + zone_name,
        )

        return jsonify({'success': True, 'item': _hw_san_zone_to_dict(zone)}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to create SAN zone')
        return jsonify({'success': False, 'error': 'Zone 등록 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/assets/<int:asset_id>/zones/<int:zone_id>', methods=['PUT'])
def update_hw_san_zone(asset_id: int, zone_id: int):
    """SAN Zone 수정."""
    payload = request.get_json(silent=True) or {}
    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        zone = HwSanZone.query.filter(
            HwSanZone.id == zone_id,
            HwSanZone.asset_id == asset_id,
        ).first()
        if not zone or int(zone.is_deleted or 0) != 0:
            return jsonify({'success': False, 'error': '대상 Zone을 찾을 수 없습니다.'}), 404

        old_data = _hw_san_zone_to_dict(zone)

        if 'zone_name' in payload:
            v = (payload['zone_name'] or '').strip()
            if not v:
                return jsonify({'success': False, 'error': 'zone_name은 필수 입력 항목입니다.'}), 400
            zone.zone_name = v
        if 'entry_type' in payload:
            et = (payload['entry_type'] or 'zone').strip().lower()
            if et in ('cfg', 'zone', 'alias'):
                zone.entry_type = et
        for k in ('fabric', 'status', 'remark'):
            if k in payload:
                setattr(zone, k, (payload[k] or '').strip())

        # 멤버 role 업데이트 (드래그 앤 드롭 결과 저장)
        members_payload = payload.get('members')
        if members_payload and isinstance(members_payload, list):
            for mp in members_payload:
                if not isinstance(mp, dict):
                    continue
                mid = mp.get('id')
                new_role = (mp.get('role') or '').strip().lower()
                if not mid or new_role not in ('initiator', 'target'):
                    continue
                member = HwSanZoneMember.query.filter(
                    HwSanZoneMember.id == int(mid),
                    HwSanZoneMember.zone_id == zone_id,
                ).first()
                if member and int(member.is_deleted or 0) == 0:
                    member.role = new_role
                    member.updated_at = now

        zone.updated_at = now
        db.session.commit()

        _try_record_change(
            action_type='UPDATE', entity_type='hardware_asset',
            entity_id=asset_id, tab_name='Zone 구성',
            old_data=old_data, new_data=_hw_san_zone_to_dict(zone),
            summary='Zone 수정: ' + (zone.zone_name or ''),
        )

        return jsonify({'success': True, 'item': _hw_san_zone_to_dict(zone)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to update SAN zone')
        return jsonify({'success': False, 'error': 'Zone 수정 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/assets/<int:asset_id>/zones/bulk-delete', methods=['POST'])
def bulk_delete_hw_san_zones(asset_id: int):
    """SAN Zone 일괄 소프트 삭제."""
    payload = request.get_json(silent=True) or {}
    ids = payload.get('ids') or []
    if not ids:
        return jsonify({'success': False, 'error': '삭제할 Zone을 선택하세요.'}), 400

    now = datetime.utcnow().isoformat(timespec='seconds')
    try:
        zones = HwSanZone.query.filter(
            HwSanZone.id.in_(ids),
            HwSanZone.asset_id == asset_id,
            (HwSanZone.is_deleted == 0) | (HwSanZone.is_deleted.is_(None)),
        ).all()

        deleted_names = []
        for z in zones:
            z.is_deleted = 1
            z.updated_at = now
            deleted_names.append(z.zone_name or '')
            # 멤버도 소프트 삭제
            HwSanZoneMember.query.filter(
                HwSanZoneMember.zone_id == z.id,
            ).update({'is_deleted': 1, 'updated_at': now})

        db.session.commit()

        if deleted_names:
            _try_record_change(
                action_type='DELETE', entity_type='hardware_asset',
                entity_id=asset_id, tab_name='Zone 구성',
                summary='Zone 삭제: ' + ', '.join(deleted_names),
            )

        return jsonify({'success': True, 'deleted': len(zones)})
    except Exception:
        db.session.rollback()
        logger.exception('Failed to bulk-delete SAN zones')
        return jsonify({'success': False, 'error': 'Zone 삭제 중 오류가 발생했습니다.'}), 500


@api_bp.route('/api/hardware/assets/<int:asset_id>/zones/import', methods=['POST'])
def import_hw_san_zones(asset_id: int):
    """cfgshow 텍스트를 파싱하여 Zone 일괄 등록."""
    import re as _re
    payload = request.get_json(silent=True) or {}
    text = payload.get('text', '')
    if not text or not text.strip():
        return jsonify({'success': False, 'error': 'cfgshow 내용을 입력하세요.'}), 400

    asset_category = (payload.get('asset_category') or 'SAN').strip().upper()
    status = (payload.get('status') or '활성').strip()
    now = datetime.utcnow().isoformat(timespec='seconds')

    # ── cfgshow 파싱 ──
    wwn_re = _re.compile(r'^[\da-fA-F]{2}(?::[\da-fA-F]{2}){7}$')
    port_re = _re.compile(r'^\d+,\d+$')
    entries = []       # [{type, name, members:[str]}]
    current = None

    for raw_line in text.splitlines():
        stripped = raw_line.strip()
        if not stripped:
            continue

        # cfg: / zone: / alias: 줄 판별
        m = _re.match(r'^(cfg|zone|alias)\s*:\s*(\S+)\s*(.*)', stripped, _re.IGNORECASE)
        if m:
            entry_type = m.group(1).lower()
            name = m.group(2)
            rest = m.group(3).strip()
            current = {'type': entry_type, 'name': name, 'members': []}
            entries.append(current)
            # zone: zone2  alias3; alias4  형태의 인라인 멤버
            if rest:
                for part in _re.split(r'[;\s]+', rest):
                    part = part.strip()
                    if part:
                        current['members'].append(part)
            continue

        # 들여쓰기 WWN / 포트 / alias 참조 (현재 zone/alias 에 소속)
        if current:
            # 여러 토큰이 한 줄에 올 수 있으므로 split
            tokens = stripped.split()
            for tok in tokens:
                tok = tok.strip().rstrip(';')
                if tok:
                    current['members'].append(tok)

    if not entries:
        return jsonify({'success': False, 'error': '파싱된 항목이 없습니다. cfgshow 형식을 확인하세요.'}), 400

    # cfg 엔트리의 members가 비어있으면, 뒤따르는 zone 이름을 자동 수집
    for ci, ent in enumerate(entries):
        if ent['type'] == 'cfg' and not ent['members']:
            for zi in range(ci + 1, len(entries)):
                if entries[zi]['type'] == 'cfg':
                    break
                if entries[zi]['type'] in ('zone', 'alias'):
                    ent['members'].append(entries[zi]['name'])

    try:
        created_zones = []
        for ent in entries:
            zone = HwSanZone(
                asset_category=asset_category,
                asset_id=asset_id,
                zone_name=ent['name'],
                entry_type=ent['type'],
                status=status,
                remark='',
                created_at=now,
                updated_at=now,
                is_deleted=0,
            )
            db.session.add(zone)
            db.session.flush()  # id 확보

            for idx, mem_val in enumerate(ent['members']):
                is_wwn = bool(wwn_re.match(mem_val))
                is_port = bool(port_re.match(mem_val))
                # WWN/포트이면 첫 번째=Initiator, 나머지=Target (모든 타입)
                if is_wwn or is_port:
                    role = 'initiator' if idx == 0 else 'target'
                else:
                    role = 'target'
                member = HwSanZoneMember(
                    zone_id=zone.id,
                    role=role,
                    alias='' if (is_wwn or is_port) else mem_val,
                    wwn=mem_val if (is_wwn or is_port) else '',
                    created_at=now,
                    updated_at=now,
                    is_deleted=0,
                )
                db.session.add(member)
            created_zones.append(zone)

        db.session.commit()

        names = [z.zone_name for z in created_zones]
        _try_record_change(
            action_type='CREATE', entity_type='hardware_asset',
            entity_id=asset_id, tab_name='Zone 구성',
            summary='cfgshow 가져오기: ' + ', '.join(names[:5]) + ('...' if len(names) > 5 else ''),
        )

        rows = [_hw_san_zone_to_dict(z) for z in created_zones]
        return jsonify({'success': True, 'rows': rows, 'total': len(rows)}), 201
    except Exception:
        db.session.rollback()
        logger.exception('Failed to import cfgshow zones')
        return jsonify({'success': False, 'error': 'cfgshow 가져오기 중 오류가 발생했습니다.'}), 500

